/* characters q13 (109 mục) — R2.6 bồi tiểu sử Liên Đạo Phi */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q13"]=window.__LIBQ["tien-nghich"]["q13"]||{};window.__LIBQ["tien-nghich"]["q13"]["characters"]={"updatedAt":"2026-07-16","count":109,"chars":[{"id":"vuong-lam","name":"Vương Lâm","cn":"王林","canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Vương Lâm từ cổ mộ bước vào La Thiên Tinh Vực, uy áp quét ngang toàn bộ tinh vực khiến Lỗ Phu Tử Không Niết Sơ Kỳ sắc mặt đại biến, thừa nhận không nắm chắc chiến thắng. Phát hiện bị La Thiên Huyễn Kính quan sát, quát một tiếng rồi dùng lôi đồ trong mắt phải phá hủy tấm kính từ xa, lôi đình kinh thiên khiến bốn người phun máu. Chậm rãi bay trong tinh không, cảm thấy quen thuộc, thầm nghĩ không biết những người năm đó có còn không.","anchor":"Không biết những người năm đó hiện giờ có còn không","bridge":true,"khoang":"@c1387"},{"mucCt":"ky","text":"Vương Lâm trở về La Thiên Tinh Vực, bình tĩnh cảm nhận có người thi triển đạo thuật dò xét mình nhưng tự tin với tu vi hiện tại không lo lắng. Gặp lại đội tu sĩ do Chiến Không Liệt chỉ huy kéo tu chân tinh, nhận ra Chiến Không Liệt nhưng không lên tiếng, nhớ lại cảnh tượng năm xưa ở Lôi Trì khi Chiến Không Liệt bái mình làm tôn chủ, mỉm cười cảm thán rồi xoay người bay đi. Cuối chương tiếng thở dài từ thiên địa truyền tới Thanh Linh Tinh, gọi tên Tạ Thanh, hàm ý chính hắn là sư tôn của Tạ Thanh đã trở về sau hơn tám trăm năm.","anchor":"Ta vẫn còn nhớ …. tên ngươi là Tạ Thanh !","bridge":true,"khoang":"@c1388"},{"chuong":"@c1389","importance":"normal","mucCt":"ky","tieuDe":"Trở lại Thanh Linh Tinh, giảng đạo và tạo vũ kiếm trấn tinh","text":"Sau tám trăm năm xa cách, Vương Lâm quay về Thanh Linh Tinh gặp lại ký danh đệ tử Tạ Thanh trên đỉnh Hoành Vân Sơn. Nhận ra Tạ Thanh đang tu hồn — chỉ tu ý cảnh, không có nguyên thần, nguyên anh hay nội thần — ý cảnh đạt Tịnh Niết sơ khuy quy tắc. Giảng lý phản phác quy chân: đem bản thân dung nhập thiên địa, bỏ hết thân thể và pháp thuật, chỉ còn hồn phách mới hoàn toàn minh ngộ. Thu toàn bộ nước mưa gần nửa Thanh Linh Tinh ngưng tụ thành vũ kiếm vạn trượng cắm trên đỉnh Hoành Vân Sơn, chú nhập Cổ Thần lực cùng lôi hỏa bổn nguyên và khí thế Đạo Cổ, uy lực khiến ngay cả cao thủ Không Linh do dự. Tuyên bố kiếm này là lễ nhập môn cho Tạ Thanh khi minh ngộ. Rời Thanh Linh Tinh hướng tới tu chân tinh Hướng gia, tuyên bố trở lại La Thiên muốn tới bốn nơi làm bốn việc, việc thứ nhất đã xong.","anchor":"Vương Lâm vung tay áo, thân ảnh hắn như điện, lao thẳng tới tu chân tinh của Hướng gia"},{"mucCt":"ky","text":"Xuất hiện ở tinh không bên ngoài Đông Lâm Tinh, mặc bạch y, nhìn trận pháp phòng ngự tỏa sáng của Hướng gia. Hồi tưởng năm xưa cùng Thanh Thủy lần đầu tới đây. Hàn quang ngập trời tỏa ra trong mắt, bộc lộ sát ý. Được Lỗ Phu Tử đánh giá có hai đạo bổn nguyên nhưng chưa đạt bước thứ ba. Lão tổ Hướng gia thèm muốn sinh cơ của hắn, cho rằng sinh cơ hắn rất hợp, có thể giúp lão trở lại rất lâu.","anchor":"Dần dần trong mắt Vương Lâm tỏa ra hàn quang ngập trời!","bridge":true,"khoang":"@c1390"},{"mucCt":"ky","text":"Đứng cách Đông Lâm Tinh mấy vạn trượng, hồi tưởng toàn bộ mối hận năm xưa bị lão tổ Hướng gia dùng Thất Tịch Thuật lừa gạt, cướp toàn bộ sức sống dưới danh nghĩa cứu Lý Mộ Uyển, gián tiếp khiến nàng hồn bay phách tán. Nhận ra Thất Tịch Thuật hoàn toàn không có khả năng hồi sinh người, và nếu không có Tị Thiên Quan thì hy vọng hồi sinh Lý Mộ Uyển cũng bị dập tắt. Bước một bước rút ngắn mấy vạn trượng, há miệng phát tiếng rống kinh thiên hóa lôi đình ngợp trời, phá hủy chín tu chân tinh bên ngoài Đông Lâm Tinh, giết sạch toàn bộ tu sĩ và 27 lão già nắm giữ trận pháp trên đó. Tiếng rống chấn động cả Đông Lâm Tinh khiến mặt đất nứt, núi tan, biển phía bắc dâng sóng ngàn trượng nhấn chìm lục địa, giết chết một trong hai lão già áo đen ở cực tây. Tuyên bố sẽ tự lôi lão tổ Hướng gia ra, ai ngăn cản đều bị chôn cùng.","anchor":"Ngươi không ra đây, như vậy phải để Vương mỗ lôi ngươi ra! Tất cả những người ngăn cản, đều sẽ bị chôn cùng!","bridge":true,"khoang":"@c1391"},{"mucCt":"ky","text":"Tiến về Đông Lâm Tinh, đối mặt đại trận thượng cổ hơn chín ngàn vạn tầng hào quang do Lữ gia kích hoạt. Kích hoạt bảy tinh điểm Cổ Thần trên mi tâm, giải phóng khí tức Đạo Cổ, phía sau hiện hư ảnh khổng lồ — cái đầu không có mắt trái che phủ tinh không. Đánh ra một quyền Thần Chấn dung hợp thất tinh Cổ Thần và Đạo Cổ truyền thừa, nắm tay hư ảo mấy vạn trượng phá vỡ toàn bộ hào quang trận pháp, đánh nát mấy chục tiểu tinh, đánh tan huyết ảnh trận linh Lữ gia, nện xuống phía bắc Đông Lâm Tinh tạo hố sâu mấy vạn trượng, gần một vạn tu sĩ Lữ gia tử vong. Toàn bộ chỉ trong tám nhịp thở. Được Lỗ Phu Tử đặt ngang hàng với mình.","anchor":"một quyền Thần Chấn của Vương Lâm là một đòn kinh thiên sau khi dung hợp sức mạnh thất tinh Cổ Thần với Đạo cổ truyền thừa","bridge":true,"khoang":"@c1392"},{"mucCt":"ky","text":"Xuất hiện trên bầu trời Đông Lâm Tinh sau quyền Đạo Cổ Thần Chấn, quát lão tổ Hướng gia chui ra khỏi quan tài. Một chưởng đỡ cột sáng Huyết Quỳ Thuật của Lưu gia gần ngang bước thứ ba Không Niết Sơ Kỳ, thân bất động, lực phản chấn tách phần phía đông Đông Lâm Tinh thành mảnh vỡ tinh cầu bay vào tinh hải. Tiếc nuối thần thông Huyết Quỳ Thuật bị hủy. Triển khai Hư Hỏa — ngọn lửa chín màu từ mắt trái — thiêu mấy vạn tu sĩ Hướng gia và Hứa gia điên cuồng lao tới thành tro bụi không ngoại lệ. Bước tới cực tây, vào không gian dưới lòng đất nơi quan tài lão tổ Hướng gia, phá tan sóng chất lỏng tử khí.","anchor":"Vương Lâm ta cả đời giết chóc rất nhiều, ta không ngại giết người","bridge":true,"khoang":"@c1393"},{"mucCt":"ky","text":"Tung hai chỉ phá nát tứ chi Đông Lâm Thái (lão tổ Hướng gia, tu vi Thiên Nhân Đệ Ngũ Suy), túm thiên linh triển khai Sưu Hồn Thuật tìm câu trả lời rồi nổ đầu kết liễu. Lão lộ thân phận tộc nhân phân hệ gia tộc Đông Lâm viễn cổ, dọa tru di cửu tộc. Cánh cửa vàng gia tộc Đông Lâm xuất hiện giữa không trung, lão già kim bào thi triển Huyễn Thần Thuật tạo người khổng lồ kim giáp ngàn trượng tuyên ba tội trạng, vung đại kiếm vàng ngàn trượng chém xuống. Vương Lâm một chỉ chứa Đạo cổ lực kết hợp lôi hỏa bổn nguyên phá tan đại kiếm, phóng huyết kiếm đâm xuyên phá vỡ Huyễn Thần Thuật, bức lão già kim bào nửa bước thứ ba lộ bản thể và trọng thương. Tuyên bố đã giết đủ, cảnh cáo xong bước vào tinh không rời đi. Nam tử trung niên Đông Lâm gia tiết lộ trên người Vương Lâm có hai luồng khí tức cao thủ bước thứ ba, chỉ mới lộ một phần nhỏ thực lực.","anchor":"hắn giơ tay phải lên hướng về phía trước điểm một cái","bridge":true,"khoang":"@c1394"},{"mucCt":"ky","text":"Qua soát hồn lão tổ Hướng gia, hiểu rõ nguyên nhân năm xưa bị hút sinh cơ: lão tổ Hướng gia vì dục vọng công pháp mà hút sinh cơ, nhưng bị thần niệm gia tộc viễn cổ Đông Lâm buộc tha mạng, chuyển sang hấp thụ sinh cơ Cổ Thần qua linh hồn Vương Lâm. Suy đoán gia tộc viễn cổ Đông Lâm có Cổ Thần tồn tại. Xác nhận đã hoàn thành hai trong bốn việc, tuyên bố mục tiêu thứ ba: Diêu gia — Huyết Thần Tử, trả thù đuổi giết phân thân năm xưa, đoạt Cổ Yêu lực cho phân thân Cổ Yêu, đồng thời xử lý nhân quả với nữ tử Diêu gia.","anchor":"Bốn việc lúc này đã hoàn thành được hai việc. Việc thứ ba tiếp theo.Diêu gia. Huvết Thần Từ.","bridge":true,"khoang":"@c1395"},{"mucCt":"ky","text":"Nhìn thấu thương thế nguyên thần Tây Tử Phượng — tật cũ do bị thương nhiều lần, gần đây lại thêm một lần nặng. Nhận ra lão già Chu Tùng Vân là tu sĩ từng được hắn cứu ra khỏi Lôi Tiên Giới, nghe lão tố cáo nam tử trung niên sứ giả Lôi Tiên Điện chính là kẻ hết lần này đến lần khác làm khó Tây Tử Phượng. Vương Lâm nhìn thấu bản chất sự việc, tuyên bố sứ giả đáng chết, giơ tay phải chuẩn bị ra tay. Cảm khái tám trăm năm vật còn người mất, hồng nhan chỉ là giấc mộng.","anchor":"Thời gian tám trăm năm, vật còn người mất, hồng nhan đêm qua chi là một giấc mộng","bridge":true,"khoang":"@c1397"},{"mucCt":"ky","text":"Phất tay giết chết sứ giả Lôi Tiên Điện (Khuy Niết) dễ như giết kiến, gần trăm tu sĩ kinh hoàng. Tặng lão già bảo vệ Tây Tử Phượng một viên đan dược chứa hồn phách mãnh thú. Đưa Tây Tử Phượng tới đỉnh núi tuyết trong La Thiên Tinh Vực, dùng nguyên lực chữa lành thương thế và khôi phục dung nhan diễm lệ (vết sẹo tự hủy tám trăm năm trước tiêu tan). Nhắc cả đời chỉ nhận hai đệ tử (Tạ Thành Thanh, Thập Tam), mời nàng làm đệ tử thứ ba. Tây Tử Phượng quỳ trong tuyết bái sư, cắt đứt tình cảm tám trăm năm. Truyền nguyên lực vô biên kèm một phần cảm ngộ cả đời vào cơ thể nàng, đưa tu vi từ dưới Dương Thực lên thẳng Tinh Tịnh Niết, đặt ba đạo phong ấn áp chế. Thuật truyền công này cực khó, ngay cả hắn cũng khó làm lại.","anchor":"Hắn vốn không phải là một người vô tình, nhưng hắn cũng không thể đón nhận hết thảy","bridge":true,"khoang":"@c1398"},{"mucCt":"ky","text":"Giữa trời tuyết, ngưng tụ tuyết thành tinh thể băng, phun máu Cổ Thần nhuốm đỏ, nhập một tia Cực Cảnh Lôi đình từ mắt phải, vỗ thành thanh trường kiếm đỏ máu, tuyên bố dưới bước thứ ba không ai chịu nổi một nhát kiếm. Đưa kiếm cho Tây Tử Phượng, kiếm dung nhập cơ thể nàng thành bản mệnh pháp bảo. Dặn nàng có sư huynh trên Thanh Linh Tinh, nếu cần trợ giúp có thể mang kiếm đi phòng thân. Lúc truyền công cho Tây Tử Phượng đã dựa vào tu vi cường hãn đảo qua ký ức của nàng, ghi nhớ bộ dạng tất cả kẻ đã làm nhục nàng trong tám trăm năm. Dựa vào thần thức cảm ứng phóng ra gần một trăm đạo kiếm khí quét ngang La Thiên Tinh Vực, giết hết những kẻ đó không thừa không sót. Kiếm khí giáng xuống giết gia chủ Triệu gia trên Vân Động Tinh, đại trưởng lão gia tộc Đông Lai trên Thiên Mạc Tinh, thiếu tộc trưởng Lô gia trên Tử Miểu Tinh cùng nhiều kẻ khác. Mười một đạo kiếm khí xâm nhập tinh trận Lôi Tiên Điện giết mười một người bên trong. Sau đó xuất hiện bên ngoài tinh trận Lôi Tiên Điện, chậm rãi bước tới, mỗi bước khiến tinh không ầm vang như lôi đình, vô số tu sĩ Lôi Tiên Điện sắc mặt tái nhợt nhất tề lùi lại như thủy triều.","anchor":"Không giết hơn một người nào, cũng không bỏ qua một người nào, Vương Lâm dựa vào cảm ứng bằng thần thức đã phóng ra gần một trăm đạo kiếm khí, quét ngang La Thiên!","bridge":true,"khoang":"@c1399"},{"mucCt":"ky","text":"Kích hoạt bảy tinh điểm Cổ Thần và đầu Đạo Cổ, phát tiếng rống Đạo Cổ áp đảo hoàn toàn tiếng gào thét Không Niết Sơ Kỳ của Lỗ Phu Tử, khiến vòng xoáy tinh trận ngừng xoay. Tiến vào tinh trận, chào Viêm Lôi Tử bằng xưng hô 'đạo hữu' thay vì 'tiền bối' năm xưa, thể hiện tu vi đã san bằng. Chỉ tay vào Huyết Thần Tử tuyên bố chỉ cần người này, nói hắn 'rất có ích', từ chối lời xin tha của Lỗ Phu Tử. Lỗ Phu Tử nổi giận thách đấu trong tinh trận, Vương Lâm thản nhiên chấp nhận.","anchor":"Đừng nói nhảm, ngươi muốn đánh, thì đánh đi.","bridge":true,"khoang":"@c1400"},{"mucCt":"ky","text":"Đối mặt Lỗ Phu Tử, nổi chiến ý vì tự tin sau khi đạt thất tinh Cổ Thần và từng đánh với Thác Sâm ở Thái Cổ Tinh Thần, chưa giao chiến cao thủ bước thứ ba nào kể từ đó. Lỗ Phu Tử đề nghị đấu văn ba hiệp thay vì giao chiến để tránh kích động Phong Giới Đại Trận, điều kiện cược: Vương Lâm thắng thì nhận Huyết Thần Tử, thua thì phải rời La Thiên. Vương Lâm mỉm cười đồng ý, chọn luyện khí cho hiệp đầu. Khi cuồng phong bổn nguyên của Lỗ Phu Tử quét qua trong lúc luyện khí, hắn dùng lôi hỏa bổn nguyên triệt tiêu từng tầng, thân thể bất động, thần sắc bình tĩnh tuyệt đối.","anchor":"hắn lúc ở trong Thái cổ Tinh Thần tại giới ngoại đã trải qua rất nhiều chuyện, gặp rất nhiều cao thủ bước thứ ba","bridge":true,"khoang":"@c1401"},{"mucCt":"ky","text":"Nhìn thấu tâm cơ Lỗ Phu Tử ẩn trong La Thiên Thụ — phá hủy nó đồng nghĩa đối kháng chiến ý toàn La Thiên, nhưng vẫn thừa nhận là thượng phẩm. Một trảo phá vỡ chín tu chân tinh rút tinh chất màu vàng làm vật liệu, Lỗ Phu Tử kinh hãi so sánh sức thân thể hắn với Cổ Thần Thác Sâm. Lần lượt dung nhập sát khí cả đời qua chín giai đoạn chiến sát: Chu Tước Tinh, Liên Minh Tinh Vực, La Thiên Tinh Vực, Vân Hải Tinh Vực, Thất Thải Giới, Thái Cổ Tinh Thần giới ngoại, Thiểm Lôi Tộc, cổ mộ, Đông Lâm Tinh. Chín giọt ngưng tụ thành viên huyết tinh chứa vô số vong hồn chết dưới tay hắn. Phóng huyết tinh tới Lỗ Phu Tử, bức lui mấy vạn tu sĩ phun máu, tinh trận dừng vận chuyển, La Thiên Thụ chấn động suýt vỡ. Tuyên bố bảo vật không cần bổn nguyên, huyết mạch hay chiến ý, chỉ sát khí cả đời cũng đủ phá La Thiên Thụ, thể hiện tự tin bá đạo tuyệt đối.","anchor":"Bởi vì nó là do ta luyện ra. Ta nói có thể phá hủy, thì nhất định là có thể","bridge":true,"khoang":"@c1402"},{"mucCt":"ky","text":"Từ chối đấu đạo niệm với Lỗ Phu Tử, bước thẳng về phía Huyết Thần Tử muốn trực tiếp giết. Đối mặt toàn bộ khí thế bước thứ ba, tinh trận La Thiên và Phong Tiên Giới của Lỗ Phu Tử mà vẫn bình tĩnh. Lần đầu tiên sau khi trở lại La Thiên Tinh Vực bộ lộ hoàn toàn khí tức Cổ Thần Thất Tinh, bảy tinh điểm mi tâm chuyển động, khí tức ngang tu sĩ bước thứ ba. Dùng Thiên Hoàng Lô triệu hoán cổ nô Linh Động Thượng Nhân, khiến Lỗ Phu Tử chấn động dừng bước, Viêm Lôi Tử thừ người.","anchor":"bảy tinh điểm trên mi tâm chuyển động, khí tức cường hãn của cổ Thần Thất Tinh có thể so với tu sĩ bước thứ ba bộc phát hoàn toàn","bridge":true,"khoang":"@c1403"},{"mucCt":"ky","text":"Bình thản đối mặt Lỗ Phu Tử kích hoạt tinh trận cùng 18 pháp bảo bức tới. Cau mày gọi Cổ nô Chu Cẩn, triệu hoán Chu Cẩn từ Thiên Hoàng Lô hiện thân. Lần đầu tiên lộ việc sở hữu HAI nô phó bước thứ ba (Linh Động Thượng Nhân + Chu Cẩn), uy áp ba bước thứ ba đè sụp hoàn toàn tinh trận, Phong Tiên Giới, tàn kiếm của phe La Thiên mà không cần tự tay ra chiêu. Lỗ Phu Tử mất hết ý chí chiến đấu.","anchor":"Cổ nô Chu Cẩn","bridge":true,"khoang":"@c1404"},{"mucCt":"ky","text":"Dùng tinh điểm Cổ Thần khuếch tán khí tức Đạo cổ, đầu lâu Đạo cổ hiện sau lưng, ánh mắt dung hợp với đầu lâu xuyên thấu nguyên thần Huyết Thần Tử. Xé đôi nguyên thần Huyết Thần Tử từ mi tâm xuống bụng, thân xác tan thành máu thịt, giải quyết hai nhân quả: bị đuổi giết năm xưa và lời hứa trong mộng với nữ tử Diêu gia tám trăm năm trước. Một quyền phá toàn bộ thần thông Cổ Yêu lục tinh (chín con yêu long, chín mươi yêu kỳ, chín trăm chín mươi chín giọt máu, chín ngàn chín trăm chín mươi chín cây hắc châm). Một chưởng đoạt vương tộc pháp khí yêu đao Táng Thổ, lực hút kéo Cổ Yêu thu nhỏ về nắm cổ, bắt sống. Nghe Cổ Yêu tiết lộ bí mật kinh thiên về Diêu gia và thần thông ba mạng. Chất vấn Lỗ Phu Tử ngăn cản kết thúc nhân quả chính vì bí mật này, Lỗ Phu Tử thừa nhận.","anchor":"Giết ngươi Vương Lâm ta xử lý xong được hai nhân quả!","bridge":true,"khoang":"@c1406"},{"mucCt":"ky","text":"Ôm quyền hứa hẹn báo đáp Lỗ Phu Tử khi chiến tranh giới ngoại xảy ra, thái độ khách khí khiến đối phương thừa nhận chịu thua. Giới thiệu hai nô bộc Linh Động Thượng Nhân và Chu Cẩn trước mặt Lỗ Phu Tử. Được Lỗ Phu Tử long trọng nghênh tiếp bằng kim quang vạn trượng, chín kim long, hư ảnh tiên nhân, mời uống rượu tiên hóa giải hiềm khích. Kể lại việc diệt Thiểm Lôi tộc, gặp Tán Linh Thượng Nhân, bị Trường Tôn hội đuổi giết trong hoàn cảnh kinh hiểm, nhưng giữ lại không kể chi tiết về vùng đất Điên Lạc. Thu hồi Cổ Yêu trong tay trước khi ngồi xuống. Nhắc với Liệt Vân Tử rằng đã gặp Chiến Tinh Dã ở giới ngoại, khiến Liệt Vân Tử chấn động kích động.","anchor":"Vương Lâm ta đã từng gặp qua lão tổ của Chiến gia, Chiến Tinh Dã!","bridge":true,"khoang":"@c1407"},{"mucCt":"ky","text":"Thông báo cho Liệt Vân Tử về cái chết của Chiến Tinh Dã, bị Chưởng Tôn của giới ngoại Thái Cổ Tinh Thần giết trong Thất Thải Giới tại Vân Hải. Giải thích Thất Thải Giới hấp thụ đạo niệm tu sĩ giới nội, kết bảy đạo quả, là mối họa khủng khiếp cho đại chiến. Viêm Lôi Tử xác nhận tổng bộ Tu Chân Liên Minh cũng có Thất Thải Giới. Vương Lâm nhận phụ trách phá hủy Thất Thải Giới ở Tu Chân Liên Minh, Lỗ Phu Tử nhận đi Yêu Tông báo tin. Đồng ý cho Viêm Lôi Tử đi cùng tới Tu Chân Liên Minh. Thu Chu Cẩn và Linh Động vào Thiên Hoàng Lô. Việc cuối cùng ở La Thiên là bắt một con thú mạnh ngang bước thứ ba để luyện cổ thần bổn mệnh thú, Vọng Nguyệt cũng không chống cự nổi con thú này. Trên đường đi ngang Nhiễm Vân Tinh, hồi tưởng tình cha con trăm năm với Vương Bình, nhớ về Liễu Mi trên Thiên Huyễn Tinh, rồi hạ xuống Nhiễm Vân Tinh.","anchor":"Hắn muốn đem nó luyện thành cổ thần bổn mệnh thú của mình!","bridge":true,"khoang":"@c1408"},{"mucCt":"ky","text":"Dùng thân phận Hứa Mộc tới Tôn gia trên Nhiễm Vân Tinh thăm cố nhân Tôn Linh đang hấp hối. Đi tới như phàm nhân không ẩn giấu bước chân, hai người trò chuyện suốt đêm. Sáng hôm sau trao cho Tôn Linh một viên đan dược phòng nếu đổi ý muốn sống, rồi thở dài từ biệt. Sau đó một mình đi qua đỉnh núi cao nhất, con sông, biển, bình nguyên, rừng sâu — từng nơi in dấu chân Vương Bình năm xưa. Nhớ lại bài học dạy con: núi như ngạo cốt, sông như lòng tin, biển như tấm lòng. Cảm nhận hồn phách Vương Bình trong Thiên Nghịch Châu. Cho dù là thất tinh Cổ Thần danh chấn giới ngoại, hắn vẫn chỉ là một người cha tưởng niệm đứa con đã chết. Mang thân ảnh cô độc tóc bạc rời khỏi Nhiễm Vân Tinh, chỉ còn tiếng thở dài vang vọng trong thiên địa.","anchor":"cho dù hắn là thất tinh cổ thần, cho dù hắn danh chấn giới ngoại","bridge":true,"khoang":"@c1409"},{"mucCt":"ky","text":"Xông vào cấm địa sương mù La Thiên Tinh Vực tìm U Minh Thú hình kình ngư thân dài mười vạn trượng để thu phục làm Cổ Thần bổn mệnh thú. Phát hiện đống đá trăm trượng là chất thải của U Minh Thú (tu chân tinh bị nuốt hóa đá sau vạn năm), dùng khí tức tàn dư truy vết. Tăng tốc vượt âm thanh bất ngờ đánh chưởng chứa khí tức Đạo cổ hoàn thành phong ấn bên ngoài. Hóa thân hàng ngàn trượng bằng cổ Thần lực vật lộn U Minh Thú, đẩy lùi hơn ngàn trượng rồi nhấc bổng ném xuống. U Minh Thú giả vờ hoảng sợ bỏ chạy nhưng thực ra là mưu lừa, xoay lại triển khai thần thông cắn nuốt — há miệng hơn mười vạn trượng, triệu hồn phách cỡ cả tinh vực, lực hút nuốt cả tu chân tinh hoang dã. Đánh ra quyền tổng lực kết hợp Linh Động hóa Ma Thần, Chu Cẩn hóa huyết lang, đầu Đạo cổ, lôi đình mắt phải, lửa chín màu mắt trái — uy lực tiếp cận Không Linh bước ba tầng hai. Hy sinh Cổ Tức Diệp ném vào hố đen chặn lực hút để thắp tinh điểm thứ năm, triệu Vọng Nguyệt lao vào chắn hố đen đổi thời gian thắp tinh điểm thứ sáu và thứ bảy — phong ấn hồn phách thành công. Nhưng ngay lập tức ánh sáng Thất Thải bùng lên từ hồn khẩu, phá hủy hơn phân nửa phong ấn ngoài và dập tắt ba trong bảy tinh điểm, Minh Chí Giả bay ra niệm kinh — U Minh Thú đã nuốt một phần Thất Thải Giới trong ngàn năm qua. Xuất hiện tấm bia đá khắc chữ đỏ như máu: Đạo Kinh.","anchor":"Lấy ý chí của vương tộc cổ Thần, của Đạo cổ truyền thừa, phong ấn hồn phách ngươi, trở thành bổn mệnh thú!","bridge":true,"khoang":"@c1410"},{"mucCt":"ky","text":"Bị bia đá Đạo Kinh kích hoạt Minh Chí Giả tấn công, phải lùi ba bước. Khi U Minh Thú thi triển tàng hình bỏ chạy, nổi giận điên cuồng vì Linh Động, Chu Cẩn, Vọng Nguyệt, cổ Tức Diệp đều nằm trong cơ thể thú. Bùng phát bổn nguyên lôi đình khuếch trương lôi đồ từ ngàn trượng lên tám ngàn vạn trượng, dung hợp Thiên Hoàng Lô biến tinh không thành lôi trì. Thi triển Chu Tước hư ảnh dung hợp lửa chín màu, đánh ra hơn mười vạn cấm chế khai mở Phần Giới Cổ Tán hình ô khổng lồ, mở một phần xả lửa diệt thế luyện hóa tinh không co rút từ bảy ngàn vạn xuống sáu trăm vạn trượng. Dùng chín giọt độc dịch từ Thiên Hoàng Lô tạo sương độc bức U Minh Thú hiện nguyên hình, xông tới vỗ tay lên phong ấn chỉ còn một tia trên đầu thú.","anchor":"Nuốt được Thất Thải Giới, cũng phải trở thành bổn mệnh thú của Vương Lâm ta!","bridge":true,"khoang":"@c1411"},{"mucCt":"ky","text":"Hoàn thành ba bước phong ấn U Minh Thú: phong ấn bên ngoài bằng chưởng lực truyền sức sống, hồn phong bằng Côn Cực Tiên quất 100 roi ép hồn thoát ra rồi đưa bảy tinh điểm Cổ Thần xuyên vào hồn khẩu khôi phục thất tinh phong ấn, phong ấn máu thịt bằng cách xé miệng U Minh Thú đánh vô số cấm chế Cổ Thần lực vào nội tạng mạch máu khớp xương. Tuyên phong bằng thân phận vương tộc thất tinh Cổ Thần và Đạo cổ truyền thừa, U Minh Thú cúi đầu thần phục. Sau khi thiết lập liên hệ máu thịt, sức sống vô biên từ U Minh Thú tràn vào, thân Cổ Thần bành trướng tới sáu ngàn trượng. Thu nhỏ lại ngoại hình trẻ hơn hẳn, mang màn hư ảo — ngoài tu sĩ bước ba ai cũng thấy hắn như hồn phách hư ảo. Đầu Côn Cực Tiên vỡ tan sau roi thứ 100, tuôn kim quang vạn trượng. Đọc toàn bộ ký ức U Minh Thú, ra lệnh nhả Linh Động Thượng Nhân, Chu Cẩn, Cổ Tức Diệp, Vọng Nguyệt. Phát hiện U Minh Thú khi nuốt Thất Thải Giới đã phá vỡ vách ngăn hấp thụ một Đạo Quả màu cam mười trượng mang đạo niệm hỗn tạp, thu lấy Đạo Quả, nhận định nó có thể giúp ba đạo bổn nguyên nhân quả, sinh tử, chân giả viên mãn.","anchor":"Khó trách trong ký ức của Đồ Ti đã từng nói, chỉ khi có được bổn mệnh thú, sau khi sinh ra Vọng Nguyệt, mới có thể chính thức trở thành cổ Thần","bridge":true,"khoang":"@c1412"},{"mucCt":"ky","text":"Bấm quyết thu phục U Minh Thú, hóa u quang dung hợp vào tinh điểm thứ hai trên mi tâm, hoàn tất bổn mệnh thú thứ hai. Tới huyết tinh đỏ như máu trong La Thiên Tinh Vực, lôi Cổ Yêu ra uy hiếp tiết lộ bí mật. Dùng đấu trí, tiết lộ biết về tế đàn Phong Diệt Tộc ở Thái Cổ Tinh Thần bị mất tích, khiến Cổ Yêu không dám đánh cuộc, tự giao nộp tòa huyết các từ khe không gian trong huyết tinh. Nhận xét bản thân cũng đã có một tòa huyết các, nay sở hữu hai phần ba tế đàn Phong Diệt Tộc. Phong ấn Cổ Yêu thu vào không gian trữ vật. Di chuyển tới ranh giới La Thiên – Vân Hải Tinh Vực, tuyên bố sẽ thanh toán mối thù với Thủy Đạo Tử.","anchor":"Mối thù với Thủy Đạo Tử năm đó, hôm nay Vương mỗ sẽ giải quyết","bridge":true,"khoang":"@c1413"},{"mucCt":"vua","text":"Bị Thủy Đạo Tử cảm nhận khí tức trở về. Bị vu cáo là gian tế của Thái Cổ Tinh Thần chiếm Thiên Nghịch, bị kêu gọi toàn giới nội bốn tinh vực truy sát. Thủy Đạo Tử tiết lộ từng báo tin hắn cho Diệu Âm đạo tôn ở giới ngoại.","anchor":"Người này chính là một trong những quân cờ của chưởng tôn!","bridge":true,"khoang":"@c1414"},{"mucCt":"ky","text":"Phát hiện sáu ngọc giản Thủy Đạo Tử vu hắn là gian tế giới ngoại, sát khí dâng trào hóa sương giá lan rộng từ ngàn trượng đến mười vạn trượng đóng băng tinh vực. Trên đường tiến về Thần Tông, sát niệm cả đời phát sinh biến hóa quỷ dị, manh nha sát lục bổn nguyên — loại bổn nguyên cực kỳ hiếm sinh từ ý niệm giết chóc. Bước vào tinh vực cấp chín, sương mù Thần Tông hóa băng, tuyên bố được chủ nhân phong giới ủy thác, thay mặt giết Thủy Đạo Tử nô bộc. Nhớ lại cảnh Lý Thiến Mai nỗ lực cứu hắn do Thủy Đạo Tử gây ra. Trận chiến này khiến Vương Lâm vang danh trong giới nội.","anchor":"Một trận chiến này khiến Vương Lâm vang danh trong giới nội!","bridge":true,"khoang":"@c1415"},{"mucCt":"ky","text":"Tuyên chiến trước Thần Tông, kết tội Thủy Đạo Tử cấu kết giới ngoại bán chủ cầu vinh, tuyên bố thay mặt chủ nhân phong giới giết kẻ phản bội. Bộc lộ sát lục bổn nguyên — bổn nguyên mà chủ nhân phong giới năm xưa cũng không nghiên cứu ra — khiến toàn bộ tu sĩ bước thứ ba chấn động. Đối diện gần vạn tu sĩ Vân Hải quyết tử bảo vệ Thần Tông, không nỡ giết, thi triển Định Thân thuật ở cực hạn; thuật thăng hoa thành Định Thần thuật, định cả thần niệm và ý chí thiên địa, dời toàn bộ gần vạn tu sĩ mà không tổn thương. Tiến lên tu chân tinh Thần Tông thách đấu Thủy Đạo Tử; khi bị dùng đám người Quy Nguyên Tông uy hiếp, bình thản đáp lại như đã tiên liệu hết thảy. Điểm lên mi tâm, một đạo huyết quang lóe lên rồi biến mất.","anchor":"từ Định thân thuật trở thành Định thần thuật","bridge":true,"khoang":"@c1416"},{"mucCt":"ky","text":"Huyết kiếm đâm xuyên ngọn núi pháp bảo Thần Tông của Thủy Đạo Tử rồi giết sạch hơn mười tu sĩ áo đen trong ba nhịp thở, hút hết sức sống biến thành thây khô. Vỗ ra một chưởng hiện bàn tay khổng lồ che bầu trời đối đầu Thủy Đạo Tử, phá vỡ Thất Thải Đinh nhưng bản thân cũng bị đẩy lui. Bị Chu Đức cùng Thủy Đạo Tử hai hướng giáp công, thêm nam tử trung niên dùng hạt châu bàn tính tấn công sau lưng, bình tĩnh kích hoạt tinh điểm Cổ Thần triệu hồi Linh Động Thượng Nhân chặn Chu Đức, Chu Cẩn chặn nam tử trung niên, rồi tiếp tục tiến tới đối phó Thủy Đạo Tử.","anchor":"Có huyết kiếm ờ bên cạnh. Vương Lâm trong mắt lạnh như băng, từng bước tiến về phía trước","bridge":true,"khoang":"@c1417"},{"mucCt":"ky","text":"Nhân danh Chủ nhân phong giới tung quyền thứ nhất phá tan cây thương hương hỏa của Thủy Đạo Tử, đánh hắn lùi chín bước, bắn vào núi vỡ tung. Quyền thứ hai có đầu Đạo cổ dung nhập, phá hủy Âm Dương Tiên Long, tấm lưới bổn nguyên lực và vô số pháp bảo, đánh nổ tung ngực Thủy Đạo Tử. Thủy Đạo Tử trong tuyệt vọng phun ra cái chuông nhỏ chứa tiên khí Viễn Cổ Tiên Vực, chuông va vào quyền bộc phát đạo khí vàng khuếch tán khắp tứ đại tinh vực, quét sạch sương mù, khiến Phong Giới Đại Trận lần đầu hiện hình trước toàn bộ tu sĩ giới nội. Khi Thái A La xuất hiện bái kiến và đề nghị giải phong ấn đổi lấy dẫn bộ tộc đánh giới ngoại, Vương Lâm không trả lời ngay, chỉ nói chuyện đó sau này hẵng nói.","anchor":"Một quyền này, nhân danh Chủ nhân phong giới, phá môn đồ của tên nô bộc nhà ngươi!","bridge":true,"khoang":"@c1418"},{"mucCt":"ky","text":"Rút nắm tay kịp thời trước khi va chạm chiếc chuông vàng do Thủy Đạo Tử kích nổ. Đứng trước cuồng phong hủy diệt toàn Vân Hải, trầm mặc thừa nhận việc báo thù cá nhân đã liên lụy giới nội. Vung song chưởng đối phó cuồng phong cùng sáu cao thủ nhưng bất thành. Kích hoạt tinh điểm thứ hai trên mi tâm, triệu U Minh Thú ra lệnh nuốt trọn cuồng phong màu vàng, cứu toàn bộ Vân Hải Tinh Vực.","anchor":"Tinh điểm thứ hai trên mi tâm của Vương Lâm nhanh chóng lóe lên","bridge":true,"khoang":"@c1419"},{"mucCt":"ky","text":"Trấn an U Minh thú qua tâm thần, thú nép vào bên cạnh. Phát hiện Thủy Đạo Tử lén lùi trốn, lập tức truy kích. Ra một quyền hư ảo phá hủy dòng xoáy hàn nhiệt tím sẫm, đánh nát song chưởng, phá hủy toàn thân Thủy Đạo Tử khiến huyết nhục tung bay. Nguyên thần Thủy Đạo Tử thoát ra bỏ chạy. Đứng giữa không trung, tóc bạc tung bay, tuyên bố nhân quả — năm đó bị Thủy Đạo Tử ép đến cận tử, nay hắn phải chịu vận mệnh. Hình ảnh trong mắt tu sĩ bốn phía như chiến tiên.","anchor":"Mái tóc bạc tung bay, một thân bạch y vũ động đủ để lại ấn tượng không bao giờ phai mờ trong tâm thần mọi người","bridge":true,"khoang":"@c1420"},{"mucCt":"ky","text":"Lao tới đánh liên tiếp sáu quyền vào nguyên thần Thủy Đạo Tử, mỗi quyền gắn một lý do: vì chủ nhân phong giới, vì Lý Thiến Mai, vì tu sĩ Vân Hải và Quy Nguyên Tông, vì cơn lốc màu vàng, vì chính mình. Thủy Đạo Tử lật quân bài mệnh hồn liên kết Mộc Băng Mi uy hiếp, Vương Lâm dừng nắm đấm cách ba tấc. Mộc Băng Mi trải lòng thừa nhận mình là Liễu Mi rồi muốn tự vẫn, Vương Lâm dùng Định Thân Thuật chế trụ nàng. Tay phải đánh quyền cuối bóp nát hồn phách Thủy Đạo Tử nhưng bảo lưu sinh cơ, lập tức thi triển Đạo Cổ Hóa Mệnh Thuật chuyển toàn bộ sinh cơ sang Mộc Băng Mi, hóa giải liên kết mệnh hồn. Nói với Mộc Băng Mi: Ngươi không nợ Bình nhi, cũng không nợ ta. Tu sĩ Yêu Tông, Thần Tông, Quỷ Tông và đông đảo tu sĩ Vân Hải đồng loạt tham kiến với danh hiệu Phong Tôn.","anchor":"Một quyền này là ta đánh thay cho chủ nhân phong giới!","bridge":true,"khoang":"@c1421"},{"mucCt":"ky","text":"Trở về Thần Tông, được toàn bộ tu sĩ giới nội tham kiến với danh xưng Phong Tôn — chủ nhân phong giới đời này. Chu Đức, Vân Phong Tử lần lượt vái chào, Vân Phong Tử xin tha tội đắc tội trước. Hồng Sam Tử công nhận, cảnh báo giới ngoại sắp xâm lấn, yêu cầu chuẩn bị chết trận. Nghe Nam Vân Tử và Hồng Sam Tử bàn đối sách, kể lại tình hình giới ngoại. Dùng thần niệm phủ khắp thiên địa phong Mộc Băng Mi làm tông chủ Thần Tông, lệnh Quy Nguyên Tông dung nhập. Mang U Minh thú, Linh Động Thượng Nhân, Chu Cẩn rời đi, hướng về Côn Hư tinh vực cứu Thanh Thủy sư huynh. Bị giới ngoại đưa lên Tất sát bảng — ai giết được coi như giết một vạn tu sĩ giới nội.","anchor":"Thanh Thủy sư huynh. Năm đó ta không có thực lực đi cứu ngươi, hôm nay ta tới rồi đây.","bridge":true,"khoang":"@c1422"},{"mucCt":"ky","text":"Thái Cổ Tinh Thần phát động trận chiến đầu tiên nhắm vào Vân Hải tinh vực, điểm phá trận chính là nơi Vương Lâm đứng. Hắn hoàn toàn có thể rời đi nhưng chọn ở lại tử chiến, hồi tưởng câu hỏi của Hồng Hủ Tử và vinh quang tu sĩ giới nội. Hắn lĩnh ngộ sát lục bổn nguyên chân chính: sát lục vì đại nghĩa, vì bảo vệ người và vật mình muốn giữ gìn, khiến sát lục bổn nguyên điên cuồng tăng trưởng. Triển khai toàn bộ chiến lực: kiếm khí ngàn vạn đạo, triệu Linh Động Thượng Nhân và Chu Cẩn, vô số cấm chế phong ấn, Huyết kiếm tỏa huyết quang ngập trời, khiên ánh sáng, lửa chín màu mắt trái, Lôi đồ mắt phải. Đứng như một vị chiến tiên tóc bạc bạch y, tỏa vinh quang tu sĩ giới nội, quyết đối mặt mười vạn đại quân xâm lấn.","anchor":"Sát lục chính thức chính là sát lục vì đại nghĩa, vì một lý tưởng nào đó, vì người mà mình muốn bảo vệ","bridge":true,"khoang":"@c1424"},{"mucCt":"ky","text":"Phong Giới Đại Trận bị xé rách, chín vạn tu sĩ giới ngoại tràn vào giới nội. Vương Lâm một mình nghênh chiến: phóng ngàn vạn kiếm khí và cấm chế, kích hoạt hư hỏa (ngọn lửa chín màu từ mắt trái) thiêu đốt kẻ địch dựa trên tâm tình trong cơ thể, tung lôi đồ lên tinh không phóng chín đạo lôi đình, dùng huyết kiếm ẩn mình quét ngang chém hàng ngàn đầu lâu. Quang Ảnh Thuẫn bị phá vỡ nhưng nhờ thân thể Cổ Thần, vết thương lập tức khép lại. Bị lão tổ Hỏa Tước Tộc phóng tộc ấn hóa hỏa điểu tấn công, tiếp đó Nam Chiếu Thượng Nhân (cảnh Không Linh, có độc công) xuyên qua hỏa điểu vỗ thẳng bằng kịch độc, buộc Vương Lâm phải lui. Nhận ra chủ nhân Phong Giới năm đó dung nhập vào trận pháp chính là vì giờ phút này.","anchor":"Cho dù là Vương Lâm trong sự hỗn loạn này nếu không có thân thể cổ Thần thì nhất định cũng phải lùi lại","bridge":true,"khoang":"@c1425"},{"mucCt":"ky","text":"Bị Nam Chiếu Thượng Nhân (tu vi Không Linh) tung chưởng hút vào hương hỏa giới — thiên địa đen kịt với hàng trăm triệu dân hương hỏa, bàn tay khổng lồ do không trung hóa thành giáng xuống, tiếng rì rầm suýt khiến khuất phục. Trong lúc nguy cấp hô lên triệu hộ tí Cổ Thần trên cánh tay phải, Cổ Thần khổng lồ hiện ra lấy lưng đỡ đòn rồi tung quyền đánh văng bàn tay vạn trượng, hộ tí thêm vết nứt. Tiếp đó dung nhập Đạo cổ cùng hư hỏa vào quyền đấm phá tan bàn tay đen, thoát khỏi hương hỏa giới. Tỉnh lại trong tinh không, phun máu sắc mặt tái nhợt lui về phía sau, nhưng cũng khiến Nam Chiếu Thượng Nhân tay phải chảy máu bị thương vô hình không thể truy kích. Trận chiến này khiến Vương Lâm xóa bỏ sự khinh thường trước đây đối với cao thủ Không Linh.","anchor":"Ta là Cổ Thần, ta là Đạo cổ","bridge":true,"khoang":"@c1426"},{"mucCt":"ky","text":"Lần đầu cảm nhận sự kinh khủng của tu sĩ cảnh giới Không Linh, bị thương phun máu phải lui lại. Lao vào đám tu sĩ giới ngoại, dùng lưng đánh chết lão già rồi hút toàn bộ sinh cơ, máu huyết và nguyên thần để hồi phục. Truyền thần niệm cho Linh Động Thượng Nhân và Chu Cẩn đi làm hộ pháp cho Nam Vân Tử chữa trị Phong Giới Đại Trận. Bị Vân Lạc đại ti ra lệnh cho Tam lão Phong Diệt Tộc truy sát.","anchor":"Đây là lần đầu tiên Vương Lâm cảm nhận được sự kinh khủng của tu sĩ Không Linh","bridge":true,"khoang":"@c1427"},{"mucCt":"ky","text":"Đơn thương độc mã nhảy vào giữa đại quân giới ngoại, dùng hỏa diễm, lôi đình, huyết kiếm chém giết điên cuồng. Bị ba tử sĩ Phong Diệt Tộc hiến mạng thi triển thần thông bộ tộc, đánh ba đạo phong ấn bất khả cự lên thân: phong ấn nguyên lực, phong ấn thể lực khiến lão hóa, phong ấn sinh cơ rút sức mạnh Cổ Thần. Trước khi bị phong ấn hoàn toàn, tung quyền giết chết cả ba tử sĩ nhưng phong ấn không tan. Mất toàn bộ sức chiến đấu, bị mấy vạn tu sĩ giới ngoại theo lệnh Vân Lạc Đại Tỉ oanh tạc bằng pháp bảo, phi kiếm, thần thông, nhiều lần phun máu trọng thương. Thân thể Cổ Thần hùng mạnh đến mức lão già giới ngoại đánh chưởng lên thiên linh hắn tự nát xương cánh tay. Cố ý chịu đòn, mượn chính cuồng phong tổng lực tấn công của mấy vạn tu sĩ làm ngoại lực phá lần lượt ba đạo phong ấn: phong ấn nguyên lực tan, hỏa diễm tràn ra giết bốn phía; phong ấn thể lực tan, dung nhan trở lại thanh niên; phong ấn sinh cơ tan, sức mạnh Cổ Thần phục hồi toàn thân. Hét lên thách thức giữa cuồng phong.","anchor":"Các ngươi đánh còn chưa đủ!","bridge":true,"khoang":"@c1428"},{"mucCt":"ky","text":"Bước ra khỏi cuồng phong sau khi chịu tấn công của hàng vạn tu sĩ giới ngoại mà không chết, khiến kẻ địch hoảng sợ lui lại. Tiếp tục lao vào chém giết dùng hư hỏa và lôi đình, nhưng thương thế vượt xa vẻ bề ngoài, tốc độ hồi phục thất tinh Cổ Thần không theo kịp cường độ chiến đấu. Quan sát toàn cục thấy Hồng Sam Tử bị mắc bẫy, gần vạn tu sĩ Vân Hải tử vong, tinh thần toàn quân sụp đổ. Lui về phía trước hàng ngũ Vân Hải, trong sự tuyệt vọng của họ thét lên một tiếng kinh thiên động địa.","anchor":"trong sự tuyệt vọng của những tu sĩ Vân Hải này thét lên một tiếng kinh thiên động địa","bridge":true,"khoang":"@c1429"},{"mucCt":"ky","text":"Một mình đứng giữa tinh không chặn toàn bộ đại quân giới ngoại hơn mười vạn người. Mở Thái Cổ Lôi Giới triệu Thái Cổ Lôi Long phóng lôi đình vô tận, tung hư hỏa Chu Tước, sức mạnh một người khiến đại quân dừng bước. Rút huyết kiếm tử chiến, diệt hơn hai ngàn tu sĩ giới ngoại, nhưng phun máu tươi, nguyên lực và Cổ Thần lực cạn kiệt, toàn thân đầy vết thương, quần áo trắng nhuốm đỏ. Hành động của hắn cảm hóa toàn bộ mấy ngàn tu sĩ Vân Hải đang bỏ chạy quay lại chiến đấu. Hét gọi Phong Tôn giúp đỡ, thần thức Phong Tôn trong ngọc bội bộc phát sức mạnh cuối cùng chế phục Khai Thiên Phủ. Nhảy lên nắm lấy Khai Thiên Phủ, tinh điểm Cổ Thần trên mi tâm xoay tròn, khí thể bộc phát sánh ngang lúc nhận truyền thừa Đạo Cổ — là người đầu tiên cầm Khai Thiên Phủ kể từ khi nó dung nhập Phong Giới Đại Trận.","anchor":"Vương Lâm chính là người đầu tiên cầm lấy Khai Thiên Phủ của Cổ Thần này","bridge":true,"khoang":"@c1430"},{"mucCt":"ky","text":"Cầm lấy Khai Thiên Phủ, Cổ Thần lực vô biên từ búa chảy vào tinh điểm thứ tám (vòng xoáy chưa thành hình), tinh điểm bành trướng điên cuồng hấp thụ. Hô hào mấy ngàn tu sĩ Vân Hải tử chiến, phát tiếng rống Cổ Thần khiến tinh không run rẩy, hơn mười vạn tu sĩ giới ngoại sợ hãi lùi lại. Cầm Khai Thiên Phủ xông thẳng vào quân giới ngoại hướng về phía Vân Lạc Đại Ti, chỉ sát khí đã khiến không ai dám cản. Dùng một búa chém phủ ảnh khổng lồ xuyên thấu hỏa điểu đen của lão tổ Hỏa Tước Tộc, phá tộc ấn, nứt hộp sọ, chẻ đôi toàn thân từ đầu xuống, diệt luôn nguyên thần — giết cao thủ bước thứ ba trong nháy mắt. Xuyên qua thi thể, mang sát khí phóng thẳng về phía Vân Lạc Đại Ti khiến toàn bộ tu sĩ giới ngoại tái nhợt lùi lại. Được mấy ngàn tu sĩ Vân Hải đồng thanh tôn xưng Phong Tôn vinh quang.","anchor":"Tu sĩ chúng ta tiếc gì mà không đánh một trận!","bridge":true,"khoang":"@c1431"},{"mucCt":"ky","text":"Sau khi chém chết Lão tổ Hỏa Tước Tộc, cầm Khai Thiên Phủ lao thẳng vào bụng đại quân giới ngoại như thanh kiếm chẻ tre, dùng Hư hỏa thiêu chết tu sĩ cản đường. Bị Nam Chiếu Thượng Nhân chặn đường bằng khói độc năm màu, xoay người triệu hồi Thiên Hoàng Lô từ tinh điểm trên mi tâm, xuất mười giọt độc dịch, tuyên bố ba giọt là đủ. Ba giọt nổ tung thành biển độc nuốt sạch năm vòi rồng độc, trùm lên Nam Chiếu Thượng Nhân khiến hắn từ chân lên hòa tan thành máu rồi bị tiêu diệt hoàn toàn, hồn phách thu vào Thiên Hoàng Lô. Dung sáu giọt còn lại vào biển độc tạo dòng xoáy lan tám hướng, đồng thời mở khe không gian thả Văn thú dữ tợn lao ra. Nhiều lần muốn gọi U Minh thú nhưng nó mất phản ứng sau khi nuốt cơn lốc màu vàng. Cuối cùng áp sát Vân Lạc đại ti cách trăm trượng, giơ Khai Thiên Phủ chém xuống.","anchor":"Giết ngươi ba giọt là đủ","bridge":true,"khoang":"@c1432"},{"mucCt":"ky","text":"Vung Khai Thiên Phủ chém giết hàng ngàn tu sĩ giới ngoại bảo vệ Vân Lạc đại ti, phủ mang xuyên thấu không gì ngăn cản. Phát hiện Vân Lạc trên chiến trường chỉ là phân thân búp bê vải, thiêu cháy búp bê rồi dùng thần thông rút hai tia tơ tạo hắc động truy tìm bổn tôn. Phóng Cực Cảnh hóa tia chớp đỏ dung hợp lôi hóa xuyên qua hắc động tấn công thẳng thánh địa truyền thừa Vân Lạc trong tam đại cấm địa Trường Tôn hội. Cực Cảnh phá hủy đảo nhỏ, phá vỡ hài cốt sư tôn, diệt thân thể và nguyên thần Vân Lạc đại ti, nhưng hồn phách nàng dung nhập cơn lốc thoát đi. Sau đó trở lại chiến trường Vân Hải tinh vực, viện quân La Thiên và Triệu Hà đồng thời xuất hiện.","anchor":"Dù là phân thân nhưng ta Cũng có thể tìm ra bổn tôn của ngươi!","bridge":true,"khoang":"@c1433"},{"mucCt":"ky","text":"Tuyên bố ba cao thủ giới ngoại (lão tổ Hỏa Tước Tộc, Nam Chiếu Thượng Nhân, Vân Lạc Đại Ti) đã chết, phá vỡ sĩ khí đối phương. Cầm Khai Thiên Phủ quét giết tu sĩ, hóa sương mù vạn trượng hút lực tu sĩ giới ngoại. Khi đại quân thứ ba gồm năm vạn tu sĩ và hai cao thủ Không Niết Trung Kỳ xuất hiện bên ngoài Phong Giới Đại Trận, xông tới lỗ hổng tuyên bố trừ khi hắn chết không ai bước vào giới nội. Hiện thân thể thật Thất Tinh Cổ Thần ngàn trượng, liên tiếp ba tiếng Giết: dùng Hư Hỏa từ mắt trái thiêu mấy ngàn tu sĩ, dùng lôi đình từ mắt phải tạo biển sấm sét quét sạch, cuối cùng dồn toàn bộ Cổ Thần lực qua bảy tinh điểm mi tâm chém Khai Thiên Phủ bay thẳng về phía hai cao thủ bước thứ ba.","anchor":"Có Vương mỗ ở đây, trừ khi ta chết, không người nào có thể bước vào giới nội nửa bước","bridge":true,"khoang":"@c1434"},{"mucCt":"ky","text":"Vung Khai Thiên Phủ chém ra khe ngàn trượng xuyên đại quân bước thứ ba, hai cao thủ bị chém đứt cánh tay, vô số tu sĩ chết. Đứng trong lỗ hổng Phong Giới Đại Trận tuyên bố giết sạch mọi kẻ xâm nhập, dùng Hư hỏa thiêu trong ngàn trượng và triệu hơn mười lá cổ Tức Diệp phong ấn bao vây mấy vạn tu sĩ giới ngoại. Lam Mộng Đạo Tôn xuất hiện yêu cầu tha tu sĩ, nhắc ba lần ân tình — Vương Lâm vái sâu nhưng từ chối. Triệu trăm vạn cấm chế ngưng tụ thành khung ô, Phần Giới cổ Tán mở ra một phần, biển lửa diệt thế thiêu sạch tu sĩ giới ngoại, sức sống trong cơ thể tản ra nhập vào cổ Tán để chống đỡ. Đợt xâm lược thứ nhất kết thúc. Hồi tưởng hình bóng con gái Lam Mộng nói 'Hãy quên giang hồ đi'. Cuối chương bị Phong Dư — ngón cái, thủ đồ Chưởng Tôn — giương cung nhắm bắn qua lỗ hổng trận pháp chưa khép hết.","anchor":"Chiến công của Vương Lâm trong trận chiến này đã hoàn toàn khiến cho tu sĩ giới nội trở nên sùng kính thân phận Phong Tôn của hắn","bridge":true,"khoang":"@c1435"},{"mucCt":"ky","text":"Nhận ra cây cung trong tay Thủ Đồ chính là bảo vật năm xưa bắn rơi mắt trái Đạo cổ, đánh giá chỉ xếp sau Thiên Nghịch và Địa La Bàn. Hồi tưởng lai lịch cây cung từ quê hương Đạo cổ, bị thất thải đạo nhân lấy đi, nay ở tay thủ đồ Chưởng Tôn, nghi ngờ mối liên hệ giữa hai người. Mi tâm đau nhức dữ dội khi dây cung kéo căng, lập tức thân thể mơ hồ dung nhập thiên địa, triệu bảy tinh điểm Cổ Thần trên mi tâm xoay tròn trước thân, bộc phát khí tức Cổ Thần vô biên, đầu Đạo cổ hiện ra phòng ngự. Suy luận: tìm được mũi tên gốc sẽ tìm được mắt trái Đạo cổ, ai tìm ra sẽ dấy lên tranh đoạt không thua Thiên Nghịch Châu.","anchor":"Vật này, ngoài Thiên Nghịch và Địa La Bàn ở vùng đất Điên Lạc, là một bảo vật mạnh nhất mà Vương Lâm đã từng nhìn thấy","bridge":true,"khoang":"@c1436"},{"mucCt":"ky","text":"Mũi tên thứ nhất từ cung Lý Quảng xuyên qua mi tâm đầu Đạo Cổ, Vương Lâm dùng hai tay Cổ Thần kẹp chặt mũi tên, bị đại lực ép hiện thân lùi một ngàn trượng, phun bảy ngụm máu. Hút sức sống tu sĩ giới ngoại bị phong ấn trong khu vực Cổ Tức Diệp qua sương đen để bổ sung năng lượng. Thái A La bất ngờ xuất hiện xả thân chắn mũi tên thứ hai, cầm cự ba nhịp thở. Nhịp thở thứ nhất cắn đầu lưỡi phun máu, nhịp thứ hai triệu lửa diệt thế Phần Giới Cổ Tán dung hợp máu Cổ Thần hủy mũi tên thứ nhất, phần nhỏ còn lại đâm vào mi tâm rồi vỡ tan. Thu Phần Giới Cổ Tán về tay, rút sức sống Cổ Thần cưỡng ép mở gần ba phần, biển lửa diệt thế phá vỡ mũi tên thứ hai nhưng dư lực xuyên qua đâm vào ngực gây trọng thương. Thân Cổ Thần héo rũ thành bộ xương do rút sức sống, nhờ U Minh Thú bổn mệnh thú tương thông sức sống mà không mất hơn chín phần tuổi thọ. Triệu huyết kiếm nhưng nhận ra huyết kiếm chỉ xuyên vật thực chất, không hiệu quả với mũi tên hư ảo sức sống ngưng tụ, tự kìm sát niệm không truy kích. Suy luận Chưởng Tôn Phong Dư đang sợ hãi, dùng cung dụ hắn ra ngoài đại trận.","anchor":"Dường như hắn đang sợ hãi. muốn lấy cây cung này để dụ ta một mình xuất hiện.","bridge":true,"khoang":"@c1437"},{"mucCt":"ky","text":"Bị uy áp bàn tay khổng lồ từ Thái Cổ Tinh Thần ép lùi hàng trăm trượng. Dùng Tinh điểm Cổ Thần xoay tròn, xuất Đạo Cổ hóa quyền khổng lồ bao quanh biển lửa và lôi đình, phối hợp toàn bộ cao thủ giới nội tấn công bàn tay. Dùng quyền Đạo Cổ phá ngón tay cuối cùng, bản thân phun máu, tay phải đau nhức xương cốt bị vỡ vụn. Tâm niệm khiến Linh Động Thượng Nhân và Chu Cẩn cùng ra tay. Chứng kiến chín tu chân tinh bốc cháy lao tới cây cung, hư ảnh Chưởng Tôn lộ diện, rồi thân ảnh bí ẩn Chiến lão quỷ xuất hiện tuyên bố nhận cung cho Lý tộc.","anchor":"thân thể Vương Lâm chấn động mạnh, máu tươi tràn ra khỏi khóe miệng, tay phải đầy máu, vô cùng đau nhức, như thể xương cốt đã bị vỡ vụn","bridge":true,"khoang":"@c1438"},{"mucCt":"ky","text":"Cây cung bay về phía Vương Lâm, hắn quyết đoán giơ tay phải túm lấy nhưng tay phải vỡ tan. Giơ tay trái nắm được cung, nhưng sợi dây cung vung mạnh xuyên thấu qua phần hông, thân thể bị chém làm hai, phần dưới hông nổ tung. Hắn cảm nhận cây cung có lực bài xích cực mạnh, chỉ có thể hiến tế sức sống để thỉnh cầu, ngoại trừ một người nào đó không ai có thể khiến nó nhận chủ. U Minh Thú tỉnh dậy vì đau đớn truyền qua sinh mệnh liên kết, phun cuồng phong màu vàng hủy diệt chiến trường, rồi nuốt Vương Lâm cùng cây cung vào miệng tàng hình biến mất.","anchor":"Thân thể của hắn đã bị sợi dây cung kia chém ra làm hai.","bridge":true,"khoang":"@c1439"},{"mucCt":"ky","text":"Sau trận chiến thứ nhất, Vương Lâm hoàn toàn biến mất, không ai tìm được. Tên Phong Tôn truyền khắp giới nội, được công nhận là người đứng đầu, danh tiếng lấn át cả đám Hồng Sam Tử. Tu sĩ Vân Hải sống sót tuyệt đối sùng kính hắn. Giới ngoại khắc cốt ghi tâm tên Vương Lâm, Chưởng Tôn truyền hình dáng hắn cho toàn bộ tu sĩ giới ngoại, treo phần thưởng chưa từng có để giết hắn. Đám Hồng Sam Tử liên tục làm phép tìm nhưng không phát hiện được.","anchor":"Cái tên Vương Lâm ở trong toàn bộ giới nội đã trở thành một truyền thuyết!","bridge":true,"khoang":"@c1440"},{"mucCt":"ky","text":"Thi thể Vương Lâm nằm trong Thất Thải Giới bên trong cơ thể U Minh Thú, được tu sĩ điên cho uống máu tươi hàng ngày. Máu tu sĩ điên xung đột kịch liệt với sức mạnh Đạo Cổ trong cơ thể, hai bên cắn nuốt lẫn nhau nhưng mơ hồ có dung hợp, tạo biến đổi kỳ dị từ trong máu — chính thức chuyển hóa từ phàm nhân thành tiên nhân. Dây cung đứt của cung Lý Quảng đâm sâu vào thân thể đang dần biến thành huyết mạch, dung hợp vào cơ thể. Cung cảm nhận huyết mạch Vương Lâm tinh thuần hơn chủ nhân năm xưa gấp bội, phát ra tiếng hoan hô vì tìm được chủ nhân mới.","anchor":"cây cung này sau vô số năm mất đi chủ nhân, lại một lần nữa tìm được chủ nhân mới","bridge":true,"khoang":"@c1441"},{"mucCt":"ky","text":"Tỉnh lại trong đau đớn, thân thể vẫn chỉ còn nửa người, máu của người điên lưu chuyển trong cơ thể chém giết với Cổ Thần lực rồi dần dung hợp vào xương cốt. Máu người điên dung nhập tủy xương, biến đổi huyết mạch, máu cũ bị bức ra khỏi thân thể, tủy sống sản sinh máu mới mang khí tức cao quý tột đỉnh khiến vạn vật sùng bái. Sau khi người điên phun bổn mệnh huyết, Cổ Thần lực và Đạo Cổ lực đều bị áp chế tan vỡ. Cây cung trong tay dung hợp nhận chủ nhờ huyết mạch mới, trở thành một phần huyết mạch. Mắt trái ngọn lửa chín màu biến thành lửa kim sắc, mắt phải lôi đồ và chín đạo sấm sét sụp đổ thành tia chớp kim sắc — kim sắc là màu sắc của tiên thật sự. Hai mắt bộc phát uy áp khủng khiếp.","anchor":"Kim sắc, màu sắc của tiên. Tiên thật sự.","bridge":true,"khoang":"@c1442"},{"mucCt":"ky","text":"Dòng máu mới từ xương tủy lưu chuyển toàn thân khiến lôi bổn nguyên hóa thành tiên lôi thật sự, hư hỏa kim sắc trong mắt trái hóa tiên hỏa thật sự. Ba bổn nguyên sinh tử, nhân quả, chân giả tiến gần viên mãn, chỉ cần thêm cơ hội là đắc đạo. Thân thể xung đột giữa truyền thừa Đạo Cổ (Cổ Thần) và tiên huyết mạch — hai lực bài xích, nửa thân dưới dao động giữa hồi phục và tan vỡ, nguyên thần tách khỏi thân thể không cử động được. Người điên tỉnh lại, cắn vai Vương Lâm, chửi mắng mấy ngày rồi nhớ ra tam ấn tổ tiên Tiên Tộc, rút ấn ký trên mi tâm mình đặt lên tinh điểm Cổ Thần trên mi tâm Vương Lâm. Sức mạnh Cổ Thần trong thân bộc phát phản kháng kinh thiên, đánh người điên bắn tung phun máu. Cuối cùng Vương Lâm mở mạnh hai mắt tỉnh lại.","anchor":"dưới sức mạnh của dòng máu mới này, lôi đình này bất ngờ biến thành tiên lôi","bridge":true,"khoang":"@c1443"},{"mucCt":"ky","text":"Ấn ký tiên tổ hình tròn xuất hiện trên mi tâm, kích hoạt huyết mạch tiên tộc sôi trào xung đột với Đạo Cổ lực và Cổ Thần lực, biến thân thể thành chiến trường. Bảy tinh điểm Cổ Thần lần lượt vỡ tan qua bảy lần toái tinh, mỗi lần thân thể chuyển đổi giữa Cổ Thần thể và Tiên Nhân Bất Diệt Thể, chịu thống khổ cực độ. Lần chuyển đổi thứ tám khi vòng xoáy chưa thành tinh điểm thứ tám cũng nổ tung, đệ nhị tổn trong tam tổn thất kiếp Cổ Thần xuất hiện. Thân thể hoàn toàn tan rã tạo cảnh tượng kim thiên hắc địa — máu thịt Cổ Thần dung nhập mặt đất đen, tiên thể nguyên thần bao phủ bầu trời vàng. Thiên Nghịch tự phát xuất hiện giữa hai hư ảnh, xoay hai vòng hút trọn tiên nguyên và Đạo Cổ Cổ Thần, dung hợp thành thân Cổ Thần phát kim quang. Sau dung hợp: ấn ký tiêu tan, bảy tinh điểm tái hiện nhưng biến thành màu vàng, mắt trái kim hỏa, mắt phải tia chớp vàng. Phun máu, khoanh chân tĩnh tọa.","anchor":"Bảy tinh điểm Cổ Thần xoay tròn, nhưng bảy tinh điểm này cũng đã biến thành màu vàng","bridge":true,"khoang":"@c1444"},{"mucCt":"ky","text":"Sau mấy ngày thổ nạp, nội thể Vương Lâm hoàn thành kết hợp: thân Cổ Thần bên ngoài, nguyên tiên thay nguyên thần bên trong, hạt châu Thiên Nghịch quay chậm ở lõi sâu nhất. Nguyên lực biến mất hoàn toàn, thay bằng tiên lực lượng cực ít nhưng khí tức kinh thiên. Thân thể cường đại gấp mấy lần, tự đánh giá giết Không Niết hậu kỳ trong nháy mắt, toàn lực thì Nam Chiếu Thượng Nhân cũng không địch nổi. Tuy nhiên lực bài xích Tiên-Thần ngày càng mạnh, chỉ phát huy được hai phần thực lực, nguy cơ thân thể nổ tung bất cứ lúc nào như lưỡi đao kề cổ. Ấn ký tiên tổ trên mi tâm đã hòa tan dung hợp với thân Thất Tinh Cổ Thần, tạo tinh điểm màu vàng chưa từng có trong cổ tộc. Mở mắt tỏa kim quang vàng nhạt. Bỏ kế hoạch ngưng luyện ma hồn tạo phân thân cổ ma, chuyển sang hóa giải huyết nhục thi thể Cổ Ma thành ma khí ngưng tụ sáu ma tinh, đưa dung nhập vào mắt phải ấn lên tia chớp vàng, kết hợp kim quang bảy tinh điểm Cổ Thần. Thi thể Cổ Ma hoàn toàn tiêu hủy.","anchor":"Bởi vì lúc này hắn là kết hợp giữa tiên và thần, là một biến hóa cực kỳ hiếm thấy trong khắp tinh không này","bridge":true,"khoang":"@c1445"},{"mucCt":"ky","text":"Tỉnh dậy bên trong thế giới cơ thể U Minh thú, dành ba ngày chuyển lực bài xích vào sáu khối ma tinh trong mắt phải khiến chúng chuyển màu vàng, tạm trì hoãn nguy cơ nhưng không giải quyết triệt để. Triệu cây cung Lý Quảng ra nhưng phát hiện dây cung đã đứt, không thể sử dụng. Bị người điên liên tục quấy phá, dùng cuồng phong vàng đá hắn đi mười sáu lần, thả hắc viên ra gầm thét thi đấu với người điên. Suy luận ra cần đại thành ba bổn nguyên sinh tử, nhân quả, thật giả để hóa giải lực bài xích — sinh tử chia hai luồng, nhân quả tạo tuần hoàn, thật giả lừa dung hợp nguyên tiên và Cổ Thần lực — năm đạo bổn nguyên đại thành sẽ mở không môn, chính thức bước vào bước thứ ba. Cuối chương chấn động khi thấy người điên thi triển Dịch Linh Ấn chính tông, coi đây là cơ may lớn lao sau huyết mạch tiên nhân.","anchor":"Đây là một cơ may lớn lao sau huyết mạch của tiên nhân mà người điên đã đem lại cho hắn","bridge":true,"khoang":"@c1446"},{"mucCt":"ky","text":"Quan sát Dịch Linh Ấn hoàn chỉnh do người điên thi triển, nhận ra phiên bản của bản thân thiếu vân tay rõ ràng và càng lớn càng mất khống chế vì thiếu khẩu quyết truyền thừa, còn bản Thủy Đạo Tử tuy không mất khống chế nhưng vân tay vẫn kém rõ. Tự thi triển Dịch Linh Ấn đánh ra hố mấy vạn trượng trên mặt đất tu chân tinh rồi thách thức người điên làm tương tự. Liên tục dùng vẻ khinh miệt, giả khiếp sợ để khích tướng, khiến người điên thi triển hàng trăm lần suốt bảy canh giờ. Toàn tâm quan sát chi tiết, dùng ngộ tính kinh người nghiền ngẫm suy diễn, hình ảnh chưởng ấn dần khắc sâu vào trí não. Ngộ ra cơ chế cốt lõi: Dịch Linh Ấn nô dịch thiên địa nguyên lực hóa linh hồn, tiên lực tràn vào biến thành chưởng ấn, nhưng vẫn thiếu khẩu quyết truyền thừa tuyệt mật để hoàn thiện. Cuối cùng tiếp tục khích bằng cách vu người điên dùng hai loại thần thông khác nhau.","anchor":"Hai mắt Vương Lâm tràn ngập tơ máu, vừa ở bên cạnh quan sát kỹ càng, lại vừa giơ tay phải về phía trước vung vẩy, dùng ngộ tính kinh người để nhanh chóng nghiền ngẫm suy diễn","bridge":true,"khoang":"@c1447"},{"mucCt":"ky","text":"Dùng mưu khích người điên oan ức bật khóc, khiến hắn đọc toàn bộ khẩu quyết Dịch Linh Ấn chính tông. Thi triển thành công, nhận ra đây là đạo thuật chứ không phải thần thông, ba luồng khí tức hóa ba chưởng đồng thời giết sạch thể, thần, hồn, uy lực vượt xa bản không hoàn chỉnh của Thủy Đạo Tử. Trong lòng cảm thấy tội lỗi, lập lời thề bảo vệ người điên, ân oán phân minh. Dùng đan dược thơm dụ người điên biểu diễn thêm ba đạo thuật: bản gốc Phần Giới Cổ Tán (ô đã mở sẵn), thuật bắn tên tư thế Lý Quảng, thuật thương bảy màu vượt xa hư hỏa. Chỉ quan sát chứ chưa có khẩu quyết ba thuật này. Cuối cùng triệu hồi hồn ảnh U Minh thú để dọa người điên.","anchor":"Hắn giơ tay phải lên bầu trời điểm một chỉ. Trong tiếng ầm vang, một Dịch Linh Ấn cực kỳ chính tông hiện ra","bridge":true,"khoang":"@c1448"},{"mucCt":"ky","text":"Dàn dựng toàn bộ màn kịch dùng U Minh thú dọa người điên để lừa lấy thần thông. Dùng thần niệm điều khiển U Minh thú giả vờ truy đuổi, cố ý phun máu giả bị thương, ôm người điên lùi lại tạo cảnh sống còn. Người điên trong hoảng sợ cực độ chủ động truyền thụ ba thần thông: Phần Giới cổ Tán, Toái Thiên Nhất Cung (Lý tộc), thuật bảy màu. So sánh và xác nhận khẩu quyết Phần Giới cổ Tán chuẩn xác hơn bản Chu Tước đời đầu học trộm. Thi triển thử Phần Giới cổ Tán bằng trăm vạn cấm chế biến ảo nhưng vừa hiện ra liền sụp đổ, cần bế quan tiềm tu nhiều năm mới phát huy uy lực. Dùng sương mù che mắt rồi giả vờ thu phục U Minh thú trước mặt người điên. Trong lòng cảm giác có lỗi ngày càng đậm, tự thề có ân tất báo, nhất định đền bù gấp bội cho người điên sau này.","anchor":"vẻ tội lỗi trong mắt Vương Lâm lại càng dày đặc nhưng bị hắn ẩn dấu sạch, không biểu lộ ra chút nào","bridge":true,"khoang":"@c1449"},{"mucCt":"ky","text":"Bất ngờ được người điên quỳ dập đầu bái sư, tiếp nhận lực lượng thề ước từ mi tâm người điên dung nhập vào cơ thể. Thu U Minh thú chỉ bằng một vỗ tay khiến thú tiêu tán vô ảnh. Dụ người điên tiết lộ về Tiên Chi Cửu Tuyệt — ca ca người điên chỉ hiểu được Thất Tuyệt, có lời thề cấm nói chi tiết kẻo chịu tiên phạt. Tính toán trong ba ngày phải trấn áp lực bài xích Huyền Lương Kiếm và đạt đạo quả để hoàn thành kế hoạch. Lần lượt thi triển toàn bộ thần thông cả đời — Hô Phong, Hoán Vũ, Rải Đậu Thành Binh, Băng Sơn, Phiên Thiên Ấn, Quang Ảnh Thuẫn, Dung Hợp, Lực Tàn Dạ, cửa đá tuế nguyệt — tất cả bị người điên chê sạch. Cuối cùng thi triển Dẫn Lực Thuật, thần thông đầu tiên hắn học được trong đời, người điên lại mê mẩn đòi học. Ghi Dẫn Lực Thuật vào ngọc giản truyền cho người điên rồi mặc kệ hắn tự luyện. Ba ngày sau mở mắt, kim quang ẩn đi, dẫn người điên rời tu chân tinh.","anchor":"Hắn vốn chỉ muốn hù dọa người điên này để hỏi khẩu quyết thần thông đạo thuật mà thôi","bridge":true,"khoang":"@c1450"}],"nhanMach":[{"ten":"Lỗ Phu Tử","tag":"ban-be","quanHe":"Từng kết bạn ở vùng đất Cổ Thần trong Liên Minh","ghiChu":"Lỗ Phu Tử thừa nhận không nắm chắc thắng Vương Lâm dù Vương Lâm chưa đạt bước thứ ba"},{"ten":"Tạ Thanh","tag":"su-mon","quanHe":"Đệ tử duy nhất","ghiChu":"Thu nhận vì có duyên, chỉ cho một hồi cảm ngộ chứ không truyền thần thông, Tạ Thanh chờ trên Thanh Linh Tinh hơn tám trăm năm"},{"ten":"Đông Lâm Thái","tag":"doi-thu","quanHe":"Đối thủ — lão tổ Hướng gia, tộc nhân phân hệ gia tộc Đông Lâm","ghiChu":"Bị Vương Lâm phá nát tứ chi, Sưu Hồn, nổ đầu giết chết @c1394"},{"ten":"Lão già mặc kim bào (Đông Lâm gia)","tag":"doi-thu","quanHe":"Đối thủ — tu sĩ Đông Lâm gia nửa bước thứ ba","ghiChu":"Thi triển Huyễn Thần Thuật tuyên tội, bị Vương Lâm phá tan trọng thương @c1394"},{"ten":"Tây Tử Phượng","tag":"ban-be","quanHe":"Nữ tử từng ái mộ hắn, tái ngộ sau tám trăm năm","ghiChu":"Nhìn thấy vết sẹo trên mặt nàng mà đau xót"},{"ten":"Chu Tùng Vân","tag":"an-nhan","quanHe":"Tu sĩ từng được Vương Lâm cứu khỏi Lôi Tiên Giới, gặp lại gọi ân công","ghiChu":"@c1397"},{"ten":"Tây Tử Phượng","tag":"su-mon","quanHe":"Đệ tử thứ ba","ghiChu":"Thu làm đệ tử, cắt đứt tình cảm tám trăm năm @c1398"},{"ten":"Huyết Thần Tử","tag":"doi-thu","quanHe":"Mục tiêu truy sát","ghiChu":"Chỉ đích danh Huyết Thần Tử trong tinh trận, nói hắn 'rất có ích' với mình, từ chối mọi lời xin tha (@c1400)"},{"ten":"Tôn Linh","tag":"ban-be","quanHe":"Cố nhân / bằng hữu từ thời Hứa Mộc trên Nhiễm Vân Tinh","ghiChu":"Mối giao tình không liên quan nam nữ, Vương Lâm coi Tôn Linh vô cùng quan trọng. Tái ngộ khi Tôn Linh sắp chết, trao đan dược từ biệt."},{"ten":"Tây Tử Phượng","tag":"khac","quanHe":"Nữ tu từng ở Lôi Tiên Giới, đơn phương nhớ về Vương Lâm suốt 800 năm","ghiChu":"Vương Lâm không biết sự tồn tại của nàng"},{"ten":"Tạ Thành Thanh","tag":"su-mon","quanHe":"Đệ tử đầu tiên","ghiChu":"Vương Lâm tự nhắc tên, xác nhận là một trong hai đệ tử trước Tây Tử Phượng","nguon":"@c1398"},{"ten":"Chu Đức","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Cao thủ bước thứ ba được Thủy Đạo Tử thuê, phân thân tới tu chân tinh giáp công Vương Lâm để đoạt lục phẩm đạo linh"},{"ten":"Thái A La","tag":"khac","quanHe":"Tu sĩ hóa hình bái kiến Vương Lâm là Chủ nhân phong giới, đề nghị giải phong ấn đổi lấy dẫn bộ tộc đánh giới ngoại","gap":"@c1418"},{"ten":"Hồng Sam Tử","tag":"dong-minh","quanHe":"Cường giả giới nội bước thứ ba, công nhận Vương Lâm là Phong Tôn","ghiChu":"@c1422"},{"ten":"Nam Vân Tử","tag":"dong-minh","quanHe":"Lão tổ Thi Âm Tông, cùng bàn đối sách chống giới ngoại","ghiChu":"@c1422"},{"ten":"Đông Địch Tử","tag":"doi-thu","quanHe":"Phó hội trưởng Trưởng Tôn hội, chủ trì trận chiến nhập giới nhắm vào giới nội","ghiChu":"@c1422"},{"ten":"Nam Chiếu Thượng Nhân","tag":"doi-thu","quanHe":"Cường giả giới ngoại nổi danh độc công, cùng chủ trì trận đánh","ghiChu":"@c1422"},{"ten":"Vân Lạc","tag":"doi-thu","quanHe":"Đại ti Trưởng Tôn hội, chủ mưu bố trí truyền tống trận và lệnh giết Vương Lâm","ghiChu":"@c1422"},{"ten":"Ba tử sĩ Phong Diệt Tộc","tag":"doi-thu","quanHe":"Ba tử sĩ hiến mạng phong ấn hắn, bị hắn tung quyền giết chết","ghiChu":"@c1428"},{"ten":"Lam Mộng Đạo Tôn","tag":"an-nhan","quanHe":"Ân nhân ba lần, đứng đầu Thái Cổ Ngũ Tôn, Không Huyền đại viên mãn","ghiChu":"Nhắc ân tình ba lần và cảnh cáo không có lần thứ tư"},{"ten":"Phong Dư","tag":"doi-thu","quanHe":"Thủ đồ Chưởng Tôn, ngón cái, giương cung nhắm bắn Vương Lâm","ghiChu":"Xuất hiện cuối chương, cây cung VL đã từng thấy"},{"ten":"Người điên","tag":"an-nhan","quanHe":"Tu sĩ điên trong Thất Thải Giới cho Vương Lâm uống máu tươi hàng ngày, gián tiếp thúc đẩy biến đổi thành tiên nhân","ghiChu":"@c1441"},{"ten":"Người điên","tag":"su-mon","quanHe":"Đồ đệ (tự nguyện bái sư)","ghiChu":"Người điên quỳ dập đầu bái Vương Lâm làm sư phụ, thề không phản bội sư môn @c1450"}],"tuViMoc":[{"chuong":"@c1412","canhGioi":"Thân Cổ Thần sáu ngàn trượng (có bổn mệnh thú)","text":"Sau khi thu phục U Minh Thú làm bổn mệnh thú, sức sống vô biên tràn vào khiến thân Cổ Thần bành trướng tới sáu ngàn trượng. Theo ký ức Đồ Ti, cần thêm sinh ra Vọng Nguyệt mới chính thức trở thành Cổ Thần. Thuộc hệ Cổ Thần, không phải tu vi chính.","importance":"major"},{"chuong":"@c1415","canhGioi":"Sát lục bổn nguyên (manh nha)","text":"Sát niệm tích lũy cả đời giết chóc phát sinh biến hóa quỷ dị, manh nha một tia khí tức bổn nguyên mới: sát lục bổn nguyên. Thuộc hệ bổn nguyên, không phải tu vi chính.","importance":"major"},{"chuong":"@c1441","canhGioi":"Chuyển hóa phàm nhân → tiên nhân","text":"Máu tu sĩ điên bài xích sức mạnh Đạo Cổ trong cơ thể Vương Lâm, hai bên cắn nuốt nhưng mơ hồ dung hợp, tạo biến đổi từ trong máu — chính thức từ phàm nhân trở thành tiên nhân.","importance":"major"},{"chuong":"@c1443","canhGioi":"Bổn nguyên tiến gần viên mãn (tiên huyết mạch hóa tiên lôi, tiên hỏa)","text":"Tiên huyết mạch khiến lôi bổn nguyên đại thành hóa tiên lôi, hư hỏa hóa tiên hỏa, ba bổn nguyên sinh tử / nhân quả / chân giả tiến gần viên mãn. Uy lực đủ giết Không Niết Sơ Kỳ, Không Niết Trung Kỳ không cầm cự lâu, Không Niết Hậu Kỳ phải bỏ chạy.","importance":"major"},{"chuong":"@c1444","canhGioi":"Cổ Thần dung hợp Tiên Nguyên","text":"Bảy tinh điểm Cổ Thần vỡ hết rồi tái hiện thành màu vàng sau khi Thiên Nghịch dung hợp tiên nguyên và Đạo Cổ Cổ Thần. Thân Cổ Thần phát kim quang, mắt trái kim hỏa, mắt phải tia chớp vàng.","importance":"major"},{"chuong":"@c1445","canhGioi":"Kết hợp Tiên-Thần (tiên lực thay nguyên lực)","text":"Nguyên lực hoàn toàn biến mất, thay bằng tiên lực. Thân Cổ Thần + nguyên tiên + Thiên Nghịch dung hợp, là biến hóa cực kỳ hiếm trong tinh không. Sức mạnh cường đại nhưng chỉ phát huy hai phần vì lực bài xích Tiên-Thần.","importance":"major"}],"diem":[{"text":"Thiếu niên phàm nhân tư chất kém quyết chí tu tiên, nhờ Nghịch Thiên Châu khai mở Mộng Cảnh làm nền tảng mọi đột phá sau này","chuong":"@c0001"},{"text":"Tự nổ thân thể đấu Đằng Hóa Nguyên (Nguyên Anh kỳ) để báo thù diệt tộc, linh hồn chi hỏa tồn tại xuyên Vực Ngoại rồi đoạt xá thân Mã Lương","chuong":"@c0100"},{"text":"Nhận truyền thừa Cổ Thần Đồ Ti, trọng tổ thân thể Cổ Thần, khai mở con đường luyện thể và thôn hồn độc đáo","chuong":"@c0176"},{"text":"Dung hợp bổn tôn và phân thân thành một thể thống nhất, đạt tam tinh Cổ Thần và Hóa Thần hậu kỳ với ý cảnh cấp Anh Biến","chuong":"@c0365"},{"text":"Vượt mười bảy tầng Thiên Tôn Niết, được sắc phong Dược Thiên Tôn — danh hiệu thứ bốn mươi chín trong lịch sử","chuong":"@c1856"},{"text":"Đạt Không Kiếp hậu kỳ với thân thể tam cổ cửu tinh, ngưng hình dáng ban đầu Đại Thiên Tôn Chi Dương, bước vào hàng ngũ đỉnh cao cổ tộc","chuong":"@c1901"}]},"nguon":["@c1387","@c1388","@c1389","@c1390","@c1391","@c1392","@c1393","@c1394","@c1395","@c1396","@c1397","@c1398","@c1399","@c1400","@c1401","@c1402","@c1403","@c1404","@c1405","@c1406","@c1407","@c1408","@c1409","@c1410","@c1411","@c1412","@c1413","@c1414","@c1415","@c1416","@c1417","@c1418","@c1419","@c1420","@c1421","@c1422","@c1423","@c1424","@c1425","@c1426","@c1427","@c1428","@c1429","@c1430","@c1431","@c1432","@c1433","@c1434","@c1435","@c1436","@c1437","@c1438","@c1439","@c1440","@c1441","@c1442","@c1443","@c1444","@c1445","@c1446","@c1447","@c1448","@c1449","@c1450"],"gioiTinh":"nam","aliases":["Hứa Mộc","Phong Tôn"],"tinhCach":"Kiên nghị bất khuất, nhiều lần từ tuyệt cảnh và tán công vươn lên đột phá; Thâm trầm mưu trí, giỏi ẩn nhẫn bố cục và phản kích trong thế yếu; Quyết đoán tàn nhẫn với kẻ thù nhưng nặng tình với cố nhân; Không chịu khuất phục trước hoàng quyền và trật tự áp đặt","vaiTro":"Nhân vật chính — tu sĩ phàm nhân nghịch thiên, Dược Thiên Tôn tam cổ cửu tinh của Đạo Cổ","blurb":"Vương Lâm xuất thân là thiếu niên phàm nhân tư chất kém ở Thạch Thôn, nhờ Nghịch Thiên Châu khai mở Mộng Cảnh, ý chí khổ tu và vô số lần sinh tử — từ đoạt xá thân Mã Lương, truyền thừa Cổ Thần Đồ Ti, dung hợp bổn tôn với phân thân, đến vượt mười bảy tầng Thiên Tôn Niết — mà từng bước vươn tới đỉnh cao tu đạo. Tính tới giai đoạn trở về Cổ Tộc, hắn đã được sắc phong Dược Thiên Tôn, đạt Không Kiếp hậu kỳ với thân thể tam cổ cửu tinh, ngưng hình dáng ban đầu của Đại Thiên Tôn Chi Dương, và đối diện trực tiếp áp lực hoàng quyền Đạo Cổ mà vẫn không quỳ gối. Sau biến cố Tiên Hoàng tự bạo, hắn tách tà"},{"id":"lo-phu-tu","name":"Lỗ Phu Tử","canhGioiCaoNhat":"Không Niết sơ kỳ (bước thứ ba)","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Đang chữa thương trong tinh trận phía tây bắc La Thiên, cảm nhận uy áp Vương Lâm quét ngang tinh vực, sắc mặt đại biến. Ra lệnh bốn người bày La Thiên Huyễn Kính quan sát, kính bị Vương Lâm phá hủy từ xa phải vung tay đẩy lực xung kích. Nhớ ra từng kết bạn với Vương Lâm ở vùng đất Cổ Thần, thừa nhận Vương Lâm chưa tới bước thứ ba nhưng bản thân không nắm chắc chiến thắng, bảo bốn người ở lại để được bảo vệ.","anchor":"Tu vi người này vẫn chưa tới bước thứ ba …. nhưng …. lão phu cũng không nắm chắc có thể chiến thắng","bridge":true,"khoang":"@c1387"},{"chuong":"@c1388","importance":"bridge","mucCt":"gon","text":"Được đám tu sĩ La Thiên tôn sùng là người mạnh nhất La Thiên, bảo vệ La Thiên bất diệt, kế hoạch chiến tranh tứ đại tinh vực do ông cùng ba tinh vực khác định ra.","anchor":"có Lỗ Phu Tử, thì La Thiên bất diệt"},{"mucCt":"vua","text":"Cố ý đợi Vương Lâm rời Thanh Linh Tinh mới xuất hiện trên Hoành Vân Sơn, không muốn đối mặt trực tiếp. Tung một chỉ thăm dò vũ kiếm vạn trượng, thân thể chấn động hoảng sợ, nhận ra khí tức giống Cổ Thần nhưng hoàn toàn khác. Phát hiện bên trong kiếm chứa hai đạo bổn nguyên.","anchor":"Chính là khí tức này! Rất giống với Cổ Thần nhưng lại hoàn toàn khác nhau","bridge":true,"khoang":"@c1389"},{"mucCt":"ky","text":"Kinh hãi khi tận mắt thấy hai đạo bổn nguyên của Vương Lâm nhưng nhanh chóng trấn tĩnh. Nhận định Vương Lâm chưa đạt bước thứ ba nên không sợ, tự tin Không Niết Sơ Kỳ đủ sức đối phó. Coi vạn vật như kiến hôi, không thèm nhìn Tạ Thanh, cất bước rời đi. Được lão tổ Hướng gia nhận xét là phóng đại về Vương Lâm, thực chất muốn mượn Vương Lâm dò xét suy đoán riêng.","anchor":"Không Niết Sơ Kỳ là dạng tồn tại gì","bridge":true,"khoang":"@c1390"},{"mucCt":"vua","text":"Tại trung tâm trận tinh La Thiên cùng Viêm Lôi Tử, Huyết Thần Tử, Liệt Vân Tử quan sát Vương Lâm phá trận Đông Lâm Tinh từ xa. Tự đánh giá bản thân cần hai mươi nhịp thở để phá trận, lần đầu nhìn thấy khí tức Đạo Cổ mà không nhận ra bản chất. Chứng kiến Vương Lâm phá trận chỉ trong tám nhịp thở, kinh hãi thừa nhận phán đoán sai lầm rất lớn, bỏ đi hoàn toàn đánh giá trước đó, đặt Vương Lâm lên vị trí ngang hàng với mình.","anchor":"trong lòng hắn đã đặt Vương Lâm lên vị trí cao vô hạn, đã đạt tới trình độ ngang hàng với mình","bridge":true,"khoang":"@c1392"},{"mucCt":"gon","text":"Ở bên trong vòng xoáy trung tâm tinh trận Lôi Tiên Điện, khi Vương Lâm tiến tới, phát ra tiếng gào thét kinh thiên.","anchor":"đột nhiên liền có một tiếng gào thét từ trong miệng của Lỗ Phu Tử bên trong vòng xoáy khổng lồ ờ trung tâm của tinh trận vang lên kinh thiên","bridge":true,"khoang":"@c1399"},{"mucCt":"ky","text":"Phát tiếng gào thét chứa toàn bộ tu vi Không Niết Sơ Kỳ bước thứ ba nhằm ngăn Vương Lâm nhưng bị tiếng rống Đạo Cổ áp đảo hoàn toàn. Chất vấn Vương Lâm vì sao giết mười một người sắp đặt tinh trận. Hạ mình ôm quyền xin Vương Lâm nể mặt tha cho Huyết Thần Tử, nguyện nợ ân tình, bị từ chối. Tức giận thách Vương Lâm giao chiến trong tinh trận của mình, tự phụ mấy vạn năm tu vi bước thứ ba.","anchor":"lão phu đã đạt tới bước thứ ba mấy vạn năm, sao một kẻ cuồng vọng như ngươi có thể hiểu hết được","bridge":true,"khoang":"@c1400"},{"chuong":"@c1401","importance":"normal","mucCt":"ky","tieuDe":"Đấu văn ba hiệp — luyện thành La Thiên Thụ","text":"Cảm nhận chiến ý và sự tự tin của Vương Lâm, e ngại giao chiến sẽ bị trọng thương ảnh hưởng kế hoạch cướp hương hỏa giới ngoại, bèn đề nghị đấu văn ba hiệp: hiệp 1 luyện khí, hiệp 2 đấu đạo niệm, hiệp 3 đấu một thức thần thông. Điều kiện cược: Vương Lâm thắng thì nhận Huyết Thần Tử, thua thì phải rời La Thiên. Tự tin vì mấy vạn năm ở Không Niết Sơ Kỳ đã nghiên cứu luyện khí, luyện đan, đạo cấm chế. Hiệp đầu luyện khí: dùng tinh quang La Thiên làm hồn phách, bụi đất vạn cổ trong tinh không La Thiên làm thân, dung nhập phong bổn nguyên cảm ngộ từ Phong Tiên Giới, lấy máu mấy vạn tu sĩ La Thiên và máu bước thứ ba của mình làm huyết mạch, tạo ra cây đại thụ mấy vạn trượng rồi tinh chế thu nhỏ còn mười trượng, đặt tên La Thiên Thụ, pháp bảo cấp Không Niết. Tuyên bố đây là chí bảo La Thiên Lôi Tiên Điện, sẽ mở La Thiên Tiên Bảng trong cuộc chiến giới ngoại, ban cho người giết địch nhiều nhất. Tiêu hao máu tươi và bổn nguyên lực đáng kể.","anchor":"Người này tuổi còn trẻ, thời gian tu đạo không dài, mặc dù hiện giờ đã đạt tới tu vi bậc này, nhưng những phương diện khác của hắn tất nhiên không thể bằng ta"},{"chuong":"@c1402","importance":"normal","mucCt":"ky","tieuDe":"La Thiên Thụ hoàn thành, bị huyết tinh bức lui","text":"La Thiên Thụ hoàn thành, mấy vạn tu sĩ tung hô cuồng nhiệt. Mời Vương Lâm ra tay luyện bảo vật đáp lễ. Khi thấy Vương Lâm phá tu chân tinh bằng thể xác, nhớ tới Cổ Thần Thác Sâm trên Chu Tước Tinh, sắc mặt khó coi. Dưới sát khí huyết tinh phải lùi mấy bước, da đầu tê dại, thừa nhận cả đời mới gặp tu sĩ có sát khí như vậy, không dám trêu chọc. Hỏi Vương Lâm dựa vào gì chỉ sát khí mà phá La Thiên Thụ, bị đáp lại bá đạo.","anchor":"hắn chưa bao giờ nghĩ tới một người cả đời lại có thể có sát khí như vậy"},{"chuong":"@c1403","importance":"normal","mucCt":"ky","tieuDe":"Toàn lực ngăn Vương Lâm, bị chấn động bởi cổ nô Linh Động","text":"Đề nghị đấu đạo niệm bị Vương Lâm từ chối. Bộc phát toàn lực Không Niết sơ kỳ bước thứ ba, triệu hoán thanh tàn kiếm, biến ảo Phong Tiên Giới hoàn chỉnh (bổn nguyên hương hỏa), kích hoạt La Thiên đại trận tinh hồn. Mang hư ảnh chúng tiên lao về phía Vương Lâm. Bị chấn động sững sờ khi Linh Động Thượng Nhân xuất hiện — lần đầu mất bình tĩnh trong mấy vạn năm, nhận ra hương hỏa Linh Động dày đặc vượt xa mình.","anchor":"Lỗ Phu Tử bình thản mấy vạn năm cuối cũng cũng bị sự xuất hiện của Linh Động Thượng Nhân khiến cho chấn động sững sờ"},{"chuong":"@c1404","importance":"normal","mucCt":"ky","tieuDe":"Kích hoạt tinh trận nhưng bất lực trước ba bước thứ ba","text":"Sắc mặt tái nhợt, thừa nhận thực lực không địch nhưng quyết đánh một trận. Tự bạch thiên tư kỳ dị, nếu không bị hạn chế hương hỏa đã sớm đạt Không Niết trung hoặc hậu kỳ, mấy vạn năm qua luyện chế rất nhiều pháp bảo. Kích hoạt tinh trận bộc phát gấp mấy chục lần, triển khai 18 pháp bảo, mấy vạn tu sĩ hô vang La Thiên lão tổ và tặng hương hỏa lực. Nhưng khi Chu Cẩn xuất hiện, vội lui hơn trăm trượng, hoàn toàn mất ý chí chiến đấu, nhận ra không thể đối đầu ba bước thứ ba.","anchor":"Cho dù là có tinh trận trợ giúp thì giờ phút này tinh trận còn chưa đầy đủ, làm sao mà có thể khai chiến với ba tu sĩ bước thứ ba chứ"},{"mucCt":"vua","text":"Sắc mặt tái nhợt trước uy lực quyền Vương Lâm. Bị chất vấn, thừa nhận ngăn cản Vương Lâm kết thúc nhân quả chính vì chuyện Cổ Yêu và bí mật Diêu gia. Cáo từ tiếp tục chuẩn bị chiến tranh, vẫn giữ ngạo cốt dù Vương Lâm có hai nô bộc bước thứ ba.","anchor":"dù là rung động nhưng muốn hắn cúi mặt thì tuyệt không thể","bridge":true,"khoang":"@c1406"},{"importance":"normal","mucCt":"ky","chuong":"@c1407","tieuDe":"Hòa giải với Vương Lâm, tiết lộ chiến tranh giới ngoại","text":"Thần sắc hòa hoãn, thừa nhận chịu thua trước Vương Lâm. Nhận ra ấn ký nô phó trên mi tâm Linh Động Thượng Nhân và Chu Cẩn, kinh ngạc vì Vương Lâm chưa bước thứ ba mà luyện hóa được nô phó bước thứ ba. Tiết lộ tình hình giới nội: Yêu Tông và Thần Tông ở Vân Hải tinh vực truyền lệnh phong bằng di chiếu chủ nhân phong giới, tứ đại tinh vực chuẩn bị chiến tranh với Thái Cổ Tinh Thần. Tự bộc lộ quá khứ từng là tiên quân nhỏ của Lôi Tiên Giới, tận mắt thấy trận chiến bi thảm, mang thù sâu với giới ngoại. Nhấn mạnh Phong Giới Đại Trận khiến tin tức bế tắc mấy vạn năm là điều trí mạng. Long trọng nghênh tiếp Vương Lâm bằng kim quang vạn trượng, chín kim long, hư ảnh tiên nhân, mời uống rượu tiên hóa giải hiềm khích.","anchor":"lão phu từng là một tiên quân nho nhỏ của Lôi tiên giới, tận mắt thấy trận chiến bi thảm khó quên kia"},{"mucCt":"vua","text":"Nhớ lại năm đó chịu ơn Chiến Tinh Dã, đó cũng là lý do nhận Liệt Vân Tử làm đệ tử. Nhận ra Thất Thải Giới là mối họa khủng khiếp cho giới nội trong đại chiến — nếu đạo niệm tu sĩ bị hấp thụ sẽ gây thảm họa. Quyết định lập tức bay đi Yêu Tông ở Vân Hải báo tin để liên lạc các lực lượng giới nội tìm diệt sáu Thất Thải Giới còn lại, rồi rời đi.","anchor":"lão phu phải lập tức đi tới Vân Hải để báo tin cho Yêu Tông","bridge":true,"khoang":"@c1408"},{"chuong":"@c1415","importance":"bridge","mucCt":"gon","text":"Đang ở sơn cốc trong Vân Hải tinh vực, khách khí nói chuyện với đám tông chủ yêu tông cùng nam tử áo đỏ.","anchor":"Lỗ Phu Tử không ngờ cũng đang ở đó, khách khí nói chuyện với đám người tông chủ yêu tông"},{"chuong":"@c1434","importance":"bridge","mucCt":"gon","text":"Dẫn đầu tu sĩ La Thiên tới chi viện giới nội, cùng mỹ phụ trung niên Triệu Hà hỗ trợ Hồng Sam Tử giáp công hàn y đồng tử.","anchor":"Lỗ Phu Tử dẫn đầu thần sắc âm trầm, trong lúc bay tới ánh mắt lộ ra sát khí ngợp trời"},{"chuong":"@c1438","importance":"bridge","mucCt":"gon","text":"Đồng thời ra tay cùng các cao thủ giới nội phối hợp tấn công bàn tay khổng lồ.","anchor":"Có thể nói tất cả những cao thủ của giới nội ở đây lúc này, toàn bộ đều trong khoảng khắc này bộc phát ra sức mạnh lớn nhất"},{"chuong":"@c1440","importance":"bridge","mucCt":"gon","text":"Tin Phong Tôn Vương Lâm vẫn còn sống.","anchor":"Lỗ Phu Tử tin rằng, Phong Tôn vẫn còn sống!"}],"nhanMach":[{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Từng kết bạn ở vùng đất Cổ Thần trong Liên Minh","ghiChu":"Thừa nhận không nắm chắc thắng dù Vương Lâm chưa đạt bước thứ ba"},{"ten":"Huyết Thần Tử","tag":"dong-minh","quanHe":"Người được bảo vệ","ghiChu":"Sẵn sàng nợ ân tình Vương Lâm để bảo vệ Huyết Thần Tử, vì Huyết Thần Tử nắm giữ thông tin về 'chỗ đó' mà Lỗ Phu Tử cần (@c1400)"}],"tuViMoc":[],"diem":[{"text":"Hoảng sợ trốn chạy khi Thác Sâm xuất hiện, rút vào tinh không không dám giao chiến","chuong":"@c1147"},{"text":"Bừng tỉnh từ nhập định khi cảm nhận khí thế Vương Lâm quét ngang La Thiên tinh vực","chuong":"@c1386"},{"text":"Đấu văn ba hiệp với Vương Lâm, luyện thành La Thiên Thụ được vạn tu sĩ tung hô","chuong":"@c1401"},{"text":"Thừa nhận bại trận, hòa giải với Vương Lâm và tiết lộ chiến tranh giới ngoại sắp tới","chuong":"@c1407"},{"text":"Dẫn đầu tu sĩ La Thiên chi viện giới nội, phối hợp các cường giả giáp công thế lực xâm nhập","chuong":"@c1434"},{"text":"Chọn ở lại Côn Hư tử chiến, bị trọng thương trong trận phản công và được Long Bàn Tử cứu rút lui","chuong":"@c1520"}]},"nguon":["@c1387","@c1388","@c1389","@c1390","@c1392","@c1399","@c1400","@c1401","@c1402","@c1403","@c1404","@c1405","@c1406","@c1407","@c1408","@c1410","@c1415","@c1434","@c1438","@c1440"],"cn":"鲁夫子","gioiTinh":"nam","vaiTro":"Cường giả mạnh nhất La Thiên tinh vực — tu vi Không Niết Sơ Kỳ bước thứ ba","tinhCach":"Thận trọng, tránh đối đầu trực diện khi chưa nắm chắc phần thắng; biết tiến biết lui, chấp nhận bại trận trước kẻ mạnh hơn; trọng nhân quả và ân nghĩa cũ; sẵn sàng xả thân tử chiến khi đại cuộc lâm nguy","blurb":"Lỗ Phu Tử là cường giả được vạn tu sĩ La Thiên tôn sùng, tu vi Không Niết Sơ Kỳ bước thứ ba, lâu nay ẩn mình chữa thương trong tinh trận tây bắc La Thiên. Từng hoảng sợ trốn chạy khi Thác Sâm xuất hiện, về sau đối đầu Vương Lâm qua ba hiệp đấu văn, luyện thành La Thiên Thụ rồi thừa nhận bại trận, hòa giải và tiết lộ mối đe dọa chiến tranh giới ngoại. Sau đó dẫn đầu tu sĩ La Thiên chi viện giới nội, chọn ở lại Côn Hư tử chiến thay vì rút lui, bị trọng thương trong trận phản công và được cứu rút vào Chu Tước tinh."},{"id":"viem-loi-tu","name":"Viêm Lôi Tử","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1387","importance":"bridge","mucCt":"vua","text":"Tham gia bày La Thiên Huyễn Kính theo lệnh Lỗ Phu Tử, khi kính bị Vương Lâm phá hủy thì phun máu. Nhận ra Vương Lâm nhưng tự nhủ không có ân oán, dần bình tĩnh lại.","anchor":"Vương Lâm ! Hắn là Vương Lâm !"},{"importance":"bridge","mucCt":"gon","chuong":"@c1392","text":"Sắc mặt tái nhợt khi cảm nhận hào quang trận pháp Đông Lâm Tinh, cùng Lỗ Phu Tử quan sát Vương Lâm phá trận từ trung tâm trận tinh La Thiên.","anchor":"Viêm Lôi Tử, Huyết Thần Tử, Liệt Vân Tử ba người sắc mặt tái nhợt"},{"chuong":"@c1400","importance":"bridge","mucCt":"vua","text":"Hoảng sợ trước sức mạnh Vương Lâm trong tinh trận, khi được Vương Lâm chào xưng 'đạo hữu' thì vội ôm quyền gọi Vương Lâm là 'tiền bối', nói La Thiên Tinh Vực là nhà của Vương Lâm.","anchor":"La Thiên Tinh Vực chính là nhà của tiền bối, sao lại lại phải xin thứ lỗi"},{"chuong":"@c1402","importance":"bridge","mucCt":"gon","text":"Đã có pháp bảo Lôi Tiên Giới nên không quá coi trọng La Thiên Thụ, nhưng thần sắc biến đổi khi cảm nhận sát khí huyết tinh Vương Lâm.","anchor":"Đám người Viêm Lôi Tử thần sắc biến đổi"},{"chuong":"@c1403","importance":"normal","mucCt":"vua","tieuDe":"Chấn động trước cổ nô bước thứ ba của Vương Lâm","text":"Chứng kiến Linh Động Thượng Nhân xuất hiện, cả người thừ ra, đầu óc rối loạn. Chấn động không thể tin tu sĩ bước thứ ba lại trở thành nô phó cho Vương Lâm.","anchor":"Một tu sĩ bước thứ ba không ngờ lại trở thành nô phó cho Vương Lâm"},{"chuong":"@c1404","importance":"bridge","mucCt":"gon","text":"Cùng Lỗ Phu Tử hoàn toàn ngây ngốc đứng đó trước cảnh Vương Lâm có hai nô phó bước thứ ba.","anchor":"Lỗ Phu Tử và đám người Viêm Lôi Tử giống nhau, đã hoàn toàn trở nên ngây ngốc đứng đó"},{"importance":"bridge","mucCt":"vua","chuong":"@c1407","tieuDe":"Nghe chuyện giới ngoại, hỏi về Tán Linh Thượng Nhân","text":"Đứng bên cạnh nghe Vương Lâm kể chuyện giới ngoại, ánh mắt kính nể. Hỏi Vương Lâm có gặp lại Tán Linh Thượng Nhân không, truyền âm cho mấy vạn tu sĩ tản đi tiếp tục bày trận.","anchor":"Vương Lâm tiền bối, vậy sau đó ngươi còn gặp lại Tán Linh Thượng Nhân kia không?"},{"mucCt":"ky","text":"Chấn động khi nghe về Thất Thải Giới, nhớ lại chuyện cũ đáng sợ. Tiết lộ bản thân từng là trưởng lão Tu Chân Liên Minh, đã nhìn thấy một thế giới kỳ dị tại tổng bộ — xác nhận đó chính là Thất Thải Giới. Cầu xin đi cùng Vương Lâm tới Tu Chân Liên Minh vì quen thuộc nơi đó và có thâm thù với Trọng Huyền Tử. Vương Lâm đồng ý, Viêm Lôi Tử sẽ đi trước chờ. Thở dài cảm thán mình đã già.","anchor":"Tại hạ năm đó là từ Liên Minh Tinh Vực bị truy sát bỏ chạy","bridge":true,"khoang":"@c1408"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Kích hoạt Lôi Tiên Đại Trận luyện hóa tiên giới, triệu hồi nguyên thần các cấp thiên tiên, tiên vương và Tiên Quân quy vị vào trận","chuong":"@c0745"},{"text":"Chủ trì nghi thức Phong Tiên: phong Hứa Mộc làm Chính phẩm Lôi tiên, hiến tinh huyết nguyên thần phá bức tường không gian mở thông đạo tới Liên Minh Tinh Vực","chuong":"@c0828"},{"text":"Bộc lộ tu vi thật vượt Toái Niết hậu kỳ trong trận chiến với Cực Hiền Thiên ở phía Bắc Liên Minh","chuong":"@c0864"},{"text":"Giao chiến một ngày với thượng cổ tu sĩ áo đỏ chưa phân thắng bại, sau đó bị dư uy Diệt Thần Mâu trọng thương nặng, được Lỗ Phu Tử cứu","chuong":"@c1066"},{"text":"Tiết lộ bản thân từng là trưởng lão Tu Chân Liên Minh trước khi gia nhập La Thiên, mang mối thù truyền kiếp với Trọng Huyền Tử vốn là đạo hữu chí cốt","chuong":"@c1408"},{"text":"Bị tu sĩ Toái Niết giới ngoại truy sát do thương thế khiến tu vi thụt lùi, được Vương Lâm cứu thoát","chuong":"@c1452"}]},"nguon":["@c1387","@c1392","@c1400","@c1402","@c1403","@c1404","@c1405","@c1407","@c1408"],"cn":"炎雷子","gioiTinh":"nam","vaiTro":"Điện chủ Lôi Tiên Điện — chỉ huy cấp cao La Thiên, cựu trưởng lão Tu Chân Liên Minh","tinhCach":"trọng dụng nhân tài, sẵn sàng chấp nhận tổn thất để chiêu nạp cao thủ; quyết đoán trong đại cục, dám hiến tinh huyết nguyên thần mở thông đạo; bình tĩnh trước chất vấn và biến cố bất ngờ; mang mối thù truyền kiếp với Tu Chân Liên Minh, không chịu dừng tay khi chiến sự chưa ngã ngũ","blurb":"Viêm Lôi Tử là Điện chủ Lôi Tiên Điện, một trong những nhân vật chỉ huy then chốt của La Thiên trong cuộc đại chiến với Tu Chân Liên Minh. Vốn từng là trưởng lão Tu Chân Liên Minh trước khi gia nhập La Thiên, ông sở hữu tu vi vượt Toái Niết hậu kỳ, từng kích hoạt Lôi Tiên Đại Trận luyện hóa tiên giới, chủ trì nghi thức Phong Tiên phong Hứa Mộc làm Chính phẩm Lôi tiên, hiến tinh huyết nguyên thần phá bức tường không gian mở thông đạo tới Liên Minh Tinh Vực, rồi trực tiếp giao chiến với các đại tu sĩ hàng đầu như Cực Hiền Thiên, Võ Đông Thiện và thượng cổ tu sĩ áo đỏ. Trải qua đại chiến thứ ba v"},{"id":"liet-van-tu","name":"Liệt Vân Tử","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1387","importance":"bridge","mucCt":"vua","text":"Tham gia bày La Thiên Huyễn Kính, phun máu khi kính bị phá, hoảng sợ nhớ lại lần bị Vương Lâm đàn áp ở Chu Tước Thánh Tông, sau cùng thở dài.","anchor":"Hắn tiếp xúc với Vương Lâm nhiều nhất, nhất là lần cuối cùng ở Chu Tước Thánh Tông còn bị Vương Lâm đàn áp"},{"importance":"bridge","mucCt":"gon","chuong":"@c1392","text":"Sắc mặt tái nhợt, cùng Viêm Lôi Tử và Huyết Thần Tử đứng bên Lỗ Phu Tử quan sát Vương Lâm phá trận Đông Lâm Tinh từ xa.","anchor":"Viêm Lôi Tử, Huyết Thần Tử, Liệt Vân Tử ba người sắc mặt tái nhợt"},{"chuong":"@c1400","importance":"bridge","mucCt":"vua","text":"Bị dư âm tiếng rống Đạo Cổ khiến phun máu, lùi hơn mười trượng, suy đoán Vương Lâm đã hoàn toàn lĩnh ngộ Chiến Tự Thiếp của Chiến gia.","anchor":"chẳng lẽ hắn đã hoàn toàn hiểu được bộ Chiến Tự Thiếp của Chiến gia ta hay sao"},{"chuong":"@c1402","importance":"bridge","mucCt":"vua","text":"Tâm thần chấn động trước La Thiên Thụ hoàn thành, khi huyết tinh Vương Lâm phóng tới thì hoảng sợ lùi lại, trong mắt hắn Lỗ Phu Tử đang đối mặt núi thây biển máu.","anchor":"Trong mắt hắn, lúc này Lỗ Phu Tử không phải đang đối mặt với Vương Lâm, mà đang đối mặt với núi thây biển máu"},{"chuong":"@c1404","importance":"normal","mucCt":"vua","tieuDe":"Hình tượng bước thứ ba sụp đổ","text":"Chấn động tột độ trước cảnh tu sĩ bước thứ ba làm nô phó của Vương Lâm, hình tượng bước thứ ba cao cao tại thượng trong lòng sụp đổ. Run rẩy phun máu tươi, nhận định Vương Lâm ở tứ đại tinh vực giới nội hẳn phải đứng đầu.","anchor":"hóa ra bước thứ ba cũng chỉ là tu sĩ, cũng có thể trở thành nô phó của người khác"},{"mucCt":"vua","text":"Đứng bên cạnh nghe chuyện, nhớ lại cảnh tượng năm xưa. Khi nghe Vương Lâm nhắc đã gặp Chiến Tinh Dã ở giới ngoại, toàn thân chấn động, kích động xá sâu hỏi lão tổ hiện ở đâu.","anchor":"Xin tiền bối cho biết, lão tổ hiện giờ ở đâu!","bridge":true,"khoang":"@c1407"},{"mucCt":"ky","text":"Nghe Vương Lâm thông báo lão tổ Chiến Tinh Dã đã chết trong Thất Thải Giới tại Vân Hải, bị Chưởng Tôn giết. Tâm thần trọng thương, khóe miệng tràn máu tươi. Sát khí và chiến ý nồng đậm dâng trào, quyết truyền thừa quyết tâm báo thù cho đời sau của Chiến gia. Sau khi Vương Lâm rời đi, cảm thán giới nội hiện giờ đã là thiên hạ của Vương Lâm.","anchor":"tâm thần của Liệt Vân Tử bị tin tức này khiến cho trọng thương, khóe miệng tràn ra máu tươi","bridge":true,"khoang":"@c1408"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Sai quân truy bắt Vương Lâm tại vùng biên Hỏa Yêu – Kim Yêu, triệu tám Tiên vệ vây giết nhưng bất thành","chuong":"@c0574"},{"text":"Dùng ngân kiếm thi triển Tâm Động Tiên Thuật xuyên thân Vọng Nguyệt, bị thương khi cản trở","chuong":"@c0789"},{"text":"Chủ trì Thiên Chi Quan, dùng Chiến Tự Thiếp khảo xét Hứa Đình và Vương Lâm","chuong":"@c0820"},{"text":"Bị tân Chu Tước Thánh Hoàng ép cúi đầu, giao nộp Chiến Tự Thiếp và La Phù","chuong":"@c1024"},{"text":"Hình tượng bước thứ ba trong tâm sụp đổ khi chứng kiến tu sĩ bước thứ ba làm nô phó cho Vương Lâm","chuong":"@c1404"},{"text":"Được Vương Lâm thông báo lão tổ Chiến Tinh Dã đã chết trong Thất Thải Giới","chuong":"@c1408"}]},"nguon":["@c1387","@c1392","@c1400","@c1402","@c1404","@c1405","@c1407","@c1408"],"cn":"烈云子","gioiTinh":"nam","vaiTro":"Lão tổ Chiến gia — sứ giả La Thiên Tinh Vực, người giữ Chiến Tự Thiếp","tinhCach":"trầm tĩnh quan sát, chủ động ứng chiến khi cần; coi trọng tư chất hậu bối; cứng rắn trước kẻ dưới nhưng dễ bị chấn nhiếp trước cường giả áp đảo; nặng lòng với bí mật và danh dự gia tộc","blurb":"Liệt Vân Tử là lão tổ Chiến gia, từ sớm đã sai quân truy bắt Vương Lâm nhưng bất thành, sau đó tham chiến cản trở Vọng Nguyệt bằng Tâm Động Tiên Thuật và chủ trì Thiên Chi Quan dùng Chiến Tự Thiếp khảo xét hậu bối. Với tư cách sứ giả La Thiên Tinh Vực, ông bị tân Chu Tước Thánh Hoàng ép cúi đầu giao nộp Chiến Tự Thiếp cùng La Phù, rồi trúng phục kích Thi Âm Tông trên đường về Lôi Tiên Điện. Khi La Thiên Thụ hoàn thành, ông chứng kiến sức mạnh của Vương Lâm khiến hình tượng bước thứ ba trong tâm sụp đổ hoàn toàn, và được thông báo lão tổ Chiến Tinh Dã đã chết trong Thất Thải Giới."},{"id":"huyet-than-tu","name":"Huyết Thần Tử","trangThai":"tu-vong","tabs":{"kinhLich":[{"mucCt":"ky","text":"Từng truy sát Vương Lâm bị Thanh Thủy cản trở, từng bị trọng thương trong trận Liên Minh nay đã hồi phục. Tham gia bày La Thiên Huyễn Kính, khi nhận ra Vương Lâm thì sắc mặt tái nhợt, không thể tin kẻ năm xưa mình coi như kiến nay lại có uy áp khiến hắn run rẩy. Trầm ngâm rồi yên lặng ngồi xuống, không dám ra ngoài.","anchor":"giống như…. không dám đi ra ngoài!","bridge":true,"khoang":"@c1387"},{"importance":"bridge","mucCt":"gon","chuong":"@c1392","text":"Sắc mặt tái nhợt, cùng Viêm Lôi Tử và Liệt Vân Tử đứng bên Lỗ Phu Tử quan sát Vương Lâm phá trận Đông Lâm Tinh từ xa.","anchor":"Viêm Lôi Tử, Huyết Thần Tử, Liệt Vân Tử ba người sắc mặt tái nhợt"},{"mucCt":"ky","text":"Sợ hãi nhất trong vòng xoáy tinh trận, thân thể run rẩy khi bị Vương Lâm chỉ tay chỉ đích danh. Ban đầu tự trấn an rằng Vương Lâm đến vì Lỗ Phu Tử, nhưng khi bị nhắm thì tuyệt vọng. Cầu xin Lỗ Phu Tử bảo vệ, hé lộ mình là người duy nhất có thể đưa Lỗ Phu Tử đến 'chỗ đó', bị Lỗ Phu Tử cắt lời.","anchor":"Lỗ Phu Tử tiền bối. Chổ đó, chỉ có vãn bối mới có thể đưa người đi","bridge":true,"khoang":"@c1400"},{"chuong":"@c1401","importance":"bridge","mucCt":"gon","text":"Trở thành vật cược trong đấu văn: nếu Vương Lâm thắng, Lỗ Phu Tử sẽ đích thân đưa Huyết Thần Tử cho hắn.","anchor":"nếu như ngươi thắng, Huyết Thần Tử lão phu sẽ đích thân đưa tới cho ngươi"},{"chuong":"@c1402","importance":"bridge","mucCt":"vua","text":"Khi sát khí đạo quả Thất Thải Giới bộc phát, lập tức phun ra máu tươi. Khi huyết tinh phóng tới thì mặt trắng bệch, không ngừng lùi lại.","anchor":"nhất là Huyết Thần Tử kia ngay khi cảm nhận được sát khí này lập tức phun ra một ngụm máu tươi"},{"chuong":"@c1403","importance":"bridge","mucCt":"gon","text":"Sắc mặt tái nhợt đứng phía sau Lỗ Phu Tử, là mục tiêu Vương Lâm muốn trực tiếp giết.","anchor":"nhìn về phía Huyết Thần Tử sắc mặt đang tái nhợt ở phía sau"},{"chuong":"@c1404","importance":"normal","mucCt":"vua","tieuDe":"Ngây ngẩn trước hai nô phó bước thứ ba","text":"Hoàn toàn ngây ngẩn, tự thì thào đây là ảo giác. Suy đoán nếu không cam tâm thì phải bị Vương Lâm mạnh mẽ thu phục, rồi lại phủ nhận vì tu vi Vương Lâm chỉ mới ngang bước thứ ba.","anchor":"Ảo giác, đây nhất định là một thứ ảo giác cực kỳ hiếm gặp trong thiên địa"},{"chuong":"@c1406","importance":"normal","mucCt":"ky","tieuDe":"Bị Vương Lâm giết, kết thúc tuyến nhân vật","text":"Bị khí tức Đạo cổ và ánh mắt Vương Lâm dung hợp đầu lâu Đạo cổ xuyên thấu nguyên thần, da thịt bị lột, xương cốt tan nát. Nguyên thần bị xé đôi từ mi tâm xuống bụng bằng tia máu, thân thể ầm vang tan thành máu thịt. Chết, kết thúc tuyến nhân vật.","anchor":"ánh mắt đối phương như một thanh kiếm sắc bén, xuyên qua ánh mắt hắn, trực tiếp tiến vào trong nguyên thần"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Phá lời thề truy vào La Thiên Tinh vực truy sát Vương Lâm, bị phản chế bằng sinh tử Diêu Tích Tuyết và mất nửa Huyết Thân","chuong":"@c0717"},{"text":"Bỏ Huyết Thân, nguyên thần chạy trốn khỏi Thiên Kiếp sau khi bị Vương Lâm dẫn lôi kiếp truy kích","chuong":"@c0724"},{"text":"Bị Thanh Thủy ép sát, hiến tế Diêu Vân cho Cổ Yêu hút huyết nhục và nguyên thần để lấy Cổ Đăng nghịch chuyển cục diện","chuong":"@c0804"},{"text":"Giao chiến một đối một với Hắc Sát Ma Tôn trong đại chiến La Thiên – Liên Minh","chuong":"@c0863"},{"text":"Được Vương Lâm giải phóng khỏi Phong Tiên Ấn, buông bỏ thù hận và được trả tự do","chuong":"@c0975"},{"text":"Bị Vương Lâm dùng khí tức Đạo cổ dung hợp đầu lâu Đạo cổ xuyên thấu nguyên thần mà giết, kết thúc tuyến nhân vật","chuong":"@c1406"}]},"nguon":["@c1387","@c1392","@c1395","@c1400","@c1401","@c1402","@c1403","@c1404","@c1405","@c1406"],"cn":"血神子","gioiTinh":"nam","aliases":["Lão tổ Diêu gia"],"vaiTro":"Lão tổ trấn tộc Diêu gia — cường giả đại gia tộc truyền thừa Tiên giới tại La Thiên Đông Vực","tinhCach":"quyết đoán tàn nhẫn, không tiếc hiến tế hậu bối hay bảo bối để đạt mục đích; âm trầm thâm hiểm, luôn ẩn nhẫn quan sát trước khi ra tay; cương ngạnh, dám đối đầu cả Thanh Thủy và các Ma Tôn; cuối đời lộ sợ hãi tuyệt vọng khi đối diện Vương Lâm đã vượt tầm kiểm soát","blurb":"Huyết Thần Tử là Lão Tổ trấn tộc của Diêu gia tại La Thiên Đông Vực, thế lực cốt lõi khiến Diêu gia được liệt vào hàng đại gia tộc truyền thừa Tiên giới. Từ khi Diêu gia ban Thiên Khung Lệnh truy sát Vương Lâm, ông nhiều lần trực tiếp can thiệp — phá lời thề truy vào La Thiên Tinh vực, ép hậu bối làm khí hồn, hiến tế Diêu Vân cho Cổ Yêu, giao chiến Thanh Thủy rồi đối đầu Hắc Sát Ma Tôn và Vân Long Yêu Tôn trong đại chiến La Thiên – Liên Minh. Sau khi hồi phục thương thế và tái xuất, Huyết Thần Tử rốt cuộc bị Vương Lâm dùng khí tức Đạo cổ dung hợp đầu lâu Đạo cổ xuyên thấu nguyên thần mà giết c"},{"id":"huong-van-dong","name":"Hướng Vân Đông","trangThai":"khong-ro","tabs":{"kinhLich":[{"mucCt":"ky","text":"Tu vi yếu nhất trong bốn người, nguyên thần tràn ngập lôi đình Vương Lâm khi La Thiên Huyễn Kính bị phá, đạo tâm bị nứt. Lo sợ ân oán Hướng gia với Vương Lâm vì vụ Thất Tịch Thuật năm xưa, cung kính từ biệt Lỗ Phu Tử rồi vội rời đi về Hướng gia để đem tin tức về chuẩn bị kỹ lưỡng.","anchor":"Một kẻ địch mà ngay cả lão tổ La Thiên Tinh Vực là Lỗ Phu Tử cũng không nắm chắc phần thắng, thì Hướng gia bọn họ lấy cái gì để đánh","bridge":true,"khoang":"@c1387"},{"mucCt":"vua","text":"Đem tin Vương Lâm trở về với tu vi khủng khiếp làm cả Hướng gia rung động kinh hoàng. Dù tu vi không đủ vẫn được Lỗ Phu Tử chọn làm một trong bốn người truyền đạo thuật nhờ thế lực Hướng gia.","anchor":"đại biểu của Hướng gia, Hướng Vân Đông đã đem một tin tức trở về khiến cho cả Hướng gia rung động kinh hoàng","bridge":true,"khoang":"@c1390"},{"importance":"bridge","mucCt":"gon","chuong":"@c1393","text":"Vẻ mặt đau khổ lặng lẽ nhìn cảnh tượng kinh hoàng tộc nhân Hướng gia bị Vương Lâm thiêu diệt.","anchor":"Hướng Vân Đông vẻ mặt đau khổ, lẳng lặng nhìn hết thảy mọi chuyện"}],"diem":[{"text":"Quan sát và tán thưởng sát khí của Vương Lâm sau Địa Chi Quan","chuong":"@c0820"},{"text":"Chẩn đoán Nguyên Anh Lý Mộ Uyển bằng Tiếp Thần thuật, nêu ra Thất Tịch Thuật khi nhận thấy tuổi thọ Nguyên Anh đã cạn","chuong":"@c0827"},{"text":"Cùng các lão quái công kích dòng xoáy, góp phần mở đường rời Lôi Tiên điện","chuong":"@c0828"},{"text":"Dẫn Vương Lâm và Thanh Thủy tới Đông Lâm tinh, đứng ngoài khe chứng kiến Vương Lâm già nua rời thông đạo","chuong":"@c0831"},{"text":"Đem tin Vương Lâm trở về với tu vi khủng khiếp làm cả Hướng gia rung động, dù tu vi yếu vẫn đứng ra đương đầu","chuong":"@c1390"},{"text":"Đau khổ lặng lẽ nhìn tộc nhân Hướng gia bị Vương Lâm thiêu diệt","chuong":"@c1393"}]},"nguon":["@c1387","@c1390","@c1393"],"cn":"向云东","gioiTinh":"nam","vaiTro":"Lão nhân Hướng gia am hiểu Tiếp Thần thuật, từng trợ giúp rồi đối mặt Vương Lâm","tinhCach":"biết quan sát đánh giá con người; thận trọng, lường trước cái giá của biến cố; sẵn sàng phối hợp ra tay trợ giúp; đau khổ bất lực trước họa diệt tộc","blurb":"Hướng Vân Đông là lão nhân của Hướng gia, am hiểu Tiếp Thần thuật, từng tán thưởng sát khí Vương Lâm sau Địa Chi Quan rồi được Vương Lâm tìm đến nhờ cứu Nguyên Anh Lý Mộ Uyển. Ông chẩn đoán tình trạng Nguyên Anh, nêu ra Thất Tịch Thuật, cùng các lão quái công kích dòng xoáy mở đường, sau đó dẫn Vương Lâm và Thanh Thủy tới Đông Lâm tinh và chứng kiến Vương Lâm già nua rời thông đạo. Về sau khi Vương Lâm trở lại với tu vi khủng khiếp, Hướng Vân Đông dù tu vi không đủ vẫn đứng ra đương đầu, và cuối cùng đau khổ bất lực nhìn tộc nhân Hướng gia bị Vương Lâm thiêu diệt."},{"id":"chien-khong-liet","name":"Chiến Không Liệt","cn":"战空烈","gioiTinh":"nam","canhGioiCaoNhat":"Tịnh Niết viên mãn","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1388","importance":"normal","mucCt":"ky","tieuDe":"Chỉ huy kéo tu chân tinh, gặp lại Vương Lâm","text":"Tu vi Tịnh Niết viên mãn, chỉ huy gần trăm tu sĩ kéo tu chân tinh ra khỏi quỹ đạo phục vụ chuẩn bị chiến tranh La Thiên. Nói rõ kế hoạch chiến tranh tứ đại tinh vực do Lỗ Phu Tử cùng ba tinh vực khác định ra, Vân Hải cầm đầu. Gặp người áo trắng (Vương Lâm) trong tinh không mà không nhận ra ngay, sau mới nhớ ra từ hình ảnh tóc trắng, kích động đuổi theo toàn lực nhưng Vương Lâm đã biến mất. Đau khổ đứng rất lâu rồi hướng tinh không vái một cái, thở dài rời đi.","anchor":"Tại sao lại không gọi ta một tiếng …."},{"importance":"bridge","mucCt":"gon","chuong":"@c1441","tieuDe":"","text":"Được nhắc từng cho rằng thiên hạ không ai có thể khiến cung Lý Quảng nhận chủ.","anchor":"ngay cả Chiến lão quỷ cũng cho rằng trong thiên hạ không người nào có thể khiến cho nó nhận chủ"}],"diem":[{"text":"Gặp Vương Lâm tại Lôi Trì, suy đoán hắn là tiền bối ẩn tu rồi cung kính bái kiến","chuong":"@c0733"},{"text":"Được Vương Lâm chỉ ra chiến ý Chiến gia thiếu niềm tin bất khuất, chấn động ngộ đạo","chuong":"@c0809"},{"text":"Tu vi đạt Tịnh Niết viên mãn, chỉ huy gần trăm tu sĩ kéo tu chân tinh chuẩn bị chiến tranh Ngoại Vực","chuong":"@c1388"},{"text":"Sẵn sàng tự bạo cùng Tây Tử Phượng và Thân Công Hổ khi màn sáng sụp đổ","chuong":"@c1559"},{"text":"Được tiết lộ là người duy nhất trong lịch sử động phủ vượt tám lần huyền kiếp bằng thân phận tu sĩ bên trong","chuong":"@c1568"},{"text":"Bị Vương Lâm suy luận chính là hồn thứ hai của Thất Thải Thiên Tôn, hồn chứa ý cảnh và bổn nguyên lực","chuong":"@c1600"}]},"nguon":["@c1388","@c1441"],"aliases":["Chiến lão quỷ"],"vaiTro":"Tu sĩ Chiến gia — hồn thứ hai Thất Thải Thiên Tôn, truy tùy trung thành của Vương Lâm","tinhCach":"thận trọng biết thời thế, suy đoán sắc bén trước cường giả; cung kính cầu đạo, sùng kính Vương Lâm sau khi chứng kiến uy lực; mang chiến ý bất khuất cố hữu của Chiến gia; trung thành kiên định, sẵn sàng tự bạo vì đại cục","blurb":"Chiến Không Liệt là tu sĩ Chiến gia xuất thân từ Lôi Tiên Giới, ban đầu ở cảnh Dương Thực viên mãn, về sau đạt tới Tịnh Niết viên mãn và vượt qua tám lần huyền kiếp — là người duy nhất trong lịch sử động phủ dựa vào thân phận tu sĩ bên trong mà đạt tới mốc này. Hắn gặp Vương Lâm tại Lôi Trì, từ nghi ngờ chuyển sang cung kính bái kiến, được Vương Lâm chỉ điểm về niềm tin bất khuất của chiến ý Chiến gia, rồi theo Vương Lâm suốt hành trình từ tranh đoạt phong hào đến chiến tranh Ngoại Vực. Về sau bị Vương Lâm suy luận chính là hồn thứ hai của Thất Thải Thiên Tôn — hồn chứa ý cảnh và bổn nguyên lự"},{"id":"ta-thanh","name":"Tạ Thanh","cn":"谢青","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"La Thiên Tinh Vực","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tạ Thanh là nhị đệ tử của Vương Lâm, vì cầu đạo mà bái sư, được giao núi Hoành Vân trên Thanh Linh Tinh thuộc La Thiên và đã ngồi đó hơn tám trăm năm chờ sư tôn trở lại. Hắn chính là hồn thứ ba của Thất Thải Tiên Tôn chuyển thế luân hồi; sau khi gặp lại Vương Lâm, hắn tiết lộ thân phận thật, trao ba đạo phong ấn rồi mỉm cười qua đời. Vương Lâm an táng hắn bằng thu lan, thề nhất định sẽ làm hắn sống lại.","vaiTro":"Nhị đệ tử của Vương Lâm — hồn thứ ba của Thất Thải Tiên Tôn chuyển thế luân hồi","tinhCach":"Trung thành tuyệt đối với sư tôn, kiên nhẫn phi thường khi ngồi chờ tám trăm năm; tự nguyện xả thân vì đại cục, đối diện cái chết bình thản mỉm cười","tabs":{"diem":[{"text":"Vì cầu đạo mà bái Vương Lâm làm sư tôn, được nhận làm ký danh đệ tử và giao núi Hoành Vân","chuong":"@c0798"},{"text":"Ngồi trên đỉnh Hoành Vân Sơn hơn tám trăm năm chờ sư tôn, chỉ tu ý cảnh thuần túy — không nguyên thần, không nguyên anh","chuong":"@c1389"},{"text":"Được xác nhận chính là hồn thứ ba của Thất Thải Tiên Tôn chuyển thế luân hồi","chuong":"@c1652"},{"text":"Tiết lộ thân phận thật với sư tôn, trao ba đạo phong ấn rồi tự nguyện mỉm cười qua đời","chuong":"@c1655"},{"text":"Được Vương Lâm bi ai an táng bằng thu lan và hứa nhất định sẽ làm sống lại","chuong":"@c1691"},{"text":"Phong ấn di nguyện phát huy tác dụng — ba đạo phong ấn ngưng tụ từ việc xả thân","chuong":"@c1690"}],"kinhLich":[{"chuong":"@c1388","importance":"normal","mucCt":"ky","tieuDe":"Lộ diện chờ sư tôn tám trăm năm","text":"Lão già mặc văn sam trên đỉnh Hoành Vân sơn, Thanh Linh Tinh, đã ngồi chờ sư tôn hơn tám trăm năm. Sư tôn từng nói cả đời không có đệ tử nhưng thu nhận hắn vì có duyên, chỉ cho một hồi cảm ngộ, cho Hoành Vân sơn làm chỗ tu luyện. Ra lệnh ba Anh Biến tu sĩ lui ra, tuyên bố tinh cầu là của sư tôn, không ai được lấy dù một cái cây ngọn cỏ. Khi nghe Lôi Tiên Điện sẽ trong ba ngày tới lấy tinh cầu, dùng ánh mắt chấn áp không cho nói thêm. Ngồi trong mưa lớn nhìn lên trời, tiếng thở dài từ thiên địa truyền tới cùng lời gọi tên hắn.","anchor":"Cả đời ta không có bất cứ một đệ tử nào, đạo của người cùng với ta có duyên"},{"chuong":"@c1389","importance":"normal","mucCt":"ky","tieuDe":"Gặp lại sư tôn Vương Lâm, được giảng đạo phản phác quy chân","text":"Ngồi suốt tám trăm năm trên Hoành Vân Sơn, tu hồn — chỉ tu ý cảnh thuần túy, không có nguyên thần, nguyên anh, nội thần, thân thể cực yếu nhưng sức sống vô biên tràn ngập hồn phách. Ý cảnh đạt Tịnh Niết, sơ khuy quy tắc. Bị Vương Lâm chỉ ra vẫn chưa bỏ hết thần thông do vô thức thi triển tiểu pháp thuật chặn mưa. Được sư tôn giảng lý phản phác quy chân và dặn khi nào bỏ được thân thể, quên hết pháp thuật, chỉ còn hồn phách thì hãy tới tìm. Quỳ dập đầu ba lần tiễn sư tôn rời đi.","anchor":"tu vi của hắn có thể nói là tăng một cách đột biến"},{"chuong":"@c1440","importance":"bridge","mucCt":"gon","text":"Trên Thanh Linh Tinh, tin sư tôn Vương Lâm còn sống.","anchor":"Tạ Thanh trên Thanh Linh Tinh, bọn họ tin rằng sư tôn vẫn còn sống!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Sư tôn (hàm ý rất mạnh)","ghiChu":"Sư tôn nói cả đời không có đệ tử nhưng thu nhận hắn vì có duyên, chỉ cho một hồi cảm ngộ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1388","@c1389","@c1440"]},{"id":"than-cong-ho","name":"Thân Công Hổ","cn":"申公虎","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1388","importance":"bridge","mucCt":"gon","text":"Được Chiến Không Liệt nhắc tới, hai người mâu thuẫn ngày càng kịch liệt những năm gần đây.","anchor":"Nhớ tới Thân Công Hổ, Chiến Không Liệt khẽ hừ một tiếng"}],"diem":[{"text":"Bị uy thế Vương Lâm chấn nhiếp tại Lôi Ngục, quỳ dâng đạo hồn xin nương tựa, chính thức trở thành tuỳ tùng","chuong":"@c0681"},{"text":"Tham chiến vây công quái nhân tóc bạc bằng phi kiếm mang lôi quang, gọi Tôn chủ ra tay","chuong":"@c0740"},{"text":"Kiên quyết tiến cử Hứa Mộc có tư cách tranh đệ nhất nhân La Thiên Tinh Vực","chuong":"@c0808"},{"text":"Từ chối bước vào Thăng Tiên trì, giữ con đường tu đạo bản thân thay vì đổi ý cảnh thành tiên nguyên","chuong":"@c0826"},{"text":"Đạo niệm được Vương Lâm giao lại cho Thân Công lão tổ","chuong":"@c0863"},{"text":"Quyết định chuyển thế đầu thai, tới bên cạnh Vương Lâm trước khi rời đi","chuong":"@c1694"}]},"nguon":["@c1388"],"vaiTro":"Tuỳ tùng trung thành của Vương Lâm — Nhị cấp sứ giả Lôi Tiên Điện, người Thân Công tộc nam vực La Thiên","tinhCach":"biết nắm thời cơ nương tựa cường giả, dâng đạo hồn quy phục không do dự; sùng kính Vương Lâm đến mức cuồng nhiệt, lấy đó làm tín niệm tu hành; kiên định với con đường tu đạo bản thân, từ chối cơ duyên đổi ý cảnh; phản ứng nhanh nhạy khi lâm nguy","blurb":"Thân Công Hổ là tu sĩ Thân Công tộc ở nam vực La Thiên, Nhị cấp sứ giả Lôi Tiên Điện, tự xưng tu vi Dương Thật. Sau khi bị uy thế Vương Lâm áp chế tại Lôi Trì trong Lôi Ngục, hắn dâng đạo hồn xin nương tựa, từ đó trở thành tuỳ tùng trung thành, nhiều lần theo Vương Lâm quan chiến và tham chiến qua các biến cố từ Lôi Tiên Giới sụp đổ đến tranh đoạt phong hào Nam vực. Hắn kiên quyết giữ con đường tu đạo bản thân khi từ chối bước vào Thăng Tiên trì, và cuối cùng quyết định chuyển thế đầu thai, tới bên cạnh Vương Lâm trước khi rời đi."},{"id":"lao-to-huong-gia","name":"Lão tổ Hướng gia","aliases":["Đông Lâm Thái","lão tổ Diêu Gia","lão tổ Hướng gia"],"tabs":{"kinhLich":[{"mucCt":"ky","text":"Nằm trong quan tài màu vàng đất giữa biển đầu lâu sâu dưới lòng đất vùng cực tây Đông Lâm Tinh. Hai lão già hắc y báo cáo đã bố trí xong, chờ Vương Lâm tới. Nhận định sinh cơ Vương Lâm năm đó rất hợp, có thể giúp hắn trở lại rất lâu. Cho rằng Lỗ Phu Tử phóng đại về Vương Lâm, Lỗ chỉ muốn mượn Vương Lâm dò xét suy đoán. Khẳng định không đáng ngại, nhưng không nhận ra Vương Lâm đã tới tinh không bên ngoài.","anchor":"Sinh cơ của người này năm đó tốt lắm, rất hợp","bridge":true,"khoang":"@c1390"},{"importance":"major","mucCt":"vua","chuong":"@c1391","tieuDe":"Bị Vương Lâm đến Đông Lâm Tinh chỉ đích danh đòi nợ","text":"Bị Vương Lâm chỉ đích danh kêu ra đối diện. Năm xưa dùng Thất Tịch Thuật lừa gạt Vương Lâm, cướp toàn bộ sức sống dưới danh nghĩa cứu Lý Mộ Uyển. Vương Lâm phát tiếng rống kinh thiên chấn động toàn Đông Lâm Tinh nhưng lão tổ không xuất hiện, Vương Lâm tuyên bố sẽ tự lôi ra.","anchor":"Tại sao lão tổ Hướng gia kia lại lừa gạt mình, lấy danh nghĩa cứu sống Lý Mộ Uyển, cướp đi toàn bộ sức sống của mình"},{"importance":"normal","mucCt":"ky","chuong":"@c1393","tieuDe":"Ngồi dậy từ quan tài, tuyên bố Viễn cổ chiếu","text":"Gào lên lệnh tử chiến đến cùng, khiến toàn bộ tộc nhân Hướng gia và Hứa gia đồng thời mất lý trí, hai mắt đỏ bừng, điên cuồng lao tới Vương Lâm. Quan tài phun chất lỏng vàng nhầy nhụa kèm tử khí tấn công Vương Lâm nhưng bị phá tan. Cánh tay khô héo vịn thành quan tài, đọc Viễn cổ chiếu viết — tuyên bố người hủy diệt Đông Lâm Tinh bị tru di cửu tộc. Giãy giụa ngồi dậy từ trong quan tài, chuẩn bị đối đầu trực tiếp Vương Lâm.","anchor":"Viễn cổ chiếu viết, người hủy diệt Đông Lâm Tinh, tru di cửu tộc"},{"chuong":"@c1394","importance":"normal","mucCt":"ky","tieuDe":"Lộ thân phận Đông Lâm Thái, bị Vương Lâm giết","text":"Hiện nguyên hình với thân thể khô gầy thối rữa, trái tim đỏ sẫm đập phát tử khí, tu vi Thiên Nhân Đệ Ngũ Suy. Thi triển Thất Tịch Thuật nghịch chuyển tử khí thành sức sống nhưng bị Vương Lâm tung hai chỉ phá nát tứ chi, túm thiên linh triển khai Sưu Hồn Thuật. Lộ thân phận thật: tên Đông Lâm Thái, tộc nhân phân hệ gia tộc Đông Lâm, gào lên Vương Lâm hủy Đông Lâm Tinh đồ sát mấy vạn tộc nhân vi phạm chiếu viết, dọa tru di cửu tộc. Cuối cùng bị Vương Lâm nổ đầu chết.","anchor":"lão phu chính là tộc nhân phân hệ của gia tộc Đông Lâm, lão phu là Đông Lâm Thái"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ thù — bị Vương Lâm phá tứ chi, Sưu Hồn, nổ đầu giết chết","ghiChu":"@c1394"}],"tuViMoc":[{"chuong":"@c1394","canhGioi":"Thiên Nhân Đệ Ngũ Suy","text":"Tu vi ở mức Thiên Nhân Đệ Ngũ Suy, thân thể thối rữa như thi thể, cần Thất Tịch Thuật nghịch chuyển tử khí","importance":"major"}],"diem":[{"text":"Tới dự khán trận tranh đoạt phong tiên, kinh động trước Phong Tiên Thạch và nhắc tới truyền thuyết người lưu danh có thể được đưa vào Viễn Cổ Tiên Vực","chuong":"@c0813"},{"text":"Trên Tham Thiên Cự Mộc hỗ trợ đẩy cự mộc xông vào liên minh, cùng nam tử họ Côn tham chiến","chuong":"@c0860"},{"text":"Bị Vương Lâm đến Đông Lâm Tinh chỉ đích danh đòi nợ vì năm xưa dùng Thất Tịch Thuật lừa gạt, cướp toàn bộ sức sống của Vương Lâm","chuong":"@c1391"},{"text":"Gào lên lệnh Viễn cổ chiếu, phát động tử chiến khiến toàn bộ tộc nhân Hướng gia và Hứa gia mất lý trí, hai mắt đỏ bừng","chuong":"@c1393"},{"text":"Lộ thân phận thực sự là Đông Lâm Thái, tu vi Thiên Nhân Đệ Ngũ Suy với thân thể khô gầy thối rữa, cuối cùng bị Vương Lâm giết","chuong":"@c1394"}]},"nguon":["@c1390","@c1391","@c1393","@c1394","@c1395"],"gioiTinh":"nam","trangThai":"tu-vong","cn":"东林太","canhGioiCaoNhat":"Thiên Nhân Đệ Ngũ Suy","vaiTro":"Lão tổ Hướng gia — thực chất là Đông Lâm Thái, kẻ từng lừa gạt Vương Lâm","tinhCach":"thâm trầm mưu kế, dùng Thất Tịch Thuật lừa gạt cướp đoạt sức sống người khác; hung hãn liều chết, sẵn sàng phát lệnh tử chiến khi bị dồn đường cùng","blurb":"Lão tổ Hướng gia là lão quái ẩn cư dưới lòng đất vùng cực tây Đông Lâm Tinh, thân phận thực sự là Đông Lâm Thái, tu vi đạt Thiên Nhân Đệ Ngũ Suy nhưng thân thể đã thối rữa. Năm xưa hắn từng dùng Thất Tịch Thuật lừa gạt Vương Lâm, cướp toàn bộ sức sống, và cuối cùng bị Vương Lâm tìm đến Đông Lâm Tinh chỉ đích danh đòi nợ rồi giết chết.","theLuc":[{"ten":"Gia tộc Đông Lâm","trangThai":"gan-bo"},{"ten":"Hướng gia","trangThai":"gan-bo"}]},{"id":"hai-lao-gia-hac-y-huong-gia","name":"Hai lão già hắc y (Hướng gia)","gioiTinh":"nam","theLuc":[{"ten":"Hướng gia","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Hai nhân vật cấp cao của Hướng gia, vào vùng cực tây báo cáo lão tổ đời đầu. Coi lão tổ là trời, nội tâm chấn động bởi tin về Vương Lâm nhưng bình tĩnh lại sau lời lão tổ.","vaiTro":"Thuộc hạ cấp cao Hướng gia, liên lạc với lão tổ đời đầu","tinhCach":"Trung thành tuyệt đối với lão tổ; dễ bị dao động nhưng nhanh trấn tĩnh","aliases":[],"tabs":{"diem":[{"text":"Coi lão tổ Hướng gia là trời, bình tĩnh lại ngay sau lời trấn an của lão tổ","chuong":"@c1390"}],"kinhLich":[{"mucCt":"gon","text":"Vào vùng cực tây Đông Lâm Tinh báo cáo lão tổ rằng mọi bố trí đã hoàn tất, chờ Vương Lâm tới.","anchor":"Lão tổ, tất cả đã bố trí theo ý của người rồi, chỉ còn chờ Vương Lâm tới mà thôi","bridge":true,"khoang":"@c1390"},{"mucCt":"vua","text":"Hai lão già áo đen ở cực tây Đông Lâm Tinh bị tiếng rống Vương Lâm đánh lảo đảo lùi trăm trượng phun máu. Một người thân thể trực tiếp tan vỡ chết, người còn sống hoảng sợ cực độ rút ngọc giản đen ra lệnh toàn Đông Lâm Tinh bày trận bất chấp mọi giá ngăn Vương Lâm tiến vào.","anchor":"Bày trận! Bất chấp tất cả mọi giá phải ngăn người này tiến vào Đông Lâm Tinh!","bridge":true,"khoang":"@c1391"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão tổ Hướng gia","tag":"cap-tren","quanHe":"Lão tổ đời đầu của Hướng gia, coi là trời"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1390","@c1391"]},{"id":"ly-mo-uyen","name":"Lý Mộ Uyển","cn":"李慕婉","gioiTinh":"nu","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1391","text":"Được Vương Lâm nhắc lại toàn bộ quá trình năm xưa bị lão tổ Hướng gia lừa gạt cướp sức sống khiến nàng hồn bay phách tán, và nhận ra nếu có sức sống mãnh liệt đưa vào đúng lúc thì nàng vẫn có cơ hội sống lại.","anchor":"trên thực tế khi Vương Lâm nhìn lại sau này, rõ ràng chính là một trong những nguyên nhân quan trọng nhất khiến cho Lý Mộ Uyển hồn bay phách tán"},{"importance":"bridge","mucCt":"gon","chuong":"@c1421","tieuDe":"Được nhắc tới trong lời trải lòng của Mộc Băng Mi","text":"Vương Lâm đánh một quyền vì Lý Thiến Mai. Mộc Băng Mi nhờ nói với Bình Nhi rằng Lý Mộ Uyển mới là mẫu thân. Đạo Cổ Hóa Mệnh Thuật đối với Lý Mộ Uyển vô dụng.","anchor":"Thuật này đối với Lý Mộ Uyển vô dụng nhưng trong giờ phút này lại có thể đem toàn bộ sinh cơ của Thủy Đạo Tử nhanh chóng chuyển cho Mộc Băng Mi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Bị Song Tu Môn truy sát vì Thiên Ly đan, được Vương Lâm cứu giúp, mở đầu mối duyên giữa hai người","chuong":"@c0123"},{"text":"Trong bốn năm đồng hành tại Tu Ma Hải, khắc 18.974 ngọc giản đan phương, thể hiện thiên phú luyện đan phi phàm","chuong":"@c0135"},{"text":"Ba lần Kết Anh thất bại, thọ nguyên cạn kiệt không quá mười năm, thân xác suy kiệt tang thương","chuong":"@c0302"},{"text":"Thân xác hóa xương khô, kim đan nứt vỡ, nguyên anh nhờ bức tranh Sinh Tử Luân Hồi đầu thai thành Chu Như","chuong":"@c0313"},{"text":"Từ chối cắn nuốt hồn phách Chu Như, tự đẩy nguyên anh ra khỏi thân thể để cứu cô bé, hy sinh cơ hội tái sinh","chuong":"@c0381"},{"text":"Tàn hồn được phát hiện dung nhập trong thân Tống Trí, Vương Lâm dùng một năm phân tách tàn hồn ra, nhưng hồn phách vẫn thiếu một phần chưa rõ tung tích","chuong":"@c0929"}]},"nguon":["@c1391","@c1421"],"trangThai":"song","aliases":["Lý Thiến Mai"],"vaiTro":"Nhân vật nữ chính — thê tử Vương Lâm, tu sĩ tài hoa luyện đan và trận pháp","tinhCach":"Tài hoa xuất chúng về luyện đan và trận pháp; kiên cường chịu đựng trước thọ nguyên cạn kiệt và ba lần Kết Anh thất bại; nặng tình sâu sắc với Vương Lâm; giàu lòng trắc ẩn, tự từ bỏ cơ hội tái sinh để cứu Chu Như","blurb":"Lý Mộ Uyển là tu sĩ Kết Đan hậu kỳ, nổi bật với thiên phú luyện đan và trận pháp, từng bị Song Tu Môn truy sát vì Thiên Ly đan rồi được Vương Lâm cứu giúp, cùng hắn trải qua bốn năm đồng hành tại Tu Ma Hải. Sau hơn trăm năm, ba lần Kết Anh thất bại khiến thọ nguyên cạn kiệt, thân xác hóa xương khô, nguyên anh nhờ bức tranh Sinh Tử Luân Hồi đầu thai thành bé gái Chu Như nhưng cuối cùng nàng tự đẩy nguyên anh ra để cứu Chu Như, rồi được Vương Lâm gìn giữ nguyên anh suốt hàng trăm năm. Tới mốc sau cùng, tàn hồn nàng được phát hiện dung nhập trong thân Tống Trí và được Vương Lâm dùng một năm phân "},{"id":"lao-gia-kim-bao-dong-lam","name":"Lão già mặc kim bào (Đông Lâm gia)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Gia tộc Đông Lâm","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nửa bước thứ ba","trangThai":"song","vaiTro":"Tu sĩ gia tộc Đông Lâm, nửa bước thứ ba, bị Vương Lâm trọng thương","blurb":"Tu sĩ gia tộc Đông Lâm mặc kim bào, tu vi nửa bước thứ ba. Thi triển Huyễn Thần Thuật tạo người khổng lồ kim giáp cao mấy ngàn trượng tuyên đọc ba tội trạng của Vương Lâm, bị Vương Lâm phá tan Huyễn Thần Thuật và trọng thương.","tinhCach":"Cứng rắn chấp hành luật gia tộc; biết tiến biết lui khi nhận ra khoảng cách thực lực","tabs":{"diem":[{"text":"Thi triển Huyễn Thần Thuật tạo người khổng lồ kim giáp ngàn trượng tuyên tội Vương Lâm, bị phá tan và trọng thương","chuong":"@c1394"},{"text":"Tu vi nửa bước thứ ba, một trong hai tu sĩ Đông Lâm gia thức tỉnh","chuong":"@c1394"}],"kinhLich":[{"mucCt":"ky","text":"Bước ra từ cánh cửa vàng gia tộc Đông Lâm, thi triển Huyễn Thần Thuật tạo người khổng lồ kim giáp cao mấy ngàn trượng, tuyên đọc ba tội trạng của Vương Lâm (lăng trì, diệt hồn, tày trời — hợp lại tru di cửu tộc), vung đại kiếm vàng ngàn trượng chém xuống. Bị Vương Lâm một chỉ phá tan đại kiếm, huyết kiếm đâm xuyên phá vỡ Huyễn Thần Thuật, bức lộ bản thể và trọng thương phun máu. Sau khi Vương Lâm rời đi, ôm quyền tuyên bố sẽ báo lại trưởng lão trong tộc.","anchor":"Các hạ tu vi cao thâm khó lường, lão phu không có khả năng ngăn cản","bridge":true,"khoang":"@c1394"}],"tuViMoc":[{"chuong":"@c1394","canhGioi":"Nửa bước thứ ba","text":"Tu vi nửa bước thứ ba, vượt Thiên Nhân Đệ Ngũ Suy","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ — tuyên tội Vương Lâm nhưng bị phá Huyễn Thần Thuật trọng thương","ghiChu":"@c1394"},{"ten":"Nam tử trung niên mặc kim bào (Đông Lâm gia)","tag":"dong-minh","quanHe":"Đồng tộc — cùng là tu sĩ Đông Lâm gia thức tỉnh","ghiChu":"@c1394"},{"ten":"Thần trưởng lão (Đông Lâm gia)","tag":"cap-tren","quanHe":"Trưởng lão trong tộc — cung kính nghênh đón xuất quan","ghiChu":"@c1394"}],"tuiDo":{}},"nguon":["@c1394"]},{"id":"nam-tu-trung-nien-dong-lam","name":"Nam tử trung niên mặc kim bào (Đông Lâm gia)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Gia tộc Đông Lâm","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nửa bước thứ ba","trangThai":"song","vaiTro":"Tu sĩ thứ hai của Đông Lâm gia thức tỉnh, tu công pháp kỳ dị cảm nhận khí tức","blurb":"Tu sĩ gia tộc Đông Lâm mặc kim bào, tu vi nửa bước thứ ba, tu luyện công pháp kỳ dị có thể cảm nhận khí tức đặc biệt. Phát hiện trên người Vương Lâm có hai luồng khí tức cao thủ bước thứ ba, nhận định Vương Lâm chỉ lộ một phần nhỏ thực lực nên không dám ra tay.","tinhCach":"Thận trọng, lý trí; biết lượng sức so tài","tabs":{"diem":[{"text":"Cảm nhận được trên người Vương Lâm có hai luồng khí tức cao thủ bước thứ ba, nhận định thực lực chỉ mới lộ một phần nhỏ","chuong":"@c1394"},{"text":"Tiết lộ lão tổ Đông Lâm trước khi bế quan từng tiên tri kiếp nạn gia tộc","chuong":"@c1394"}],"kinhLich":[{"mucCt":"vua","text":"Bước ra từ cánh cửa vàng sau khi Vương Lâm rời đi, tiết lộ tu công pháp kỳ dị cảm nhận được trên người Vương Lâm có hai luồng khí tức cao thủ bước thứ ba, thực lực chỉ mới lộ một phần nhỏ. Cho biết lão tổ Đông Lâm trước khi bế quan từng nói Đông Lâm Tinh bị hủy là kiếp nạn gia tộc, tộc nhân rất ít chỉ có hai người thức tỉnh.","anchor":"Ở trên người hắn ta còn cảm nhận được hai luồng khí tức của cao thủ bước thứ ba","bridge":true,"khoang":"@c1394"}],"tuViMoc":[{"chuong":"@c1394","canhGioi":"Nửa bước thứ ba","text":"Tu vi nửa bước thứ ba, tương đương lão già kim bào","importance":"major"}],"nhanMach":[{"ten":"Lão già mặc kim bào (Đông Lâm gia)","tag":"dong-minh","quanHe":"Đồng tộc — cùng là tu sĩ Đông Lâm gia thức tỉnh","ghiChu":"@c1394"},{"ten":"Thần trưởng lão (Đông Lâm gia)","tag":"cap-tren","quanHe":"Trưởng lão trong tộc — cung kính nghênh đón xuất quan","ghiChu":"@c1394"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ gián tiếp — nhận định Vương Lâm quá mạnh không thể giữ","ghiChu":"@c1394"}],"tuiDo":{}},"nguon":["@c1394"]},{"id":"than-truong-lao-dong-lam","name":"Thần trưởng lão (Đông Lâm gia)","cn":"","aliases":["Nữ Cổ Thần thất tinh"],"gioiTinh":"nu","theLuc":[{"ten":"Gia tộc Đông Lâm","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Cổ Thần thất tinh","trangThai":"song","vaiTro":"Thần trưởng lão gia tộc Đông Lâm, nữ tử mang huyết mạch Cổ Thần, vừa xuất quan","blurb":"Nữ tử dung mạo xinh đẹp tuyệt trần, bị đóng băng cùng đại lục trong thế giới đóng băng phía sau cánh cửa vàng gia tộc Đông Lâm. Mi tâm hiện tinh điểm xoay tròn phát ra khí tức Cổ Thần, cho thấy mang huyết mạch hoặc truyền thừa Cổ Thần. Được hai tu sĩ kim bào cung kính nghênh đón xuất quan.","tinhCach":"Chưa rõ — vừa mới mở mắt xuất quan","tabs":{"diem":[{"text":"Mi tâm hiện tinh điểm xoay tròn phát khí tức Cổ Thần — mang huyết mạch/truyền thừa Cổ Thần","chuong":"@c1394"},{"text":"Bị đóng băng cùng đại lục bên trong thế giới đóng băng gia tộc Đông Lâm, vừa xuất quan","chuong":"@c1394"}],"kinhLich":[{"chuong":"@c1394","importance":"normal","mucCt":"vua","tieuDe":"Xuất quan từ thế giới đóng băng Đông Lâm gia","text":"Bất ngờ mở mắt trong thế giới đóng băng hoàn toàn phía sau cánh cửa vàng gia tộc Đông Lâm, mi tâm hiện tinh điểm xoay tròn phát ra khí tức Cổ Thần. Được hai tu sĩ kim bào cung kính nghênh đón xuất quan, gọi là Thần trưởng lão.","anchor":"trên mi tâm của nàng không ngờ có những tinh điểm lần lượt hiện ra, chậm rãi xoay tròn, một khí tức Cổ Thần tràn ngập"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già mặc kim bào (Đông Lâm gia)","tag":"dong-minh","quanHe":"Đồng tộc — tu sĩ Đông Lâm gia cung kính nghênh đón","ghiChu":"@c1394"},{"ten":"Nam tử trung niên mặc kim bào (Đông Lâm gia)","tag":"dong-minh","quanHe":"Đồng tộc — tu sĩ Đông Lâm gia cung kính nghênh đón","ghiChu":"@c1394"}],"tuiDo":{}},"nguon":["@c1394","@c1395"]},{"id":"tay-tu-phuong","name":"Tây Tử Phượng","cn":"西紫凤","aliases":[],"gioiTinh":"nu","canhGioiCaoNhat":"Khuy Niết","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1395","importance":"major","mucCt":"ky","tieuDe":"Tái xuất bi thương, gia tộc diệt vong, tự hủy dung nhan","text":"Tái xuất với thân phận nữ tu trung niên trong đội trăm người ở tinh vực phía nam La Thiên Tinh Vực. Gia tộc Tây gia gần diệt vong sau đại chiến liên minh, lão tổ chết vì cứu nàng trên Chu Tước Tinh. Sau chiến tranh trở thành kẻ không nhà, tự hủy dung nhan để lại vết sẹo đỏ sẫm không thể xóa nhằm tránh bị quấy rối. Tu vi chỉ gần Dương Thực. Suốt tám trăm năm dựa vào ký ức về Vương Lâm trong Lôi Tiên Giới — phong tiên, trở thành lôi tiên — mà có dũng khí sống tiếp. Hiện bị nam tử trung niên sứ giả Khuy Niết trung kỳ ép dùng nguyên thần rung chuyển tu chân tinh dù nguyên thần chưa hồi phục.","anchor":"Nàng tự mình phá hủy dung nhan, xóa đi hết thảy những ánh mắt thèm muốn."},{"chuong":"@c1396","importance":"normal","mucCt":"ky","tieuDe":"Di tinh thất bại, tái ngộ Vương Lâm","text":"Tây Tử Phượng hai lần tách nguyên thần dùng thần thức lay chấn tu chân tinh để di tinh nhưng đều thất bại, nguyên thần trọng thương, phun máu. Bị sứ giả Lôi Tiên Điện khinh miệt gọi là phế vật. Nhận đan dược từ lão già Khuy Niết, cảm thán tám trăm năm qua thế giao Tây gia chẳng bằng những người được Vương Lâm cứu. Khi Vương Lâm xuất hiện gọi tên nàng, nước mắt trào ra chảy qua vết sẹo, nàng phủ nhận danh tính, cắn môi lùi lại, không muốn Vương Lâm thấy mình xấu xí chật vật.","anchor":"Nàng thà cả đời cô độc già đi, đến khi chết đi cũng không muốn dưới tình huống này, khi bản thân đang vô cùng chật vật, với vé mặt xấu xí này mà để người đó nhìn thấy"},{"chuong":"@c1397","importance":"normal","mucCt":"vua","tieuDe":"Thương thế nguyên thần bị phơi bày","text":"Nguyên thần bị thương nhiều lần thành tật, gần đây lại bị sứ giả Lôi Tiên Điện làm khó khiến thêm một lần bị thương nặng. Trước mặt Vương Lâm, nàng càng lúc càng cúi đầu lùi lại, thể hiện sự yếu đuối xấu hổ.","anchor":"nguyên thần bị thương nhiều lần để lại, đã trớ thành tật"},{"chuong":"@c1398","importance":"major","mucCt":"ky","tieuDe":"Bái Vương Lâm làm sư tôn, tu vi bạo tăng lên Tinh Tịnh Niết","text":"Được Vương Lâm chữa lành thương thế và khôi phục dung nhan diễm lệ, vết sẹo tự hủy tám trăm năm trước tiêu tan. Xúc động rơi lệ khi sờ lên gương mặt nhẵn nhụi. Được mời làm đệ tử thứ ba, sau hồi trầm mặc nở nụ cười nhu hòa, quỳ xuống tuyết bái sư, cắt đứt tình cảm tám trăm năm chấp nhận quan hệ sư đồ. Nói nhà mình ở La Thiên. Được Vương Lâm truyền nguyên lực vô biên kèm một phần cảm ngộ cả đời, tu vi đột phá Dương Thực, vượt Khuy Niết, đạt Tinh Tịnh Niết, bị đặt ba đạo phong ấn áp chế để từ từ tiêu hóa.","anchor":"Nàng quỳ trên tuyết, thấp giọng nói: - Đệ tử bái kiến sư tôn"},{"chuong":"@c1399","importance":"major","mucCt":"ky","tieuDe":"Nhận huyết kiếm bản mệnh, Vương Lâm báo thù tám trăm năm nhục nhã","text":"Nhận huyết kiếm từ Vương Lâm, kiếm dung nhập cơ thể thành bản mệnh pháp bảo. Yên lặng ngẩng đầu nhìn Vương Lâm rời đi, trong mắt ẩn tình cảm chôn giấu tám trăm năm. Hồi tưởng những hình ảnh oai vệ của hắn trên mảnh vỡ đại lục Lôi Tiên Giới dẫn tu sĩ xông ra, trận chiến Phong Tiên trấn áp quần hùng. Tự nhủ kết cục này có lẽ là tốt nhất. Qua ký ức được hé lộ: tám trăm năm chịu đủ nỗi nhục — bị gia chủ Triệu gia bắt làm lô đinh, bị đại trưởng lão gia tộc Đông Lai ép lấy pháp bảo tối hậu lão tổ khiến tự hủy dung nhan, bị thiếu tộc trưởng Lô gia và nhiều kẻ khác mạo phạm. Vương Lâm phóng gần trăm đạo kiếm khí quét ngang La Thiên giết hết tất cả kẻ từng làm nhục nàng.","anchor":"Trong mắt nàng ẩn chứa một tình cảm đã chôn giấu suốt tám trăm nãm"},{"chuong":"@c1440","importance":"bridge","mucCt":"vua","text":"Ở La Thiên Tinh Vực, tin sư tôn Vương Lâm còn sống, trầm mặc nhìn tinh không.","anchor":"Tây Tử Phượng ở La Thiên, Tạ Thanh trên Thanh Linh Tinh, bọn họ tin rằng sư tôn vẫn còn sống!"}],"tuViMoc":[{"chuong":"@c1398","canhGioi":"Khuy Niết","text":"Được Vương Lâm truyền công, tu vi đột phá Dương Thực trực tiếp đạt Khuy Niết.","importance":"major"},{"chuong":"@c1398","canhGioi":"Tinh Tịnh Niết","text":"Tu vi tiếp tục bạo tăng sau Khuy Niết, đạt tới Tinh Tịnh Niết rồi mới dừng lại, bị đặt ba đạo phong ấn áp chế.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Người nàng từng ái mộ, tái ngộ sau tám trăm năm","ghiChu":"Phủ nhận danh tính trước mặt hắn vì tự ti dung mạo đã hủy"},{"ten":"Sứ giả Lôi Tiên Điện (nam tử trung niên)","tag":"doi-thu","quanHe":"Sứ giả cấp trên tại Lôi Tiên Điện","ghiChu":"Mắng nàng là phế vật, từng đưa yêu cầu bị nàng từ chối"},{"ten":"Lão già Khuy Niết","tag":"dong-minh","quanHe":"Người cùng phục vụ Lôi Tiên Điện, bênh vực nàng","ghiChu":"Tặng đan dược trân quý chữa thương"},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Bái Vương Lâm làm sư tôn, cắt đứt tình cảm tám trăm năm @c1398"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người nàng đơn phương nhớ về suốt 800 năm từ thời Lôi Tiên Giới","ghiChu":"Hắn không biết nàng tồn tại"},{"ten":"Nam tử trung niên (sứ giả, Khuy Niết trung kỳ)","tag":"doi-thu","quanHe":"Kẻ ép buộc nàng rung chuyển tu chân tinh, từng theo đuổi nàng rồi ghê tởm vì dung nhan bị hủy","ghiChu":""},{"ten":"Lão già Khuy Niết","tag":"an-nhan","quanHe":"Người từng được Vương Lâm cứu, bênh vực nàng","ghiChu":"Tặng đan dược trân quý, dùng uy danh Vương Lâm trấn áp sứ giả"},{"ten":"Lão già Khuy Niết sơ kỳ (Lôi Tiên Điện)","tag":"an-nhan","quanHe":"Người tặng đan dược và bênh vực nàng trước sứ giả","ghiChu":"Từng được Vương Lâm mang ra khỏi Lôi Tiên Giới, vì ân tình đó mà giúp nàng"},{"ten":"Sứ giả trung niên Lôi Tiên Điện","tag":"doi-thu","quanHe":"Cấp trên bức bách, mắng nàng là phế vật","ghiChu":"Từng gợi ý yêu cầu liên quan dung mạo, bị nàng từ chối"}],"tuiDo":{},"diem":[{"text":"Gặp Vương Lâm giữa Lôi Tiên Giới sụp đổ, cung kính cảm tạ ân cứu mạng hai lần","chuong":"@c0750"},{"text":"Đau lòng rơi lệ khi phát hiện Vương Lâm tranh phong tiên vì Lý Mộ Uyển","chuong":"@c0826"},{"text":"Tái xuất sau tám trăm năm với gia tộc diệt vong, dung nhan tự hủy giữ khí tiết","chuong":"@c1395"},{"text":"Được Vương Lâm chữa thương, khôi phục dung mạo, truyền công đạt Tinh Tịnh Niết và chính thức bái sư tôn","chuong":"@c1398"},{"text":"Nhận huyết kiếm bản mệnh từ Vương Lâm, sẵn sàng rửa nhục tám trăm năm","chuong":"@c1399"},{"text":"Xin Vương Lâm cho một năm ở bên cạnh, lặng lẽ đồng hành trong đại chiến giới ngoại","chuong":"@c1573"}]},"nguon":["@c1395","@c1396","@c1397","@c1398","@c1399","@c1440"],"theLuc":[{"ten":"Lôi Tiên Điện","trangThai":"gan-bo"}],"vaiTro":"Nữ tu sĩ trọng tình, từng được Vương Lâm nhiều lần cứu giúp và sau bái hắn làm sư tôn","tinhCach":"biết cảm ân, cung kính tạ ơn và trung thành với ân nhân; trọng tình cảm, nhiều lần rung động trước Vương Lâm nhưng âm thầm chịu đựng; kiên cường chịu nhục, tự hủy dung nhan để giữ khí tiết; dễ tự ti trước khoảng cách thân phận","blurb":"Tây Tử Phượng là nữ tu sĩ lần đầu gặp Vương Lâm trong biến cố Lôi Tiên Giới sụp đổ, được hắn hai lần cứu mạng rồi mang theo tình cảm thầm kín qua cuộc tranh phong tiên tại Lôi Tiên Điện, nơi nàng chứng kiến hắn tranh đoạt vì Lý Mộ Uyển mà đau lòng rơi lệ. Tám trăm năm sau, nàng tái xuất với gia tộc đã bị diệt, dung nhan tự hủy thành vết sẹo, được Vương Lâm chữa lành thương thế, khôi phục dung mạo, truyền công cho tu vi bạo tăng tới Tinh Tịnh Niết, rồi chính thức bái hắn làm sư tôn và nhận huyết kiếm bản mệnh để rửa nhục. Trong đại chiến giới ngoại, nàng xin được ở bên cạnh Vương Lâm một năm và"},{"id":"nam-tu-trung-nien-su-gia","name":"Nam tử trung niên (sứ giả, Khuy Niết trung kỳ)","cn":"","aliases":[],"gioiTinh":"nam","vaiTro":"Sứ giả dẫn đầu tiểu đội, ép Tây Tử Phượng làm việc nguy hiểm","tinhCach":"Cao ngạo; tàn nhẫn; từng theo đuổi Tây Tử Phượng nhưng ghê tởm khi nàng hủy dung nhan","blurb":"Nam tử trung niên tu vi Khuy Niết trung kỳ, dẫn đầu tiểu đội trăm tu sĩ ở phía nam La Thiên Tinh Vực. Ép Tây Tử Phượng dùng nguyên thần rung chuyển tu chân tinh dù nàng chưa hồi phục.","canhGioiCaoNhat":"Khuy Niết trung kỳ","trangThai":"tu-vong","theLuc":[],"tabs":{"diem":[{"text":"Thần sắc cao ngạo, từng theo đuổi Tây Tử Phượng nhưng vì nàng hủy dung nhan mà ghê tởm","chuong":"@c1395"}],"kinhLich":[{"chuong":"@c1395","importance":"normal","mucCt":"gon","tieuDe":"Ép Tây Tử Phượng dùng nguyên thần rung chuyển tu chân tinh","text":"Dẫn đầu đội trăm tu sĩ, tu vi Khuy Niết trung kỳ. Ép Tây Tử Phượng dùng nguyên thần rung chuyển tu chân tinh dù biết nàng đã thương tổn.","anchor":"Nam tử trung niên này tu vi đã đạt tới Khuy Niết trung kỳ, lời nói ra ẩn chứa một khí phách uy nghiêm không thể nghi ngờ."},{"chuong":"@c1397","importance":"normal","mucCt":"ky","tieuDe":"Bị Vương Lâm tuyên án tử","text":"Bị Chu Tùng Vân tố cáo trước mặt Vương Lâm là kẻ hết lần này đến lần khác làm khó Tây Tử Phượng khiến nguyên thần nàng bị thương nghiêm trọng. Phản bác Chu Tùng Vân ngậm máu phun người, tự xưng hành động vì chuẩn bị chiến tranh cho La Thiên. Nhanh chóng lùi trăm trượng khi thấy nguy hiểm. Bị Vương Lâm tuyên án đáng chết vì tội làm nhục người con gái yếu đuối. Dùng đủ lý do gào xin: đe dọa bằng danh nghĩa Lôi Tiên Điện và tứ đại tinh vực liên thủ, xin cơ hội chết trên chiến trường chống giới ngoại, xin sống thêm trăm năm.","anchor":"Chu Tùng Vân, ngươi ngậm máu phun người! Ta thân là sứ giả của Lôi Tiên Điện"},{"chuong":"@c1398","importance":"normal","mucCt":"gon","tieuDe":"Bị Vương Lâm phất tay giết chết","text":"Cố dùng lời lẽ chính khí cầu xin tha mạng nhưng bị Vương Lâm nhìn thấu là hoa ngôn xảo ngữ, bị phất tay nổ tung tiêu tan.","anchor":"thân thể hắn chấn động, trong tiếng ầm ầm từ tất cả các vị trí trên thân thể đều phun ra máu tươi"}],"tuViMoc":[],"nhanMach":[{"ten":"Tây Tử Phượng","tag":"khac","quanHe":"Thuộc hạ / từng theo đuổi","ghiChu":"Từng theo đuổi Tây Tử Phượng, sau khi nàng hủy dung nhan thì ghê tởm, ép nàng làm việc nguy hiểm"}],"tuiDo":{}},"nguon":["@c1395","@c1397","@c1398"]},{"id":"to-tien-huong-gia","name":"Tổ tiên Hướng gia","cn":"","aliases":["Lão tổ Hướng gia"],"gioiTinh":"nam","trangThai":"tu-vong","tabs":{"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1395"]},{"id":"su-gia-loi-tien-dien","name":"Sứ giả Lôi Tiên Điện","cn":"","aliases":["Nam tử trung niên (sứ giả Lôi Tiên Điện)","Nam tử trung niên sứ giả Lôi Tiên Điện"],"gioiTinh":"nam","canhGioiCaoNhat":"Khuy Niết trung kỳ trở lên (vượt xa Khuy Niết sơ kỳ)","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1396","importance":"normal","mucCt":"vua","tieuDe":"Di tinh và bị Vương Lâm trấn áp","text":"Dùng thần thức hét một tiếng khiến tu chân tinh thoát quỹ đạo, chỉ huy gần trăm tu sĩ dùng tơ tằm bạc di tinh. Khinh miệt Tây Tử Phượng gọi là phế vật. Khi Vương Lâm xuất hiện, bị ánh mắt khóa chặt, thân thể mềm nhũn quỳ xuống, nghe tên Vương Lâm thì nguyên thần sụp đổ hồn phi phách tán.","anchor":"ngay cả nguyên thần cũng bị một câu nói này mà sụp đổ, linh hồn vì một cái tên này mà chia nãm sẽ bảy, hồn phi phách tán"},{"chuong":"@c1397","importance":"normal","mucCt":"ky","tieuDe":"Bị tố cáo và Vương Lâm tuyên án","text":"Bị Chu Tùng Vân tố cáo trước mặt Vương Lâm là kẻ hết lần này đến lần khác làm khó Tây Tử Phượng, khiến nguyên thần nàng bị thương nghiêm trọng. Hoảng sợ lui về phía sau trăm trượng, gào lên biện hộ rằng mọi việc là chuẩn bị chiến tranh cho La Thiên, tự nhận quen biết Tây Tử Phượng. Bị Vương Lâm tuyên bố đáng chết. Trong tuyệt vọng viện dẫn thân phận sứ giả Lôi Tiên Điện, đe dọa giết hắn sẽ thành kẻ địch của Lôi Tiên Điện, La Thiên, tứ đại tinh vực liên thủ. Xin được chết trên chiến trường chống giới ngoại, xin sống thêm trăm năm.","anchor":"Lúc hắn còn trẻ vốn đã nói năng rất giỏi, còn tự cho là rất sắc bén"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Tiền bối đáng sợ mà hắn ngưỡng mộ kiêm kính sợ","ghiChu":"Tự nhận so với Vương Lâm chẳng khác gì con kiến hôi"},{"ten":"Tây Tử Phượng","tag":"khac","quanHe":"Thuộc hạ tại Lôi Tiên Điện","ghiChu":"Mắng là phế vật, từng đưa yêu cầu bị từ chối"},{"ten":"Lão già Khuy Niết","tag":"khac","quanHe":"Tu sĩ Khuy Niết sơ kỳ trong đoàn","ghiChu":"Bênh vực Tây Tử Phượng, dùng uy danh Vương Lâm trấn áp hắn","nguon":"@c1396"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm quyết giết vì tội làm khó Tây Tử Phượng","ghiChu":"@c1397"}],"tuViMoc":[],"diem":[{"text":"Thoát khỏi ba tiểu kỳ liền định bỏ trốn, bị Vương Lâm chặn lại phải cầu xin tha mạng","chuong":"@c0765"},{"text":"Cùng các sứ giả Lôi Tiên Điện chuyển từ chống đối sang bội phục khi nhận ra tiếng trống không thể ngăn được","chuong":"@c0820"},{"text":"Đồng loạt xuất hiện trên bầu trời, đứng thẳng cung kính trong nghi lễ Phong Tiên","chuong":"@c0825"},{"text":"Dùng thần thức hét khiến tu chân tinh thoát quỹ đạo, chỉ huy gần trăm tu sĩ dùng tơ tằm bạc di tinh, bị Vương Lâm trấn áp","chuong":"@c1396"},{"text":"Bị Chu Tùng Vân tố cáo trước mặt Vương Lâm vì nhiều lần gây khó dễ cho Tây Tử Phượng, bị tuyên án","chuong":"@c1397"}]},"nguon":["@c1396","@c1397"],"vaiTro":"Nguyên thần sứ giả Lôi Tiên Điện — bị Vương Lâm khống chế và sai khiến","tinhCach":"tham sống sợ chết, khi thế cùng liền cầu xin tha mạng; ngạo mạn bướng bỉnh, nhiều lần gây khó dễ cho người dưới trướng Vương Lâm; biết thời thế, chuyển sang bội phục khi đối diện sức mạnh áp đảo","blurb":"Sứ giả của Lôi Tiên Điện chỉ còn nguyên thần, bị phong trong ba tiểu kỳ màu tím. Khi được giải phong, hắn tìm cách bỏ chạy rồi cầu xin Vương Lâm tha mạng, sau đó bị khống chế sai phái — từ cung kính tham dự nghi lễ Phong Tiên đến chỉ huy di chuyển tu chân tinh, nhưng rốt cuộc bị tố cáo vì nhiều lần làm khó thuộc hạ của Vương Lâm và bị tuyên án trấn áp.","theLuc":[{"ten":"Lôi Tiên Điện","trangThai":"gan-bo"}]},{"id":"lao-gia-khuy-niet","name":"Lão già Khuy Niết","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Lôi Tiên Điện","trangThai":"gan-bo"}],"vaiTro":"Tu sĩ Khuy Niết sơ kỳ từng được Vương Lâm cứu khỏi Lôi Tiên Giới, bênh vực Tây Tử Phượng","tinhCach":"Trọng ân nghĩa; can đảm đứng ra bênh vực người yếu trước cường quyền","blurb":"Lão già tu vi Khuy Niết sơ kỳ, từng được Vương Lâm mang ra khỏi Lôi Tiên Giới. Vẫn nhớ ơn Vương Lâm, tám trăm năm sau tặng đan dược trân quý cho Tây Tử Phượng và dùng uy danh Vương Lâm trấn áp sứ giả Lôi Tiên Điện.","canhGioiCaoNhat":"Khuy Niết sơ kỳ","trangThai":"song","tabs":{"diem":[{"text":"Từng được Vương Lâm mang ra khỏi Lôi Tiên Giới, vẫn nhớ ơn sau tám trăm năm","chuong":"@c1396"},{"text":"Can đảm dùng uy danh Vương Lâm trấn áp sứ giả Lôi Tiên Điện để bênh vực Tây Tử Phượng","chuong":"@c1396"}],"kinhLich":[{"chuong":"@c1396","importance":"normal","mucCt":"vua","tieuDe":"Bảo vệ Tây Tử Phượng, nhắc tên Vương Lâm đe sứ giả","text":"Tặng Tây Tử Phượng đan dược trân quý La Thiên Tinh Vực. Bật lại sứ giả bảo vệ nàng, nhắc rằng khi Vương Lâm còn ở đây sứ giả không dám khinh, hỏi nếu hắn đã về thì sao, khiến sứ giả trầm mặc bất an.","anchor":"Tây Tử đạo hữu, lão phu nãm đó cũng là được hắn mang ra khòi Lôi Tiên Giới"}],"tuViMoc":[{"chuong":"@c1396","canhGioi":"Khuy Niết sơ kỳ","text":"Tu vi Khuy Niết sơ kỳ khi xuất hiện tại đoàn di tinh Lôi Tiên Điện.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Ân nhân cứu mạng, mang ra khỏi Lôi Tiên Giới","ghiChu":"Vẫn nhớ ơn sau tám trăm năm"},{"ten":"Tây Tử Phượng","tag":"dong-minh","quanHe":"Người cùng phục vụ Lôi Tiên Điện","ghiChu":"Tặng đan dược, bênh vực trước sứ giả"},{"ten":"Tây Tử Phượng","tag":"ban-be","quanHe":"Đạo hữu cùng phục vụ Lôi Tiên Điện","ghiChu":"Tặng đan dược, bênh vực trước sứ giả"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1396"]},{"id":"chu-tung-van","name":"Chu Tùng Vân","aliases":["lão già Khuy Niết"],"gioiTinh":"nam","theLuc":[{"ten":"Lôi Tiên Điện","trangThai":"da-roi"}],"trangThai":"song","blurb":"Lão già tu sĩ cảnh giới Khuy Niết, từng được Vương Lâm cứu ra khỏi Lôi Tiên Giới. Tính cách cương trực, dám đứng ra tố cáo sứ giả Lôi Tiên Điện trước mặt Vương Lâm.","vaiTro":"Tu sĩ từng được Vương Lâm cứu mạng, nhân chứng tố cáo sứ giả","tinhCach":"Cương trực; trọng ân nghĩa; dám đối đầu kẻ mạnh hơn","tabs":{"diem":[{"text":"Từng được Vương Lâm cứu khỏi Lôi Tiên Giới, luôn ghi nhớ ân tình gọi ân công","chuong":"@c1397"},{"text":"Dám chỉ thẳng mặt sứ giả Lôi Tiên Điện tố cáo hành vi làm khó Tây Tử Phượng","chuong":"@c1397"},{"text":"Nhớ ơn Vương Lâm cứu mạng, gặp lại gọi ân công vái sâu, dám đứng ra tố cáo sứ giả Lôi Tiên Điện làm khó Tây Tử Phượng","chuong":"@c1397"},{"text":"Dám chỉ thẳng tố cáo sứ giả Lôi Tiên Điện làm khó Tây Tử Phượng","chuong":"@c1397"},{"text":"Một trong những tu sĩ năm đó được Vương Lâm cứu khỏi Lôi Tiên Giới, nhận ra ân nhân liền cúi người vái sâu.","chuong":"@c1397"},{"text":"Sùng kính Vương Lâm như ân nhân, thanh âm run rẩy ôm quyền vái khi gặp lại","chuong":"@c1397"}],"kinhLich":[{"chuong":"@c1397","importance":"normal","mucCt":"vua","tieuDe":"Tố cáo sứ giả Lôi Tiên Điện","text":"Gặp lại Vương Lâm, kích động gọi là Ân công, ôm quyền vái. Chỉ thẳng tay tố cáo nam tử trung niên sứ giả Lôi Tiên Điện hết lần này đến lần khác làm khó Tây Tử Phượng, khiến nguyên thần nàng bị thương nghiêm trọng.","anchor":"Là hắn! Nếu không có hắn trong mẩy ngày này hết lần này đến lần khác làm khó Tây Tử đạo hữu"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Ân nhân cứu mạng khỏi Lôi Tiên Giới, sùng kính gọi ân công","ghiChu":"@c1397"},{"ten":"Tây Tử Phượng","tag":"dong-minh","quanHe":"Đạo hữu cùng phe, đứng ra tố cáo sứ giả bảo vệ nàng","ghiChu":"@c1397"},{"ten":"Nam tử trung niên sứ giả Lôi Tiên Điện","tag":"doi-thu","quanHe":"Kẻ bị Chu Tùng Vân tố cáo trước mặt Vương Lâm","ghiChu":"@c1397"},{"ten":"Tây Tử Phượng","tag":"ban-be","quanHe":"Đạo hữu, bênh vực nàng trước sứ giả Lôi Tiên Điện","nguon":"@c1397"},{"ten":"Sứ giả Lôi Tiên Điện","tag":"doi-thu","quanHe":"Kẻ bị Chu Tùng Vân công khai tố cáo trước mặt Vương Lâm","ghiChu":"@c1397"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1397"],"canhGioiCaoNhat":"không rõ"},{"id":"gia-chu-trieu-gia","name":"Gia chủ Triệu gia (Vân Động Tinh)","gioiTinh":"nam","canhGioiCaoNhat":"Tịnh Niết Trung Kỳ","trangThai":"tu-vong","theLuc":[{"ten":"Triệu gia (Vân Động Tinh)","trangThai":"gan-bo"}],"blurb":"Gia chủ Triệu gia trên Vân Động Tinh, tu vi Tịnh Niết Trung Kỳ. Tám trăm năm trước lợi dụng lúc Tây gia gặp khó khăn, dùng thủ đoạn bắt Tây Tử Phượng làm lô đinh. Bị kiếm khí Vương Lâm giáng xuống, tan vỡ tử vong.","vaiTro":"Gia chủ Triệu gia, kẻ từng hãm hại Tây Tử Phượng","tinhCach":"Thủ đoạn; thừa nước đục thả câu","tabs":{"diem":[{"text":"Lợi dụng lúc Tây gia gặp khó khăn dùng thủ đoạn bắt Tây Tử Phượng làm lô đinh.","chuong":"@c1399"}],"kinhLich":[{"chuong":"@c1399","importance":"normal","mucCt":"gon","tieuDe":"Bị kiếm khí Vương Lâm giết chết","text":"Bị kiếm khí Vương Lâm từ tinh không giáng xuống xuyên vào cơ thể, tan vỡ tử vong.","anchor":"dùng thủ đoạn để âm thầm bắt Tây Tử Phượng về làm lô đinh"}],"tuViMoc":[],"nhanMach":[{"ten":"Tây Tử Phượng","tag":"doi-thu","quanHe":"Nạn nhân","ghiChu":"Tám trăm năm trước bắt nàng làm lô đinh"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết","ghiChu":"Bị kiếm khí Vương Lâm giết chết để báo thù cho Tây Tử Phượng"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1399"]},{"id":"dai-truong-lao-dong-lai","name":"Đại trưởng lão gia tộc Đông Lai","gioiTinh":"nam","canhGioiCaoNhat":"Tịnh Niết viên mãn","trangThai":"tu-vong","theLuc":[{"ten":"Gia tộc Đông Lai (Thiên Mạc Tinh)","trangThai":"gan-bo"}],"blurb":"Đại trưởng lão gia tộc Đông Lai trên Thiên Mạc Tinh, tu vi Tịnh Niết viên mãn. Bề ngoài hiền lành trồng hoa tu tâm, nhưng tám trăm năm trước ép Tây Tử Phượng lấy ra pháp bảo tối hậu của lão tổ, khiến nàng tự hủy dung nhan. Bị kiếm khí Vương Lâm giết chết.","vaiTro":"Đại trưởng lão gia tộc Đông Lai, kẻ ép Tây Tử Phượng","tinhCach":"Bề ngoài hiền lành; bên trong tàn nhẫn","tabs":{"diem":[{"text":"Ép Tây Tử Phượng lấy ra pháp bảo tối hậu của lão tổ, khiến nàng tự hủy dung nhan.","chuong":"@c1399"}],"kinhLich":[{"mucCt":"gon","text":"Đang giảng đạo cho ba nam tử trung niên thì bị kiếm khí giáng xuống, tan vỡ tiêu tan.","anchor":"đã từng ép Tây Tử Phượng không thể không lấy ra pháp bảo tối hậu mà lão tổ để lại, tự hủy dung nhan","bridge":true,"khoang":"@c1399"}],"tuViMoc":[],"nhanMach":[{"ten":"Tây Tử Phượng","tag":"doi-thu","quanHe":"Nạn nhân","ghiChu":"Tám trăm năm trước ép nàng lấy pháp bảo tối hậu, khiến nàng tự hủy dung nhan"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết","ghiChu":"Bị kiếm khí Vương Lâm giết để báo thù cho Tây Tử Phượng"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1399"]},{"id":"thieu-toc-truong-lo-gia","name":"Thiếu tộc trưởng Lô gia","gioiTinh":"nam","trangThai":"tu-vong","theLuc":[{"ten":"Lô gia (Tử Miểu Tinh)","trangThai":"gan-bo"}],"blurb":"Thiếu tộc trưởng Lô gia thuộc tứ đại gia tộc phía nam La Thiên, trên Tử Miểu Tinh. Hành vi tà dâm, hút sinh lực nữ tu để tu luyện. Bị kiếm khí Vương Lâm xuyên qua nữ tu không gây thương tổn, nhập vào mi tâm khiến tan vỡ tử vong.","vaiTro":"Thiếu tộc trưởng Lô gia, kẻ từng mạo phạm Tây Tử Phượng","tinhCach":"Tà dâm; tàn nhẫn","tabs":{"diem":[{"text":"Hành vi tà dâm hút sinh lực nữ tu để tu luyện, dùng nữ tu làm lá chắn nhưng kiếm khí vẫn xuyên qua giết hắn.","chuong":"@c1399"}],"kinhLich":[{"mucCt":"gon","text":"Đang hành vi tà dâm, dùng nữ tu làm lá chắn nhưng kiếm khí xuyên qua không gây thương tổn cho nữ tu, nhập vào mi tâm khiến tan vỡ tử vong.","anchor":"kiếm khí gào thét xuyên thấu qua nữ tu kia, nhưng lại không hề gây nên cho đối phương một chút thương tổn gì","bridge":true,"khoang":"@c1399"}],"tuViMoc":[],"nhanMach":[{"ten":"Tây Tử Phượng","tag":"doi-thu","quanHe":"Nạn nhân","ghiChu":"Từng mạo phạm Tây Tử Phượng"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết","ghiChu":"Bị kiếm khí Vương Lâm giết để báo thù cho Tây Tử Phượng"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1399"]},{"id":"linh-dong-thuong-nhan","name":"Linh Động Thượng Nhân","cn":"灵动上人","aliases":["Linh Động","Cổ nô Linh Động"],"gioiTinh":"nam","canhGioiCaoNhat":"Bước thứ ba (chân chính)","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1403","importance":"normal","mucCt":"vua","tieuDe":"Được triệu hoán, uy áp vượt lão tổ La Thiên","text":"Được Vương Lâm triệu hoán từ Thiên Hoàng Lô bằng lệnh cổ nô. Xuất hiện bộc phát khí tức chân chính bước thứ ba, tạo khe nứt khổng lồ trong tinh không tỏa hương hỏa dày đặc vượt xa Lỗ Phu Tử. Uy áp mênh mông còn vượt lão tổ La Thiên Tinh Vực.","anchor":"một luồng khí tức chân chính của bước thứ ba nhanh chóng từ trong thân thể Lỗ Phu Tử ầm ầm bạo phát ra"},{"chuong":"@c1404","importance":"normal","mucCt":"vua","tieuDe":"Cùng Chu Cẩn trấn áp phe La Thiên","text":"Uy áp kinh thiên động địa khiến mấy vạn tu sĩ không đứng vững. Cùng Chu Cẩn bước nửa bước về phía trước, hương hỏa lực tràn khắp tinh không, quét sạch Phong Tiên Giới biến ảo.","anchor":"dưới uy áp của Linh Động Thượng Nhân và Chu Cẩn cũng lập tức sụp đổ"},{"chuong":"@c1406","importance":"bridge","mucCt":"gon","text":"Đứng yên phía sau Vương Lâm, không cần ra tay, được nói rõ là bị Vương Lâm tự mình luyện hóa nên không thể phản nghịch.","anchor":"Hắn là bị Vương Lâm tự mình luyện hóa, không thể phản nghịch"},{"importance":"bridge","mucCt":"vua","chuong":"@c1407","tieuDe":"Tự giới thiệu thân phận lão tổ Linh Động tộc","text":"Tự xưng là lão tổ Linh Động tộc tại Thái Cổ Tinh Thần, tộc chỉ có một vạn tộc nhân. Lần đầu nghe đầy đủ chuyện Vương Lâm diệt Thiểm Lôi tộc, động dung.","anchor":"lão phu là Linh Động, lão tổ của Linh Động tộc trong Thái cổ Tinh Thần của giới ngoại!"},{"chuong":"@c1410","importance":"normal","mucCt":"vua","tieuDe":"Bị hút vào thế giới U Minh Thú","text":"Được Vương Lâm triệu xuất từ mi tâm, cùng Chu Cẩn bấm quyết tạo hương hỏa bảo vệ. Trong quyền tổng lực hóa thành pho tượng Linh Động Ma Thần khổng lồ lao theo quyền Vương Lâm. Là người đầu tiên bị hút vào thế giới thần thông trong cơ thể U Minh Thú.","anchor":"Linh Động Thượng Nhân là người đầu tiên biến mất, trực tiếp bị hút vào trong thế giới thần thông trong cơ thể của U Minh Thú!"},{"chuong":"@c1412","importance":"bridge","mucCt":"gon","text":"Được U Minh Thú phun ra theo lệnh Vương Lâm, thần sắc vẫn hoảng sợ.","anchor":"Lập tức Linh Động Thượng Nhân chật vật bị phun ra, thần sắc hắn vẫn còn lộ ra vẻ hoảng sợ"},{"chuong":"@c1414","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Khí tức của vị này cùng Chu Cẩn khiến Thủy Đạo Tử bất an.","anchor":"khí tức của Linh Động Thượng Nhân và Chu cẩn khiến trong lòng Thủy Đạo Tử lại càng không yên"},{"chuong":"@c1417","importance":"normal","mucCt":"ky","tieuDe":"Được triệu hồi, tử hải phá tan phân thân Chu Đức","text":"Được Vương Lâm triệu hồi qua tinh điểm Cổ Thần, xuất hiện trong tử quang tự xưng nô bộc của chủ nhân. Tung tử hải ngợp trời và tượng Ma Thần sừng sững đối đầu Chu Đức, phá tan biển bùn lầy phân thân dễ dàng vì hương hỏa vượt xa, khiến Chu Đức phun nguyên thần khí lui lại, rồi truy kích.","anchor":"Ta là nô bộc của chủ nhân, Linh Động!"},{"chuong":"@c1419","importance":"bridge","mucCt":"gon","text":"Theo thần niệm Vương Lâm bước tới cùng sáu cao thủ hợp lực ngăn cuồng phong.","anchor":"Linh Động và Chu cẩn theo thần niệm của Vương Lâm cũng bước tới"},{"importance":"bridge","mucCt":"gon","chuong":"@c1422","text":"Đứng phía sau Vương Lâm, tư tưởng đơn giản đã bị Vương Lâm luyện hóa thành thâm căn cố đế, theo Vương Lâm rời Thần Tông.","anchor":"cho Mộc Băng Mi trở thành tông chủ của Thần Tông"},{"importance":"bridge","mucCt":"gon","chuong":"@c1424","tieuDe":"Bị triệu ra tham chiến","text":"Bị Vương Lâm triệu ra từ tay áo, bất kể đồng ý hay không phải nghe lệnh chiến đấu.","anchor":"Linh Động Thượng Nhân và Chu Cẩn đồng thời xuất hiện"},{"importance":"bridge","mucCt":"gon","chuong":"@c1425","tieuDe":"","text":"Theo thần niệm Vương Lâm, cùng Chu Cẩn ngăn cản Đông Địch Tử nhưng bị hắn một mình áp chế.","anchor":"Còn Linh Động kia vẻ mặt tỉnh bơ, lời nói của đối phương hoàn toàn không khiến cho hắn có một chút động lòng"},{"chuong":"@c1427","importance":"bridge","mucCt":"gon","text":"Theo thần niệm Vương Lâm, ôm quyền với Nam Vân Tử rồi cùng Chu Cẩn làm hộ pháp cho Nam Vân Tử chữa trị Phong Giới Đại Trận.","anchor":"Giới nội còn chưa chuẩn bị tốt, còn cần một ít thời gian"},{"chuong":"@c1438","importance":"bridge","mucCt":"gon","text":"Theo tâm niệm Vương Lâm mà trầm mặc thi triển thần thông tham gia liên thủ giới nội.","anchor":"Có thể nói tất cả những cao thủ của giới nội ở đây lúc này, toàn bộ đều trong khoảng khắc này bộc phát ra sức mạnh lớn nhất"},{"chuong":"@c1439","importance":"bridge","mucCt":"gon","tieuDe":"Rời khỏi chiến trường","text":"Cùng Chu Cẩn phải rời khỏi chiến trường trước cuồng phong màu vàng hủy diệt.","anchor":"Trận chiến đầu tiên đã kết thúc một cách kỳ dị như vậy."}],"tuViMoc":[],"nhanMach":[{"ten":"Chu Đức","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Đánh bại phân thân Chu Đức dễ dàng nhờ hương hỏa vượt xa"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Đứng trên đài cao trong phong ấn trên lưng Cổ Thần, khinh thường đám tu sĩ yếu, sai thuộc hạ đi phá phong ấn thay mình","chuong":"@c1354"},{"text":"Bị Vương Lâm đánh bại trọng thương, bị nhốt vào Thiên Hoàng Lô luyện hóa, ký ức bị xâm nhập và cải biến, thu phục hoàn toàn, được ban tên Cổ Nô Tử","chuong":"@c1361"},{"text":"Lĩnh ngộ hoàn toàn đạo thuật Dung mà Vương Lâm ban cho, củng cố chân chính bước thứ ba","chuong":"@c1371"},{"text":"Được triệu hoán từ Thiên Hoàng Lô, bộc phát khí tức bước thứ ba, uy áp vượt xa lão tổ La Thiên","chuong":"@c1403"},{"text":"Tung tử hải phá tan phân thân Chu Đức, tự xưng nô bộc của chủ nhân trước chư tu","chuong":"@c1417"},{"text":"Tự giới thiệu thân phận lão tổ Linh Động tộc tại Thái Cổ Tinh Thần, tộc chỉ có một vạn tộc nhân","chuong":"@c1407"}]},"nguon":["@c1403","@c1404","@c1405","@c1406","@c1407","@c1410","@c1412","@c1414","@c1417","@c1419","@c1422","@c1424","@c1425","@c1427","@c1438","@c1439"],"tinhCach":"Kiêu ngạo khinh thường kẻ yếu; tàn nhẫn sẵn sàng hy sinh thuộc hạ; đạo tâm kiên định trải mấy vạn năm tu hành; trung thành tuyệt đối sau khi bị luyện hóa","vaiTro":"Cường giả Thái Cổ Tinh Thần, bị Vương Lâm luyện nô thu phục, đổi tên Cổ Nô Tử","blurb":"Lão tổ của Linh Động tộc tại Thái Cổ Tinh Thần, tu sĩ tóc đỏ như máu từng dẫn đầu chín tu sĩ trong chỗ phong ấn trên lưng Cổ Thần. Sau khi bước vào bước thứ ba, bị Vương Lâm đánh bại, nhốt vào Thiên Hoàng Lô luyện nô, ký ức bị cải biến hoàn toàn khiến nhận Vương Lâm là chủ nhân, đổi tên Cổ Nô Tử. Từ đó trở thành chiến lực bước thứ ba dưới trướng Vương Lâm, lĩnh ngộ đạo thuật Dung để củng cố cảnh giới, nhiều lần được triệu hoán từ Thiên Hoàng Lô xông trận tác chiến."},{"id":"chu-can","name":"Chu Cẩn","cn":"朱芹","tabs":{"kinhLich":[{"chuong":"@c1404","importance":"normal","mucCt":"ky","tieuDe":"Hiện thân từ Thiên Hoàng Lô trấn áp La Thiên","text":"Được Vương Lâm gọi Cổ nô Chu Cẩn, từ Thiên Hoàng Lô hiện ra với tiếng sói gào kinh thiên. Nửa thân trên trần, khí tức bạo ngược khát máu, phía sau hư ảnh huyết lang mấy vạn trượng mắt đỏ rực. Cùng Linh Động Thượng Nhân bước nửa bước, hương hỏa lực tràn khắp tinh không, quét sạch Phong Tiên Giới và ép tàn kiếm nứt nẻ. Huyết lang phía sau khiến Lỗ Phu Tử nhớ tới một lời đồn.","anchor":"Thân ảnh của Chu Cẩn từ trong Thiên Hoàng Lô hiện ra"},{"mucCt":"vua","text":"Đứng phía sau Vương Lâm, bị cổ nỏ ấn trên mi tâm áp chế nguyên thần không thể phản kháng. Ánh mắt nhìn Vương Lâm phức tạp, Vương Lâm càng cường đại vẻ phức tạp càng đậm, trước khí Đạo cổ tự cảm thấy mình như con kiến.","anchor":"Vương Lâm càng cường đại thì vẻ phức tạp trong mắt hắn lại càng đậm","bridge":true,"khoang":"@c1406"},{"importance":"bridge","mucCt":"vua","chuong":"@c1407","tieuDe":"Tự giới thiệu thân phận lão tổ Phụng Thiên Lang tộc","text":"Tự xưng là lão tổ Phụng Thiên Lang tộc tại Thái Cổ Tinh Thần, đại tộc tồn tại từ thời thái cổ. Lần đầu nghe đầy đủ chuyện diệt Thiểm Lôi tộc, cùng Linh Động Thượng Nhân nhìn nhau trầm mặc.","anchor":"Chu Cẩn, lão tổ Phụng Thiên Lang tộc tại Thái Cổ Tinh Thần!"},{"chuong":"@c1408","importance":"bridge","mucCt":"gon","text":"Bị Vương Lâm thu vào trong Thiên Hoàng Lô cùng Linh Động.","anchor":"Hai người Chu cẩn, Linh Động bị Vương Lâm thu vào trong Thiên Hoàng Lô"},{"chuong":"@c1410","importance":"normal","mucCt":"vua","tieuDe":"Hóa huyết lang rồi bị hút vào U Minh Thú","text":"Được triệu xuất cùng Linh Động, bấm quyết hương hỏa bảo vệ Vương Lâm. Hóa thành huyết lang lao theo quyền tổng lực. Bị hút vào thế giới thần thông U Minh Thú ngay sau Linh Động, đổi lấy vài nhịp thở quý giá cho Vương Lâm phong hồn.","anchor":"Ngay sau đó là Chu cẩn. dưới lực hút rất lớn này, đột nhiên biến mất!"},{"chuong":"@c1412","importance":"bridge","mucCt":"gon","text":"Được U Minh Thú phun ra, được Vương Lâm thu hồi vào tinh điểm Cổ Thần.","anchor":"Chu cẩn và cổ Tức Diệp cũng lần lượt được phun ra"},{"chuong":"@c1414","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Khí tức của cô cùng Linh Động Thượng Nhân khiến Thủy Đạo Tử bất an, hắn mơ hồ đoán ra chân tướng.","anchor":"Nhất là khí tức của Linh Động Thượng Nhân và Chu cẩn khiến trong lòng Thủy Đạo Tử lại càng không yên"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Xông ra tấn công Vương Lâm trong hỗn loạn tại Hỏa Phần quốc, bị Phượng Loan can thiệp ngăn lại","chuong":"@c0119"},{"text":"Bị Vương Lâm và Linh Động phối hợp áp chế trong cổ mộ, luyện hóa trong Thiên Hoàng Lô rồi bị điểm ấn Cổ Nô lên mi tâm, buộc phải khuất phục","chuong":"@c1380"},{"text":"Đạo tâm tan nát, quỳ phục trước uy áp Cổ Thần bùng phát trong cổ mộ","chuong":"@c1379"},{"text":"Thi triển thần thông Quần Lang Bái Nguyệt, áp đảo Vân Phong Tử bằng hương hỏa vượt trội tại La Thiên Tinh Vực","chuong":"@c1418"},{"text":"Phản bội giới nội sau khi Vương Lâm mất tích, mang Phụng Thiên Lang tộc gây loạn tại Chu Tước Tinh","chuong":"@c1520"},{"text":"Liều mạng tập kích Vương Lâm lúc dung hợp bổn nguyên, bị một chỉ trấn áp hoàn toàn","chuong":"@c1527"}]},"nguon":["@c1404","@c1405","@c1406","@c1407","@c1408","@c1410","@c1412","@c1414"],"canhGioiCaoNhat":"Không Niết Sơ Kỳ đỉnh phong (gần đạt)","trangThai":"song","gioiTinh":"nam","tinhCach":"Hiếu chiến, dám liều mạng tập kích kẻ mạnh hơn dù tuyệt vọng; đa nghi nghiêm khắc khi tra xét chiến công bất thường; phản phúc, lập tức phản bội khi mất ràng buộc; khiếp nhược trước cường quyền tuyệt đối, đạo tâm dễ tan nát dưới uy áp","vaiTro":"Nhân vật phụ — lão tổ Phụng Thiên Lang tộc, Cổ Nô dưới trướng Vương Lâm","blurb":"Chu Cẩn, tên thật Dương Sâm, là tu sĩ Nguyên Anh sơ kỳ mang dáng trung niên văn sĩ, tự xưng lão tổ Phụng Thiên Lang tộc — đại tộc tồn tại từ thời thái cổ tại Thái Cổ Tinh Thần. Vốn thuộc phe Phượng Loan trong Chiến Thần Điện tại Hỏa Phần quốc và từng thù địch Vương Lâm, về sau bị áp chế trong cổ mộ, bị điểm ấn Cổ Nô lên mi tâm buộc phải phục tùng và được thu trong Thiên Hoàng Lô để triệu xuất khi cần, tham gia nhiều trận chiến tại La Thiên Tinh Vực và Phong Giới Đại Trận. Sau khi Vương Lâm mất tích, Chu Cẩn phản bội giới nội mang Phụng Thiên Lang tộc gây loạn, nhưng khi Vương Lâm trở lại liền "},{"id":"thuy-dao-tu","name":"Thủy Đạo Tử","cn":"水道子","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Thần Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thái Sơ","trangThai":"tu-vong","blurb":"Thủy Đạo Tử là đồng tử tóc bạc tu vi Đệ Tam Bộ, nắm quyền cao nhất Thần Tông khi sư tôn Vương San vắng mặt, ngồi trấn tại cung điện trung tâm tinh vực cấp chín. Năm xưa y từng theo chủ nhân phong giới chinh chiến khắp thiên địa rồi phản bội đánh lén tôn sư, về sau điều tra truy sát Vương Lâm suốt nhiều năm. Trong trận quyết chiến cuối cùng, y lần lượt dùng hết mọi thủ đoạn từ pháp bảo chuông vàng Viễn cổ Tiên Vực đến quân bài mệnh hồn nhưng đều bị Vương Lâm hóa giải, cuối cùng nguyên thần bị đánh nát từng phần và bị diệt sát.","vaiTro":"Cao thủ Đệ Tam Bộ của Thần Tông — kẻ phản chủ truy sát Vương Lâm","tinhCach":"Tàn nhẫn quyết đoán, giết lầm không tha kẻ khả nghi; phản trắc mưu mô, từng đánh lén tôn sư để đoạt quyền; liều mạng bất chấp tổn thất khi quyết diệt mục tiêu; tham sống sợ chết, sẵn sàng hy sinh toàn môn phái để bảo toàn bản thân","tabs":{"diem":[{"text":"Tiết lộ quá khứ từng theo chủ nhân phong giới chinh chiến khắp thiên địa rồi phản bội đánh lén tôn sư, mưu bày Luân Hồi đại trận trong cung điện Thần Tông","chuong":"@c1193"},{"text":"Bị Thất Thải Thần Không Đinh găm hoàn toàn vào mi tâm hủy diệt, hy sinh toàn bộ môn phái để bỏ chạy bảo mạng","chuong":"@c1211"},{"text":"Cảm nhận Vương Lâm trở về, phát bảy đạo mệnh lệnh tổng động viên toàn Vân Hải tinh vực chống trả","chuong":"@c1414"},{"text":"Kích nổ chuông vàng Viễn cổ Tiên Vực bằng bí thuật do Chủ nhân phong giới truyền, mưu phá hủy toàn bộ Vân Hải tinh vực để đồng quy vu tận với Vương Lâm","chuong":"@c1419"},{"text":"Lật quân bài mệnh hồn cuối cùng nhưng thất bại, nguyên thần bị Vương Lâm đánh từng quyền phá hủy và diệt sát","chuong":"@c1421"},{"text":"Sau khi chết vẫn nhiều lần được Vương Lâm lấy làm mốc đối chiếu uy lực các cường giả khác như Điên Lạc đại đế, Thiên Vận Tử, Viêm Long","chuong":"@c1293"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1413","text":"Được Vương Lâm nhắc tên khi tuyên bố sẽ tới Vân Hải Tinh Vực thanh toán mối thù năm đó.","anchor":"Mối thù với Thủy Đạo Tử năm đó, hôm nay Vương mỗ sẽ giải quyết"},{"chuong":"@c1414","importance":"normal","mucCt":"ky","tieuDe":"Tổng động viên chống Vương Lâm","text":"Cảm nhận khí tức Vương Lâm trở về, vô cùng khiếp sợ. Phát bảy đạo mệnh lệnh: triệu tập tu sĩ Vân Hải tinh vực bố trí Cửu Diệt Lê Thiên Trận bên ngoài Thần Tông; sai phân tông cấp bảy bắt toàn bộ người Quy Nguyên Tông về Thần Tông chờ lệnh chém sạch. Ép Mộc Băng Mi nuốt đan dược ra khỏi bế quan trợ giúp, nhắc ơn chữa thương và khôi phục tu vi. Triệu tông chủ Phá Thiên Tông đến Thần Tông, đe dọa diệt môn nếu không đến. Ra lệnh cho Thái A La — vua mãnh thú đã hóa hình bị hắn phong ấn — giúp giết một người, hứa cho trở về cố hương. Phát thông điệp tới bốn tinh vực Vân Hải, Triệu Hà, Liên Minh, La Thiên, tự xưng đồng tử chủ nhân phong giới, vu cáo Vương Lâm là gian tế Thái Cổ Tinh Thần chiếm Thiên Nghịch, kêu gọi toàn giới nội truy sát. Dùng mảnh mai rùa — tín vật đồng tử — liên lạc viễn cổ tiên vực, nhận chiếc chuông vàng vốn dùng dung hợp Phong Giới Đại Trận ngăn xâm lấn một trăm năm, nhưng không có ý thực hiện, định dùng chuông tự bảo mệnh rồi đổi công lao với chưởng tôn. Tiết lộ từng báo tin Vương Lâm cho Diệu Âm đạo tôn ở giới ngoại.","anchor":"Còn về chuyện khiến vật này dung nhập vào trong Phong Giới Đại Trận thì Thủy Đạo Tử căn bản là không có ý định thực hiện!"},{"chuong":"@c1415","importance":"bridge","mucCt":"gon","text":"Thanh Lâm tiết lộ hắn là nô bộc của sư tổ Tư Đồ Nam. Phát sáu ngọc giản vu Vương Lâm là gian tế, ra hiệu lệnh triệu tập tu sĩ triển khai Cửu Diệt Lê Thiên Trận tại Thần Tông.","anchor":"Lý Thiến Mai nỗ lực hết thảy để cứu sống hắn lại hiện lên"},{"chuong":"@c1416","importance":"normal","mucCt":"ky","tieuDe":"Đối đầu Vương Lâm tại tu chân tinh Thần Tông","text":"Ngồi trên đỉnh núi tu chân tinh Thần Tông, tay nắm cái chuông màu vàng. Phát thanh âm hóa kiếm sắc tấn công Vương Lâm nhưng bị đánh tan. Nhận ra Vương Lâm có thêm sát lục bổn nguyên nhưng tỏ thái độ bất cần. Âm mưu cho gần vạn tu sĩ chết dưới tay Vương Lâm để kích động phẫn nộ giới nội phối hợp giới ngoại, nhưng kế hoạch phản tác dụng. Dùng hình ảnh đám người Quy Nguyên Tông bị vây uy hiếp đạo tâm Vương Lâm, bị đáp lại bình thản khiến sửng sốt.","anchor":"Bọn họ vì ngươi mà chết. Ta muốn xem đạo tâm của ngươi có xuất hiện sơ hở gì không!"},{"chuong":"@c1417","importance":"normal","mucCt":"ky","tieuDe":"Ngọn núi bị phá, phun máu kêu cứu, liều mạng tung trường thương","text":"Dùng ngọn núi pháp bảo Thần Tông đè bồn địa nhưng bị huyết kiếm Vương Lâm đâm xuyên phá nát. Tung Thất Thải Đinh hóa cầu vồng chống chưởng Vương Lâm, phá được bàn tay hư ảo nhưng bản thân phun máu tươi, hoảng sợ kêu cứu Chu Đức. Cuối chương điên cuồng triệu hồi vô số Âm Dương Môn Đồ hóa thành trường thương khổng lồ dung hợp tu vi và toàn bộ hương hỏa cả đời đâm Vương Lâm, uy lực khiến tu chân tinh nứt vỡ sắp hủy diệt.","anchor":"Cây thương này dung hợp tu vi cả đời của Thủy Đạo Tử, dung hợp toàn bộ hương hỏa của hắn"},{"mucCt":"ky","text":"Thương thế chưa phục hồi, uy lực yếu hơn trước, thi triển thần thông hương hỏa hóa cây thương bị Vương Lâm một quyền phá tan, lùi chín bước phun chín ngụm máu, bắn vào núi vỡ. Tiếp tục thi triển Bổn nguyên lực Âm Dương Tiên Long cùng tấm lưới bổn nguyên lực và vô số pháp bảo, tất cả bị quyền thứ hai của Vương Lâm phá hủy, ngực nổ tung bị đánh rơi xuống đất. Trong tuyệt vọng gọi Thái A La, rồi phun ra cái chuông nhỏ chứa tiên khí Viễn Cổ Tiên Vực, chuông va vào quyền Vương Lâm bộc phát đạo khí vàng khiến Phong Giới Đại Trận hiện hình toàn giới nội.","anchor":"Bổn nguyên lực, âm dương tiên long!","bridge":true,"khoang":"@c1418"},{"chuong":"@c1419","importance":"major","mucCt":"ky","tieuDe":"Kích nổ chuông vàng Viễn cổ Tiên Vực mưu phá Vân Hải","text":"Dùng bí thuật do Chủ nhân phong giới truyền cho để triệu chiếc chuông vàng Viễn cổ Tiên Vực, phun máu tươi kích cho nổ tung. Mưu đồ hủy diệt toàn Vân Hải tạo sơ hở Phong Giới Đại Trận rồi trốn vào Thái Cổ Tinh Thần dựa công lao. Tuyên bố Vương Lâm là tội nhân vạn cổ của giới nội, khiêu khích đạo tâm. Sửng sốt hoảng sợ khi U Minh Thú nuốt trọn cuồng phong khiến kế hoạch thất bại.","anchor":"Chiếc chuông đến từ Viễn cổ Tiên Vực, có thể kéo dài thời gian cho giới nội thêm mấy trăm nãm trong khoảnh khắc này nổ tung"},{"mucCt":"ky","text":"Kế hoạch hoàn toàn bị U Minh thú phá hỏng. Lợi dụng lúc mọi người chú ý thú để lén lùi trốn nhưng bị Vương Lâm phát hiện truy kích. Phun máu đen phát dòng xoáy tím sẫm hàn nhiệt chuyển đổi, dùng song chưởng đối kháng nhưng bị một quyền hư ảo đánh nát hoàn toàn, thân thể tan rã. Nguyên thần thoát ra điên cuồng bỏ chạy, bất chấp mặt mũi tu sĩ bước thứ ba van xin tha mạng. Tự xưng trưởng lão Thần Tông, nô bộc chủ nhân phong giới, tự nguyện làm nô bộc Vương Lâm. Tuyên bố biết tin tức giới ngoại, có thể vì giới nội lập công.","anchor":"Ta nguyện trờ thành nô bộc của ngươi. Ngươi đừng giết ta!","bridge":true,"khoang":"@c1420"},{"importance":"major","mucCt":"ky","chuong":"@c1421","tieuDe":"Lật quân bài mệnh hồn, bị Vương Lâm diệt sát","text":"Nguyên thần bị Vương Lâm đánh từng quyền phá hủy: chân vỡ nát, tay trái nổ tung, ngực bị đánh thủng. Cầu xin làm nô bộc bị từ chối. Lật quân bài cuối cùng: tiết lộ tính mạng tương liên Mộc Băng Mi qua liên kết mệnh hồn bằng đan dược và khôi phục tu vi, tuyên bố Mộc Băng Mi mới là hộ thân phù thật sự. Triển khai thiên địa biến ảo cho Vương Lâm thấy Mộc Băng Mi trong đại trận. Cuối cùng bị Vương Lâm bóp nát hồn phách, chết. Được xác nhận là nô bộc chủ nhân phong giới, đại trưởng lão Thần Tông, tu sĩ bước thứ ba Vân Hải tinh vực.","anchor":"Ta và Mộc Băng Mi tính mạng tương liên. Ngươi giết ta, chính là giết nàng!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1448","bridge":true,"khoang":"@c1448–@c1448","text":"Được Vương Lâm nhắc khi so sánh: Dịch Linh Ấn của Thủy Đạo Tử chỉ đánh tan thân thể, không phải bản chính tông.","anchor":"Thủy Đạo Tử khi thi triển Dịch Linh Ấn chỉ đánh tan thân thể mà thôi"}],"tuViMoc":[],"nhanMach":[{"ten":"Thái A La","tag":"khac","quanHe":"Mãnh thú bị hắn phong ấn, sai giết người đổi tự do","ghiChu":"@c1414"},{"ten":"Chu Đức","tag":"dong-minh","quanHe":"Đại năng Triệu Hà, thuê ra tay một lần đổi lục phẩm đạo linh","ghiChu":"@c1414"},{"ten":"Vân Phong Tử","tag":"dong-minh","quanHe":"Đại năng Triệu Hà, thuê ra tay một lần đổi Định Thần Thuật","ghiChu":"@c1414"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1405","@c1413","@c1414","@c1415","@c1416","@c1417","@c1418","@c1419","@c1420","@c1421","@c1448"]},{"id":"nu-tu-phong-an-than-tong","name":"Nữ tử tuyệt mỹ bị phong ấn trong Thần Tông","gioiTinh":"nu","aliases":[],"theLuc":[],"trangThai":"bi-phong-an","blurb":"Nữ tử tuyệt mỹ bị giam trong trận pháp phong ấn khổng lồ của Thần Tông tại Vân Hải tinh vực, tóc bù xù, không phản ứng gì với khí tức bước thứ ba.","vaiTro":"Bí ẩn, bị phong ấn trong Thần Tông","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Bị giam trong trận pháp phong ấn khổng lồ của Thần Tông, không hề phản ứng trước khí tức bước thứ ba khiến Thủy Đạo Tử hoảng sợ.","chuong":"@c1405"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1405"]},{"id":"nam-tu-ao-do-van-hai","name":"Nam tử áo đỏ","gioiTinh":"nam","aliases":[],"theLuc":[],"trangThai":"song","blurb":"Nam tử trung niên bí ẩn mặc áo đỏ, ngồi đả tọa trên đại lục hoang vu tại Vân Hải tinh vực, quyền lực trên cả tông chủ Yêu Tông. Nhận xét Vương Lâm là người được chủ nhân Phong giới coi trọng.","vaiTro":"Nhân vật bí ẩn, quyền lực trên tông chủ Yêu Tông","tinhCach":"Uy nghiêm; bình tĩnh; tự tin","tabs":{"diem":[{"text":"Tông chủ Yêu Tông cùng đại trưởng lão cung kính quỳ trước mặt, quyền lực siêu nhiên.","chuong":"@c1405"},{"text":"Nhận xét Vương Lâm là người được chủ nhân Phong giới coi trọng, gọi VL là tiểu tử không tồi.","chuong":"@c1405"}],"kinhLich":[{"chuong":"@c1415","importance":"normal","mucCt":"ky","tieuDe":"Tán thưởng Vương Lâm, quyết xem tầm mắt chủ nhân phong giới","text":"Ngồi trong sơn cốc cùng Lỗ Phu Tử và tông chủ yêu tông, nghe tin Vương Lâm bị vu gian tế. Thần sắc bình thản nhưng mắt lóe hàn quang, nói Thất Thải Giới giỏi lắm, chưởng tôn giỏi lắm. Khi nghe thần niệm Thần Tông khẳng định Vương Lâm được chủ nhân phong giới giao thống lĩnh giới nội, chuyển sang tán thưởng. Nói vốn tiếc tu vi Thủy Đạo Tử chưa muốn phá, nay hắn tự tìm chết. Tiết lộ chủ nhân phong giới đích thân nói với hắn để Vương Lâm thống lĩnh, quyết định xem tầm mắt chủ nhân phong giới, coi đây là chuyện nhà của bọn họ.","anchor":"Ta vốn tiếc một thân tu vi của hắn chưa muốn phá đi"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Đánh giá VL là người được chủ nhân Phong giới coi trọng","ghiChu":"@c1405"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1405","@c1415"]},{"id":"thanh-lam","name":"Thanh Lâm","cn":"青鸾","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1415","importance":"normal","mucCt":"vua","tieuDe":"Truyền thần niệm bảo vệ Vương Lâm","text":"Đang chữa thương trong Vũ tiên giới, nhận tin Vương Lâm bị vu gian tế. Dùng thần lực ngưng tụ nước mưa cả Vũ giới thành lệnh bài, truyền thần niệm khẳng định Vương Lâm là đệ tử bổn tiên đế. Quát Tư Đồ Nam ngồi xuống, nói sẽ tự xử lý. Tiết lộ Thủy Đạo Tử là nô bộc của sư tổ Tư Đồ Nam, vẻ mặt phức tạp khi nhắc đến chưởng tôn.","anchor":"Không phải vi sư không tin mà là vì chưởng tôn kia"}],"diem":[{"text":"Được xác nhận là Tiên Đế, cường giả đệ nhất Tiên giới và là phụ thân của Thanh Sương.","chuong":"@c0595"},{"text":"Lập Cửu Ấn Trận, thi triển Định Thân Thuật để áp chế thánh tổ Phù Tộc trong động phủ Tiên Đế.","chuong":"@c0968"},{"text":"Hiện thân truyền Quy tắc thân thể cho Vương Lâm trong lúc đối đầu Cổ Ma Tháp Già.","chuong":"@c1047"},{"text":"Thức tỉnh trong trận pháp hồi sinh và khai sinh Tân Vũ Giới.","chuong":"@c1050"},{"text":"Thi triển viễn cổ tiên thuật, dẫn đầu giới nội chống tu sĩ giới ngoại.","chuong":"@c1453"},{"text":"Được xác nhận là phách thứ ba của Thất Thải Tiên Tôn, phách chứa chính khí và lương tri.","chuong":"@c1650"}]},"nguon":["@c1405","@c1415"],"vaiTro":"Tiên Đế — phách Thất Thải Tiên Tôn","tinhCach":"Che chở đệ tử và giới nội; mưu tính sâu xa; lạnh lùng quyết đoán với kẻ địch; trọng ân nghĩa","blurb":"Thanh Lâm là Tiên Đế, từng được xác nhận là cường giả đệ nhất Tiên giới, phụ thân Thanh Sương, phu quân Hoa Phi, ân sư của Vương Nguy và Hồ Quyên. Sau biến cố Tiên giới, thân thể ông bị Cổ Ma Tháp Già chiếm, rồi nhờ trận pháp hồi sinh mà thức tỉnh, truyền Quy tắc thân thể cho Vương Lâm và khai sinh Tân Vũ Giới. Về sau ông bế quan chữa thương tại Vũ Tiên Giới, nhiều lần ra tay bảo vệ giới nội, tham dự đại chiến giới ngoại, và được xác nhận là một phách của Thất Thải Tiên Tôn."},{"id":"tu-do-nam","name":"Tư Đồ Nam","cn":"司徒南","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Tức giận điên cuồng khi nghe Vương Lâm bị vu là gian tế, đứng phắt dậy muốn đi trả thù nhưng bị Thanh Lâm quát ngồi xuống. Khẳng định biết toàn bộ chuyện Vương Lâm từ khi bắt đầu tu tiên, nhìn chằm chằm vào Thanh Lâm không bị lời nói đả động.","anchor":"Người tuy là sư tôn của ta nhưng hắn lại là huynh đệ ta","bridge":true,"khoang":"@c1415"},{"mucCt":"ky","text":"Tư Đồ Nam trong bi thương ở Vũ Giới, bỏ mặc tu luyện, uống rượu say ba ngày vừa cười vừa khóc. Sau đó rời Vũ Giới cùng Chu Như hướng ra tinh không Côn Hư đi tìm Vương Lâm. Hai người ngắm tinh hải mịt mờ trong tinh không Côn Hư.","anchor":"Tư Đồ Nam trong sự bi thương, ở trong Vũ Giới bỏ mặc tất cả việc tu luyện","bridge":true,"khoang":"@c1440"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Từng là cường giả Chu Tước Quốc lục cấp, thân hủy sau khi bị truy sát và ẩn tinh hoa Nguyên Anh vào Thạch Châu.","chuong":"@c0047"},{"text":"Thức tỉnh nhờ lửa Chu Tước thâm nhập Thiên Nghịch Châu, trong trạng thái rất suy yếu vẫn nhập thân Vương Lâm để hư trương thanh thế.","chuong":"@c0397"},{"text":"Đoạt xá đồng tử trong khối viêm băng, hoàn tất dung hợp và về sau hiện thân với bản lãnh đạt Vấn Đỉnh kỳ.","chuong":"@c0401"},{"text":"Tại Thủy Linh tinh, dùng thần thức Tịnh Niết sơ kỳ quét ngang khiến tinh cầu chấn động.","chuong":"@c0932"},{"text":"Được Thanh Lâm trợ giúp phá Không Môn, chính thức trở thành tu sĩ bước thứ ba và tử chiến tại Chu Tước Tinh.","chuong":"@c1520"},{"text":"Được xác nhận là phách thứ hai màu xanh của Thất Thải Tiên Tôn, phách ẩn chứa toàn bộ tu vi Không Kiếp.","chuong":"@c1650"}]},"nguon":["@c1405","@c1415","@c1440"],"vaiTro":"Huynh trưởng Vương Lâm — cường giả Chu Tước, phách Thất Thải","tinhCach":"Kiêu ngạo ngang tàng; tàn nhẫn quyết đoán; trọng nghĩa với Vương Lâm; nóng nảy nhưng biết toan tính","blurb":"Tư Đồ Nam vốn là cường giả lục cấp của Chu Tước Quốc, bị truy sát đến thân hủy rồi dùng tinh hoa Nguyên Anh ẩn trong Thiên Nghịch Châu, nhiều năm chỉ điểm và bảo vệ Vương Lâm. Sau khi thức tỉnh và đoạt xá thành công, ông phục hồi thực lực, nhiều lần cùng Vương Lâm vượt hiểm, về sau được Thanh Lâm trợ giúp bước vào bước thứ ba. Ở các mốc sau, ông được xác nhận là phách thứ hai màu xanh của Thất Thải Tiên Tôn, phách ẩn chứa toàn bộ tu vi Không Kiếp."},{"id":"nam-tu-hac-y-tuong-da","name":"Nam tử hắc y dưới tượng đá","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Vũ Tiên Giới","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Đồ đệ bí ẩn của Vương Lâm, diện mạo giống hệt Vương Lâm năm xưa, trông coi pho tượng Tiên Đế Thanh Lâm trên ngọn núi cao nhất Vũ Tiên Giới suốt mấy trăm năm, coi là cấm địa không cho bất kỳ ai lên.","vaiTro":"Đồ đệ Vương Lâm, người canh giữ pho tượng đá","tinhCach":"Trung thành tuyệt đối với sư tôn; lạnh lùng; kiên định","tabs":{"diem":[{"text":"Diện mạo giống hệt Vương Lâm năm đó, tóc đen quá vai, khí tức lạnh như băng.","chuong":"@c1405"},{"text":"Tự coi ngọn núi cao nhất Vũ Tiên Giới là cấm địa, không cho ai lên kể cả Tư Đồ Nam, Thanh Lâm, Thanh Sương, Chu Dật.","chuong":"@c1405"},{"text":"Khi cảm nhận khí tức bước thứ ba, run lên kích động gọi Sư tôn, trong cõi u minh cảm ứng được sự tồn tại của Vương Lâm.","chuong":"@c1405"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Sư tôn, người mà hắn trung thành canh giữ tượng đá theo lời dặn","ghiChu":"@c1405"},{"ten":"Tư Đồ Nam","tag":"khac","quanHe":"Không cho phép lên núi cấm địa","ghiChu":"@c1405"},{"ten":"Thanh Lâm","tag":"khac","quanHe":"Không cho phép lên núi cấm địa","ghiChu":"@c1405"},{"ten":"Thanh Sương","tag":"khac","quanHe":"Không cho phép lên núi cấm địa","ghiChu":"@c1405"},{"ten":"Chu Dật","tag":"khac","quanHe":"Không cho phép lên núi cấm địa","ghiChu":"@c1405"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1405"]},{"id":"nu-tu-bach-y-vu-tien-gioi","name":"Nữ tử bạch y trên bãi cỏ","gioiTinh":"nu","aliases":[],"trangThai":"song","blurb":"Nữ tử bạch y yên lặng khoanh chân trên bãi cỏ hương hoa trong Vũ Tiên Giới, trước mặt có hổ khổng lồ nằm ườn.","vaiTro":"Nhân vật bí ẩn trong Vũ Tiên Giới","tinhCach":"Yên tĩnh","tabs":{"diem":[{"text":"Ngồi khoanh chân trên bãi cỏ hương hoa, trước mặt có hổ khổng lồ nằm ườn.","chuong":"@c1405"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1405"]},{"id":"nu-tu-suong-tuyet-vu-tien-gioi","name":"Nữ tử sương tuyết trên núi đóng băng","gioiTinh":"nu","aliases":[],"trangThai":"song","blurb":"Nữ tử lạnh như sương tuyết ngàn năm, khoanh chân đả tọa trên ngọn núi đóng băng trong Vũ Tiên Giới, lãnh đạm nhìn về xa.","vaiTro":"Nhân vật bí ẩn trong Vũ Tiên Giới","tinhCach":"Lãnh đạm","tabs":{"diem":[{"text":"Ngồi trên ngọn núi dường như bị đóng băng, lãnh đạm như sương tuyết ngàn năm không tan.","chuong":"@c1405"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1405"]},{"id":"nam-tu-thanh-sam-vu-tien-gioi","name":"Nam tử thanh sam dưới núi đóng băng","gioiTinh":"nam","aliases":[],"trangThai":"song","blurb":"Nam tử thanh sam thân thể tang thương, trẻ anh tuấn, tồn tại như linh thể không thực chất, đứng trong sân dưới núi đóng băng của Vũ Tiên Giới, ngẩng đầu nhìn ngọn núi với si tình ngàn năm không đổi.","vaiTro":"Nhân vật bí ẩn trong Vũ Tiên Giới, si tình ngàn năm","tinhCach":"Si tình; tang thương","tabs":{"diem":[{"text":"Tồn tại như linh thể không thực chất, si tình ngàn năm không đổi, ngẩng đầu nhìn ngọn núi đóng băng.","chuong":"@c1405"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1405"]},{"id":"ke-gam-thet-tu-chan-lien-minh","name":"Kẻ gầm thét trong Tu Chân Liên Minh","gioiTinh":"nam","aliases":[],"trangThai":"bi-phong-an","blurb":"Kẻ bí ẩn bị phong kín trong tổng bộ Tu Chân Liên Minh, gầm thét phẫn nộ thê lương suốt mấy trăm năm, muốn giết sạch mọi sinh linh.","vaiTro":"Nhân vật bí ẩn bị phong kín trong Tu Chân Liên Minh","tinhCach":"Phẫn nộ; điên cuồng; thê lương","tabs":{"diem":[{"text":"Bị phong kín trong tổng bộ Tu Chân Liên Minh, gầm thét muốn giết sạch mọi sinh linh suốt mấy trăm năm.","chuong":"@c1405"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1405"]},{"id":"anh-mat-thi-am-tong","name":"Ánh mắt từ Thi Âm Tông","gioiTinh":"nam","aliases":[],"trangThai":"song","blurb":"Tồn tại bí ẩn tại khu vực Thi Âm Tông trong Liên Minh Tinh Vực, ánh mắt có thể khiến tinh không sụp đổ, nhận ra Vương Lâm là người mà chủ nhân Phong giới ước định năm đó.","vaiTro":"Nhân vật bí ẩn tại Thi Âm Tông","tinhCach":"Bí ẩn; quan sát từ xa","tabs":{"diem":[{"text":"Ánh mắt có thể khiến tinh không sụp đổ, nhận ra Vương Lâm là người được chủ nhân Phong giới ước định.","chuong":"@c1405"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Nhận ra VL là người được chủ nhân Phong giới ước định","ghiChu":"@c1405"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1405"]},{"id":"co-yeu-lao-to-tong","name":"Cổ Yêu","cn":"古妖","aliases":["Huyết Thần Tử","Yêu Thánh Quỷ Tông"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1406","importance":"normal","mucCt":"ky","tieuDe":"Hiện nguyên hình, bị Vương Lâm bắt sống","text":"Khi Huyết Thần Tử chết, yêu khí từ thi thể tràn ra dung hợp với yêu ảnh, hiện nguyên hình lục tinh trăm trượng. Lộ ra đã nương nhờ Huyết Thần Tử chữa thương từ lâu, từng chỉ dẫn Huyết Thần Tử bắt Vương Lâm theo lời Diêu gia để hấp thu khí tức Cổ Thần. Liều mạng thi triển đủ loại thần thông (chín con yêu long, chín mươi yêu kỳ, chín trăm chín mươi chín giọt máu chứa hồn phách huyết mạch ngàn năm Diêu gia, chín ngàn chín trăm chín mươi chín cây hắc châm kịch độc) và vương tộc pháp khí yêu đao Táng Thổ — tất cả bị Vương Lâm một quyền phá nát. Bị bắt sống, thu nhỏ thành người thường, cầu xin tha mạng, tiết lộ bí mật kinh thiên về Diêu gia và thần thông ba mạng.","anchor":"Đừng giết ta, ta biết một bí mật! Một bí mật kinh thiên!"},{"importance":"normal","mucCt":"ky","chuong":"@c1413","tieuDe":"Bị ép giao nộp huyết các tế đàn","text":"Bị Vương Lâm lôi ra từ không gian trữ vật tại huyết tinh trong La Thiên Tinh Vực, bị uy hiếp tiết lộ bí mật. Ban đầu cưỡng lại, sau khai về khe không gian chứa tế đàn Phong Diệt Tộc và Tam Mệnh Thuật. Dẫn đường vào huyết tinh bằng huyết mạch Diêu gia, định bẫy Vương Lâm bước vào khe rồi bỏ chạy nhưng bị nhìn thấu. Không dám đánh cuộc, tự lấy tòa huyết các giao nộp. Tiết lộ tế đàn có ba phần (ba huyết các), nơi này chỉ một tòa. Bị phong ấn thu vào không gian trữ vật.","anchor":"Tế đàn của Phong Diệt Tộc có ba phần, tương ứng có ba tòa huyết các"},{"importance":"bridge","mucCt":"gon","chuong":"@c1421","tieuDe":"Nhận ra Đạo Cổ Hóa Mệnh Thuật","text":"Nhận ra Vương Lâm thi triển Đạo Cổ Hóa Mệnh Thuật và biến sắc, nói cổ tộc tổ tiên cả đời chỉ thi triển được ba lần.","anchor":"Đạo Cổ hóa mệnh thuật! Đây là Đạo cổ hóa mệnh thuật!"},{"mucCt":"vua","text":"Ẩn nấp chờ nam tử áo trắng hết sức, phái phân thân cửu tinh tập kích khi đối phương định bỏ đi. Bị dụ vào bẫy, uy áp Chưởng Tôn Phong Dư từ Thái Cổ Tinh Thần giáng bàn tay khổng lồ bóp nát phân thân, yêu khí bị hút.","anchor":"Cá nhỏ không tới, nhưng lại có một con cá lớn tới!","bridge":true,"khoang":"@c1437"},{"mucCt":"ky","text":"Yêu khí từ giới nội hóa thành khuôn mặt dữ tợn cửu tinh Cổ Yêu, há miệng phun yêu khí hóa yêu long cực lớn. Chín tinh điểm Cổ Yêu từ mắt trái bay ra dung nhập vào yêu long, phối hợp cùng cuồng phong và quyền Đạo Cổ của Vương Lâm phá nát ngón tay cuối cùng của bàn tay khổng lồ.","anchor":"chín tinh điểm Cổ Yêu trong mắt trái của Cổ Yêu này đồng loạt bay ra, bất ngờ dung nhập vào trong con yêu long","bridge":true,"khoang":"@c1438"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Lần đầu lộ diện, lập giao kèo với Vương Lâm và kể nguồn gốc chín tồn tại không hoàn chỉnh cùng chiến tranh cửu quận Yêu Lin","chuong":"@c0555"},{"text":"Giáng ý chí cường đại từ Thiên Yêu thành cứu Vương Lâm, mượn máu ngưng huyết ảnh đại chiến tán ma ba ngày","chuong":"@c0565"},{"text":"Đoạt cuốn tranh trong bình bạch ngọc, biến tiên khí thành yêu khí tại Tiên phủ","chuong":"@c0963"},{"text":"Liên thủ cùng Vương Lâm đối đầu Cổ Ma Tháp Già, hóa thất tinh Cổ Yêu thi triển Yêu Linh Biến và tự bạo phân thân cản địch","chuong":"@c0999"},{"text":"Phong ấn bị Cửu Thiên Ma Tôn nghiền nát mà thức tỉnh, sau đó bị Vương Lâm bắt sống và hiện nguyên hình lục tinh trăm trượng","chuong":"@c1406"},{"text":"Sống sót sau đại chiến Vân Hải tinh vực, cảm nhận khí tức cổ Mạch Thương Khung Huyết và mơ hồ muốn bái tế","chuong":"@c1612"}]},"nguon":["@c1406","@c1413","@c1421","@c1437","@c1438"],"vaiTro":"Cường giả viễn cổ ẩn trong Yêu Cổ — lão tổ tông Thiên Yêu quận, đồng minh giao kèo của Vương Lâm","tinhCach":"Hành sự qua giao kèo và điều kiện ràng buộc lợi ích, tính toán chặt chẽ; sẵn sàng hao tổn bản thể và tự bạo phân thân để chiến đấu, không né tránh khi cần đối đầu; can thiệp gián tiếp qua trung gian thay vì trực tiếp lộ diện; mỉa mai sắc bén và tự phụ về lai lịch cổ tộc","blurb":"Cổ Yêu là một trong chín tồn tại không hoàn chỉnh từ giới ngoại đến, trú ngụ trong Yêu Cổ với tư cách lão tổ tông của Thiên Yêu quận, thường được gọi là Bối La. Ông lập giao kèo với Vương Lâm từ sớm, nhiều lần giáng ý chí hoặc hiện bản thể cứu viện và tham chiến — từ đại chiến tán ma đến liên thủ đánh Cổ Ma Tháp Già trong Tiên phủ — đồng thời trở thành biến số then chốt trong nhiều bước ngoặt của Vương Lâm. Về sau phong ấn bị Cửu Thiên Ma Tôn nghiền nát mà thức tỉnh, bị Vương Lâm bắt sống và ép giao nộp bí mật, hiện vẫn tồn tại dưới dạng cổ yêu bị phong ấn trong không gian trữ vật của Vương Lâ"},{"id":"chien-tinh-da","name":"Chiến Tinh Dã","cn":"战星野","gioiTinh":"nam","trangThai":"tu-vong","canhGioiCaoNhat":"Không Niết Hậu Kỳ đại viên mãn","tabs":{"kinhLich":[{"chuong":"@c1408","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm xác nhận đã chết trong Thất Thải Giới tại Vân Hải, bị Chưởng Tôn của giới ngoại Thái Cổ Tinh Thần giết.","anchor":"Di hài của Chiến Tinh Dã tiền bối vẫn còn ở trong Thất Thải Giới tại Vân Hải"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Đạt cảnh giới Không Linh Chi (Đệ Tam Bộ) nhờ cảm ngộ Chiến Tự Thiếp","chuong":"@c1134"},{"text":"Bị Chưởng Tôn phong ấn giết chết trong Thiên Đạo Kế, thi triển chữ Chiến kim sắc chống lại thần thông bảy màu trước khi tử vong","chuong":"@c1134"},{"text":"Nửa bộ hài cốt bị hai cây đinh bảy màu ghim chặt trên bia đá; di ngôn truyền qua chữ Chiến đến Vương Lâm","chuong":"@c1136"},{"text":"Chiến ý và câu nói vang vọng trong đầu Vương Lâm, trở thành động lực để hắn đối đầu tu sĩ cường đại","chuong":"@c1142"},{"text":"Được Vương Lâm xác nhận đã chết trong Thất Thải Giới tại Vân Hải, bị Chưởng Tôn của giới ngoại Thái Cổ Tinh Thiên sát hại","chuong":"@c1408"}]},"nguon":["@c1408"],"vaiTro":"Lão tổ Chiến gia trên La Thiên — truyền nhân Chiến Lão Quỷ, nạn nhân Thiên Đạo Kế","tinhCach":"Thiên tư phi phàm, cảm ngộ Chiến Tự Thiếp đạt Không Linh Chi; kiên cường chiến đấu đến chết, thi triển chữ Chiến chống lại thần thông phong ấn; ý chí bất khuất, di ngôn còn vang vọng truyền cảm sau khi tử vong","blurb":"Chiến Tinh Dã là lão tổ Chiến gia trên La Thiên, nhờ cảm ngộ Chiến Tự Thiếp mà đạt tới cảnh giới Không Linh Chi (Đệ Tam Bộ). Ông bị Chưởng Tôn của giới ngoại Thái Cổ Tinh Thiên dùng thần thông phong ấn giết chết trong Thiên Đạo Kế, chỉ còn lại nửa bộ hài cốt bị hai cây đinh bảy màu ghim chặt trên bia đá khổng lồ. Chiến ý cùng di ngôn của ông sau này truyền đến Vương Lâm, trở thành động lực để hắn dám đối đầu cường địch."},{"id":"chuong-ton","name":"Chưởng Tôn","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1408","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm xác nhận là kẻ giết Chiến Tinh Dã, thuộc giới ngoại Thái Cổ Tinh Thần.","anchor":"Người giết hắn chính là Chưởng Tôn của giới ngoại Thái Cổ Tinh Thần"},{"importance":"normal","mucCt":"gon","chuong":"@c1413","tieuDe":"Phát lệnh tàn sát Phong Giới","text":"Tại giới ngoại Thái Cổ Tinh Thần, truyền mệnh lệnh khắp tinh vực: tuân ý chỉ Viễn Cổ Tiên Vực, triển khai trận chiến thứ ba giữa Phong Giới và các bộ tộc Thái Cổ, ra lệnh tàn sát Phong Giới và xóa bỏ giới nội.","anchor":"Hôm nay theo lệnh của chưởng Tôn, các bộ tộc hãy tàn sát Phong Giới, xóa bỏ giới nội"},{"importance":"normal","mucCt":"vua","chuong":"@c1424","tieuDe":"Phát lệnh phá Phong Giới Đại Trận","text":"Từ Thiên Phạt Điện của Trưởng Tôn hội lơ lửng trong tinh không, phát lệnh phá trận. Thanh kiếm trong suốt cùng tất cả pháp bảo lao vào trận pháp. Cùng bốn người khác đồng loạt hạ lệnh cho pháp bảo nổ tung, xé mở Phong Giới Đại Trận.","anchor":"từ trong lầu các Thiên Phạt Điện của Trưởng Tôn hội vẫn đang lơ lửng trong tinh không có một âm thanh già nua truyền ra"},{"importance":"bridge","mucCt":"gon","chuong":"@c1425","tieuDe":"","text":"Ra mệnh lệnh cho hơn mười bộ lạc Thái cổ Tinh Thần chuẩn bị truyền tống trận, tăng viện giới ngoại qua lổ hổng.","anchor":"nhận được mệnh lệnh của Chưởng Tôn, những bộ lạc này đã sớm chuẩn bị xong"},{"chuong":"@c1428","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được nhắc là người thu nhận nuôi dưỡng ba tử sĩ Phong Diệt Tộc từ nhỏ với mục đích phong ấn cao thủ.","anchor":"Bọn họ từ nhỏ đã được Chưởng Tôn thu nhận với mục đích phong ấn những cao thủ"},{"chuong":"@c1430","importance":"major","mucCt":"vua","tieuDe":"Hiến sức mạnh cuối cùng, truyền Khai Thiên Phủ","text":"Thần thức để lại trong ngọc bội bộc phát luồng sức mạnh cuối cùng trong sinh mệnh, dung nhập Phong Giới Đại Trận rồi nhập Khai Thiên Phủ để chế phục. Thanh âm già nua vang lên cho phép người được truyền thừa sử dụng, truyền Khai Thiên Phủ cho Vương Lâm.","anchor":"thần thức của Phong Tôn để lại như thể bộc phát ra một luồng sức mạnh cuối cùng trong sinh mệnh"},{"importance":"bridge","mucCt":"gon","chuong":"@c1436","tieuDe":"","text":"Được nhắc: thủ đồ của Chưởng Tôn cầm cây cung Lý Quảng tham chiến.","anchor":"Người này là thủ đồ của Chưởng Tôn"},{"chuong":"@c1437","importance":"bridge","mucCt":"gon","text":"Uy áp từ Thái Cổ Tinh Thần giáng xuống diệt phân thân Cổ Yêu, mệnh lệnh thủ đồ trao cung cho giới nội kèm điều kiện.","anchor":"phụng mệnh sư tôn mang cây cung này tới cho những đạo hữu giới nội"},{"chuong":"@c1438","importance":"normal","mucCt":"ky","tieuDe":"Lộ diện từ bàn tay, giao chiến tu chân tinh","text":"Hư ảnh mặc hắc bào bước ra từ bên trong bàn tay khổng lồ bị phá, chính là Chưởng Tôn mà Vương Lâm từng thấy ngoài cổ mộ. Dùng ánh sáng cánh tay khô héo chặn tu chân tinh thứ tư, bị ép lùi. Bị bốn tu chân tinh (thứ năm tới thứ tám) đồng thời nổ tung xé rách thân, phun nguyên thần khí. Triệu hồi cái giếng khổng lồ có ánh trăng, nhúng tay mò ánh trăng ném ra phá tu chân tinh thứ chín, nhưng bị ấn ký ánh trăng xuyên qua. Kinh hãi nhận ra Chiến lão quỷ vẫn chưa chết, hắc bào bị xé tung lộ dung nhan.","anchor":"Hư ảnh mặc hắc bào này không ngờ chính là Chưởng Tôn mà Vương Lâm đã nhìn thấy ở bên ngoài cổ mộ"},{"chuong":"@c1439","importance":"normal","mucCt":"ky","tieuDe":"Lộ ngoại hình — sợ hãi trước U Minh Thú","text":"Chưởng Tôn hiện rõ khuôn mặt cực kỳ già nua đầy nếp nhăn, mi tâm có ấn ký mơ hồ giống vết sẹo bị đóng vào từ vô số năm trước, không hề có râu tóc. Nhìn Chiến lão quỷ thù hận ngợp trời nhưng không dám mở miệng, túm lấy thủ đồ bỏ chạy. Khi nhìn thấy U Minh Thú, ánh mắt lộ vẻ kích động và sợ hãi.","anchor":"nhất là sau khi nhìn thấy U Minh Thú này, ánh mắt hắn liền lộ ra một sự kích động và sợ hãi"},{"chuong":"@c1440","importance":"normal","mucCt":"gon","tieuDe":"Hạ lệnh chuẩn bị trận chiến thứ hai","text":"Hạ lệnh chuẩn bị trận chiến thứ hai cho giới ngoại, truyền hình dáng Vương Lâm cho toàn bộ tu sĩ, treo thưởng chưa từng có để giết hắn.","anchor":"Chưởng Tôn liền hạ lệnh chuẩn bị cho trận chiến thứ hai!"}],"tuViMoc":[],"nhanMach":[{"ten":"Lam Mộng Đạo Tôn","tag":"khac","quanHe":"Chỉ Lam Mộng mới có thể khiến Chưởng Tôn thay đổi kế hoạch"},{"ten":"Phong Dư","tag":"khac","quanHe":"Thủ đồ, danh hiệu ngón cái"},{"ten":"Chiến lão quỷ","tag":"doi-thu","quanHe":"Kẻ thù năm xưa","ghiChu":"Bị Chiến lão quỷ đánh bại đoạt hương hỏa, kinh hãi khi biết đối phương chưa chết"}],"tuiDo":{},"diem":[{"text":"Tự xưng bản tôn, dùng thần thông bảy màu Thiên Địa Thái Sơ phong ấn giết Chiến Tinh Dã để lấy chiến hồn trong Thiên Đạo Kế.","chuong":"@c1134"},{"text":"Luyện 108 cây Thất Thải Thần Không Đinh, pháp bảo chuyên uy hiếp và giết tu sĩ bước thứ ba.","chuong":"@c1206"},{"text":"Từng cùng người Viễn Cổ Tiên Vực liên thủ đánh trọng thương Chủ nhân Phong Giới gần tử vong.","chuong":"@c1238"},{"text":"Tại Thái Cổ Tinh Thần phát lệnh tuân ý chỉ Viễn Cổ Tiên Vực, triển khai tàn sát Phong Giới.","chuong":"@c1413"},{"text":"Lần đầu dùng bổn tôn bước vào giới nội, nhưng sau đó bị mũi tên xuyên thấu và phải dùng tam mệnh thuật bỏ trốn.","chuong":"@c1561"},{"text":"Bị Vương Lâm lấy nửa hồn, kết cục được khái quát là một đời kiêu hùng nhưng chỉ là nô bộc người điên.","chuong":"@c1680"}]},"nguon":["@c1408","@c1413","@c1423","@c1424","@c1425","@c1428","@c1430","@c1435","@c1436","@c1437","@c1438","@c1439","@c1440"],"cn":"掌尊","aliases":["Phong Dư","Thủ Đồ"],"vaiTro":"Lão tổ Nguyệt Tộc, kẻ thù lớn của Vương Lâm","tinhCach":"Mưu tính thâm sâu, bày Thiên Đạo Kế và mai phục Thất Thải Giới; tàn nhẫn quyết đoán, giết Chiến Tinh Dã đoạt chiến hồn; giỏi dụ lợi mua chuộc, lôi kéo người khác ra tay; ngoài mạnh trong yếu, nhiều lần hoảng sợ trước tồn tại vượt tầm","blurb":"Chưởng Tôn là lão tổ tông Nguyệt Tộc bước thứ ba, tự xưng Chưởng Tôn Thái Cổ Tinh Thần, từng bị đạo nhân bảy màu thu phục làm sai vặt chiếm cứ giới ngoại. Hắn nhiều đời bố trí Thiên Đạo Kế, luyện Thất Thải Thần Không Đinh, liên thủ trọng thương Chủ nhân Phong Giới và phát động giới ngoại tàn sát Phong Giới theo ý chỉ Viễn Cổ Tiên Vực. Trong các lần đối đầu Vương Lâm, hắn liên tiếp bị phá cục, trọng thương, cuối cùng bị lấy nửa hồn và rơi vào luân hồi nhân quả."},{"id":"linh-dong","name":"Linh Động","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1408","importance":"bridge","mucCt":"gon","text":"Bị Vương Lâm thu vào trong Thiên Hoàng Lô cùng Chu Cẩn.","anchor":"Hai người Chu cẩn, Linh Động bị Vương Lâm thu vào trong Thiên Hoàng Lô"},{"chuong":"@c1429","importance":"bridge","mucCt":"gon","text":"Cùng Nam Vân Tử và Chu Cẩn nghênh chiến Tiên Phi áo đỏ.","anchor":"cùng với Linh Động và Chu Cẩn nghênh chiến Tiên Phi này"},{"chuong":"@c1434","importance":"bridge","mucCt":"gon","text":"Theo Nam Vân Tử rút về sửa chữa Phong Giới Đại Trận.","anchor":"dẫn theo Linh Động và Chu Cẩn nhảy vào trong Phong Giới Đại Trận, lại bắt đầu nhanh chóng sửa chữa"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Trọng thương sau trận chiến, lùi ra xa khoanh chân trị thương với thần sắc bình tĩnh","chuong":"@c1384"},{"text":"Bị Vương Lâm thu vào Thiên Hoàng Lô cùng Chu Cẩn","chuong":"@c1386"},{"text":"Cùng Nam Vân Tử và Chu Cẩn nghênh chiến Tiên Phi áo đỏ","chuong":"@c1429"},{"text":"Theo Nam Vân Tử rút về sửa chữa Phong Giới Đại Trận","chuong":"@c1434"}]},"nguon":["@c1408","@c1429","@c1434"],"vaiTro":"Tu sĩ phụ trợ — đồng hành cùng Vương Lâm trong cổ mộ Đạo Cổ","tinhCach":"Bình tĩnh khi bị trọng thương; phục tùng, không phản kháng khi bị thu phục","blurb":"Linh Động là tu sĩ từng có mặt trong cổ mộ Đạo Cổ, bị trọng thương do dư ba trận chiến giữa Vương Lâm và Thác Sâm nhưng vẫn giữ thần sắc bình tĩnh tự trị thương. Sau đó bị Vương Lâm thu vào Thiên Hoàng Lô cùng Chu Cẩn, rồi tham gia nghênh chiến Tiên Phi áo đỏ và theo Nam Vân Tử rút về sửa chữa Phong Giới Đại Trận."},{"id":"ton-linh","name":"Tôn Linh","cn":"","aliases":["lão phu nhân Tôn gia"],"gioiTinh":"nu","theLuc":[{"ten":"Tôn gia (Nhiễm Vân Tinh)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Tu sĩ (cảnh giới cụ thể chưa rõ)","trangThai":"song","vaiTro":"Lão tổ tông Tôn gia trên Nhiễm Vân Tinh, cố nhân của Vương Lâm thời Hứa Mộc","tinhCach":"Nhìn thấu sinh tử, bình thản đối diện cái chết; trọng tình nghĩa với cố nhân; cương quyết bảo hộ con cháu bằng cách cấm tu đạo","blurb":"Nữ tu sĩ đã sống hàng ngàn năm, là lão tổ tông duy nhất tu đạo của Tôn gia trên Nhiễm Vân Tinh. Năm xưa từng quen biết Vương Lâm khi hắn dùng thân phận Hứa Mộc, từng giáo huấn hắn phải chăm chỉ tu luyện mà không hay biết thực lực thật sự của đối phương. Khi đại hạn tới gần, bà triệu tập con cháu dặn dò di huấn và tái ngộ Vương Lâm lần cuối.","tabs":{"diem":[{"text":"Đại hạn đến gần, tự biết không sống quá bảy ngày, triệu tập con cháu Tôn gia dặn dò di huấn và tái ngộ Vương Lâm","chuong":"@c1409"}],"kinhLich":[{"chuong":"@c1409","importance":"major","mucCt":"ky","tieuDe":"Đại hạn tới gần, di huấn và tái ngộ Vương Lâm","text":"Đại hạn đến gần, tự biết không sống quá bảy ngày. Triệu tập con cháu Tôn gia dặn dò di huấn: đời sau tuyệt đối không tu đạo, ở phàm trần hưởng phú quý. Phóng uy áp khiến mọi người quỳ tuân mệnh. Sau đó ngồi nhìn trăng hồi tưởng cố nhân. Vương Lâm (Hứa Mộc) xuất hiện, hai người tái ngộ trò chuyện suốt đêm. Sáng hôm sau nói có sinh tất có tử, chấp nhận cái chết, nhận viên đan dược Vương Lâm trao. Nhìn Vương Lâm rời đi, hồi tưởng cảnh năm xưa giáo huấn hắn ngoài động phủ.","anchor":"lão bà đã sống hàng ngàn năm, lúc này đại hạn đã tới"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Cố nhân / bằng hữu từ thời hắn dùng thân phận Hứa Mộc","ghiChu":"Năm xưa từng giáo huấn hắn ngoài động phủ. Tái ngộ khi bản thân sắp chết, được trao đan dược."}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Viên đan dược Vương Lâm trao","trangThai":"dang-co","moTa":"Vương Lâm để lại, nuốt vào có thể kéo dài thọ mệnh. Tôn Linh chưa quyết định dùng.","nguon":"@c1409"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1409"]},{"id":"vuong-binh","name":"Vương Bình","cn":"王平","aliases":[],"gioiTinh":"nam","trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c1409","importance":"bridge","mucCt":"vua","tieuDe":"Vương Lâm tưởng niệm","text":"Vương Lâm đi lại từng nơi in dấu chân Vương Bình trên Nhiễm Vân Tinh để tưởng niệm. Hồn phách Vương Bình hiện ở trong Thiên Nghịch Châu.","anchor":"cảm nhận hồn phách của Vương Bình trong Thiên Nghịch Châu"}],"diem":[{"text":"Từ oán anh trong màn sương đen, được Vương Lâm nhận là huyết mạch ruột thịt thay vì diệt trừ.","chuong":"@c0636"},{"text":"Được Vương Lâm nuôi như con tại thôn Lạc Nguyệt, sống bằng thân phận phàm nhân yếu bệnh.","chuong":"@c0644"},{"text":"Dù nhiều lần muốn tu đạo, bị phụ thân cấm và chuyển sang học điêu khắc, sống đời phàm tục.","chuong":"@c0646"},{"text":"Theo phụ thân du ngoạn núi sông biển cả, trải qua sự thăng hoa phàm tâm trong hành trình dài.","chuong":"@c0647"},{"text":"Từ thủ lĩnh Thiên Hành phái trở thành quân chủ Thiên Hành đế quốc.","chuong":"@c0652"},{"text":"Cuối đời biết chân tướng, tha thứ cho phụ thân rồi tan thành hồn tức sau khi bị nhìn thấu là oán anh.","chuong":"@c0659"}]},"nguon":["@c1409"],"vaiTro":"Con trai duy nhất của Vương Lâm — oán anh sống đời phàm nhân","tinhCach":"hiếu thuận và quyến luyến phụ thân; nhiều lần khẩn cầu tu đạo dù bị cấm; trầm ổn trước hiểm nguy; biết tha thứ lúc cuối đời","blurb":"Vương Bình vốn là oán anh trong màn sương đen trên Nhiễm Vân Tinh, sau được Vương Lâm nhận làm huyết mạch ruột thịt và nuôi dưỡng như một phàm nhân ở thôn Lạc Nguyệt. Hắn sống một đời bên phụ thân, học điêu khắc, du ngoạn sơn xuyên, lập Thiên Hành đế quốc, rồi cuối đời bị Lôi Đạo Tử nhìn thấu thân phận oán anh và tan thành hồn tức. Sau đó Vương Bình vẫn tồn tại trong Thiên Nghịch Châu, trở thành nỗi day dứt lâu dài trong tâm thần, ký ức và nhân quả của Vương Lâm."},{"id":"dao-ton-ton-gia","name":"Đạo Tôn","cn":"","aliases":["nam tử trung niên mặc áo giáp (Tôn gia)"],"gioiTinh":"nam","theLuc":[{"ten":"Tôn gia (Nhiễm Vân Tinh)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân","trangThai":"song","vaiTro":"Hậu duệ Tôn gia trên Nhiễm Vân Tinh","tinhCach":"Hiếu thuận với lão tổ tông, hồ đồ khi mang ngự y phàm nhân chữa tu sĩ","blurb":"Con cháu Tôn gia trên Nhiễm Vân Tinh, được gọi là Đạo Tôn, phi ngựa mang ngự y tới chữa cho lão tổ tông Tôn Linh nhưng bị mắng hồ đồ.","tabs":{"diem":[{"text":"Phi ngựa mang ngự y phàm nhân tới chữa cho lão tổ tông tu sĩ, bị mắng hồ đồ","chuong":"@c1409"}],"kinhLich":[{"chuong":"@c1409","importance":"bridge","mucCt":"gon","tieuDe":"Mang ngự y chữa lão tổ tông","text":"Phi ngựa mang ngự y tới chữa cho lão phu nhân Tôn Linh, bị mắng hồ đồ rồi quỳ tuân mệnh khi bà phóng uy áp.","anchor":"lão bà đã sống hàng ngàn năm, lúc này đại hạn đã tới"}],"tuViMoc":[],"nhanMach":[{"ten":"Tôn Linh","tag":"ho-hang","quanHe":"Lão tổ tông của gia tộc","ghiChu":"Kính trọng, mang ngự y tới chữa bệnh cho bà."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1409"]},{"id":"vong-nguyet","name":"Vọng Nguyệt","tabs":{"kinhLich":[{"chuong":"@c1410","importance":"normal","mucCt":"vua","tieuDe":"Lao vào chắn hố đen U Minh Thú","text":"Được Vương Lâm triệu xuất ở thời khắc cuối cùng, thân thể khổng lồ như ngọn núi băng lao vào chắn ngang hố đen xoay tròn, đổi lấy khoảng thời gian để Vương Lâm thắp sáng tinh điểm thứ sáu và thứ bảy hoàn thành phong hồn.","anchor":"thân thể khổng lồ của Vọng Nguyệt như một ngọn núi băng ầm ầm lao ra, bay thẳng về phía hố đen xoay tròn kia!"},{"chuong":"@c1412","importance":"bridge","mucCt":"gon","text":"Thân thể khổng lồ được U Minh Thú phun ra, bành trướng hóa thành ngọn núi lớn như trước đây.","anchor":"trong tiếng ầm ầm, thân thể khổng lồ của Vọng Nguyệt nhanh chóng bị phun ra"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1410","@c1412"],"trangThai":"song","cn":"望月","gioiTinh":"khac"},{"id":"lao-dao-that-thai-gioi","name":"Lão đạo (Thất Thải Giới)","cn":"","aliases":["Thân ảnh từ Thất Thải Giới"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"khong-ro","blurb":"Nhân vật bí ẩn quần áo rách rưới chui ra từ khe Thất Thải Giới trong cấm địa sương mù, hoảng sợ chạy lại vào khi thấy U Minh Thú.","vaiTro":"Nhân vật xuất hiện trong hồi ức về quá khứ U Minh Thú, danh tính chưa rõ","tinhCach":[{"text":"Mừng rỡ cuồng nhiệt khi thoát ra, hoảng sợ cực độ khi thấy U Minh Thú, chửi rủa bất lực"}],"tabs":{"diem":[{"text":"Hai lần chui ra từ khe Thất Thải Giới, cả hai lần đều hoảng sợ chạy lại vào khi thấy U Minh Thú chặn ngoài","chuong":"@c1410"},{"text":"Hai lần thoát ra từ khe Thất Thải Giới nhưng thấy U Minh Thú liền hoảng sợ chui ngược lại vào, cuối cùng bị nuốt luôn","chuong":"@c1410"}],"kinhLich":[{"chuong":"@c1410","importance":"normal","mucCt":"vua","tieuDe":"Hai lần thoát khe Thất Thải — bị U Minh Thú nuốt luôn","text":"Lần đầu chui ra từ khe nứt bảy màu reo vui được tự do, nhưng thấy U Minh Thú thì hét thảm thiết chui lại vào. Trăm năm sau lại thò đầu ra, thấy U Minh Thú vẫn ngồi đó, chửi rồi lại chui vào. Năm trăm năm sau U Minh Thú đói nuốt luôn cả khe nứt Thất Thải Giới.","anchor":"rốt cuộc là đã ra được rồi, rốt cuộc đã ra khỏi cái chồ chết giẫm này rồi, lão đạo rốt cuộc cũng được tự do!"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1410"]},{"id":"minh-chi-gia","name":"Minh Chí Giả","tabs":{"kinhLich":[{"chuong":"@c1410","importance":"normal","mucCt":"gon","tieuDe":"Xuất hiện từ hồn khẩu U Minh Thú cùng Thất Thải","text":"Hàng loạt thân ảnh hư ảo Minh Chí Giả bay ra từ hồn khẩu U Minh Thú giữa ánh sáng bảy màu Thất Thải, niệm kinh «minh chí, theo phong thiên đạo…».","anchor":"rốt cuộc là đã ra được rồi, rốt cuộc đã ra khỏi cái chồ chết giẫm này rồi, lão đạo rốt cuộc cũng được tự do!"},{"chuong":"@c1411","importance":"bridge","mucCt":"gon","text":"Bị bia đá Đạo Kinh thao túng, xoay thành lốc xoáy tấn công Vương Lâm đẩy hắn lùi ba bước, sau đó biến mất cùng U Minh Thú khi thú tàng hình.","anchor":"những Minh Chí giả ở bốn phía dường như nổi giận, truyền ra những tiếng gào thét"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Hiện thân qua âm thanh quỷ dị và hư ảnh trong sương mù, xuyên qua Thương Tùng Tử; có đạo cảnh nhưng không có Đạo Kinh","chuong":"@c1118"},{"text":"Bị chấn động từ vụ nổ vùng giao chiến kinh động, đồng loạt phóng về nơi phát ra tiếng nổ","chuong":"@c1121"},{"text":"Hàng loạt thân ảnh hư ảo bay ra từ hồn khẩu U Minh Thú giữa ánh sáng bảy màu Thất Thải, niệm kinh","chuong":"@c1410"},{"text":"Bị bia đá Đạo Kinh thao túng, xoay thành lốc xoáy tấn công Vương Lâm đẩy hắn lùi ba bước, sau đó biến mất","chuong":"@c1411"}]},"nguon":["@c1410","@c1411"],"trangThai":"khong-ro","gioiTinh":"khong-ro","vaiTro":"Tàn lưu đạo hồn hư ảo — tồn tại bí ẩn gắn liền bí mật Đạo Kinh","tinhCach":"chấp niệm mãnh liệt với Đạo Kinh; hành động theo bản năng, bị ngoại lực dễ dàng kinh động và dẫn dắt","blurb":"Minh Chí Giả là những tồn tại hư ảo mang đạo cảnh nhưng không sở hữu Đạo Kinh, xuất hiện dưới dạng thân ảnh quỷ dị trong vùng sương mù của thế giới bảy màu. Chúng gắn liền với chấp niệm đạo hồn, có thể bị bia đá Đạo Kinh thao túng và từng đồng loạt hiện thân từ hồn khẩu U Minh Thú giữa ánh sáng Thất Thải."},{"id":"u-minh-thu","name":"U Minh Thú","cn":"幽冥兽","aliases":["Vu Minh Thú","Văn Thú","U Minh thú"],"gioiTinh":"khong-ro","canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1410","importance":"major","mucCt":"ky","tieuDe":"Bị Vương Lâm phong ấn — lộ Thất Thải Giới và Đạo Kinh","text":"Đang ngủ trong cấm địa sương mù La Thiên bị Vương Lâm bất ngờ phong ấn bên ngoài. Tỉnh giấc hung hãn nghênh chiến thay vì bỏ chạy, lộ cơ trí giả vờ hoảng sợ bỏ chạy rồi đột ngột xoay lại triển khai thần thông cắn nuốt — há miệng hơn mười vạn trượng, triệu hồn phách cỡ cả tinh vực, lực hút nuốt cả tu chân tinh hoang dã. Hút được Linh Động Thượng Nhân, Chu Cẩn, Cổ Tức Diệp, Vọng Nguyệt vào thế giới bên trong cơ thể. Bị Vương Lâm dùng bảy tinh điểm cổ Thần khắc vào hồn khẩu phong ấn hồn phách. Nhưng ngay sau đó ánh sáng Thất Thải bùng lên từ hồn khẩu phá hủy hơn phân nửa phong ấn ngoài và dập tắt ba trong bảy tinh điểm — lộ ra trong ngàn năm qua đã nuốt một phần Thất Thải Giới. Minh Chí Giả bay ra niệm kinh và xuất hiện tấm bia đá khắc chữ Đạo Kinh.","anchor":"U Minh Thú ngàn năm không há miệng, mỗi một lần há miệng thời gian lưu chuyển!"},{"mucCt":"ky","text":"Hồn phách bị bia đá Đạo Kinh ảnh hưởng, thêm hai tinh điểm trên hồn bị dập tắt, chỉ còn hai. Hồn khẩu dung nhập vào bản thể. Sinh sợ hãi mãnh liệt vì phong ấn chưa tiêu tan hết, thi triển thần thông tàng hình biến mất khỏi tinh không cùng toàn bộ Minh Chí Giả và Đạo Kinh. Bị Vương Lâm luyện hóa tinh không co rút còn ba trăm vạn trượng, sương độc bao phủ khiến không thể duy trì tàng hình, bị bức hiện nguyên hình. Vương Lâm xông tới vỗ tay lên phong ấn chỉ còn một tia trên đầu.","anchor":"thân thể của U Minh Thú với tốc độ mắt thường có thể nhìn thấy đang dần trở nên mơ hồ","bridge":true,"khoang":"@c1411"},{"chuong":"@c1412","importance":"major","mucCt":"ky","tieuDe":"Bị Vương Lâm thu phục làm bổn mệnh thú","text":"Bị Vương Lâm hoàn thành ba tầng phong ấn: phong ngoài, hồn phong bằng bảy tinh điểm Cổ Thần, phong ấn máu thịt bằng cấm chế Cổ Thần lực. Bị quất 100 roi Côn Cực Tiên, hồn bị ép bay ra khỏi cơ thể; miệng bị xé mở để phong ấn máu thịt nội tạng. Hoàn thành phong ấn, cúi đầu thần phục, truyền sức sống vô biên cho Vương Lâm. Bị Vương Lâm đọc toàn bộ ký ức — ký ức hỗn loạn, không biết mình sinh ra thế nào, rõ nhất chỉ là cảnh Thất Thải Giới mấy trăm năm trước. Nhả ra Linh Động Thượng Nhân, Chu Cẩn, Cổ Tức Diệp, Vọng Nguyệt và một Đạo Quả màu cam. Sau khi mất Đạo Quả trở lại ngơ ngác nhưng thông minh hơn trước.","anchor":"trong đầu lại trở nên ngơ ngác"},{"chuong":"@c1419","importance":"major","mucCt":"ky","tieuDe":"Nuốt trọn cuồng phong chuông vàng cứu Vân Hải","text":"Được Vương Lâm triệu ra qua tinh điểm thứ hai trên mi tâm. Theo lệnh mở U Minh Hồn Khẩu khổng lồ đủ nuốt cả tinh không, hút trọn cuồng phong màu vàng. Sau khi nuốt xong còn nhấm nháp thưởng thức, rồi ngẩn người nhìn Vương Lâm, dần lộ vẻ hoang mang sợ hãi vì bị mọi người nhìn chằm chằm, phát tiếng gầm nhẹ buồn bực.","anchor":"Hồn khẩu này rất lớn, đủ để nuốt lấy cả tinh không"},{"chuong":"@c1420","importance":"normal","mucCt":"vua","tieuDe":"Bộc lộ tính cách cổ quái, uy hiếp tu sĩ bốn phía","text":"Sợ hãi khi bị tu sĩ nhìn chằm chằm, vọt về nép vào Vương Lâm như hài tử nép vào cha mẹ. Sau khi được trấn an qua tâm thần, bộc phát tính cách dữ tợn — mọc lông dựng đứng, gầm rống uy hiếp tu sĩ bốn phía. Lực va chạm khi cọ đầu vào Vương Lâm ngang tu sĩ bước thứ ba, khiến mọi người dập tắt tham niệm thu phục.","anchor":"lực va chạm của u Minh thú này cũng có thể đánh lui Vương Lâm"},{"importance":"bridge","mucCt":"gon","chuong":"@c1421","tieuDe":"Gầm thét dọa tu sĩ rồi hoảng sợ chạy theo Vương Lâm","text":"Tiếp tục gầm thét dữ tợn hướng đám tu sĩ nhưng không nhận ra Vương Lâm đã rời đi, khi quay đầu kinh hãi run rẩy chạy theo chủ, sau đó đứng bên cạnh lại dựng lông uy vũ nhưng luôn liếc Vương Lâm sẵn sàng lui.","anchor":"ánh mắt lộ vé sợ hãi và tủi thân vô cùng"},{"importance":"bridge","mucCt":"gon","chuong":"@c1422","text":"Được Nam Vân Tử nêu vấn đề cần quan sát thêm do từng nuốt cơn lốc màu vàng, theo Vương Lâm rời Thần Tông.","anchor":"U Minh thú này có hơi khác biệt so với trí nhớ của lão phu"},{"importance":"bridge","mucCt":"gon","chuong":"@c1433","tieuDe":"Văn thú tràn chiến trường","text":"Mấy vạn Văn thú gầm thét chuyển động theo biển độc trên chiến trường Vân Hải tinh vực, lao về phía tu sĩ giới ngoại.","anchor":"mấy vạn Văn thú dữ tợn gầm thét, chuyển động theo biển độc"},{"chuong":"@c1437","importance":"bridge","mucCt":"gon","text":"Được nhắc với vai trò bổn mệnh thú của Vương Lâm, sức sống tương thông giúp Vương Lâm mở Cổ Tán không mất hơn chín phần tuổi thọ.","anchor":"Nếu lúc trước không phải hắn đã thu phục được U Minh Thú làm bổn mệnh thú, sức sống tương thông"},{"mucCt":"ky","text":"Vì sinh mệnh gắn liền Vương Lâm, đau đớn truyền vào tâm thần khiến tỉnh dậy từ giấc ngủ. Phun ra cơn cuồng phong màu vàng chưa tiêu hóa kịp, sức mạnh hủy diệt cả tinh vực, khiến Phong Giới Đại Trận sụp đổ phạm vi lớn, Thái Cổ Tinh Thần giới ngoại sụp đổ, tạo hố đen khổng lồ. Cuồng phong tiêu diệt điện chủ Thiên Phạt Điện. Sau đó nuốt Vương Lâm cùng cây cung vào miệng rồi tàng hình biến mất.","anchor":"con U Minh Thú đang ngủ say đột nhiên tỉnh lại","bridge":true,"khoang":"@c1439"},{"chuong":"@c1440","importance":"bridge","mucCt":"gon","text":"Tàng hình trốn trong khu vực đá vụn hỗn độn cực bắc Côn Hư Tinh Vực, bị cơn cuồng phong hủy diệt dọa sợ vỡ mật, thà chết không chịu ra ngoài.","anchor":"Nó cảm thấy thế giới bên ngoài rất đáng sợ, cực kỳ đáng sợ."},{"importance":"normal","mucCt":"ky","chuong":"@c1449","tieuDe":"Lần đầu hù dọa kẻ khác và phối hợp diễn kịch","text":"Nhận ra người điên là kẻ năm xưa từng khiến nó kinh hãi, hồn truyền ra tiếng gào rít run rẩy. Nhưng nhờ có Vương Lâm ở bên, tính cách dữ tợn chiếm ưu thế, lao tới hù dọa người điên, lần đầu trong đời trải nghiệm cảm giác dọa người khác chạy. Nhận thần niệm từ Vương Lâm, phối hợp diễn kịch giả vờ truy đuổi. Khi Vương Lâm thi triển Phần Giới cổ Tán, thân thể sững lại, mắt lộ vẻ sợ hãi. Cuối cùng đóng vai thú đã thuần phục, thân mật dụi đầu vào tay Vương Lâm.","anchor":"Cả đời nó đều bị người khác dọa chạy, chưa bao giờ được cảm nhận niềm vui được hù dọa người khác"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Chủ nhân triệu hồi qua tinh điểm trên mi tâm"},{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Chủ nhân","ghiChu":"Nghe theo thần niệm của Vương Lâm, phối hợp diễn kịch"},{"ten":"Người điên","tag":"khac","quanHe":"Kẻ từng khiến nó kinh hãi năm xưa","ghiChu":"Nhận ra người điên là người năm xưa, hồn gào rít; lần này ngược lại hù dọa được hắn"}],"tuViMoc":[],"diem":[{"text":"Bị Vương Lâm hoàn thành ba tầng phong ấn (phong ngoài, hồn phong bằng bảy tinh điểm Cổ Thần, phong ấn máu thịt), thu phục làm bổn mệnh thú","chuong":"@c1412"},{"text":"Mở U Minh Hồn Khẩu khổng lồ nuốt trọn cuồng phong chuông vàng, cứu nguy Vân Hải","chuong":"@c1419"},{"text":"Bộc lộ bản tính cổ quái — vọt về nép vào Vương Lâm như hài tử nép cha mẹ khi bị tu sĩ nhìn chằm chằm","chuong":"@c1420"},{"text":"Tái xuất huyễn hóa hư ảnh khổng lồ thôn phệ mãnh thú viễn cổ, bao trùm Vô Danh Chuyển Luân trận","chuong":"@c1576"},{"text":"Phóng sương mù thiên đạo tràn ngập tinh không, lực hút kinh thiên nuốt gần hết tiên nhân","chuong":"@c1633"},{"text":"Được xác nhận là một bộ phận của Vương Lâm, sinh mệnh và sức sống tương thông với chủ nhân","chuong":"@c1631"}]},"nguon":["@c1411","@c1412","@c1410","@c1419","@c1420","@c1421","@c1422","@c1432","@c1433","@c1437","@c1439","@c1440","@c1449"],"vaiTro":"Bổn mệnh thú của Vương Lâm — linh thú cổ quái sở hữu U Minh Hồn Khẩu","tinhCach":"Hung hãn dữ tợn khi chiến đấu, uy lực kinh người; nhút nhát cổ quái, run rẩy sợ hãi khi bị đám đông chú ý, nép vào Vương Lâm như hài tử nép cha mẹ; tham ăn, nuốt cuồng phong rồi nhấm nháp thưởng thức","blurb":"Linh thú khổng lồ vốn ngủ trong cấm địa sương mù La Thiên, bị Vương Lâm hoàn thành ba tầng phong ấn thu phục làm bổn mệnh thú, sinh mệnh từ đó gắn liền chủ nhân. Sở hữu U Minh Hồn Khẩu uy lực đủ nuốt cả tinh không, từng nuốt trọn cuồng phong chuông vàng cứu nguy Vân Hải, huyễn hóa hư ảnh khổng lồ thôn phệ mãnh thú viễn cổ, và phóng sương mù thiên đạo nuốt gần hết tiên nhân. Dẫu uy mãnh vô song, nó lại run rẩy sợ hãi mỗi khi bị người khác nhìn chằm chằm, bộc lộ bản tính vừa dữ tợn vừa ngờ nghệch."},{"id":"co-tuc-diep","name":"Cổ Tức Diệp","cn":"古息叶","aliases":[],"gioiTinh":"khong-ro","trangThai":"song","vaiTro":"Pháp bảo linh tính thuộc sở hữu của Vương Lâm","tinhCach":"Không rõ (vật phẩm linh tính)","blurb":"Cổ Tức Diệp là một loại pháp bảo linh tính do Vương Lâm sở hữu, gồm hơn mười lá. Chúng từng bị Vương Lâm ném vào hố đen thế giới thần thông của U Minh Thú nhằm chặn lực hút, sau đó được U Minh Thú phun trả ra ngoài theo lệnh của Vương Lâm.","tabs":{"diem":[{"text":"Hơn mười lá bị Vương Lâm ném vào hố đen xoay tròn của U Minh Thú để chặn lực hút","chuong":"@c1410"},{"text":"Được U Minh Thú phun ra cùng lúc với Chu Cẩn theo lệnh Vương Lâm","chuong":"@c1412"}],"kinhLich":[{"chuong":"@c1410","importance":"normal","mucCt":"gon","tieuDe":"Bị ném vào hố đen U Minh Thú","text":"Toàn bộ hơn mười lá được Vương Lâm ném vào hố đen xoay tròn (thế giới thần thông U Minh Thú) để chặn lực hút, đổi thời gian thắp sáng tinh điểm thứ năm.","anchor":"toàn bộ cổ Tức Diệp bay ra, lao thẳng tới thế giới thần thông như cái hố đen xoay tròn kia!"},{"mucCt":"gon","text":"Được U Minh Thú phun ra cùng lúc với Chu Cẩn theo lệnh Vương Lâm.","anchor":"Chu cẩn và cổ Tức Diệp cũng lần lượt được phun ra","bridge":true,"khoang":"@c1412"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Chủ nhân","ghiChu":"Thuộc sở hữu của Vương Lâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1412","@c1410"]},{"id":"tu-si-mac-ket-u-minh-thu","name":"Tu sĩ mắc kẹt trong U Minh Thú","aliases":["lão đạo"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một tu sĩ tự xưng lão đạo, bị mắc kẹt bên trong thế giới thần thông của U Minh Thú suốt mấy trăm năm kể từ khi Thất Thải Giới sụp đổ, vẫn kiên trì tìm đường ra.","vaiTro":"Tu sĩ bí ẩn bị kẹt trong U Minh Thú, chưa rõ danh tính","tinhCach":"Kiên trì; lạc quan tự khích lệ","tabs":{"diem":[{"text":"Bị mắc kẹt trong thế giới thần thông U Minh Thú mấy trăm năm từ khi Thất Thải Giới sụp đổ, vẫn cắn răng tìm đường ra.","chuong":"@c1413"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1413","tieuDe":"Mắc kẹt trong U Minh Thú","text":"Bị mắc kẹt bên trong thế giới thần thông vô biên của U Minh Thú suốt mấy trăm năm kể từ khi Thất Thải Giới sụp đổ, không tìm được đường ra. Tự khích lệ bản thân kiên trì tìm kiếm, chính là người từng bị U Minh Thú hù dọa hai lần.","anchor":"Con mãnh thú này quả thật là kiên nhẫn, đợi lão đạo suốt mấy trăm năm"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1413"]},{"id":"thai-a-la","name":"Thái A La","cn":"泰阿拉","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thái A La là vua mãnh thú đã hóa hình người, bị Thủy Đạo Tử phong ấn từ lâu và buộc phải phục tùng đổi lấy tự do trở về cố hương. Sau này hắn xuất hiện tại Vân Hải Tinh Vực, xả thân chắn mũi tên cho Vương Lâm và phối hợp cùng các cao thủ giới nội chiến đấu.","vaiTro":"Vua mãnh thú hóa hình người, bị phong ấn và sai khiến bởi Thủy Đạo Tử","tinhCach":"Cam chịu phục tùng khi bị ép buộc; trọng nghĩa xả thân","tabs":{"diem":[{"text":"Bị Thủy Đạo Tử sai giết người, hứa cho trở về cố hương, thân phận là vua mãnh thú đã hóa hình","chuong":"@c1414"},{"text":"Tự xưng tu sĩ hóa hình, xuất hiện quỳ dị từ không trung trước đương kim","chuong":"@c1418"},{"text":"Bị Hồng Sam Tử quyết định chỉ giải một nửa phong ấn, đợi sau cuộc chiến mới giải nốt","chuong":"@c1422"},{"text":"Xả thân chắn mũi tên cho Vương Lâm, xuất hiện dưới dạng nam tử trung niên chân đất từ Vân Hải Tinh Vực","chuong":"@c1437"},{"text":"Phối hợp cùng các cao thủ giới nội tấn công bàn tay khổng lồ","chuong":"@c1438"}],"kinhLich":[{"chuong":"@c1414","importance":"normal","mucCt":"vua","tieuDe":"Bị Thủy Đạo Tử sai giết người đổi tự do","text":"Thủy Đạo Tử ra lệnh cho hắn giúp giết một người, hứa cho trở về cố hương. Hắn là vua mãnh thú đã hóa hình, bị phong ấn từ vô số năm trước.","anchor":"Thái A La ngươi thân là vua của mãnh thú đã hóa thành hình người, vô số năm trước bị Thủy Đạo Tử ta phong ấn"},{"mucCt":"vua","text":"Xuất hiện quỳ dị từ không trung bị hủy diệt khi Thủy Đạo Tử gào tên, tự xưng tu sĩ hóa hình bái kiến đương kim Chủ nhân phong giới Vương Lâm. Đề nghị nếu Vương Lâm giải phong ấn trên thân hắn, hắn sẽ dẫn bộ tộc trong khe Vân Hải đánh giới ngoại, thậm chí cho phép giết Thủy Đạo Tử.","anchor":"Tu sĩ hóa hình, Thái A La, bái kiến đương kim Chủ nhân phong giới","bridge":true,"khoang":"@c1418"},{"chuong":"@c1419","importance":"bridge","mucCt":"gon","text":"Lơ lửng trên bầu trời sắc mặt đại biến, phát tiếng gầm nhẹ hai tay ấn về phía trước ngăn cuồng phong.","anchor":"Thái A La lơ lửng trên bầu trời sắc mặt cũng đại biến"},{"importance":"bridge","mucCt":"gon","chuong":"@c1422","text":"Bị Hồng Sam Tử quyết định phong ấn tạm chỉ giải một nửa, đợi sau cuộc chiến mới giải nốt, nhướng mày trầm mặc rồi gật đầu đồng ý.","anchor":"Nhưng như thế còn không đủ. Ngươi vốn là chủ nhân phong giới, nên chuẩn bị tốt, cùng lão phu, cùng cả giới nội chuẩn bị chết trận."},{"chuong":"@c1437","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện xả thân chắn mũi tên cho Vương Lâm","text":"Mãnh thú vốn bị Phong Tôn phong ấn, bất ngờ xuất hiện từ Vân Hải Tinh Vực dưới dạng nam tử trung niên chân đất. Xả thân chắn mũi tên thứ hai, dùng toàn thân vảy đen nhạt và lá chắn ba vảy vàng cầm cự đúng ba nhịp thở, hai tay vỡ nát rồi cười khổ tránh ra.","anchor":"Ta chỉ có thể cầm cự cho ngươi ba nhịp thở!"},{"chuong":"@c1438","importance":"bridge","mucCt":"gon","text":"Đồng thời ra tay cùng các cao thủ giới nội phối hợp tấn công bàn tay khổng lồ.","anchor":"Có thể nói tất cả những cao thủ của giới nội ở đây lúc này, toàn bộ đều trong khoảng khắc này bộc phát ra sức mạnh lớn nhất"}],"tuViMoc":[],"nhanMach":[{"ten":"Thủy Đạo Tử","tag":"khac","quanHe":"Người phong ấn hắn, sai giết người đổi tự do","ghiChu":"@c1414"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Bái kiến Vương Lâm là Chủ nhân phong giới, đề nghị giải phong ấn đổi dẫn bộ tộc đánh giới ngoại","gap":"@c1418"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người được bảo vệ","ghiChu":"Xả thân chắn mũi tên cung cổ cho Vương Lâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1414","@c1418","@c1419","@c1422","@c1437","@c1438"]},{"id":"chu-duc","name":"Chu Đức","cn":"朱德","aliases":["Lão già áo đen"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Bước thứ ba","trangThai":"song","blurb":"Lão già hắc bào tu luyện lâu năm trong dòng xoáy hiểm địa Triệu Hà, da đen kịt như chứa kịch độc. Nhận lời Thủy Đạo Tử ra tay một lần đổi lấy lục phẩm đạo linh, song phân thân bị Linh Động đánh bại, cuối cùng phải cười khổ tham kiến Vương Lâm là Phong Tôn.","vaiTro":"Đại năng ẩn cư Triệu Hà, trợ thủ thuê của Thủy Đạo Tử","tinhCach":"Tính toán thực dụng, hành sự vì lợi ích; biết lượng sức, sẵn sàng lui bước khi thế yếu; tham lam nhưng không mù quáng","tabs":{"diem":[{"text":"Nhận lời Thủy Đạo Tử, đổi một lần ra tay lấy lục phẩm đạo linh","chuong":"@c1414"},{"text":"Phân thân ngưng tụ giáp công Vương Lâm, bị Linh Động Thượng Nhân đánh bại","chuong":"@c1417"},{"text":"Chứng kiến Vương Lâm áp đảo Thủy Đạo Tử, sợ hãi ngầm trách đồng minh","chuong":"@c1418"},{"text":"Nổi tham niệm muốn thu phục U Minh thú nhưng thấy lực quá kinh khủng liền từ bỏ","chuong":"@c1420"},{"text":"Cười khổ tham kiến Vương Lâm là Phong Tôn, quy phục thế lực","chuong":"@c1422"}],"kinhLich":[{"chuong":"@c1414","importance":"normal","mucCt":"vua","tieuDe":"Nhận lời trợ giúp Thủy Đạo Tử","text":"Nhận con hạc của Thủy Đạo Tử trong dòng xoáy hiểm địa Triệu Hà. Đồng ý ra tay một lần đổi lấy lục phẩm đạo linh.","anchor":"Thủy Đạo Tử là hạng người keo kiệt, lần này dùng lục phẩm đạo linh đổi lấy việc lão phu ra tay, không biết là gặp phải đại địch gì"},{"chuong":"@c1417","importance":"normal","mucCt":"ky","tieuDe":"Phân thân xuất hiện giáp công Vương Lâm, bị Linh Động đánh bại","text":"Phân thân ngưng tụ trong bóng tối, tuyên bố nhận tiền Thủy Đạo Tử chỉ giúp một lần, mục đích đoạt lục phẩm đạo linh từ Vương Lâm. Thi triển biển bùn lầy vô hạn cùng Thủy Đạo Tử hai hướng giáp công. Bị Linh Động Thượng Nhân tung tử hải và tượng Ma Thần phá tan biển bùn lầy, phun nguyên thần khí chấn động lui lại.","anchor":"Nhận tiền của người, cứu người khòi tai họa. Thủy Đạo Tử, ngươi đừng quên thứ đã hứa với lão phu"},{"importance":"bridge","mucCt":"gon","chuong":"@c1418","tieuDe":"Hoảng sợ trách Thủy Đạo Tử","text":"Đang giao chiến với Linh Động Thượng Nhân, chứng kiến Vương Lâm áp đảo Thủy Đạo Tử, sợ hãi ngầm trách Thủy Đạo Tử hại mình.","anchor":"Đều là tên Thủy Đạo Tử này hại người!"},{"chuong":"@c1419","importance":"bridge","mucCt":"gon","text":"Cùng Vân Phong Tử sắc mặt tái nhợt lao tới hợp lực ngăn cuồng phong chuông vàng nhưng bất thành.","anchor":"Chu Đức và Vân Phong Tử kia hai người sắc mặt tái nhợt"},{"chuong":"@c1420","importance":"bridge","mucCt":"gon","text":"Nổi tham niệm muốn thu phục U Minh thú nhưng thấy lực va chạm quá kinh khủng liền từ bỏ.","anchor":"Thân thể lão phu dù là không kém nhưng cũng không được tới mức này"},{"importance":"bridge","mucCt":"gon","chuong":"@c1422","tieuDe":"Tham kiến Phong Tôn","text":"Lão già mặc hắc y từ Triệu Hà tinh vực, cười khổ tham kiến Vương Lâm là Phong Tôn.","anchor":"Chu Đức ở Triệu Hà tinh vực tham kiến Phong Tôn"}],"tuViMoc":[],"nhanMach":[{"ten":"Thủy Đạo Tử","tag":"khac","quanHe":"Người thuê ra tay, đổi lục phẩm đạo linh","ghiChu":"@c1414"},{"ten":"Thủy Đạo Tử","tag":"dong-minh","quanHe":"Người thuê","ghiChu":"Nhận tiền Thủy Đạo Tử đổi lấy lục phẩm đạo linh, chỉ giúp một lần"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu tấn công","ghiChu":"Giáp công Vương Lâm để đoạt lục phẩm đạo linh"},{"ten":"Linh Động Thượng Nhân","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Bị Linh Động đánh bại dễ dàng khi phân thân giao chiến"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1414","@c1417","@c1418","@c1419","@c1420","@c1422"]},{"id":"van-phong-tu","name":"Vân Phong Tử","cn":"云峰子","aliases":["Nam tử trung niên"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Vân Phong Tử là nam tử trung niên giả làm chủ hiệu cầm đồ trên tu chân tinh hoang phế tại Triệu Hà, nhận lời Thủy Đạo Tử đổi Định Thần Thuật lấy một lần ra tay. Sau khi chứng kiến sức mạnh của Vương Lâm và thất bại trước cuồng phong chuông vàng, ông thức thời tham kiến Phong Tôn xin tha tội, rồi về sau dẫn viện quân Vân Hải cùng Hồng Sam Tử tiếp viện giới nội.","vaiTro":"Đại năng ẩn cư Triệu Hà, trợ thủ thuê của Thủy Đạo Tử","tinhCach":"Vẻ ôn hòa nhưng tính toán chi li; biết lượng sức, dứt khoát từ bỏ khi bất lợi; thức thời, chủ động nhận lỗi trước cường giả","tabs":{"diem":[{"text":"Nhận con hạc của Thủy Đạo Tử tại Triệu Hà, được hứa tặng Định Thần Thuật đổi lấy một lần ra tay","chuong":"@c1414"},{"text":"Giao chiến với Chu Cẩn, bị hương hỏa áp đảo phải xuất pháp bảo đối kháng; chứng kiến Vương Lâm đánh bại đối thủ","chuong":"@c1418"},{"text":"Cùng Chu Đức hợp lực ngăn cuồng phong chuông vàng nhưng bất thành","chuong":"@c1419"},{"text":"Nổi tham niệm với U Minh thú nhưng cảm nhận lực va chạm quá mạnh liền dứt khoát từ bỏ","chuong":"@c1420"},{"text":"Thức thời tham kiến Phong Tôn, cười khổ xin tha tội đắc tội trước đây","chuong":"@c1422"},{"text":"Cùng Hồng Sam Tử dẫn mấy vạn tu sĩ Vân Hải từ tinh không tiếp viện giới nội","chuong":"@c1425"}],"kinhLich":[{"mucCt":"vua","text":"Nhận con hạc của Thủy Đạo Tử trên tu chân tinh hoang phế Triệu Hà. Được hứa tặng Định Thần Thuật của chủ nhân phong giới, tỏ ra hứng thú và đồng ý ra tay.","anchor":"Định thần thuật thú vị, thú vị!","bridge":true,"khoang":"@c1414"},{"mucCt":"vua","text":"Đang giao chiến với Chu Cẩn, bị hương hỏa áp đảo phải xuất pháp bảo đối kháng. Chứng kiến Vương Lâm đánh bại Thủy Đạo Tử, hoảng sợ, quyết định không muốn tiếp tục vụ mua bán Định Thần Thuật vì đối phương có cao thủ bước thứ ba làm nô bộc.","anchor":"Chi vì Định Thần Thuật mà đắc tội với người có cao thủ bước thứ ba làm nô bộc như thế này, vụ mua bán này, Vân Phong Tử ta không muốn làm!","bridge":true,"khoang":"@c1418"},{"chuong":"@c1419","importance":"bridge","mucCt":"gon","text":"Cùng Chu Đức sắc mặt tái nhợt lao tới hợp lực ngăn cuồng phong chuông vàng nhưng bất thành.","anchor":"Chu Đức và Vân Phong Tử kia hai người sắc mặt tái nhợt"},{"chuong":"@c1420","importance":"bridge","mucCt":"gon","text":"Nổi tham niệm với U Minh thú, nghĩ có nó sẽ vang danh thiên hạ, nhưng thấy lực va chạm liền từ bỏ, da đầu tê dại.","anchor":"Có con thú này bên cạnh, cho dù không phải là tu sĩ bước thứ ba cũng có thể vang danh thiên hạ"},{"importance":"bridge","mucCt":"gon","chuong":"@c1422","tieuDe":"Tham kiến Phong Tôn, xin tha tội","text":"Nam tử từ Triệu Hà tinh vực, cười khổ tham kiến Phong Tôn, xin tha tội đắc tội trước đây.","anchor":"Vân Phong Tử ở Triệu Hà tinh vực tham kiến Phong Tôn"},{"importance":"normal","mucCt":"gon","chuong":"@c1425","tieuDe":"Dẫn viện quân Vân Hải tiếp viện giới nội","text":"Cùng Hồng Sam Tử xuất hiện từ tinh không Vân Hải, dẫn mấy vạn tu sĩ Vân Hải tiếp viện giới nội.","anchor":"Hồng Sam Tử, Vân Phong Tử bất ngờ đi ra"}],"tuViMoc":[],"nhanMach":[{"ten":"Thủy Đạo Tử","tag":"khac","quanHe":"Người thuê ra tay, đổi Định Thần Thuật","ghiChu":"@c1414"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu tấn công lén","ghiChu":"Tấn công sau lưng Vương Lâm bằng hạt châu bàn tính"},{"ten":"Chu Cẩn","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Bị Chu Cẩn phá vỡ pháp bảo và truy kích"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1414","@c1417","@c1418","@c1419","@c1420","@c1422","@c1425"]},{"id":"moc-bang-mi","name":"Mộc Băng Mi","cn":"莫冰眉","aliases":["Liễu Mi"],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Mộc Băng Mi là Côn Hư Thánh Nữ, mẹ của Vương Bình và từng nắm quyền điều động thần thông, nguyên lực thiên địa trong Côn Hư Tinh vực. Sau biến cố Côn Hư bị Thác Sâm hủy diệt, nàng trọng thương lưu lạc tới Vân Hải, lấy thân phận Liễu Mi tái ngộ Vương Lâm rồi về Thần Tông và bị giam cầm nhiều năm. Về sau nàng được Vương Lâm phong làm tông chủ Thần Tông, tham dự phòng tuyến giới nội trong đại chiến, đồng thời được hé lộ là phách thứ sáu của Thất Thải Tiên Tôn.","vaiTro":"Côn Hư Thánh Nữ — mẹ Vương Bình, tông chủ Thần Tông","tinhCach":"Lạnh lùng quyền uy nhưng nặng tình; bất khuất trước uy hiếp; âm thầm chịu đựng chia ly; kiên định trong đại chiến","tabs":{"diem":[{"text":"Cứu Vương Lâm lúc cận tử và trực diện đối đầu Thiên Vận Tử.","chuong":"@c1010"},{"text":"Khẳng định mọi thần thông cùng nguyên lực thiên địa trong Côn Hư Tinh vực đều nằm trong tay nàng.","chuong":"@c1011"},{"text":"Sống sót sau khi Côn Hư cảnh bị Thác Sâm hủy diệt, tái ngộ Vương Lâm tại Vân Hải.","chuong":"@c1195"},{"text":"Xác nhận thân phận Liễu Mi, mẹ của Vương Bình, rồi từ biệt Vương Lâm.","chuong":"@c1196"},{"text":"Được Vương Lâm phong làm tông chủ Thần Tông.","chuong":"@c1422"},{"text":"Được nhận ra là phách thứ sáu màu lam của Thất Thải Tiên Tôn.","chuong":"@c1651"}],"kinhLich":[{"chuong":"@c1414","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Bị Thủy Đạo Tử ép nuốt đan dược ra khỏi bế quan trợ giúp, nhắc ơn từng chữa thương và khôi phục tu vi.","anchor":"Mộc Băng Mi, lão phu giúp ngươi chữa thương, giúp ngươi khôi phục tu vi, lại giúp tu vi của ngươi tiến bộ"},{"mucCt":"vua","text":"Đang bế quan trong đại trận Thần Tông, lấy ra viên đan dược Thủy Đạo Tử tặng mấy trăm năm trước — hứa giúp khôi phục tu vi nhưng phải trả giá đắt. Run rẩy cầm đan, do dự.","anchor":"Mộc Băng Mi cả đời coi trọng lời hứa","bridge":true,"khoang":"@c1415"},{"mucCt":"ky","text":"Xuất hiện trong thiên địa biến ảo do Thủy Đạo Tử triển khai, ngồi trong đại trận, áo trắng nhuốm máu. Bị Thủy Đạo Tử lén liên kết mệnh hồn qua đan dược và khôi phục tu vi mà không hay biết. Trải lòng: thừa nhận mình chính là Liễu Mi, biết giữa hai người không có kết quả vì Bình Nhi, kể Côn Hư bị hủy diệt, quê quán tàn phá, tự nhận nợ Bình Nhi nhiều, không phải người mẹ tốt, nhờ nói với Bình Nhi rằng Lý Mộ Uyển mới là mẫu thân. Muốn lấy cái chết giải gút mắc hai ngàn năm, giơ tay ấn mi tâm tự vẫn nhưng bị Vương Lâm Định Thân Thuật chế trụ. Được Vương Lâm dùng Đạo Cổ Hóa Mệnh Thuật chuyển sinh cơ Thủy Đạo Tử sang cứu sống.","anchor":"Ta muốn lấy cái chết của ta để giải thoát gút mắc hai ngàn nãm nay với ngươi.","bridge":true,"khoang":"@c1421"},{"importance":"normal","mucCt":"vua","chuong":"@c1422","tieuDe":"Được phong tông chủ Thần Tông","text":"Đang ngồi trong thiên địa hư ảo, được Vương Lâm dùng thần niệm phủ khắp thiên địa phong làm tông chủ Thần Tông. Quy Nguyên Tông dung nhập Thần Tông, toàn bộ tu sĩ tuân theo mệnh lệnh.","anchor":"cho Mộc Băng Mi trở thành tông chủ của Thần Tông"},{"chuong":"@c1440","importance":"normal","mucCt":"vua","tieuDe":"Trở thành tông chủ Thần Tông, chỉ huy phòng tuyến","text":"Nhờ một câu nói của Phong Tôn, Mộc Băng Mi trở thành tông chủ Thần Tông. Chỉ huy bày binh bố trận tạo phòng tuyến vững chắc đề phòng trận chiến thứ hai. Lo lắng nhưng kiên định tin Vương Lâm còn sống, uống thuốc trị thương, nhìn trời thì thào.","anchor":"Vì một câu nói của Phong Tôn, Mộc Băng Mi nay đã trở thành tông chủ của Thần Tông"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1414","@c1415","@c1421","@c1422","@c1440"]},{"id":"dieu-am-dao-ton","name":"Diệu Âm đạo tôn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Diệu Âm Đạo Tôn là một trong Thái Cổ Ngũ Tôn, bản thể là lão già tóc bạc ẩn tu dưới đáy hải dương ở tu chân tinh trung tâm, từng cùng Thủy Đạo Tử và Chưởng Tôn hợp lực giết chủ nhân Thần Tông năm xưa. Y lấy âm bổn nguyên đại thành phá vỡ cửa ải Không Niết lên bước thứ ba, phái phân thân thiếu niên tham gia tranh đoạt tại cổ mộ và giao chiến khốc liệt với phân hồn Đại Hoang Lão Độc để cướp tứ phẩm đạo linh. Sau đại chiến dung hợp âm–thủy, y bị trọng thương rồi bị Đại Hoang Thượng Nhân đoạt xá; mấy vạn năm sau ẩn dưới đáy tử hải ôm mối oán hận, mở mắt trở lại khi khe cổ mộ tái xuất, nhưng bị Vươ","vaiTro":"Cường giả cổ tu — một trong Thái Cổ Ngũ Tôn, bản thể ẩn tu dưới đáy hải dương","tinhCach":"Nhàn nhã phóng túng, thường nằm mây ăn đào quan sát thế cục; tham lam dã tâm, lộ rõ tham niệm khi thấy bảo vật; âm trầm khó lường, bề ngoài thiếu niên xinh xắn nhưng bản thể là lão già tóc bạc tu luyện dưới đáy hải dương","tabs":{"diem":[{"text":"Từng cùng Thủy Đạo Tử và Chưởng Tôn hợp lực giết chủ nhân Thần Tông năm xưa","chuong":"@c1193"},{"text":"Lấy âm bổn nguyên đại thành phá cửa ải Không Niết, đạt bước thứ ba; dung hợp âm–thủy đại chiến nhưng bị trọng thương gần chết, bị Đại Hoang Thượng Nhân đoạt xá","chuong":"@c1365"},{"text":"Mấy vạn năm ẩn dưới đáy tử hải ôm oán hận, mở mắt trở lại khi khe cổ mộ tái xuất","chuong":"@c1378"},{"text":"Cùng Cửu Thiên Ma Tôn và Đại Hoang Thượng Nhân hợp lực đánh Lam Mộng Đạo Tôn ba ngày, bại trận trọng thương","chuong":"@c1583"},{"text":"Bị Vương Lâm bắt gọn nguyên thần bằng mũi tên cung Lý Quảng","chuong":"@c1596"},{"text":"Tu vi giảm xuống Không Linh do bị Lam Mộng đánh trọng thương, đang trị thương dưới đáy biển thì bị Vương Lâm tuyên chiến, không còn đường thoát","chuong":"@c1697"}],"kinhLich":[{"chuong":"@c1414","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Thủy Đạo Tử tiết lộ từng báo tin Vương Lâm cho vị này ở giới ngoại.","anchor":"Ta vốn đem tin tức về hắn báo cho Diệu âm đ*o tôn ở giới ngoại rồi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1414"]},{"id":"lu-yen-phi","name":"Lữ Yên Phi","cn":"吕烟飞","aliases":["Lữ Tử Hạo"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1415","importance":"normal","mucCt":"vua","tieuDe":"Quy Nguyên Tông bị khống chế, trầm mặc chấp nhận","text":"Bị phân tông Thần Tông khống chế cùng toàn bộ Quy Nguyên Tông, chuyển tới Thần Tông cấp chín. Trầm mặc bình tĩnh, đã sớm đoán trước ngày này, không hối hận.","anchor":"Không có Lữ Tử Hạo, hay nói cách khác là không có Vương Lâm thì sẽ không có Quy Nguyên Tông ngày nay!"}],"diem":[{"text":"Mười ba tuổi bái sư, nhờ sư tôn bất chấp hao phí luyện Man Thiên Đan mà đột phá từ Khuy Niết Hậu Kỳ đại viên mãn lên Vấn Đỉnh thành công","chuong":"@c1071"},{"text":"Thu nhận bảy đệ tử trong đợt tuyển chọn toàn Mạc La, bao gồm Tằng Ngưu từ Bắc Thủy Thôn","chuong":"@c1069"},{"text":"Mang sát khí nghênh chiến Tử Đạo Tông, thề dù chết cũng không khuất phục Lô Địch, sau đó chứng kiến Vương Lâm xuất hiện giải nguy","chuong":"@c1074"},{"text":"Cắt quan hệ sư đồ, rời Quy Nguyên Tông gia nhập Vô Cực Tông, đứng trên ngọn núi nơi xưa lần đầu nói chuyện với Vương Lâm chờ đợi thân ảnh hắn","chuong":"@c1163"},{"text":"Khóc sung sướng khi Vương Lâm giáng lâm đại hội Vô Cực Tông bảo hộ, được đưa ra khán đài an toàn","chuong":"@c1184"},{"text":"Bị phân tông Thần Tông khống chế cùng toàn bộ Quy Nguyên Tông, trầm mặc bình tĩnh chấp nhận","chuong":"@c1415"}]},"nguon":["@c1415"],"vaiTro":"Đại trưởng lão Quy Nguyên Tông — phụ nữ duy nhất trong bốn đại trưởng lão, sư phụ danh nghĩa của Vương Lâm","tinhCach":"Trọng ân nghĩa, khắc ghi di ngôn sư tôn và luôn nhớ ơn người giúp mình; kiên cường quyết liệt, thề chết không khuất phục kẻ thù; cung kính lễ độ trước Vương Lâm, tự nguyện nhường vị thế; trung thành gắn bó với tông môn, bảo vệ đệ tử không chùn bước","blurb":"Lữ Yên Phi là đại trưởng lão Quy Nguyên Tông, từ năm mười ba tuổi bái sư, tu vi từ Khuy Niết Hậu Kỳ đại viên mãn đột phá Vấn Đỉnh nhờ Man Thiên Đan do sư tôn bất chấp hao phí tự luyện. Nàng thu nhận bảy môn hạ trong đó có Tằng Ngưu (Vương Lâm), cung kính trao cho hắn thân phận Lữ Tử Hạo làm sư thúc tổ Quy Nguyên Tông, trải qua thời kỳ tông môn suy yếu bị Tử Đạo Tông ức hiếp và biến cố tại đại hội Vô Cực Tông. Sau khi cắt quan hệ sư đồ rời Quy Nguyên Tông gia nhập Vô Cực Tông, nàng được Vương Lâm bảo hộ rồi triệu tập dẫn toàn bộ đệ tử rút về Mạc La đại lục, cuối cùng bị phân tông Thần Tông khốn"},{"id":"tong-chu-pha-thien-tong","name":"Tông chủ Phá Thiên Tông","gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1415","importance":"bridge","mucCt":"gon","text":"Lê thân thể già nua, thở dài, vẻ bình tĩnh, hướng về Thần Tông mà đi.","anchor":"tông chủ Phá Thiên tông lê thân thể già nua, thần sắc phức tạp"}]},"nguon":["@c1415"]},{"id":"dai-hu-quy-tong","name":"Đại Hư (Quỷ Tông)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quỷ Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Lão già thanh y tại sơn môn Quỷ Tông cấp mười hai trong Vân Hải tinh vực. Nhận được thông điệp có kẻ muốn dùng năm triệu âm dương môn đồ đổi lấy yêu thánh Quỷ Tông ra tay.","vaiTro":"Nhân vật tại Quỷ Tông, nhận tin giao dịch yêu thánh","tinhCach":"Trầm tĩnh","tabs":{"diem":[{"text":"Lão già thanh y đả tọa tại Quỷ Tông cấp mười hai, lửa ma trơi vờn quanh, nhận tin năm triệu âm dương môn đồ đổi yêu thánh ra tay","chuong":"@c1415"}],"kinhLich":[{"mucCt":"gon","text":"Đang đả tọa tại sơn môn Quỷ Tông, nhận được thông điệp con hạc sương khói — có kẻ muốn dùng năm triệu âm dương môn đồ đổi lấy yêu thánh Quỷ Tông ra tay.","anchor":"Đại Hư của Quỷ Tông, ta nguyện lấy năm triệu âm dương môn đồ tặng cho Yêu thánh","bridge":true,"khoang":"@c1415"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1415"]},{"id":"nu-tu-hu-ao-trieu-ha","name":"Nữ tử hư ảo (Triệu Hà tinh vực)","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tử toàn thân hư ảo, tóc dài phủ quá eo, đả tọa trên đỉnh núi mây mù ở Triệu Hà tinh vực. Nhận ra Vương Lâm là quân cờ của chưởng tôn.","vaiTro":"Nhân vật bí ẩn ở Triệu Hà tinh vực","tinhCach":"Bí ẩn; bình thản","tabs":{"diem":[{"text":"Toàn thân hư ảo, tóc dài phủ quá eo, nhận xét Vương Lâm là quân cờ của chưởng tôn","chuong":"@c1415"}],"kinhLich":[{"chuong":"@c1415","importance":"normal","mucCt":"gon","tieuDe":"Nhận xét Vương Lâm là quân cờ chưởng tôn","text":"Mở mắt trên đỉnh núi mây mù ở Triệu Hà tinh vực, nhận xét Vương Lâm là quân cờ của chưởng tôn.","anchor":"Vương Lâm quân cờ của chưởng tôn"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1415"]},{"id":"nam-tu-thanh-y-trieu-ha","name":"Nam tử thanh y (Triệu Hà tinh vực)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Đang tìm thứ gì đó ở Triệu Hà tinh vực theo lời Mã sư bá. Nhận ra Vương Lâm là tiểu tử năm đó, tỏ vẻ thú vị.","vaiTro":"Nhân vật bí ẩn ở Triệu Hà tinh vực, quen biết Vương Lâm từ trước","tinhCach":"Thú vị; tò mò","tabs":{"diem":[{"text":"Nhận ra Vương Lâm là tiểu tử năm đó, tỏ vẻ thú vị, đang tìm vật gì đó theo lời Mã sư bá","chuong":"@c1415"}],"kinhLich":[{"mucCt":"gon","text":"Đang tìm thứ gì đó ở Triệu Hà tinh vực theo lời Mã sư bá, nhận ra Vương Lâm là tiểu tử năm đó, tỏ vẻ thú vị.","anchor":"Vương Lâm này không phải là tiểu tử năm đó sao thú vị, thú vị!","bridge":true,"khoang":"@c1415"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1415"]},{"id":"thien-van-tu","name":"Thiên Vận Tử","cn":"天运子","aliases":[],"gioiTinh":"nam","trangThai":"tu-vong","tabs":{"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Cưỡi tảng đá khổng lồ như sao băng đi qua Chu Tước tinh, lần đầu xuất hiện với sức mạnh ước lượng vượt Hóa Thần","chuong":"@c0241"},{"text":"Nhận Vương Lâm làm đệ tử chân chính, mở tâm thần chứa 3600 phân thân cho Vương Lâm tự chọn thần thông cấm pháp","chuong":"@c0474"},{"text":"Thi triển Dẫn Tiên thuật cuốn hơn vạn đệ tử Đại La Kiếm Tông, thể hiện thực lực áp đảo trong đại thọ vạn năm","chuong":"@c0468"},{"text":"Chủ động hiến hồn để đoạt cấm chế bổn nguyên của Vương Lâm, tiết lộ Luân Hồi Toàn Thể Thuật là âm mưu hai ngàn năm","chuong":"@c1624"},{"text":"Bị phơi bày chân tướng: không phải Thất Thải Tiên Tôn mà là thực thể nguyên thủy thuộc Thiên Đạo, bổn tôn là nửa nghịch la bàn","chuong":"@c1628"},{"text":"Hoàn thành thức tỉnh thứ chín mươi chín, chiếm cứ phân thân Vương Lâm nhưng bị đoạt bổn tôn và tiêu diệt hoàn toàn","chuong":"@c1629"}]},"nguon":["@c1416"],"vaiTro":"Chưởng môn Thiên Vận Tông — bộ phận Thiên Đạo, bổn tôn là nửa nghịch la bàn","tinhCach":"Giỏi tính toán thiên cơ và bố cục dài hạn qua hàng ngàn năm; điềm tĩnh uy nghi khi chủ trì tông môn, giảng đạo; tự tin quyết liệt trước cường địch; che giấu dã tâm thôn phệ dưới thân phận sư tôn","blurb":"Thiên Vận Tử là chưởng môn Thiên Vận Tông, thành viên Liên Minh Trưởng Lão Đoàn, từng nhận Vương Lâm làm đệ tử chân chính nhưng âm thầm bố cục qua lạc ấn, phân hồn và Luân Hồi Toàn Thể Thuật suốt hai ngàn năm. Chân tướng về sau phơi bày: hắn không phải tàn hồn Thất Thải Tiên Tôn mà là thực thể nguyên thủy đã nuốt phách Thất Thải, bổn tôn là nửa nghịch la bàn — một bộ phận của Thiên Đạo. Sau lần thức tỉnh thứ chín mươi chín và ý đồ chiếm cứ phân thân Vương Lâm, hắn bị Vương Lâm đoạt bổn tôn rồi tiêu diệt hoàn toàn."},{"id":"nu-co-than-that-tinh","name":"Nữ Cổ Thần thất tinh","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tử tuyệt sắc mang bảy tinh điểm màu tím trên mi tâm, xác nhận thân phận Cổ Thần thất tinh. Nàng tỉnh giấc trên một đại lục bị băng bao phủ, phá vỡ toàn bộ tầng băng khi thức dậy; thân phận của nàng là đáp án cho nhiều sự kiện liên quan đến Đông Lâm tinh và Nhất Mộc Tử.","vaiTro":"Cổ Thần thất tinh bí ẩn, liên quan gia tộc viễn cổ Đông Lâm tinh","tinhCach":[],"tabs":{"diem":[{"text":"Phá vỡ toàn bộ tầng băng bao phủ đại lục, tỉnh giấc và lộ bảy tinh điểm màu tím trên mi tâm, xác nhận thân phận Cổ Thần thất tinh","chuong":"@c1395"}],"kinhLich":[{"chuong":"@c1395","importance":"major","mucCt":"vua","tieuDe":"Tỉnh giấc trên đại lục băng, lộ thân phận Cổ Thần thất tinh","text":"Phá vỡ toàn bộ tầng băng bao phủ đại lục, tỉnh dậy. Tinh điểm trên mi tâm xoay tròn, lộ ra bảy tinh điểm màu tím — xác nhận là Nữ Cổ Thần thất tinh.","anchor":"Tinh điểm trên mi tâm nữ tử lại xoay tròn một lần nữa, lộ rõ ra bảy tinh điểm màu tím."}],"tuViMoc":[{"chuong":"@c1395","canhGioi":"Cổ Thần thất tinh","text":"Mi tâm lộ bảy tinh điểm màu tím, xác nhận thân phận Cổ Thần thất tinh.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Linh hồn từng bị hút sinh cơ Cổ Thần qua liên kết với nàng","ghiChu":"Liên quan gián tiếp qua lão tổ Hướng gia @c1395"},{"ten":"Nhất Mộc Tử","tag":"khac","quanHe":"Phụng mệnh tới Vọng Nguyệt vì thân phận Cổ Thần thất tinh của nàng","ghiChu":"@c1395"},{"ten":"Lão tổ Hướng gia","tag":"khac","quanHe":"Hút sinh cơ Cổ Thần từ nàng thông qua linh hồn Vương Lâm","ghiChu":"@c1395"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1395"]},{"id":"su-gia-trung-nien-loi-tien-dien","name":"Sứ giả trung niên Lôi Tiên Điện","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Lôi Tiên Điện","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Sứ giả trung niên của Lôi Tiên Điện, tu vi cao nhất trong đoàn di tinh gần trăm người, tính tình hống hách bức bách thuộc hạ.","vaiTro":"Chỉ huy đoàn di tinh Lôi Tiên Điện, bức bách Tây Tử Phượng","tinhCach":[{"text":"Hống hách, khinh thường kẻ yếu, mắng Tây Tử Phượng là phế vật","chuong":"@c1396"},{"text":"Nhát gan trước kẻ mạnh, quỳ sụp hồn phi phách tán khi Vương Lâm xuất hiện","chuong":"@c1396"}],"tabs":{"diem":[{"text":"Bức bách Tây Tử Phượng, từng gợi ý yêu cầu liên quan dung mạo bị nàng từ chối. Khi nghe tên Vương Lâm thì hồn phi phách tán.","chuong":"@c1396"}],"kinhLich":[{"chuong":"@c1396","importance":"normal","mucCt":"vua","tieuDe":"Bức bách Tây Tử Phượng, bị Vương Lâm chấn nhiếp","text":"Mắng Tây Tử Phượng là phế vật, tự tay dùng thần thức di chuyển tu chân tinh và chỉ huy gần trăm tu sĩ di tinh. Khi Vương Lâm xuất hiện với uy áp kinh khủng, hắn quỳ sụp run rẩy, nghe tên Vương Lâm thì hồn phi phách tán.","anchor":"ngay cả nguyên thần cũng bị một câu nói này mà sụp đổ, linh hồn vì một cái tên này mà chia nãm sẽ bảy, hồn phi phách tán"}],"tuViMoc":[],"nhanMach":[{"ten":"Tây Tử Phượng","tag":"khac","quanHe":"Thuộc hạ bị hắn bức bách","ghiChu":"Mắng là phế vật, từng gợi ý yêu cầu liên quan dung mạo bị nàng từ chối"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Cường giả khiến hắn khiếp sợ","ghiChu":"Nghe tên Vương Lâm thì hồn phi phách tán"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1396"]},{"id":"lao-gia-khuy-niet-loi-tien-dien","name":"Lão già Khuy Niết sơ kỳ (Lôi Tiên Điện)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Lôi Tiên Điện","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Khuy Niết sơ kỳ","trangThai":"song","blurb":"Lão già tu vi Khuy Niết sơ kỳ, năm đó được Vương Lâm mang ra khỏi Lôi Tiên Giới, vì ân tình mà bênh vực Tây Tử Phượng.","vaiTro":"Tu sĩ Lôi Tiên Điện, ân nhân gián tiếp của Tây Tử Phượng","tinhCach":[{"text":"Biết ơn, trọng tình nghĩa, dám đứng ra bênh vực Tây Tử Phượng trước sứ giả quyền hành","chuong":"@c1396"}],"tabs":{"diem":[{"text":"Từng được Vương Lâm cứu, vì ân tình đó mà tặng đan dược và bênh vực Tây Tử Phượng trước sứ giả hống hách.","chuong":"@c1396"}],"kinhLich":[{"chuong":"@c1396","importance":"normal","mucCt":"vua","tieuDe":"Bênh vực Tây Tử Phượng, dùng tên Vương Lâm dọa sứ giả","text":"Tặng Tây Tử Phượng đan dược trân quý La Thiên Tinh Vực chữa thương nguyên thần. Đứng ra bênh vực nàng trước sứ giả, nhắc tới Vương Lâm khiến sứ giả trầm mặc bất an.","anchor":"Tây Tử đạo hữu, lão phu nãm đó cũng là được hắn mang ra khòi Lôi Tiên Giới"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Ân nhân cứu mạng, mang lão ra khỏi Lôi Tiên Giới","ghiChu":""},{"ten":"Tây Tử Phượng","tag":"ban-be","quanHe":"Đạo hữu cùng Lôi Tiên Điện, tặng đan dược bênh vực","ghiChu":"Vì ân tình với Vương Lâm mà chăm sóc nàng"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1396"]},{"id":"dai-han-phung-thien-lang-toc","name":"Chu Cẩn","cn":"朱瑾","aliases":["#chu-duc-chu-can"],"gioiTinh":"nam","theLuc":[],"trangThai":"song","blurb":"Chu Cẩn là tu sĩ Không Niết sơ kỳ bước thứ ba thuộc Phụng Thiên lang tộc, thân cao ba trượng, mi tâm mang ấn ký đầu sói xanh. Nhận lệnh Chưởng Tôn phục kích Vương Lâm nhưng liên tiếp thất bại, bị luyện hóa trong Thiên Hoàng Lô và trở thành nô bộc. Sau khi Vương Lâm mất tích, hắn phản bội giới nội mang lang tộc gây tang tóc, song khi Vương Lâm tái xuất liền tuyệt vọng khiếp sợ và bị áp chế hoàn toàn.","vaiTro":"Đại hán Phụng Thiên lang tộc — tu sĩ bước thứ ba, nguyên nô bộc của Vương Lâm","tinhCach":"Hung hãn cuồng bạo khi giao chiến; tham lam, muốn chiếm đoạt Cổ Tức Diệp; tuân lệnh nhưng phản bội khi mất ràng buộc; khiếp nhược trước cường giả áp chế","tabs":{"diem":[{"text":"Phục kích Vương Lâm từ khe nứt hư không, bị móng tay Đại Hoang thượng nhân xuyên thấu trúng độc","chuong":"@c1343"},{"text":"Bị Vương Lâm cùng Linh Động áp chế hoàn toàn, luyện hóa trong Thiên Hoàng Lô","chuong":"@c1373"},{"text":"Thoát Thiên Hoàng Lô nhưng đạo tâm tan nát, quỳ phục trước Vương Lâm","chuong":"@c1379"},{"text":"Thi triển Quần Lang Bái Nguyệt — hồng nguyệt đỏ máu xé bầu trời, phá bàn tính truy kích kẻ địch","chuong":"@c1417"},{"text":"Phản bội giới nội sau khi Vương Lâm mất tích, mang Phụng Thiên lang tộc gây tang tóc cho giới nội","chuong":"@c1520"},{"text":"Tuyệt vọng trước sức mạnh Vương Lâm tái xuất, là tu sĩ giới ngoại duy nhất gần Chu Tước Tinh sống sót","chuong":"@c1529"}],"kinhLich":[{"chuong":"@c1417","importance":"normal","mucCt":"ky","tieuDe":"Quần Lang Bái Nguyệt phá hạt châu bàn tính, truy kích nam tử trung niên","text":"Xuất hiện cùng huyết lang vạn trượng, thi triển Quần Lang Bái Nguyệt — hồng nguyệt đỏ máu xé bầu trời phá vỡ ba mươi hai hạt châu bàn tính, lộ ra nam tử trung niên bản thể đầy máu kinh hãi. Lùi mấy bước nhưng bình tĩnh tiếp tục truy kích, huyết lang há miệng nuốt đối phương.","anchor":"Quần Lang Bái Nguyệt!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1418","text":"Giao chiến với Vân Phong Tử, hương hỏa vượt xa đối phương khiến Vân Phong Tử phải lùi.","anchor":"Chi vì Định Thần Thuật mà đắc tội với người có cao thủ bước thứ ba làm nô bộc như thế này, vụ mua bán này, Vân Phong Tử ta không muốn làm!"},{"chuong":"@c1419","importance":"bridge","mucCt":"gon","text":"Theo thần niệm Vương Lâm bước tới cùng sáu cao thủ hợp lực ngăn cuồng phong.","anchor":"Linh Động và Chu cẩn theo thần niệm của Vương Lâm cũng bước tới"},{"importance":"bridge","mucCt":"gon","chuong":"@c1422","text":"Thần sắc phức tạp, khiếp sợ trước thân phận tôn quý của Vương Lâm trong giới nội, theo Vương Lâm rời Thần Tông.","anchor":"Thần sắc Chu Cẩn lúc này rất phức tạp, trong mắt hiện lên vẻ khiếp sợ"},{"importance":"bridge","mucCt":"gon","chuong":"@c1424","tieuDe":"Bị triệu ra tham chiến","text":"Bị Vương Lâm triệu ra cùng Linh Động Thượng Nhân, hồn phách phải nghe lệnh tham chiến.","anchor":"Mặc kệ hai người hắn có đồng ý hay không, lúc này đều phải nghe theo mệnh lệnh của Vương Lâm"},{"importance":"bridge","mucCt":"gon","chuong":"@c1425","tieuDe":"","text":"Theo thần niệm Vương Lâm cùng Linh Động ngăn cản Đông Địch Tử, ánh mắt phức tạp nhưng không do dự ra tay.","anchor":"Chu Cẩn trầm mặc, ánh mắt lộ ra vẻ phức tạp, nhưng cũng không chút do dự ra tay"},{"chuong":"@c1427","importance":"bridge","mucCt":"gon","text":"Theo thần niệm Vương Lâm, cùng Linh Động Thượng Nhân làm hộ pháp cho Nam Vân Tử chữa trị Phong Giới Đại Trận.","anchor":"Giới nội còn chưa chuẩn bị tốt, còn cần một ít thời gian"},{"chuong":"@c1429","importance":"bridge","mucCt":"gon","text":"Cùng Nam Vân Tử và Linh Động nghênh chiến Tiên Phi áo đỏ.","anchor":"cùng với Linh Động và Chu Cẩn nghênh chiến Tiên Phi này"},{"chuong":"@c1434","importance":"bridge","mucCt":"gon","text":"Theo Nam Vân Tử rút về sửa chữa Phong Giới Đại Trận.","anchor":"dẫn theo Linh Động và Chu Cẩn nhảy vào trong Phong Giới Đại Trận, lại bắt đầu nhanh chóng sửa chữa"},{"chuong":"@c1438","importance":"bridge","mucCt":"gon","text":"Theo tâm niệm Vương Lâm mà trầm mặc thi triển thần thông tham gia liên thủ giới nội.","anchor":"Có thể nói tất cả những cao thủ của giới nội ở đây lúc này, toàn bộ đều trong khoảng khắc này bộc phát ra sức mạnh lớn nhất"},{"chuong":"@c1440","importance":"bridge","mucCt":"gon","text":"Nô ấn chưa vỡ, vẫn còn trong Vân Hải, chứng tỏ Vương Lâm còn sống.","anchor":"Nô ấn của Linh Động Thượng Nhân và Chu cẩn vẫn chưa vỡ"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Chủ nhân / đồng minh","ghiChu":"Chiến đấu bên cạnh Vương Lâm chặn nam tử trung niên"},{"ten":"Vân Phong Tử","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Phá vỡ hạt châu bàn tính của Vân Phong Tử, truy kích"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1417","@c1418","@c1419","@c1422","@c1424","@c1425","@c1427","@c1429","@c1434","@c1438","@c1440"]},{"id":"hong-sam-tu","name":"Hồng Sam Tử","cn":"红衫子","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1418","tieuDe":"Nhận ra khí tức Viễn Cổ Tiên Vực — lao tới Thần Tông","text":"Đang ở sơn cốc tầng thứ nhất Vân Hải, sau khi Phong Giới Đại Trận hiện hình, sắc mặt đại biến, nhận ra khí tức Viễn Cổ Tiên Vực trên chuông của Thủy Đạo Tử. Phá hư không đi thẳng tới Thần Tông.","anchor":"Đáng chết, đây là khí tức của Viễn cổ Tiên Vực, không ngờ Thủy Đạo Tử lại có vật này!"},{"chuong":"@c1419","importance":"normal","mucCt":"vua","tieuDe":"Hợp lực ngăn cuồng phong rồi chuyển sang giết Thủy Đạo Tử","text":"Xuất hiện sau lưng Vương Lâm cùng chống cuồng phong nhưng nhận ra không thể cứu Vân Hải. Cười thảm tuyên bố mọi người rút lui, rồi đi thẳng tới Thủy Đạo Tử để giết hắn.","anchor":"Thôi, thôi. Các vị mau lui đi, có thể mang theo mấy người rời khỏi Vân Hải thì mang"},{"chuong":"@c1420","importance":"bridge","mucCt":"gon","text":"Nhận định U Minh thú là bổn mạng thú của Vương Lâm, đánh giá sự lựa chọn của chủ nhân phong giới không sai, trao đổi ánh mắt với tu sĩ Liên Minh Tinh Vực và Thi Âm Tông.","anchor":"sự lựa chọn của chủ nhân phong giới hẳn là không sai rồi"},{"mucCt":"vua","text":"Công nhận Vương Lâm là Phong Tôn, khen công vây khốn thái cổ ngũ tôn và Đại Hoang Thượng Nhân. Yêu cầu toàn giới nội chuẩn bị chết trận chống giới ngoại. Quyết định phong ấn Thái A La tạm chỉ giải một nửa, đợi sau cuộc chiến mới giải nốt.","anchor":"Nhưng như thế còn không đủ. Ngươi vốn là chủ nhân phong giới, nên chuẩn bị tốt, cùng lão phu, cùng cả giới nội chuẩn bị chết trận.","bridge":true,"khoang":"@c1422"},{"importance":"bridge","mucCt":"gon","chuong":"@c1424","tieuDe":"Được Vương Lâm hồi tưởng","text":"Được Vương Lâm hồi tưởng câu hỏi trước đây về việc đã chuẩn bị tử chiến chưa.","anchor":"Giống như Hồng Hủ Tử lúc trước hỏi hắn, ngươi đã chuẩn bị tử chiến trong cuộc chiến này chưa"},{"mucCt":"gon","text":"Bất ngờ xuất hiện từ tinh không Vân Hải cùng Vân Phong Tử, dẫn mấy vạn tu sĩ Vân Hải lao tới tiếp viện giới nội.","anchor":"Hồng Sam Tử, Vân Phong Tử bất ngờ đi ra","bridge":true,"khoang":"@c1425"},{"mucCt":"vua","text":"Toàn thân mặc áo đỏ, dù chiến tranh nổ ra ngoài dự kiến vẫn không sợ hãi, cười dài lao ra chiến đấu cùng Nam Vân Tử, lộ khí thế cao thủ bước thứ ba.","anchor":"trong tiếng cười dài lao tới","bridge":true,"khoang":"@c1426"},{"chuong":"@c1427","importance":"major","mucCt":"ky","tieuDe":"Lộ danh hiệu Huyết Sam Đồng Tử, đối mặt năm bước ba","text":"Chặn Nam Chiếu Thượng Nhân, tuyên bố mấy vạn năm không phạm sát giới. Thi triển thần thông Huyết Sam bức máu huyết hàng ngàn tu sĩ giới ngoại ra ngoài qua lỗ chân lông thành hồng sam, biến họ thành thây khô rồi xác sống khát máu chém giết đồng đội. Bị Nam Chiếu nhận ra là Huyết Sam đồng tử — truyền thuyết kinh sợ lưu truyền giới ngoại mấy vạn năm từ lần hai giới đại chiến. Đối mặt năm tu sĩ bước thứ ba hợp chiến.","anchor":"Huyết Sam đồng tử! Ngươi chính là Huyết Sam đồng tử!"},{"chuong":"@c1429","importance":"major","mucCt":"ky","tieuDe":"Bị mắc bẫy liên hoàn, Tiên Phi đánh trúng","text":"Tu vi Không Huyền Trung Kỳ, cách Hậu Kỳ nửa bước, đang chiếm ưu thế trước năm cao thủ bước ba. Bỏ năm người lao tới tấn công Vân Lạc Đại Ti nhưng bị đồng tử hàn băng chặn đường bằng cuồng phong hàn băng. Đánh tan cuồng phong để cứu tu sĩ Vân Hải nhưng mắc bẫy — Tiên Phi áo đỏ ẩn bên trong bất ngờ tấn công, ngực xuất hiện vết máu hình đầu quỷ khuếch tán. Sau đó bị đồng tử hàn băng cùng năm cao thủ bước ba liên thủ tấn công. Bị tiết lộ hiện tại chỉ là phân thân, bổn tôn chưa lộ diện.","anchor":"sắc mặt tái nhợt, thân thể lùi lại phía sau mấy bước, trên ngực bất ngờ xuất hiện một vết máu"},{"mucCt":"vua","text":"Một mình đối đầu sáu cao thủ bước thứ ba, kiên quyết không lùi vì hiểu nếu lùi thì giới nội hoàn toàn thất bại. Khi nghe thanh âm Phong Tôn, hồi tưởng năm xưa cùng Phong Tôn to tiếng luận đạo, nhớ sự cố chấp và nụ cười của Phong Tôn.","anchor":"cùng với Phong Tôn tính cách cố chấp to tiếng luận đạo","bridge":true,"khoang":"@c1430"},{"mucCt":"vua","text":"Cùng Nam Vân Tử ngăn cản các cao thủ bước thứ ba giới ngoại rời trận. Tuy nhiên trước đó đã bị Tiên Phi đánh lén bị thương, đang giao chiến với hàn y đồng tử tu vi rất cao thâm cùng nhiều cao thủ khác, sức lực không đủ cầm chân tất cả, để lão tổ Hỏa Tước Tộc thoát ra.","anchor":"Hồng Sam Tử đã bị Tiên Phi đánh lén, lúc này đang bị thương","bridge":true,"khoang":"@c1431"},{"chuong":"@c1432","importance":"normal","mucCt":"vua","tieuDe":"Tuyên bố tất thắng, vây khốn hàn y đồng tử","text":"Cười dài tuyên bố cuộc chiến không thể bại được sau khi Vương Lâm chém chết Lão tổ Hỏa Tước Tộc. Vung tay áo phóng hồng quang lao thẳng tới hàn y đồng tử, vây khốn chặt chẽ tu sĩ bước thứ ba giới ngoại.","anchor":"Phong Tôn chém chết tu sĩ bước thứ ba của giới ngoại, cuộc chiến này chúng ta không thể bại được"},{"chuong":"@c1434","importance":"bridge","mucCt":"gon","text":"Được mỹ phụ trung niên Triệu Hà và Lỗ Phu Tử hỗ trợ giáp công hàn y đồng tử, áp lực giảm bớt.","anchor":"Hai người gia nhập vào cuộc chiến, khiến cho Hồng Sam Tử được thảnh thơi một chút"},{"mucCt":"gon","text":"Đang giao chiến với hàn y đồng tử, ánh mắt ngưng trọng khi Lam Mộng Đạo Tôn xuất hiện.","anchor":"Hồng Sam Tử đang giao chiến với hàn y đồng tử kia lúc này ánh mắt cũng lộ ra vẻ ngưng trọng","bridge":true,"khoang":"@c1435"},{"importance":"bridge","mucCt":"gon","chuong":"@c1436","tieuDe":"","text":"Ngừng chém giết khi nghe tiếng gào thét mũi tên cung Lý Quảng, ngẩng đầu lộ vẻ khiếp sợ.","anchor":"những cao thủ như Hồng Sam Tử và Vân Nam Tử đồng loạt ngừng chém giết"},{"chuong":"@c1438","importance":"bridge","mucCt":"vua","text":"Bước mạnh về phía trước vung tay phóng đám mây đỏ tấn công bàn tay khổng lồ, sau khi cuồng phong nổ tung thì phun máu lùi lại.","anchor":"trong lúc lui về phía sau hắn bỗng bước mạnh về phía trước một bước, giơ tay phải lên vung về phía trước, lập tức liền có một đám mây đỏ tràn ra"},{"chuong":"@c1439","importance":"bridge","mucCt":"gon","tieuDe":"Dẫn đầu rút lui khỏi chiến trường","text":"Dẫn đầu mấy vạn tu sĩ Triệu Hà, La Thiên, Vân Hải vội vàng rút lui khỏi chiến trường trước cuồng phong hủy diệt.","anchor":"Trận chiến đầu tiên đã kết thúc một cách kỳ dị như vậy."}],"tuViMoc":[{"chuong":"@c1429","canhGioi":"Không Huyền Trung Kỳ","text":"Tu vi được xác nhận đạt Không Huyền Trung Kỳ, cách Hậu Kỳ nửa bước.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Phong Tôn đời này, công nhận và yêu cầu chuẩn bị chiến đấu","ghiChu":"@c1422"},{"ten":"Thái A La","tag":"khac","quanHe":"Bị Hồng Sam Tử hạn chế chỉ giải nửa phong ấn","ghiChu":"@c1422"}],"tuiDo":{},"diem":[{"text":"Được chủ nhân Phong Giới chọn là một trong những người được ủy thác ước định hợp nhất Tứ Đại Tiên Giới","chuong":"@c1233"},{"text":"Dẫn mấy vạn tu sĩ Vân Hải bất ngờ xuất hiện tiếp viện giới nội khi chiến tranh bùng nổ","chuong":"@c1425"},{"text":"Phá sát giới mấy vạn năm, thi triển thần thông Huyết Sam, một mình đối đầu năm cao thủ bước thứ ba và chiếm ưu thế với tu vi Không Huyền Trung Kỳ","chuong":"@c1427"},{"text":"Bị hàn y đồng tử và tu sĩ bước thứ ba giới ngoại liên thủ phong ấn tại Thất Thải Giới, sau được Vương Lâm giải cứu khỏi đạo quả","chuong":"@c1469"},{"text":"Không do dự lao theo hỗ trợ Vương Lâm, cùng Thanh Lâm và Lam Mộng Đạo Tôn hộ pháp bổn tôn và khống chế phân thân Vương Lâm trong trận quyết chiến cuối","chuong":"@c1628"},{"text":"Chọn chuyển thế đầu thai rời đi sau khi đại cục an định","chuong":"@c1694"}]},"nguon":["@c1418","@c1419","@c1420","@c1422","@c1424","@c1425","@c1426","@c1427","@c1429","@c1430","@c1431","@c1432","@c1434","@c1435","@c1436","@c1438","@c1439"],"aliases":["Hồng Hủ Tử","Huyết Sam đồng tử","Hạng Đại Thông"],"canhGioiCaoNhat":"Không Huyền Trung Kỳ","vaiTro":"Cường giả Vân Hải tinh vực — người được ủy thác ước định hợp nhất Tứ Đại Tiên Giới","tinhCach":"Dũng mãnh không sợ chết, sẵn sàng xả thân vì đại cục; quyết đoán trên chiến trường, không lùi dù đối mặt cường địch áp đảo; trọng nghĩa khí, giữ sát giới mấy vạn năm nhưng phá giới khi cần; trung thành tận tụy, hết lòng phò tá Vương Lâm trong mọi trận quyết chiến","blurb":"Hồng Sam Tử, biệt hiệu Huyết Sam Đồng Tử, là cường giả Không Huyền Trung Kỳ trú tại tầng thứ nhất Vân Hải tinh vực, một trong những người được chủ nhân Phong Giới ủy thác ước định hợp nhất Tứ Đại Tiên Giới. Khi Phong Giới Đại Trận hiện hình và chiến tranh giới nội–giới ngoại bùng nổ, Hồng Sam Tử dẫn mấy vạn tu sĩ Vân Hải tiếp viện, một mình đối đầu nhiều cao thủ bước thứ ba, phá sát giới mấy vạn năm để chiến đấu, đóng vai trò then chốt trong nhiều trận quyết chiến bảo vệ giới nội. Sau đại chiến thứ hai bị phong ấn tại Thất Thải Giới, được Vương Lâm giải cứu, tiếp tục tham chiến trong các trận "},{"id":"nam-van-tu","name":"Nam Vân Tử","cn":"南云子","gioiTinh":"nam","aliases":["Lão già Thi Âm Tông","Lão già hư ảo","Vân Nam Tử"],"trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Thân ảnh toàn thân hư ảo từ Thi Âm Tông (Liên Minh Tinh Vực), nhận ra chuông nhỏ là vật của Viễn Cổ Tiên Vực dùng để dung hợp với Phong Giới Đại Trận, trước khi dung hợp cực kỳ yếu ớt không thể để bị hủy. Phá hư không lao thẳng tới Thần Tông.","anchor":"Vật của Viễn Cổ Tiên Vực! Vật này dường như là vật để dung hợp với Phong Giới Đại Trận","bridge":true,"khoang":"@c1418"},{"mucCt":"vua","text":"Hỏi Vương Lâm về thực lực giới ngoại, lo lắng khi nghe kể. Nêu vấn đề U Minh thú nuốt cơn lốc vàng cần quan sát, chuông vàng bị Thủy Đạo Tử hủy, cần xử lý Thất Thải Giới còn lại.","anchor":"U Minh thú này có hơi khác biệt so với trí nhớ của lão phu","bridge":true,"khoang":"@c1422"},{"importance":"bridge","mucCt":"gon","chuong":"@c1426","tieuDe":"Xung trận cùng Hồng Sam Tử","text":"Mắt lóe hàn quang, cùng Hồng Sam Tử lao ra chiến đấu bảo vệ Vân Hải.","anchor":"trong tiếng cười dài lao tới"},{"chuong":"@c1427","importance":"normal","mucCt":"vua","tieuDe":"Chữa trị Phong Giới Đại Trận","text":"Không tham chiến, lao thẳng tới Phong Giới Đại Trận để chữa trị, tuyên bố giới nội chưa chuẩn bị tốt cần thêm thời gian. Mượn Linh Động Thượng Nhân và Chu Cẩn làm hộ pháp, bước vào trận bắt quyết thi triển cấm chế.","anchor":"Giới nội còn chưa chuẩn bị tốt, còn cần một ít thời gian"},{"chuong":"@c1429","importance":"normal","mucCt":"vua","tieuDe":"Bỏ sửa Phong Giới Đại Trận nghênh chiến","text":"Đang sửa chữa Phong Giới Đại Trận nhưng khi Tiên Phi áo đỏ lao tới, thở dài bỏ việc sửa chữa, cùng Linh Động và Chu Cẩn nghênh chiến Tiên Phi.","anchor":"Nam Vân Tử thở dài bỏ qua việc sửa chữa, mà xoay người cùng với Linh Động và Chu Cẩn nghênh chiến Tiên Phi này"},{"chuong":"@c1430","importance":"normal","mucCt":"vua","tieuDe":"Kiên trì chiến đấu vì ân tình Phong Tôn","text":"Không lùi bước, cả đời ít nói nhưng trọng nghĩa, quyết báo đáp đại ân của Phong Tôn năm xưa, ánh mắt lóe lên chiến ý. Khi nghe thanh âm Phong Tôn, mắt lộ vẻ bi ai.","anchor":"ánh mắt Nam Vân Tử lộ ra vẻ bi ai, hắn không thể nào quên được thanh âm này"},{"chuong":"@c1431","importance":"bridge","mucCt":"gon","text":"Cùng Hồng Sam Tử ngăn cản các cao thủ bước thứ ba giới ngoại rời trận.","anchor":"Hồng Sam Tử cùng với Nam Vân Tử kia đồng thời xuất hiện, ngăn cản bất cứ một cao thủ bước thứ ba nào rời khỏi"},{"chuong":"@c1432","importance":"bridge","mucCt":"gon","text":"Cười vang, ngăn cản tiên phi giới ngoại chiến đấu trong trận đại chiến.","anchor":"Ngăn hắn lại!"},{"chuong":"@c1434","importance":"bridge","mucCt":"gon","text":"Sau khi Tử Mộng tiếp quản trận đấu với Tiên Phi, rút về cùng Linh Động và Chu Cẩn sửa chữa Phong Giới Đại Trận.","anchor":"dẫn theo Linh Động và Chu Cẩn nhảy vào trong Phong Giới Đại Trận, lại bắt đầu nhanh chóng sửa chữa"},{"chuong":"@c1435","importance":"normal","mucCt":"gon","tieuDe":"Sửa chữa Phong Giới Đại Trận","text":"Đang sửa chữa Phong Giới Đại Trận tới giai đoạn cuối, lỗ hổng dần thu hẹp. Nhận ra Lam Mộng Đạo Tôn tu vi Không Huyền đỉnh, bản thân không phải đối thủ.","anchor":"Tu vi của Lam Mộng Đạo Tôn đã đạt tới đỉnh của Không Huyền, Nam Vân Tử hắn không phải là đối thủ"},{"importance":"bridge","mucCt":"gon","chuong":"@c1436","tieuDe":"","text":"Ngừng chém giết khi nghe tiếng gào thét mũi tên cung Lý Quảng, ngẩng đầu lộ vẻ khiếp sợ.","anchor":"những cao thủ như Hồng Sam Tử và Vân Nam Tử đồng loạt ngừng chém giết"},{"chuong":"@c1438","importance":"bridge","mucCt":"vua","text":"Vỗ tay lên trán, từ phía sau hiện ra hư ảnh ngưng tụ thành trận pháp khổng lồ, phối hợp tấn công bàn tay khổng lồ.","anchor":"tay phải vỗ lên trán, thân thể hắn bỗng nhiến chấn động, chỉ thấy có một đám hư ảnh từ phía sau hắn hiện ra"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Phong Tôn đời này, cùng bàn đối sách","ghiChu":"@c1422"},{"ten":"Lam Mộng Đạo Tôn","tag":"doi-thu","quanHe":"Nhận ra tu vi Lam Mộng vượt xa, không phải đối thủ"}],"tuiDo":{},"diem":[{"text":"Được chủ nhân Phong Giới chọn làm một trong ba người giữ ước định hợp nhất Tứ Đại Tiên Giới","chuong":"@c1233"},{"text":"Xung trận chiến đấu bảo vệ Vân Hải và đảm nhận sửa chữa Phong Giới Đại Trận trong đại chiến giới nội – giới ngoại","chuong":"@c1427"},{"text":"Ngưng tụ hư ảnh trận pháp khổng lồ phối hợp tấn công kẻ địch, thể hiện trình độ trận pháp cao thâm","chuong":"@c1438"},{"text":"Cầm đầu chưa đầy tám ngàn tu sĩ giới nội quyết tử chiến bên ngoài Chu Tước Tinh","chuong":"@c1520"},{"text":"Nắm thời cơ chỉ huy chiến trường và dốc toàn lực trợ giúp Vương Lâm mở Không Môn","chuong":"@c1524"},{"text":"Sau khi đấu tranh nội tâm rất lâu, cuối cùng chọn ở lại động phủ giới","chuong":"@c1694"}]},"nguon":["@c1418","@c1419","@c1422","@c1426","@c1427","@c1429","@c1430","@c1431","@c1432","@c1434","@c1435","@c1436","@c1438"],"vaiTro":"Tu sĩ Thi Âm Tông (Liên Minh Tinh Vực) — người giữ ước định hợp nhất Tứ Đại Tiên Giới, tinh thông trận pháp","tinhCach":"Trọng nghĩa khí, cả đời ít nói nhưng quyết báo đáp ân tình Phong Tôn; kiên định không lùi bước trước kẻ địch mạnh; tinh thông trận pháp, hành sự cẩn trọng; có tầm nhìn đại cục, biết nắm thời cơ chỉ huy chiến trường","blurb":"Nam Vân Tử là tu sĩ thuộc Thi Âm Tông của Liên Minh Tinh Vực, một trong ba người ở ba tinh vực được chủ nhân Phong Giới giao ước định hợp nhất Tứ Đại Tiên Giới Phong Vũ Lôi Điện. Trong đại chiến giới nội – giới ngoại, ông vừa xung trận bảo vệ Vân Hải, vừa đảm nhận sửa chữa Phong Giới Đại Trận và ngưng tụ hư ảnh trận pháp khổng lồ tấn công kẻ địch; sau khi bị Chưởng Tôn đánh trọng thương bế quan rồi phục hồi, ông cầm đầu lực lượng cuối cùng chưa đầy tám ngàn tu sĩ giới nội quyết tử chiến tại Chu Tước Tinh, dốc toàn lực trợ giúp Vương Lâm mở Không Môn, và tiếp tục theo sát Vương Lâm xuất chinh c","theLuc":[{"ten":"Thi Âm Tông","trangThai":"gan-bo"}]},{"id":"dai-hu-thuong-nhan","name":"Đại Hư Thượng Nhân","cn":"大虚上人","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Quỷ Tông","trangThai":"gan-bo"}],"trangThai":"song","vaiTro":"Cao thủ Quỷ Tông, gia nhập liên thủ chống cuồng phong chuông vàng","tinhCach":"Âm trầm; quyết đoán khi ra tay","blurb":"Tu sĩ thuộc Quỷ Tông, sắc mặt âm trầm, sở hữu thuật triệu hồi khuôn mặt Cổ Yêu khổng lồ với chín yêu tinh xoay tròn ở mắt trái.","tabs":{"diem":[{"text":"Triệu ra khuôn mặt Cổ Yêu khổng lồ với chín yêu tinh ở mắt trái vây cuồng phong","chuong":"@c1419"}],"kinhLich":[{"chuong":"@c1419","importance":"normal","mucCt":"vua","tieuDe":"Triệu khuôn mặt Cổ Yêu chín yêu tinh ngăn cuồng phong","text":"Sắc mặt âm trầm hiện thân gia nhập chống cuồng phong. Triệu ra khuôn mặt khổng lồ dung nhan một Cổ Yêu, mắt trái có chín yêu tinh xoay tròn bay ra chia chín hướng vây cuồng phong nhưng vẫn bất thành.","anchor":"Đại Hư Thượng Nhân của Quỷ Tông kia sắc mặt âm trầm"},{"importance":"bridge","mucCt":"gon","chuong":"@c1421","tieuDe":"Dẫn Quỷ Tông tham kiến Phong Tôn","text":"Dẫn dắt tu sĩ Quỷ Tông ôm quyền tham kiến Vương Lâm với danh hiệu Phong Tôn.","anchor":"Quỷ Tông Vân Hải tham kiến Phong Tôn!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Cùng phe chống cuồng phong chuông vàng"}],"tuiDo":{}},"nguon":["@c1419","@c1421"]},{"id":"dong-dich-tu","name":"Đông Địch Tử","gioiTinh":"nam","canhGioiCaoNhat":"Không rõ (tu vi cao thâm)","trangThai":"song","theLuc":[{"ten":"Trưởng Tôn hội","trangThai":"gan-bo"}],"vaiTro":"Phó hội trưởng Trưởng Tôn hội, chủ trì trận chiến nhập giới đầu tiên","tinhCach":"Uy nghiêm; quyền thế","blurb":"Phó hội trưởng Trưởng Tôn hội, tu vi Không Huyền sơ kỳ, lão già mặc hắc bào với ấn ký mi tâm hình rắn đen. Chủ trì trận chiến nhập giới đầu tiên xâm lược giới nội.","tabs":{"diem":[{"text":"Phó hội trưởng Trưởng Tôn hội, Không Huyền sơ kỳ, ấn ký rắn đen","chuong":"@c1422"},{"text":"Bề ngoài cười ha hả nhưng trong lòng coi thường lời dặn dò, bản tính tàn nhẫn hiếu sát.","chuong":"@c1423"},{"text":"Tu vi cao thâm, một mình đấu hai cường giả giới nội mà không hạ phong","chuong":"@c1425"}],"kinhLich":[{"mucCt":"vua","text":"Tự xưng phó hội trưởng Trưởng Tôn hội, chủ trì trận chiến nhập giới đầu tiên. Tổ chức tiệc rượu họp bàn cùng Nam Chiếu Thượng Nhân, lão tổ Hỏa Tước tộc và Vân Lạc đại ti.","anchor":"Lão phu là phó hội trưởng Trưởng Tôn hội - Đông Địch Tử, chủ trì trận chiến nhập giới đầu tiên","bridge":true,"khoang":"@c1422"},{"mucCt":"vua","text":"Dẫn đầu giới ngoại nhảy vào khe Phong Giới Đại Trận. Một mình chiến đấu với Linh Động Thượng Nhân và Chu Cẩn mà không rơi vào hạ phong, đồng thời phân lực ngăn cản Khai Thiên Phủ.","anchor":"lấy sức mạnh của một mình hắn chiến đấu với Linh Động và Chu Cẩn","bridge":true,"khoang":"@c1425"},{"chuong":"@c1427","importance":"normal","mucCt":"vua","tieuDe":"Nhận ra Huyết Sam đồng tử, bỏ Khai Thiên Phủ hợp chiến","text":"Nhận ra Hồng Sam Tử là Huyết Sam đồng tử trong truyền thuyết, thần sắc kịch biến. Bỏ Linh Động Thượng Nhân, Chu Cẩn và Khai Thiên Phủ, cùng hai tu sĩ bước ba khác lao về phía Hồng Sam Tử hợp chiến.","anchor":"Đông Địch Tử kia dưới thần thông của Hồng Sam Tử cũng đã nhận ra kẻ đáng sợ trong tin đồn năm xưa"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu truy sát trên Tất sát bảng","ghiChu":"@c1422"},{"ten":"Linh Động Thượng Nhân","tag":"doi-thu","quanHe":"Đối thủ trong trận chiến giới nội","ghiChu":"@c1425"},{"ten":"Chu Cẩn","tag":"doi-thu","quanHe":"Đối thủ trong trận chiến giới nội","ghiChu":"@c1425"}],"tuiDo":{}},"nguon":["@c1422","@c1423","@c1425","@c1427"]},{"id":"nam-chieu-thuong-nhan","name":"Nam Chiếu Thượng Nhân","gioiTinh":"nam","canhGioiCaoNhat":"Bước thứ ba","trangThai":"tu-vong","theLuc":[{"ten":"Trưởng Tôn hội","trangThai":"gan-bo"}],"vaiTro":"Cường giả bước thứ ba giới ngoại, nổi danh độc công, đồng chủ trì trận chiến nhập giới","tinhCach":"Âm trầm, thiện dụng kịch độc; chiến đấu kiên quyết, sẵn sàng dùng thân dự phòng để tiếp tục giao chiến; hung hãn truy kích, không ngại liên thủ vây sát đối thủ","blurb":"Nam Chiếu Thượng Nhân là tu sĩ bước thứ ba giới ngoại, ngoại hình thanh niên thanh tú nhưng mắt dài nhỏ như hai cái khe, sương mù dày đặc thường trực bao quanh thân. Hắn cùng Đông Địch Tử đồng chủ trì trận chiến nhập giới đầu tiên, sở hữu độc công bổn mạng cực kỳ lợi hại và nhiều lần giao chiến Vương Lâm trong hương hỏa giới. Sau khi bị phá thân phải dùng thân dự phòng tiếp chiến, cuối cùng bị Vương Lâm tiêu diệt bằng Thiên Hoàng Lô, hồn bị phong ấn và dung hợp vào mũi tên Lý Quảng.","tabs":{"diem":[{"text":"Cùng Đông Địch Tử đồng chủ trì trận chiến nhập giới đầu tiên, ấn ký mi tâm hiện sương mù đen quay cuồng thể hiện độc công","chuong":"@c1422"},{"text":"Liên thủ lão tổ Hỏa Tước Tộc tấn công Vương Lâm, tay phải hóa đen chứa kịch độc xuyên phá hỏa điểu","chuong":"@c1425"},{"text":"Tung chưởng chứa linh lực Không Linh hút Vương Lâm vào hương hỏa giới của mình để giao chiến","chuong":"@c1426"},{"text":"Bị Huyết Sam phá thân thể, nguyên thần thoát ra, chuyển sang dùng thân dự phòng tiếp tục chiến đấu","chuong":"@c1427"},{"text":"Bị Vương Lâm tiêu diệt bằng Thiên Hoàng Lô, kết cục tu vong","chuong":"@c1432"},{"text":"Hồn bị phong ấn trong Thiên Hoàng Lô, bị Vương Lâm lôi ra dung hợp vào ký hiệu trên mũi tên Lý Quảng","chuong":"@c1482"}],"kinhLich":[{"mucCt":"vua","text":"Cùng Đông Địch Tử chủ trì trận chiến nhập giới đầu tiên. Ấn ký mi tâm là sương mù đen quay cuồng, độc công nổi danh ngang Đại Hoang Thượng Nhân.","anchor":"độc công của hắn lại nổi danh ngang với Đại Hoang Thượng Nhân","bridge":true,"khoang":"@c1422"},{"mucCt":"vua","text":"Cùng lão tổ Hỏa Tước Tộc liên thủ tấn công Vương Lâm. Tay phải hóa đen chứa kịch độc, xuyên qua hỏa điểu của lão tổ Hỏa Tước Tộc vỗ thẳng Vương Lâm, buộc hắn phải lui.","anchor":"Nam Chiếu Thượng Nhân này tu vi cực kỳ kinh thiên, đã đạt tới cảnh giới Không Linh","bridge":true,"khoang":"@c1425"},{"importance":"normal","mucCt":"ky","chuong":"@c1426","tieuDe":"Giao chiến Vương Lâm trong hương hỏa giới","text":"Tung một chưởng chứa linh lực Không Linh hút Vương Lâm vào hương hỏa giới của mình — thiên địa đen kịt với hàng trăm triệu dân hương hỏa. Dùng toàn bộ không trung hóa thành bàn tay khổng lồ giáng xuống đối thủ. Bị Vương Lâm triệu Cổ Thần phản kích và dùng Đạo cổ cùng hư hỏa phá hủy bàn tay đen, tay phải chảy máu bị thương vô hình, không thể tiếp tục truy kích. Lộ vẻ khiếp sợ trước sức mạnh thân thể Vương Lâm, nhận định nếu hắn đạt bước thứ ba sẽ cực kỳ kinh khủng, quyết tâm tuyệt đối không thể để sống sót.","anchor":"Người này tuyệt đối không thể để sống sót"},{"chuong":"@c1427","importance":"normal","mucCt":"ky","tieuDe":"Bị Huyết Sam phá thân, dùng thân dự phòng hợp chiến","text":"Muốn truy kích Vương Lâm nhưng bị Hồng Sam Tử chặn. Bị hồng sam xuất hiện trên thân, thân thể sụp đổ, nguyên thần hoảng sợ lao ra. Nhận ra Hồng Sam Tử chính là Huyết Sam đồng tử trong truyền thuyết mấy vạn năm. Dùng khối thân thể dự phòng dung nhập nguyên thần, phản kích bằng ba quả cầu độc dịch. Cùng bốn tu sĩ bước thứ ba khác hợp chiến Hồng Sam Tử.","anchor":"Sắc mặt hắn tái nhợt, phun ra một ngụm tinh thần khí, thần sắc đại biến, thân thể chấn động mãnh liệt"},{"chuong":"@c1432","importance":"major","mucCt":"ky","tieuDe":"Bị Vương Lâm tiêu diệt bằng Thiên Hoàng Lô","text":"Bị hàn y đồng tử đánh văng ra khỏi vòng vây của Hồng Sam Tử, được lệnh đi giết Vương Lâm. Xuất hiện phía sau Vương Lâm cách hơn trăm trượng, thi triển độc tố bổn mạng — khói độc năm màu luyện cả vạn năm, đánh ra năm vòi rồng khói độc. Bị ba giọt độc dịch từ Thiên Hoàng Lô của Vương Lâm nổ thành biển độc nuốt sạch năm vòi rồng, trùm lên người. Kinh hãi nhận ra đây không phải độc của Đại Hoang Thượng Nhân mà là biến thể quỷ dị mạnh hơn. Thân thể từ chân lên hòa tan thành máu, xương cốt nát vụn, kêu cầu cứu thảm thiết rồi bị tiêu diệt hoàn toàn. Hồn phách bị Vương Lâm thu vào Thiên Hoàng Lô.","anchor":"Đây không phải là độc của Đại Hoang Thượng Nhân"}],"tuViMoc":[{"chuong":"@c1425","canhGioi":"Không Linh","text":"Được xác nhận đã đạt cảnh giới Không Linh, tu vi cực kỳ cao thâm.","importance":"major"},{"chuong":"@c1432","canhGioi":"Bước thứ ba","text":"Tu sĩ bước thứ ba giới ngoại, sở hữu độc công bổn mạng.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ, một mình đủ sức giết","ghiChu":"@c1425"},{"ten":"Lão tổ Hỏa Tước tộc","tag":"dong-minh","quanHe":"Liên thủ tấn công Vương Lâm","ghiChu":"@c1425"},{"ten":"Đại Hoang Thượng Nhân","tag":"khac","quanHe":"Độc công cùng tề danh","ghiChu":"Được nhắc so sánh @c1425"}],"tuiDo":{}},"nguon":["@c1422","@c1423","@c1425","@c1426","@c1427","@c1432"],"cn":"南照上人"},{"id":"van-lac","name":"Vân Lạc","aliases":["Vân Lạc đại ti"],"gioiTinh":"nu","trangThai":"mat-tich","theLuc":[{"ten":"Trưởng Tôn hội","trangThai":"gan-bo"}],"tabs":{"kinhLich":[{"mucCt":"vua","text":"Đang bắt quyết tính toán, lo lắng. Đã tính ra giới nội tìm được Thất Thải Giới mà chưởng tôn bố trí. Tiết lộ mục đích cuộc chiến thật sự là bố trí truyền tống trận chứ không phải giết người, yêu cầu giết Vương Lâm nhanh chóng.","anchor":"Mục đích cuộc chiến này không phải để giết người mà là để bố trí truyền tống trận","bridge":true,"khoang":"@c1422"},{"importance":"normal","mucCt":"gon","chuong":"@c1425","tieuDe":"","text":"Tiến vào trận pháp, thấy Vương Lâm liền sợ hãi, ra lệnh giết hắn.","anchor":"Nàng ngay lập tức đã nhìn thấy Vương Lâm, ánh mắt lộ ra vẻ sợ hãi, giơ tay lên chỉ về phía trước"},{"chuong":"@c1427","importance":"normal","mucCt":"ky","tieuDe":"Chỉ huy phản công, ra lệnh truy sát Vương Lâm","text":"Chỉ huy đại quân giới ngoại từ vị trí được vô số tu sĩ bảo vệ, nhận thấy tổn thất gần hai vạn tu sĩ trong thời gian ngắn. Ra lệnh Thiên Phạt Điện — Thị Kiếm Tộc dùng Phá hồn nhất kiếm ngăn Khai Thiên Phủ. Hướng mắt trầm mặc nhìn Vương Lâm, sau đó ra lệnh Tam lão Phong Diệt Tộc phong ấn hoặc giết hắn.","anchor":"Chỉ trong thời gian ngắn như vậy mà giới ngoại đã hy sinh gần hai vạn tu sĩ"},{"mucCt":"vua","text":"Ra lệnh cho mấy vạn tu sĩ giới ngoại dồn toàn lực tấn công Vương Lâm đã bị phong ấn. Khi nhận ra Vương Lâm đang mượn ngoại lực phá phong ấn, sắc mặt đại biến, tay đang bấm quyết nứt vết thương chảy máu, hét lên ngăn cản nhưng đã chậm một bước.","anchor":"Không được! Người này không thể bị giết như vậy!","bridge":true,"khoang":"@c1428"},{"chuong":"@c1429","importance":"normal","mucCt":"ky","tieuDe":"Điều khiển toàn quân, bẫy liên hoàn Hồng Sam Tử","text":"Ở sâu trong đám tu sĩ giới ngoại, bấm quyết điều khiển toàn bộ đại quân phân bốn hướng, biết trước mọi tiên cơ khiến trận pháp Vân Hải không thể bày thành. Toàn bộ trận chiến nằm trong kế hoạch liên hoàn của nàng: dụ Hồng Sam Tử vào bẫy đồng tử hàn băng và Tiên Phi áo đỏ. Cuối chương ra lệnh tổng quyết chiến, tu sĩ giới ngoại lao vào chém giết.","anchor":"Nha đầu Vân Lạc kia đã sớm đoán được hết thảy"},{"mucCt":"vua","text":"Ra lệnh cho tu sĩ giới ngoại xông lên ngăn Vương Lâm nhưng quân lính sợ hãi tản ra. Sau khi chứng kiến lão tổ Hỏa Tước Tộc bị chẻ đôi, sắc mặt trắng bệch, cuống quýt lui lại, nhận ra cảnh tượng mà nàng đã tính toán ra trước đó đang ứng nghiệm vào chính mình.","anchor":"nàng đã tính toán ra. Bóng lưng trong cảnh tượng đó, tất cả những thứ khiến cho nàng hoảng sợ dường như đang xảy ra với chính mình","bridge":true,"khoang":"@c1431"},{"chuong":"@c1432","importance":"normal","mucCt":"vua","tieuDe":"Hoảng sợ trước sức tấn công của Vương Lâm","text":"Sắc mặt tái nhợt, theo bản năng lui lại, lần đầu trong trận đánh phát tiếng nói hoảng sợ ra lệnh ngăn Vương Lâm. Cuối chương Vương Lâm đã áp sát cách trăm trượng giơ Khai Thiên Phủ chém xuống.","anchor":"Ngăn hắn lại!"},{"importance":"normal","mucCt":"ky","chuong":"@c1433","tieuDe":"Bổn tôn bị diệt — hồn phách thoát đi","text":"Phân thân trên chiến trường bị Khai Thiên Phủ chém nát huyết thuẫn bát giác rồi xuyên thấu, thân thể hóa búp bê vải lộ bản chất phân thân. Bổn tôn ẩn tại thánh địa truyền thừa trong tam đại cấm địa Trường Tôn hội, ngồi trên đảo nhỏ giữa hồ nước. Bị Cực Cảnh xuyên không gian tấn công, ánh sáng nhu hòa từ lầu các không đỡ nổi. Lấy hài cốt sư tôn màu đen ra chắn nhưng hài cốt cũng vỡ. Đọc quẻ tượng tổ tiên ứng nghiệm từ tam tượng đến lục tượng. Thân thể vỡ tan, nguyên thần sụp đổ, nhưng hồn phách dung nhập cơn lốc từ hài cốt sư tôn hóa thành và biến mất — chưa chết hẳn, cửu tượng chưa đọc hết.","anchor":"Quẻ tượng của tổ tiên đã thành ngũ tượng!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu cần giết nhanh chóng","ghiChu":"@c1422"}],"tuiDo":{},"diem":[{"text":"Dùng Thuật Thiên Đại Tinh Thần thôi diễn quả cầu nước hiển hiện hình bóng Vương Lâm, suy tính ra khí tức và tung tích của hắn để hỗ trợ Tư Mặc Tử truy sát","chuong":"@c1281"},{"text":"Bị lực lượng bí ẩn phản phệ khi thôi diễn bí ẩn cây hương trên Đại Đế tinh, tay phải rách nát nôn máu, trong cảnh hư ảo thấy dự tượng hạo kiếp Thái Cổ Tinh Thần","chuong":"@c1322"},{"text":"Chỉ huy đại quân giới ngoại bày bẫy liên hoàn truy sát Vương Lâm, điều khiển toàn quân phân bốn hướng và tiên tri tiên cơ để phục kích Hồng Sam Tử","chuong":"@c1429"},{"text":"Phân thân trên chiến trường bị Khai Thiên Phủ chém nát huyết thuẫn bát giác rồi xuyên thấu, thân thể hóa tan, bổn tôn bị diệt nhưng hồn phách thoát đi","chuong":"@c1433"},{"text":"Nhận ra Vương Lâm chính là bóng hình đáng sợ từng thấy trong thôi diễn, thân thể run rẩy không thể khống chế","chuong":"@c1561"},{"text":"Bóp nát ngọc giản bảo mạng do sư tôn trước khi chết tế luyện để thoát khỏi bánh xe vận mệnh của Vương Lâm","chuong":"@c1566"}]},"nguon":["@c1422","@c1423","@c1425","@c1427","@c1428","@c1429","@c1431","@c1432","@c1433"],"canhGioiCaoNhat":"Khuy Niết","cn":"云落","vaiTro":"Đại Tư của Trường Tôn Hội — chuyên gia thôi diễn tinh thần, chỉ huy quân sự giới ngoại","tinhCach":"Tinh thông thuật toán thôi diễn, suy tính tung tích và bí ẩn với độ chính xác cao; hành sự âm trầm kín kẽ, thường giấu tay bắt ấn quyết ngay giữa đám đông; kiên trì truy xét và chỉ huy quyết đoán dù liên tục bị phản phệ trọng thương; dễ hoảng loạn khiếp sợ khi biến cố vượt ngoài dự liệu hoặc đối diệ","blurb":"Vân Lạc là Đại Tư của Trường Tôn Hội, sở hữu Thuật Thiên Đại Tinh Thần có thể thôi diễn hình ảnh, ký ức và tung tích mục tiêu. Nàng tính ra hình dáng cùng khí tức của Vương Lâm để hỗ trợ Tư Mặc Tử truy sát, đồng hành tới Đại Đế tinh bái kiến đại đế, và tại đó nhiều lần âm thầm thôi diễn bí ẩn liên quan tới hạo kiếp Thái Cổ Tinh Thần nhưng liên tục bị lực lượng bí ẩn cắt đứt phép tính và phản phệ trọng thương. Sau khi bế quan hồi phục, nàng tái xuất với vai trò chỉ huy đại quân giới ngoại tấn công Vương Lâm, bày bẫy liên hoàn nhưng phân thân bị Khai Thiên Phủ chém nát; về sau phân thân của nàng"},{"id":"lao-to-hoa-tuoc-toc","name":"Lão tổ Hỏa Tước tộc","gioiTinh":"nam","trangThai":"song","theLuc":[{"ten":"Hỏa Tước tộc","trangThai":"gan-bo"}],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1422","text":"Sắc mặt cực kỳ âm trầm, mắt lộ sát khí điên cuồng, nhìn chằm chằm Phong Giới Đại Trận, ngồi cùng Đông Địch Tử và Nam Chiếu Thượng Nhân.","anchor":"Lão phu là phó hội trưởng Trưởng Tôn hội - Đông Địch Tử, chủ trì trận chiến nhập giới đầu tiên"},{"mucCt":"vua","text":"Dẫn đầu giới ngoại xông vào khe Phong Giới Đại Trận. Phóng tộc ấn Hỏa Tước Tộc hóa thành hỏa điểu đen mang hư hỏa lực tấn công Vương Lâm, liên thủ cùng Nam Chiếu Thượng Nhân.","anchor":"tộc ấn của Hỏa Tước Tộc hiện lên, một hỏa điểu màu đen ầm ầm bay ra","bridge":true,"khoang":"@c1425"},{"chuong":"@c1427","importance":"normal","mucCt":"gon","tieuDe":"Hợp chiến Hồng Sam Tử","text":"Cắn răng bỏ Vương Lâm, lao về phía Hồng Sam Tử cùng bốn tu sĩ bước thứ ba khác hợp chiến.","anchor":"Lão tổ Hỏa Tước Tộc cũng cắn răng lao tới, không để ý tới Vương Lâm mà tiến về phía Hồng Sam Tử"},{"chuong":"@c1431","importance":"normal","mucCt":"ky","tieuDe":"Bị Khai Thiên Phủ chẻ đôi, tử trận","text":"Là người đầu tiên thoát khỏi vòng cầm chân của Hồng Sam Tử, toàn thân bao phủ ngọn lửa đen, ấn kỳ Hỏa Tước Tộc trên mi tâm hóa thành hỏa điểu đen khổng lồ mang hương hỏa lực, lao thẳng tới Vương Lâm. Bị Vương Lâm dùng Khai Thiên Phủ chém một búa — phủ ảnh khổng lồ xuyên thấu hỏa điểu, phá tộc ấn, nứt hộp sọ, chẻ đôi toàn thân từ đầu xuống ngực, nguyên thần tiêu tan giữa tinh không. Chết.","anchor":"Tiểu tạp chủng, ngươi có chiếc búa kia thì đã sao, hãy xem lão phu giết ngươi như thế nào"}],"tuViMoc":[{"chuong":"@c1431","canhGioi":"Bước thứ ba","text":"Cao thủ bước thứ ba giới ngoại, tu vi cao thâm.","importance":"major"}],"nhanMach":[{"ten":"Nam Chiếu Thượng Nhân","tag":"dong-minh","quanHe":"Liên thủ tấn công Vương Lâm","ghiChu":"@c1425"},{"ten":"Hồng Sam Tử","tag":"doi-thu","quanHe":"Gia nhập liên thủ năm người vây đánh Hồng Sam Tử"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ giết mình","ghiChu":"Bị Vương Lâm dùng Khai Thiên Phủ chẻ đôi, tử trận."}],"tuiDo":{},"diem":[{"text":"Tu luyện trong biển lửa tím thánh địa chủ tinh Hỏa Tước, trách phạt tộc trưởng vì tự ti, thể hiện uy nghiêm trưởng bối","chuong":"@c1304"},{"text":"Truy tìm huyết mạch Chu Tước tại Điên Lạc, bắt Lưu Kim Bưu và kiểm tra nhiều lần nhưng bị lừa nhận giả Chu Tước","chuong":"@c1335"},{"text":"Thi triển Súc Địa Thành Thốn mang Lưu Kim Bưu về thánh địa, quỳ gối trước cánh cửa hư ảo gọi chủ","chuong":"@c1337"},{"text":"Bị mảnh vỡ cánh cửa thánh địa sụp đổ đâm trúng, phun máu trọng thương","chuong":"@c1340"},{"text":"Dẫn đầu giới ngoại xông vào khe Phong Giới Đại Trận, phóng tộc ấn Hỏa Tước Tộc hóa hỏa điểu đen","chuong":"@c1425"},{"text":"Tử trận khi bị Khai Thiên Phủ chẻ đôi — là người đầu tiên thoát vòng cầm chân Hồng Sam Tử, toàn thân bao phủ ngọn lửa đen","chuong":"@c1431"}]},"nguon":["@c1422","@c1423","@c1425","@c1427","@c1431"],"canhGioiCaoNhat":"Bước thứ ba","vaiTro":"Lão tổ Hỏa Tước tộc — cao thủ bước thứ ba giới ngoại, trưởng bối tối cao của Hỏa Tước tộc","tinhCach":"Uy nghiêm và nghiêm khắc với tộc nhân; cẩn trọng đa nghi khi kiểm chứng huyết mạch Chu Tước; sát phạt quyết đoán trên chiến trường; trung thành tuyệt đối với tộc ấn và sứ mệnh Hỏa Tước tộc","blurb":"Lão tổ Hỏa Tước tộc là cường giả bước thứ ba giới ngoại, tu luyện ẩn cư trong biển lửa tím nơi thánh địa chủ tinh Hỏa Tước. Ông từng rời thánh địa truy tìm nguồn gốc huyết mạch Chu Tước tại Điên Lạc, bắt Lưu Kim Bưu đưa về kiểm chứng nhưng bị lừa nhận giả Chu Tước, sau đó còn bị trọng thương khi cánh cửa thánh địa sụp đổ. Trong cuộc đại chiến phá Phong Giới Đại Trận, ông dẫn đầu giới ngoại xông trận, hợp chiến Hồng Sam Tử cùng bốn tu sĩ bước thứ ba khác, và là người đầu tiên thoát khỏi vòng cầm chân nhưng bị Khai Thiên Phủ chẻ đôi tử trận."},{"id":"lao-nhan-thien-phat-dien","name":"Lão nhân trong Thiên Phạt Điện","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Trưởng Tôn hội","trangThai":"gan-bo"},{"ten":"Thiên Phạt Điện","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Lão nhân giọng tang thương hỗn tạp từ trong lầu các đen Thiên Phạt Điện, tuyên bố tuân mệnh Trưởng Tôn hội tới đốc chiến và sẽ mở Phong Giới Đại Trận.","vaiTro":"Đốc chiến gia Thiên Phạt Điện","tinhCach":[],"tabs":{"diem":[],"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1423"]},{"id":"nu-tu-the-gioi-tien-khi","name":"Nữ tử ung dung cao quý","cn":"","aliases":["Nữ tử thế giới tiên khí","Phụ nhân y phục cung đình"],"gioiTinh":"nu","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Bước thứ ba (ước đoán)","trangThai":"song","blurb":"Nữ tử mặc quần áo trong cung, mi tâm có điểm tròn đỏ, ngụ trong thế giới tiên khí bên trong Thái Cổ Tinh Thần. Dùng ngọc như ý khiến đóa hoa sống lại, gỡ thoa vàng ném tới Lam Sơn thúc giục Lam Mộng Đạo Tôn quyết định tham chiến.","vaiTro":"Cường giả ẩn cư trong Thái Cổ Tinh Thần","tinhCach":["Ung dung cao quý, quyết đoán giúp người khác hạ quyết tâm"],"tabs":{"diem":[{"text":"Ngụ trong thế giới tiên khí, dùng ngọc như ý hồi sinh đóa hoa thành chín cánh lốc xoáy, ném thoa vàng xuyên không thúc giục Lam Mộng Đạo Tôn.","chuong":"@c1423"}],"kinhLich":[{"mucCt":"vua","text":"Đứng trên đỉnh núi trong một cái khe ở Thái Cổ Tinh Thần, mắt lóe hàn quang, bình thản bắt quyết hạ lệnh cho pháp bảo nổ tung. Là một trong hai tiên phi phối hợp phá Phong Giới Đại Trận.","anchor":"đôi mắt phụ nhân mặc y phục cung đình đứng trên đỉnh núi lóe lên hàn quang","bridge":true,"khoang":"@c1424"}],"tuViMoc":[],"nhanMach":[{"ten":"Lam Mộng Đạo Tôn","tag":"dong-minh","quanHe":"Thúc giục tham chiến","ghiChu":"Ném thoa vàng giúp hắn hạ quyết tâm"}],"tuiDo":{"phapBao":[{"ten":"Ngọc như ý","moTa":"Trên có đóa hoa, điểm vào khiến hoa sống lại thành chín cánh lốc xoáy","nguon":"@c1423"},{"ten":"Thoa vàng","moTa":"Gỡ từ đỉnh đầu ném xuyên không tới Lam Sơn","nguon":"@c1423","trangThai":"da-dung"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1423","@c1424"]},{"id":"lam-mong-dao-ton","name":"Lam Mộng Đạo Tôn","cn":"蓝梦道尊","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Lam Ti tộc","trangThai":"gan-bo"}],"trangThai":"song","tabs":{"diem":[{"text":"Là một trong ngũ đại tôn giả Thái Cổ Tinh Thần, được Vương Lâm xác định qua ký ức tu sĩ giới ngoại.","chuong":"@c1237"},{"text":"Chiêu mộ Vương Lâm kế thừa đạo thống không thành, sau đó truyền ba thức thần thông cho hắn.","chuong":"@c1243"},{"text":"Can thiệp cứu Vương Lâm trong Địa Phương hương nhưng bị sức mạnh Thiên Nghịch bức lui.","chuong":"@c1320"},{"text":"Đạt Không Huyền đại viên mãn, được nêu là đứng đầu Thái Cổ Ngũ Tôn.","chuong":"@c1435"},{"text":"Vì ước định với Chưởng Tôn mà xuất thủ chặn Vương Lâm, dẫn tới ân đoạn nghĩa tuyệt.","chuong":"@c1492"},{"text":"Một mình đánh bại Diệu Âm Đạo Tôn, Cửu Thiên và Đại Hoang Thượng Nhân trong ba ngày.","chuong":"@c1583"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1424","tieuDe":"Bất đắc dĩ hạ lệnh phá trận","text":"Trên Lam Sơn của Lam Ti tộc, ngơ ngác nhìn cây thoa rồi bất đắc dĩ bắt quyết hạ lệnh cho pháp bảo nổ tung. Dây đàn của hắn bị cây roi tử ý từ trận linh tấn công.","anchor":"Lam Mộng Đạo Tôn ngơ ngác nhìn cây thoa nọ, tay phải giơ lên, bắt quyết, miệng nói một cách bất đắc dĩ"},{"chuong":"@c1435","importance":"normal","mucCt":"ky","tieuDe":"Xuất hiện can thiệp trận chiến Phong Giới","text":"Xuất hiện từ Thái Cổ Tinh Thần trong đạo lam quang, yêu cầu Vương Lâm tha tu sĩ giới ngoại trở về. Nhắc ba lần ân tình: truyền thần thông vì con gái, chuyện Chưởng Tôn Tĩnh Trung Lao, và lần này. Cảnh cáo lần thứ tư sẽ ra tay. Vương Lâm vái sâu nhưng từ chối, Lam Mộng thở dài rời đi.","anchor":"Ta không muốn ra tay với ngươi. Hãy nhớ tới ân tình của ta đối với ngươi trước kia mà tha cho bọn họ trở về"}],"tuViMoc":[{"chuong":"@c1435","canhGioi":"Không Huyền đại viên mãn","text":"Tu vi đạt đỉnh Không Huyền, đứng đầu Thái Cổ Ngũ Tôn, vượt Cửu Thiên Ma Tôn và Diệu Âm Đạo Tôn","importance":"major"}],"nhanMach":[{"ten":"Lý Thiến Mai","tag":"cha-me","quanHe":"Phụ thân — con gái","ghiChu":"Ngồi đối diện yên lặng khi phụ thân do dự rồi quyết định hy sinh tu vi"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Từng truyền thần thông cho VL vì con gái, nhắc ân tình ba lần","ghiChu":"Cảnh cáo lần thứ tư sẽ ra tay"},{"ten":"Chưởng Tôn","tag":"khac","quanHe":"Chỉ Lam Mộng mới có thể khiến Chưởng Tôn thay đổi kế hoạch"},{"ten":"Cửu Thiên Ma Tôn","tag":"khac","quanHe":"Đồng liệt Thái Cổ Ngũ Tôn, tu vi không bằng Lam Mộng"},{"ten":"Diệu Âm Đạo Tôn","tag":"khac","quanHe":"Đồng liệt Thái Cổ Ngũ Tôn, tu vi không bằng Lam Mộng"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Dây cổ cầm đứt","moTa":"Dây đàn bị đứt, được dung nhập máu tươi và tu vi cả đời + hương hỏa lực, phóng lên bầu trời phá trận","nguon":"@c1423","trangThai":"da-dung"}]}},"nguon":["@c1423","@c1424","@c1435"],"canhGioiCaoNhat":"Không Huyền đại viên mãn","vaiTro":"Thái Cổ Ngũ Tôn — lãnh đạo Lam Ti Tộc","tinhCach":"Thâm trầm u buồn; trọng tình thân; điềm tĩnh thận trọng; nặng nhân quả","blurb":"Lam Mộng Đạo Tôn là một trong Thái Cổ Ngũ Tôn của Thái Cổ Tinh Thần, lãnh đạo Lam Ti Tộc, cư ngụ tại Lam Sơn và về sau được tiết lộ là người sinh ra trong giới nội. Ông từng chiêu mộ Vương Lâm kế thừa đạo thống không thành nhưng vẫn truyền thần thông, nhiều lần dõi theo và can thiệp giúp Vương Lâm. Dù từng vì ước định với Chưởng Tôn mà xuất thủ chặn Vương Lâm, về sau ông tuyên bố đứng về phía Vương Lâm và tham chiến trong các biến cố lớn."},{"id":"ly-thien-mai","name":"Lý Thiến Mai","cn":"","aliases":["Liên Minh Tinh Vực"],"gioiTinh":"nu","trangThai":"song","tabs":{"diem":[{"text":"Thiên tài tu đạo truyền kỳ Vân Hải tinh vực: 5 tuổi nhập đạo, hơn 1200 năm đạt Toái Niết hậu kỳ","chuong":"@c1090"},{"text":"Luận đạo cùng Vương Lâm tại Bồng Lai, đặt ba câu hỏi về thiên — đạo — nơi đi, kết hẹn ước trăm năm","chuong":"@c1097"},{"text":"Bất chấp lệnh cấm rời chiến trường Yêu Tông, vượt tinh vực tìm Vương Lâm, bị Phá Thiên Tông đoạn tuyệt sư đồ","chuong":"@c1200"},{"text":"Suốt mười năm hy sinh máu tươi và tinh huyết chăm sóc tượng đá Vương Lâm tại đại lục hoang dã, kiệt sức gần mất sinh cơ","chuong":"@c1214"},{"text":"Được Vương Lâm tiếp nhận sau khi khôi phục ký ức, xác nhận tình cảm giữa hai người","chuong":"@c1583"},{"text":"Quyết định chuyển thế đầu thai, nguyện chờ Vương Lâm trong luân hồi, là người cuối cùng rời đi","chuong":"@c1697"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1423"],"vaiTro":"Nữ tu sĩ Phá Thiên Tông — thiên chi kiêu nữ Vân Hải tinh vực, tri kỷ của Vương Lâm","tinhCach":"ham hỏi đạo, trọng bản tâm; nặng tình và giữ hẹn; kiên định trước sư mệnh, tông lệnh; sẵn sàng hy sinh vì người mình chọn","blurb":"Lý Thiến Mai, bí danh Lý Oánh Chi, là thiên chi kiêu nữ Vân Hải tinh vực xuất thân Phá Thiên Tông, năm tuổi nhập đạo, hơn 1200 năm tu luyện đạt Toái Niết hậu kỳ. Nàng kết giao với Vương Lâm qua luận đạo tại Bồng Lai, trải trăm năm chém giết mãnh thú tại chiến trường Yêu Tông rồi bất chấp tông lệnh vượt tinh vực tìm hắn, bị đoạn tuyệt sư đồ và hy sinh máu tươi, tinh huyết chăm sóc tượng đá Vương Lâm suốt mười năm đến kiệt quệ mất trí nhớ. Sau khi dần khôi phục ký ức và được Vương Lâm tiếp nhận, nàng quyết định chuyển thế đầu thai, nguyện chờ hắn trong luân hồi."},{"id":"dong-tu-tam-dong-chi-tu","name":"Đồng tử tam đồng chi tu","cn":"","aliases":["Đồng tử (cực tây Thái Cổ Tinh Thần)"],"gioiTinh":"nam","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Đồng tử bảy tám tuổi bị đóng băng trong khối hàn băng khổng lồ do chín tu chân tinh tạo thành tại vùng cực tây Thái Cổ Tinh Thần. Mỗi mắt có ba con ngươi, mở mắt khiến băng nổ tung, phóng ba đạo u quang vào tinh không.","vaiTro":"Cường giả ẩn cư cực tây Thái Cổ Tinh Thần","tinhCach":[],"tabs":{"diem":[{"text":"Mỗi bên mắt có ba con ngươi, bị phong ấn trong khối hàn băng chín tu chân tinh, khi mở mắt băng nổ tung phóng u quang.","chuong":"@c1423"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1424","tieuDe":"Hạ lệnh phá trận tại cực tây","text":"Ở nơi chín tu chân tinh bị đóng băng tại cực tây Thái Cổ Tinh Thần, giơ tay bắt quyết thì thào lệnh cho pháp bảo nổ tung. Là một trong ba tu sĩ bước thứ ba phối hợp phá Phong Giới Đại Trận.","anchor":"Chổ cực tây của Thái cổ Tinh Thần, tại chín tu chân tinh bị đóng băng, đồng tử nọ giơ tay phải lên, thì thào nói"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1423","@c1424"]},{"id":"nu-tu-hong-y-toc-do","name":"Nữ tử hồng y tóc đỏ","cn":"","aliases":["Nữ tử áo đỏ (tiên phi)","Tiên Phi"],"gioiTinh":"nu","theLuc":[{"ten":"Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tử dung nhan tuyệt mỹ mặc hồng y tóc đỏ, ngụ trên khối đại lục cổ kính trôi nổi trong khe không gian bên trong Thái Cổ Tinh Thần. Cắn ngón tay, ba giọt máu hóa ba quỷ ảnh dữ tợn tham gia phá Phong Giới Đại Trận.","vaiTro":"Cường giả ẩn cư trong Thái Cổ Tinh Thần","tinhCach":[],"tabs":{"diem":[{"text":"Dung nhan tuyệt mỹ, cắn ngón tay hóa máu thành quỷ ảnh dữ tợn tham chiến.","chuong":"@c1423"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1424","tieuDe":"Hạ lệnh phá trận tại khe tiên khí","text":"Đứng trên mảnh đại lục trong khe tràn ngập tiên khí, ánh mắt lóe lên, như cười như không ngâm khẽ lệnh cho pháp bảo nổ tung. Là tiên phi thứ hai trong sáu cường giả phối hợp phá Phong Giới Đại Trận.","anchor":"nữ tử áo đỏ đứng trên mảnh đại lục kia ánh mắt cũng lóe lên, như cười như không ngâm khẽ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1423","@c1424"]},{"id":"lao-gia-gay-nhom","name":"Lão già gầy nhom","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Giới ngoại","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (thực lực mạnh)","trangThai":"song","blurb":"Tu sĩ giới ngoại thân hình gầy như thây khô, từ lầu các màu đen bước ra. Quen biết chủ nhân Phong Giới, gọi là Phong Giới lão quỷ. Bị ngọc bội phong tỏa.","vaiTro":"Cường giả giới ngoại, bị phong tỏa bởi ngọc bội chủ nhân Phong Giới","tinhCach":"Tự tin; am hiểu nội tình","tabs":{"diem":[{"text":"Nhận ra chủ nhân Phong Giới đã tự dung nhập vào trận pháp, gọi là Phong Giới lão quỷ","chuong":"@c1425"}],"kinhLich":[{"mucCt":"gon","text":"Từ lầu các đen bước ra định ngăn Khai Thiên Phủ nhưng bị ngọc bội phát ra màn sáng bao phủ phong tỏa. Nhận ra đây là thần thông của chủ nhân Phong Giới đã tự dung nhập vào trận pháp.","anchor":"Phong Giới lão quỷ. Ngươi đã tự mình dung nhập vào trong trận pháp","bridge":true,"khoang":"@c1425"}],"tuViMoc":[],"nhanMach":[{"ten":"Chủ nhân Phong Giới","tag":"doi-thu","quanHe":"Quen biết, gọi là Phong Giới lão quỷ","ghiChu":"@c1425"}],"tuiDo":{}},"nguon":["@c1425"]},{"id":"chu-nhan-phong-gioi","name":"Chủ nhân Phong Giới","nguon":["@c1425"],"trangThai":"khong-ro","tabs":{"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1425","tieuDe":"Kích hoạt ngọc bội và Khai Thiên Phủ bảo vệ giới nội","text":"Ngọc bội mang khí tức của chủ nhân Phong Giới xuất hiện trên Phong Giới Đại Trận, kích hoạt Khai Thiên Phủ chém hai lần giết gần mười nghìn tu sĩ giới ngoại. Đồng thời phát ra màn sáng phong tỏa lão già gầy nhom. Lộ ra đã tự dung nhập vào trận pháp từ trước chính vì giờ phút này.","anchor":"Nãm đó chủ nhân Phong Giới dung nhập vào trong trận pháp có lẽ chính là vì giờ phút này"}],"diem":[{"text":"Được Vương Lâm gọi xuất hiện trong lúc đối đầu nguy cấp, tiết lộ đã được bố trí tại Phong Giới đại trận từ trước","chuong":"@c1232"},{"text":"Hiện thân từ ngọc bội dưới dạng cây đại thụ chọc trời với mặt người già nua, ban mệnh lệnh và hé lộ bản chất Thiên Kiếp","chuong":"@c1233"},{"text":"Dùng sợi tơ màu xanh quấn lên trận pháp phá hoại trên phạm vi lớn, ngăn khí linh phản kích, đối kháng Khai Thi","chuong":"@c1235"},{"text":"Được Vương Lâm nhắc tới như người thủ hộ toàn bộ giới nội khi so sánh với Chu Tước lão Thái","chuong":"@c1287"},{"text":"Ngọc bội mang khí tức của chủ nhân Phong Giới xuất hiện trên Phong Giới Đại Trận, kích hoạt Khai Thiên Phủ bảo vệ giới nội","chuong":"@c1425"}]},"vaiTro":"Chủ nhân Phong Giới — đồng minh bí ẩn được Vương Lâm bố trí thủ hộ giới nội","tinhCach":"Bí ẩn, ẩn mình chờ thời; uy nghiêm khi ban mệnh lệnh; mang khí chất già nua, ánh mắt hồi tưởng tang thương","blurb":"Chủ nhân Phong Giới là nhân vật bí ẩn được Vương Lâm đưa tới Phong Giới đại trận từ trước, chỉ hiện thân vào thời khắc nguy cấp dưới dạng cây đại thụ chọc trời mang mặt người già nua. Người này nắm giữ hiểu biết về bản chất Thiên Kiếp, giữ vai trò thủ hộ toàn bộ giới nội và có khả năng kích hoạt Khai Thiên Phủ cùng ngọc bội để bảo vệ Phong Giới Đại Trận trước các mối đe dọa từ bên ngoài."},{"id":"tam-lao-phong-diet-toc","name":"Tam lão Phong Diệt Tộc","gioiTinh":"nam","theLuc":[{"ten":"Phong Diệt Tộc","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Ba vị lão nhân mặc tử bào thuộc Phong Diệt Tộc, nhận lệnh Vân Lạc đại ti phong ấn hoặc giết Vương Lâm.","vaiTro":"Ba cao thủ Phong Diệt Tộc, nhận lệnh truy sát Vương Lâm","tinhCach":"Phục tùng mệnh lệnh Vân Lạc đại ti","tabs":{"diem":[{"text":"Ba người mặc tử bào che kín toàn thân, nhận lệnh Vân Lạc đại ti lao về phía Vương Lâm để phong ấn hoặc giết hắn.","chuong":"@c1427"},{"text":"Ba người mặc tử bào thuộc Phong Diệt Tộc, nhận lệnh Vân Lạc truy sát Vương Lâm","chuong":"@c1427"},{"text":"Ba người mặc tử bào che kín toàn thân, hóa u quang lao về phía Vương Lâm theo lệnh Vân Lạc.","chuong":"@c1427"}],"kinhLich":[{"chuong":"@c1427","importance":"normal","mucCt":"vua","tieuDe":"Nhận lệnh truy sát Vương Lâm","text":"Theo lệnh Vân Lạc đại ti, ba người mặc tử bào hóa u quang lao về phía Vương Lâm để phong ấn hoặc giết hắn.","anchor":"phía sau lập tức có ba luồng u quang lóe lên, vừa vặn vẹo liền hóa thành ba người mặc tử bào"}],"tuViMoc":[],"nhanMach":[{"ten":"Vân Lạc","tag":"cap-tren","quanHe":"Nhận lệnh từ Vân Lạc đại ti"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu truy sát theo lệnh Vân Lạc"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1427"],"canhGioiCaoNhat":"Không rõ"},{"id":"ba-tu-si-tu-bao-phong-diet-toc","name":"Ba tử sĩ Phong Diệt Tộc","cn":"","aliases":["Ba tu sĩ tử bào Phong Diệt Tộc"],"gioiTinh":"nam","theLuc":[{"ten":"Phong Diệt Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Ba tử sĩ mặc tử bào của Phong Diệt Tộc, được Chưởng Tôn nuôi dưỡng từ nhỏ với mục đích duy nhất là hiến tế sinh mạng phong ấn cao thủ. Bị Vương Lâm tung quyền giết chết cả ba.","vaiTro":"Tử sĩ Phong Diệt Tộc, công cụ phong ấn dùng một lần","tinhCach":"Bình tĩnh, không sợ hãi trước cái chết; hoàn toàn tuân phục sứ mệnh được giao","tabs":{"diem":[{"text":"Được Chưởng Tôn nuôi dưỡng từ nhỏ chỉ để phong ấn cao thủ, hiến mạng không chút do dự","chuong":"@c1428"}],"kinhLich":[{"mucCt":"vua","text":"Ẩn mình trong đại quân giới ngoại dưới dạng u quang, hiện thân thi triển thần thông bộ tộc Phong Diệt: mỗi người hiến tế sinh mạng đánh một đạo phong ấn lên Vương Lâm (nguyên lực, thể lực, sinh cơ). Phong ấn thành công nhưng cả ba bị Vương Lâm tung quyền đánh tan thân xác và nguyên thần.","anchor":"Bọn họ từ nhỏ đã được Chưởng Tôn thu nhận với mục đích phong ấn những cao thủ","bridge":true,"khoang":"@c1428"}],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng Tôn","tag":"su-mon","quanHe":"Người nuôi dưỡng họ từ nhỏ với mục đích phong ấn cao thủ","ghiChu":"@c1428"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu phong ấn, cũng là người giết chết cả ba","ghiChu":"@c1428"}],"tuiDo":{}},"nguon":["@c1428"]},{"id":"tu-si-khuy-niet-giang-dao","name":"Tu sĩ Khuy Niết giảng đạo","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Thiên Nhân Đệ Nhất Suy","trangThai":"song","blurb":"Tu sĩ vô danh từng tham dự trận chiến Vân Hải khi mới đạt Khuy Niết, sau thành đại trưởng lão một tông phái nhỏ ở cảnh giới Thiên Nhân Đệ Nhất Suy. Đăng đàn giảng đạo kể lại ý nghĩa vinh quang gắn liền với Vương Lâm.","vaiTro":"Người kể chuyện flash-forward về trận chiến Vân Hải","tinhCach":"Kính phục Vương Lâm sâu sắc; truyền đạt kinh nghiệm cho hậu bối","tabs":{"diem":[{"text":"Nhân chứng trận chiến Vân Hải, sau nhiều năm vẫn kể về vinh quang gắn liền với Vương Lâm như bài giảng đạo quan trọng nhất","chuong":"@c1428"}],"kinhLich":[{"chuong":"@c1428","importance":"normal","mucCt":"gon","tieuDe":"Đăng đàn giảng đạo về vinh quang Vân Hải","text":"Đăng đàn giảng đạo, kể lại trận chiến Vân Hải năm xưa và một câu nói của Vương Lâm đã thay đổi nhận thức vinh quang của tất cả.","anchor":"một tu sĩ đã từng tham dự cuộc chiến ở Vân Hải"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Người truyền cảm hứng về vinh quang trong trận chiến Vân Hải","ghiChu":"@c1428"}],"tuiDo":{}},"nguon":["@c1428"]},{"id":"dong-tu-han-bang","name":"Đồng tử hàn băng","aliases":["Hàn y đồng tử","Đồng tử đầu to","Đầu to"],"trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1429","importance":"normal","mucCt":"ky","tieuDe":"Phá Phong Giới Đại Trận, giết gần vạn tu sĩ Vân Hải","text":"Bước ra từ Thái Cổ Tinh Thần, tảng băng khổng lồ phá tan Phong Giới Đại Trận tạo lỗ hổng lớn rồi tiến vào giới nội, vỡ thành cuồng phong hàn băng giết gần vạn tu sĩ Vân Hải bị đóng băng tan vỡ tử vong. Yêu cầu Hồng Sam Tử đưa bổn tôn ra đánh, nói rõ đây chỉ là phân thân. Sau đó cùng năm cao thủ bước ba liên thủ tấn công Hồng Sam Tử.","anchor":"Ngươi và ta sẽ tái chiến một phen. Hãy đưa bổn tôn của ngươi ra đây, chỉ là một phân thân lão phu không muốn đánh"},{"chuong":"@c1431","importance":"bridge","mucCt":"gon","text":"Đang giao chiến với Hồng Sam Tử, tu vi rất cao thâm.","anchor":"hàn y đồng tử đang đánh với Hồng Sam Tử kia tu vi vốn rất cao thâm"},{"chuong":"@c1432","importance":"normal","mucCt":"vua","tieuDe":"Ra lệnh giết Phong Tôn, điều binh chặn Vương Lâm","text":"Nhận thấy tâm thần quân giới ngoại đang tan rã, gầm lệnh giết Phong Tôn. Đánh văng Nam Chiếu Thượng Nhân ra khỏi vây khốn của Hồng Sam Tử và đánh văng lão già Bạch Lặc tộc, phái cả hai đi diệt Vương Lâm.","anchor":"Giết Phong Tôn!"},{"chuong":"@c1434","importance":"bridge","mucCt":"gon","text":"Bị Hồng Sam Tử, mỹ phụ trung niên Triệu Hà và Lỗ Phu Tử ba người giáp công, thần sắc trở nên âm trầm.","anchor":"Hai người gia nhập vào cuộc chiến, khiến cho Hồng Sam Tử được thảnh thơi một chút"},{"chuong":"@c1438","importance":"bridge","mucCt":"gon","text":"Trầm mặc rút lui, lần lượt bước vào lỗ hổng Phong Giới Đại Trận đi vào Thái Cổ Tinh Thần.","anchor":"khuôn mặt xinh đẹp hiện lên vẻ phẫn nộ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Phá tan Phong Giới Đại Trận bằng tảng băng khổng lồ, giết gần vạn tu sĩ Vân Hải và xâm nhập giới","chuong":"@c1429"},{"text":"Giao chiến với Hồng Sam Tử, thể hiện tu vi rất cao thâm","chuong":"@c1431"},{"text":"Ra lệnh giết Phong Tôn, đánh văng Nam Chiếu Thượng Nhân, điều binh chặn Vương Lâm","chuong":"@c1432"},{"text":"Bị Hồng Sam Tử, Triệu Hà và Lỗ Phu Tử ba người giáp công","chuong":"@c1434"},{"text":"Trầm mặc rút lui, rời giới Vân Hải trở về Thái Cổ Tinh Thần","chuong":"@c1438"}]},"nguon":["@c1429","@c1431","@c1432","@c1434","@c1438"],"gioiTinh":"nam","vaiTro":"Cường giả từ Thái Cổ Tinh Thần — chỉ huy cuộc xâm nhập giới Vân Hải","tinhCach":"hung hãn quyết đoán; lạnh lùng tàn nhẫn; biết tiến biết lui","blurb":"Đồng tử hàn băng là cường giả xuất thân từ Thái Cổ Tinh Thần, dẫn đầu cuộc tấn công vào giới Vân Hải. Hắn phá tan Phong Giới Đại Trận bằng tảng băng khổng lồ, giết gần vạn tu sĩ Vân Hải và giao chiến với nhiều cao thủ bản địa, nhưng cuối cùng bị ba cường giả giáp công buộc phải trầm mặc rút lui về Thái Cổ Tinh Thần."},{"id":"nu-tu-ao-do","name":"Nữ tử áo đỏ","aliases":["Tiên Phi","Tiên Phi áo đỏ"],"gioiTinh":"nu","theLuc":[{"ten":"Giới ngoại Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Tiên Phi","trangThai":"song","blurb":"Nữ tử áo đỏ là một Tiên Phi thuộc phe giới ngoại, tham chiến trong đại chiến Vân Hải. Bà ẩn mình trong cuồng phong hàn băng, dùng ba giọt máu bổn mệnh hóa tam đầu quỷ ảnh đánh trúng đòn chí mạng Hồng Sam Tử, rồi liên tiếp giao chiến với Nam Vân Tử và Tử Mộng. Khi nhận ra mình chỉ là quân cờ trong kế hoạch của người khác, bà phẫn nộ rời khỏi giới nội qua lỗ hổng Phong Giới.","vaiTro":"Tiên Phi phe giới ngoại, tham gia đại chiến Vân Hải","tinhCach":"Tàn nhẫn, ra đòn chí mạng bất ngờ; kiêu ngạo, khinh miệt đối thủ; mưu lược nhưng cảnh giác cao; quyết đoán, dám cắt đứt khi nhận ra bị lợi dụng","tabs":{"diem":[{"text":"Dùng ba giọt máu bổn mệnh hóa tam đầu quỷ ảnh, ẩn trong cuồng phong hàn băng bất ngờ đánh trúng đòn chí mạng Hồng Sam Tử","chuong":"@c1429"},{"text":"Giao chiến với Nam Vân Tử, biến sắc kiêng kị khi nghe thanh âm Phong Tôn","chuong":"@c1430"},{"text":"Giao chiến với Tử Mộng, hừ lạnh gọi đối phương là tiện tỳ, thể hiện thái độ khinh miệt","chuong":"@c1434"},{"text":"Nhận ra cây cung Lý Quảng, lộ vẻ sợ hãi không thể che giấu trước lai lịch của bảo vật","chuong":"@c1436"},{"text":"Nhận ra bản thân bị biến thành quân cờ, phẫn nộ rời giới nội qua lỗ hổng Phong Giới","chuong":"@c1438"}],"kinhLich":[{"chuong":"@c1429","importance":"normal","mucCt":"vua","tieuDe":"Ẩn trong cuồng phong đánh trúng Hồng Sam Tử","text":"Dùng ba giọt máu bổn mệnh hóa thành tam đầu quỷ ảnh, ẩn mình trong cuồng phong hàn băng bất ngờ tấn công Hồng Sam Tử đánh trúng ngực. Tiết lộ toàn bộ là kế hoạch liên hoàn của Vân Lạc Đại Ti rồi lao thẳng tới tấn công Nam Vân Tử.","anchor":"Một trong những Tiên Phi đã lấy ba giọt máu bổn mệnh để hóa thành tam đầu quỷ ảnh"},{"chuong":"@c1430","importance":"bridge","mucCt":"gon","text":"Đang giao chiến với Nam Vân Tử, khi nghe thanh âm Phong Tôn thì biến sắc, mắt hiện vẻ kiêng kị, nhớ lại ký ức năm xưa.","anchor":"nữ tử áo đỏ đang giao chiến với hắn cũng biến sắc, trong mắt hiện lên vẻ kiêng kị hiếm thấy"},{"chuong":"@c1434","importance":"bridge","mucCt":"gon","text":"Giao chiến với Tử Mộng sau khi Nam Vân Tử rút đi, hừ lạnh gọi Tử Mộng là tiện tỳ, hỏi vì sao tỉ tỉ của Tử Mộng không tới, hai bên khó phân thắng bại.","anchor":"Tiện tỳ, tỉ tỉ của ngươi vì sao lại không đến?"},{"mucCt":"gon","text":"Nhận ra cây cung Lý Quảng ngay khi nhìn thấy, lộ vẻ sợ hãi không thể che giấu, cho thấy hiểu biết về lai lịch bảo vật từ quê hương Đạo cổ.","anchor":"chỉ có Tiên Phi cùng với nữ tu Tử Mộng của Triệu Hà kia ngay khi nhìn thấy cây cung này, trong mắt liền lộ ra một sự sợ hãi không thể che giấu được","bridge":true,"khoang":"@c1436"},{"chuong":"@c1438","importance":"normal","mucCt":"gon","tieuDe":"Nhận ra là quân cờ, rời giới nội","text":"Nhận ra mình bị biến thành quân cờ trong kế hoạch của người khác, phẫn nộ xoay người bước qua lỗ hổng Phong Giới Đại Trận vào Thái Cổ Tinh Thần, không ai ngăn cản.","anchor":"khuôn mặt xinh đẹp hiện lên vẻ phẫn nộ"}],"tuViMoc":[],"nhanMach":[{"ten":"Vân Lạc","tag":"dong-minh","quanHe":"Phối hợp theo kế hoạch của Vân Lạc Đại Ti trong đại chiến Vân Hải"},{"ten":"Hồng Sam Tử","tag":"doi-thu","quanHe":"Ẩn trong cuồng phong đánh trúng đòn chí mạng Hồng Sam Tử"},{"ten":"Nam Vân Tử","tag":"doi-thu","quanHe":"Bỏ Hồng Sam Tử lao tới tấn công Nam Vân Tử"},{"ten":"Tử Mộng","tag":"doi-thu","quanHe":"Đối thủ giao chiến, gọi là tiện tỳ"},{"ten":"Vân Lạc Đại Ti","tag":"cap-tren","quanHe":"Phục tùng chỉ huy của Vân Lạc","ghiChu":"Thực hiện kế hoạch phục kích theo bố trí của Vân Lạc."}],"tuiDo":{}},"nguon":["@c1429","@c1430","@c1432","@c1434","@c1436","@c1438"]},{"id":"dong-tu-dau-to","name":"Đồng tử đầu to","cn":"","aliases":["Hàn y đồng tử","Đồng tử hàn băng","Đầu to"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1430","importance":"bridge","mucCt":"gon","text":"Nghe thanh âm Phong Tôn thì mắt lộ vẻ sợ hãi — người hắn sợ nhất cả đời không phải Chưởng Tôn giới ngoại hay Tiên Phi mà là Phong Tôn.","anchor":"Người mà hắn cả đời này sợ nhất không phải Chưởng Tôn của giới ngoại, cũng không phải là Tiên Phi, mà là Phong Tôn này"},{"chuong":"@c1440","importance":"bridge","mucCt":"vua","text":"Ngày thứ hai sau khi Tư Đồ Nam rời đi, cùng Lôi Cát bỏ Vũ Giới đi tìm chủ nhân Vương Lâm.","anchor":"đầu to và Lôi Cát cũng cùng nhau bỏ đi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Là một trong số ít Thiên Cương tiên có thể khắc tên lên Phong Tiên thạch.","chuong":"@c0826"},{"text":"Bị Vương Lâm đánh bại, ấn phong ấn lên mi tâm và nguyên thần, từ đó xưng Vương Lâm là chủ nhân.","chuong":"@c0838"},{"text":"Khi bị sáu phân thân Khuy Niết sơ kỳ của Vu Phi dồn ép, từng định tự bạo nguyên thần để liều mạng.","chuong":"@c0853"},{"text":"Thể hiện tạo nghệ về cấm chế trong Tiên phủ thứ tư, cùng Lôi Cát tính toán phương pháp phá giải và đề xuất hướng phá cấm.","chuong":"@c0942"},{"text":"Nhục thân cũ sụp đổ ở Yêu Linh chi địa, được các Trưởng lão Toái Niết trợ giúp ngưng tụ thân thể mới tại Chu Tước Thánh Tông.","chuong":"@c1016"},{"text":"Được Vương Lâm trả hồn huyết, giải phong ấn và hoàn toàn tự do, nhưng không rời đi mà tiếp tục ở lại bên Vương Lâm.","chuong":"@c1621"}]},"nguon":["@c1430","@c1440"],"vaiTro":"Thiên Cương tiên La Thiên — thuộc hạ trung thành của Vương Lâm","tinhCach":"ngoài mặt cười ngây ngô nhưng nội tâm thận trọng; trung thành với Vương Lâm, từng định tự bạo nguyên thần khi nguy cấp; mang quá khứ bị gia tộc ruồng bỏ nên cô độc trầm mặc; am hiểu cấm chế và phá trận","blurb":"Đồng tử đầu to là tu sĩ Khuy Niết La Thiên Bắc Vực, thuộc nhóm Thiên Cương tiên hiếm hoi có thể khắc tên lên Phong Tiên thạch. Từ kẻ dẫn quân xâm phạm Chu Tước Tinh, hắn bị Vương Lâm đánh bại, phong ấn nguyên thần rồi thu phục, về sau nhiều lần theo hầu, hộ pháp và trợ chiến cho Vương Lâm. Sau khi nhục thân cũ sụp đổ rồi được tái tạo, hắn được trả hồn huyết, giải phong ấn nhưng vẫn chọn ở lại bên Vương Lâm."},{"id":"thanh-nien-khuy-niet-van-hai","name":"Thanh niên Khuy Niết Sơ Kỳ","cn":"","aliases":[],"gioiTinh":"nam","trangThai":"song","theLuc":[{"ten":"Vân Hải","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Khuy Niết Sơ Kỳ","blurb":"Tu sĩ Vân Hải vô danh, người đầu tiên dừng bước bỏ chạy và quay lại nhìn Vương Lâm, thì thào khởi đầu phản ứng dây chuyền khiến toàn bộ tu sĩ Vân Hải bừng tỉnh chiến ý.","vaiTro":"Tu sĩ Vân Hải vô danh, người khởi đầu phản ứng dây chuyền bừng tỉnh chiến ý","tinhCach":"can đảm; trọng nghĩa","tabs":{"diem":[{"text":"Người đầu tiên dừng bước bỏ chạy, quay lại và thì thào lời khơi dậy sĩ khí toàn quân Vân Hải","chuong":"@c1430"}],"kinhLich":[{"mucCt":"gon","text":"Là tu sĩ đầu tiên dừng bước bỏ chạy, quay lại nhìn bóng lưng Vương Lâm và thì thào khiến toàn bộ tu sĩ Vân Hải bừng tỉnh chiến ý.","anchor":"Tu sĩ chúng ta tiếc gì mà không đánh một trận","bridge":true,"khoang":"@c1430"}],"tuViMoc":[{"chuong":"@c1430","canhGioi":"Khuy Niết Sơ Kỳ","text":"Tu vi Khuy Niết Sơ Kỳ khi xuất hiện trong trận đại chiến Vân Hải.","importance":"minor"}],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1430"]},{"id":"lao-gia-bach-lac-toc","name":"Lão già mặc lam bào (Bạch Lặc tộc)","gioiTinh":"nam","canhGioiCaoNhat":"Bước thứ ba","trangThai":"song","theLuc":[{"ten":"Bạch Lặc tộc","trangThai":"gan-bo"}],"blurb":"Tu sĩ bước thứ ba giới ngoại đến từ Bạch Lặc tộc, thuộc đợt đại quân thứ hai xâm nhập Vân Hải. Chứng kiến Nam Chiếu Thượng Nhân bị tiêu diệt thì hoảng sợ rút lui.","vaiTro":"Tu sĩ bước thứ ba giới ngoại thuộc Bạch Lặc tộc","tinhCach":["Thận trọng, biết sợ khi thấy đồng đẳng bị tiêu diệt"],"tabs":{"diem":[{"text":"Bị hàn y đồng tử phái đi giết Vương Lâm nhưng chứng kiến Nam Chiếu bị diệt thì hoảng sợ rút lui.","chuong":"@c1432"}],"kinhLich":[{"chuong":"@c1432","importance":"normal","mucCt":"gon","tieuDe":"Hoảng sợ rút lui sau cái chết của Nam Chiếu","text":"Bị hàn y đồng tử đánh văng ra lao về phía Vương Lâm, nhưng chứng kiến Nam Chiếu Thượng Nhân bị tiêu diệt thì toát mồ hôi lạnh, nhanh chóng lui lại.","anchor":"trán lão già toát mồ hôi lạnh đầm đìa, nhanh chóng lui lại phía sau"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu ám sát được hàn y đồng tử chỉ định, hoảng sợ rút lui"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1432"]},{"id":"tu-mong","name":"Tử Mộng","cn":"紫梦","aliases":["Nữ tử cải trang văn sĩ mặc trường bào"],"gioiTinh":"nu","theLuc":[{"ten":"Triệu Hà","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tu dẫn đầu lực lượng Triệu Hà chi viện giới nội, dung nhan xinh đẹp tuyệt trần, cưỡi tia chớp hình rồng. Tiếp quản trận chiến với Tiên Phi, giao đấu ngang tài ngang sức.","vaiTro":"Thủ lĩnh đội quân Triệu Hà, đồng minh giới nội","tinhCach":"Tự tin; bình tĩnh trước đối thủ mạnh","tabs":{"diem":[{"text":"Nữ tu xinh đẹp tuyệt trần dẫn đầu đại quân Triệu Hà, đứng trên tia chớp hình rồng tới chi viện giới nội.","chuong":"@c1434"},{"text":"Tiếp quản trận chiến với Tiên Phi thay Nam Vân Tử, giao đấu ngang tài ngang sức.","chuong":"@c1434"}],"kinhLich":[{"mucCt":"vua","text":"Dẫn đầu mấy vạn nữ tu Triệu Hà tới chi viện giới nội, cưỡi tia chớp hình rồng. Tiếp quản trận chiến với Tiên Phi thay Nam Vân Tử, hai bên ngang tài ngang sức. Khi Tiên Phi hỏi vì sao tỉ tỉ không đến, đáp rằng tỉ tỉ sẽ sớm tới.","anchor":"Nam Vân Tử đạo hữu, người này giao cho Tử Mộng là được rồi","bridge":true,"khoang":"@c1434"},{"mucCt":"gon","text":"Cùng Tiên Phi nhận ra cây cung Lý Quảng ngay khi nhìn thấy, lộ vẻ sợ hãi không thể che giấu.","anchor":"chỉ có Tiên Phi cùng với nữ tu Tử Mộng của Triệu Hà kia ngay khi nhìn thấy cây cung này, trong mắt liền lộ ra một sự sợ hãi không thể che giấu được","bridge":true,"khoang":"@c1436"},{"chuong":"@c1438","importance":"bridge","mucCt":"gon","text":"Đồng thời ra tay cùng Triệu Hà và các cao thủ giới nội tấn công bàn tay khổng lồ.","anchor":"Có thể nói tất cả những cao thủ của giới nội ở đây lúc này, toàn bộ đều trong khoảng khắc này bộc phát ra sức mạnh lớn nhất"}],"tuViMoc":[],"nhanMach":[{"ten":"Tiên Phi","tag":"doi-thu","quanHe":"Đối thủ giao chiến","ghiChu":"Tiếp quản trận đấu với Tiên Phi từ Nam Vân Tử"},{"ten":"Nam Vân Tử","tag":"dong-minh","quanHe":"Đồng minh giới nội","ghiChu":"Thay Nam Vân Tử giao chiến với Tiên Phi"}],"tuiDo":{}},"nguon":["@c1434","@c1436","@c1438"]},{"id":"my-phu-trung-nien-trieu-ha","name":"Mỹ phụ trung niên Triệu Hà","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Triệu Hà","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Mỹ phụ trung niên đi cùng Tử Mộng dẫn đầu đại quân Triệu Hà, cùng Lỗ Phu Tử hỗ trợ Hồng Sam Tử giao chiến hàn y đồng tử.","vaiTro":"Cao thủ Triệu Hà, đồng minh giới nội","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Cùng Lỗ Phu Tử hỗ trợ Hồng Sam Tử giáp công hàn y đồng tử.","chuong":"@c1434"}],"kinhLich":[{"chuong":"@c1434","importance":"bridge","mucCt":"gon","text":"Cùng Tử Mộng dẫn đầu đại quân Triệu Hà tới chi viện, hợp lực với Lỗ Phu Tử hỗ trợ Hồng Sam Tử giao chiến hàn y đồng tử.","anchor":"Hai người gia nhập vào cuộc chiến, khiến cho Hồng Sam Tử được thảnh thơi một chút"},{"chuong":"@c1440","importance":"bridge","mucCt":"gon","text":"Chỉ huy bộ phận tu sĩ Triệu Hà lưu lại bên ngoài cơn lốc sương mù đóng quân.","anchor":"với sự chỉ huy của mỹ phụ trung niên, yên lặng đóng quân ở đó"}],"tuViMoc":[],"nhanMach":[{"ten":"Tử Mộng","tag":"dong-minh","quanHe":"Cùng dẫn đầu đại quân Triệu Hà"},{"ten":"Lỗ Phu Tử","tag":"dong-minh","quanHe":"Hợp lực giáp công hàn y đồng tử"},{"ten":"Hồng Sam Tử","tag":"dong-minh","quanHe":"Hỗ trợ trong trận chiến"}],"tuiDo":{}},"nguon":["@c1434","@c1440"]},{"id":"hai-cao-thu-buoc-ba-dai-quan-ba","name":"Hai cao thủ bước thứ ba đại quân thứ ba","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đại quân thứ ba giới ngoại Thái Cổ Tinh Thần","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Niết Trung Kỳ","trangThai":"khong-ro","blurb":"Hai cao thủ bước thứ ba Không Niết Trung Kỳ dẫn đầu đại quân thứ ba gồm năm vạn tu sĩ giới ngoại, sắc mặt đại biến trước sức mạnh Cổ Thần của Vương Lâm.","vaiTro":"Chỉ huy đại quân thứ ba giới ngoại","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Dẫn đầu năm vạn tu sĩ giới ngoại xông vào lỗ hổng Phong Giới Đại Trận, bị Vương Lâm một mình chặn lại.","chuong":"@c1434"}],"kinhLich":[{"mucCt":"vua","text":"Dẫn đầu đại quân thứ ba gồm năm vạn tu sĩ giới ngoại xông tới lỗ hổng Phong Giới Đại Trận. Sắc mặt đại biến khi Vương Lâm hiện thân thể thật Thất Tinh Cổ Thần ngàn trượng, liên tiếp dùng Hư Hỏa và lôi đình quét sạch quân tiên phong, rồi chém Khai Thiên Phủ thẳng về phía hai người.","anchor":"Có Vương mỗ ở đây, trừ khi ta chết, không người nào có thể bước vào giới nội nửa bước","bridge":true,"khoang":"@c1434"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ trực tiếp, bị Vương Lâm chặn đường"}],"tuiDo":{}},"nguon":["@c1434"]},{"id":"phong-du","name":"Phong Dư","cn":"封余","aliases":["ngón cái","Thủ Đồ"],"gioiTinh":"nam","theLuc":[{"ten":"Chưởng Tôn (thủ đồ)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Thủ đồ của Chưởng Tôn, danh hiệu 'ngón cái', nam tử áo trắng giương cung nhắm bắn Vương Lâm từ phía Thái Cổ Tinh Thần.","vaiTro":"Thủ đồ số một của Chưởng Tôn, sát thủ cung tiễn","tinhCach":[{"text":"Lạnh lùng, xuất thủ quyết đoán, nhắm bắn ngay khi VL kiệt sức sau trận chiến"}],"tabs":{"diem":[{"text":"Thủ đồ của Chưởng Tôn, danh hiệu ngón cái, cầm cây cung mà Vương Lâm đã từng nhìn thấy","chuong":"@c1435"}],"kinhLich":[{"chuong":"@c1435","importance":"normal","mucCt":"ky","tieuDe":"Giương cung nhắm bắn Vương Lâm","text":"Xuất hiện cuối trận chiến Phong Giới từ phía Thái Cổ Tinh Thần, giương cung nhắm sát khí lên mi tâm Vương Lâm qua lỗ hổng trận pháp chưa khép hết. Vương Lâm nhận ra đã từng thấy cây cung này.","anchor":"Thủ đồ của Chưởng Tôn, ngón cái, Phong Dư"},{"chuong":"@c1438","importance":"bridge","mucCt":"vua","text":"Khiêu khích tu sĩ giới nội không ai dám tới lấy cây cung.","anchor":"Sao vậy, những đạo hữu của giới nội, không có ai dám tới lấy cây cung này sao?"}],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng Tôn","tag":"su-mon","quanHe":"Thủ đồ, danh hiệu ngón cái"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Giương cung nhắm bắn VL sau trận chiến Phong Giới"}],"tuiDo":{"phapBao":[{"ten":"Cây cung","moTa":"Cung mà Phong Dư cầm giương lên nhắm bắn VL, Vương Lâm nhận ra đã từng nhìn thấy","nguon":"@c1435"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1435","@c1438"]},{"id":"trieu-ha","name":"Triệu Hà","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Triệu Hà là nữ tu sĩ thuộc giới nội Vân Hải, tham chiến xuyên suốt cuộc đại chiến với giới ngoại. Cô từng cùng La Thiên truy kích chém giết hàng ngàn tu sĩ giới ngoại, phối hợp tấn công bàn tay khổng lồ cùng Tử Mộng, và sau đó giao chiến như la sát với tu sĩ Không Niết giới ngoại trước khi xuất nguyên thần đẩy bánh xe vòng ba.","vaiTro":"Nữ tu sĩ giới nội Vân Hải — chiến tướng tham gia nhiều trận quyết chiến với giới ngoại","tinhCach":"Hung hãn trong chiến đấu, giết đến đỏ cả mắt; quyết liệt diệt trừ ngoại địch; dũng mãnh như la sát","tabs":{"diem":[{"text":"Cùng La Thiên và mấy ngàn tu sĩ Vân Hải truy kích chém giết tu sĩ giới ngoại trong giới nội, giết đến đỏ cả mắt","chuong":"@c1435"},{"text":"Phối hợp cùng Tử Mộng và các cao thủ giới nội tấn công bàn tay khổng lồ","chuong":"@c1438"},{"text":"Xông ra từ tinh trận tham gia quyết chiến với tu sĩ giới ngoại","chuong":"@c1563"},{"text":"Như la sát giao chiến với tu sĩ Không Niết giới ngoại, nhận lệnh Vương Lâm liên thủ chặn hai Không Niết","chuong":"@c1564"},{"text":"Xuất nguyên thần cùng Hồng Sam Tử, Thanh Lâm, Thanh Thủy đẩy bánh xe vòng ba","chuong":"@c1565"}],"kinhLich":[{"mucCt":"gon","text":"Cùng La Thiên và mấy ngàn tu sĩ Vân Hải truy kích chém giết tu sĩ giới ngoại trong giới nội, giết đến đỏ cả mắt.","anchor":"Tu sĩ La Thiên, tu sĩ Triệu Hà, còn có mấy ngàn tu sĩ Vân Hải, bọn họ đã giết đến đỏ cả mắt","bridge":true,"khoang":"@c1435"},{"chuong":"@c1438","importance":"bridge","mucCt":"gon","text":"Đồng thời ra tay cùng Tử Mộng và các cao thủ giới nội tấn công bàn tay khổng lồ.","anchor":"Có thể nói tất cả những cao thủ của giới nội ở đây lúc này, toàn bộ đều trong khoảng khắc này bộc phát ra sức mạnh lớn nhất"}],"tuViMoc":[],"nhanMach":[{"ten":"La Thiên","tag":"dong-minh","quanHe":"Cùng tham chiến truy kích giới ngoại"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1435","@c1438"]},{"id":"la-thien","name":"La Thiên","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Tu sĩ giới nội, cùng Triệu Hà và mấy ngàn tu sĩ Vân Hải truy kích chém giết tu sĩ giới ngoại trong trận chiến Phong Giới.","vaiTro":"Tu sĩ giới nội tham chiến","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"mucCt":"gon","text":"Cùng Triệu Hà và tu sĩ Vân Hải tham gia trận chém giết truy kích tu sĩ giới ngoại bên trong giới nội.","anchor":"Tu sĩ La Thiên, tu sĩ Triệu Hà, còn có mấy ngàn tu sĩ Vân Hải","bridge":true,"khoang":"@c1435"}],"tuViMoc":[],"nhanMach":[{"ten":"Triệu Hà","tag":"dong-minh","quanHe":"Cùng tham chiến truy kích giới ngoại"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1435"]},{"id":"thu-do","name":"Thủ Đồ","cn":"","aliases":["Phong Dư","Nam tử áo trắng"],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1436","tieuDe":"Bắn cung Lý Quảng, chấn động Phong Giới Đại Trận","text":"Cầm cây cung Lý Quảng kéo dây cung thành hình trăng tròn rồi buông tên. Hơn một nửa sức sống bị cây cung hấp thụ khiến thân thể héo rũ như bộ xương khô. Sức sống hóa thành mũi tên hư ảo màu nhũ bạc lao qua lỗ hổng Phong Giới Đại Trận, tiếng gào thét kinh thiên khiến vô số tu sĩ cả giới ngoại lẫn giới nội thất khiếu chảy máu, một số trọng thương chết tại chỗ. Toàn bộ Phong Giới Đại Trận bao phủ khắp tinh không giới nội chấn động kịch liệt. Ngẩn người khi thấy Vương Lâm phản ứng cực nhanh, nghi ngờ đối phương nhận ra cây cung.","anchor":"Chẳng lẽ hắn lại nhận ra cây cung này"},{"chuong":"@c1437","importance":"normal","mucCt":"vua","tieuDe":"Bắn mũi tên thứ hai, trao cung cho giới nội","text":"Bắn mũi tên thứ hai từ cung Lý Quảng, dung nhan già đi nhanh chóng từ thanh niên hóa lão già do mất sức sống. Dụ phân thân Cổ Yêu vào bẫy, gọi uy áp sư tôn Phong Dư từ Thái Cổ Tinh Thần giáng bàn tay khổng lồ diệt phân thân. Tự xưng thủ đồ Chưởng Tôn Phong Dư, ném cây cung ra trước lỗ hổng Phong Giới Đại Trận, đưa điều kiện ba cơ hội lấy cung, mỗi lần trả ba phần tu sĩ giới ngoại.","anchor":"Thủ đồ của Chưởng Tôn Phong Dư, phụng mệnh sư tôn mang cây cung này tới cho những đạo hữu giới nội!"}],"tuViMoc":[],"nhanMach":[{"ten":"Phong Dư","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Phụng mệnh Phong Dư mang cung tới giới nội"}],"tuiDo":{},"diem":[{"text":"Ứng kiếp nạn thay Hồng Diệp, thống lĩnh tu sĩ Tuyết Vực tiến quân chống liên minh Tứ Phái","chuong":"@c0253"},{"text":"Kéo cung Lý Quảng bắn mũi tên đầu tiên, chấn động Phong Giới Đại Trận, mất hơn một nửa sức sống","chuong":"@c1436"},{"text":"Bắn mũi tên thứ hai từ cung Lý Quảng, dung nhan già đi nhanh chóng từ thanh niên hóa lão già, trao cung cho giới nội","chuong":"@c1437"},{"text":"Tử trận sau khi ứng kiếp thay Hồng Diệp","chuong":"@c0253"}]},"nguon":["@c1436","@c1437"],"vaiTro":"Sư tỷ của Hồng Diệp — thống lĩnh tu sĩ Tuyết Vực","tinhCach":"hy sinh quên mình, dũng cảm ứng kiếp thay người khác","blurb":"Sư tỷ của Hồng Diệp, được giao thống lĩnh toàn bộ tu sĩ nước Tuyết Vực tiến quân chống liên minh Tứ Phái, ứng kiếp nạn thay Hồng Diệp. Về sau sử dụng cung Lý Quảng bắn hai mũi tên chấn động Phong Giới Đại Trận, đánh đổi phần lớn sức sống khiến dung nhan lão hóa nhanh chóng, và cuối cùng tử trận."},{"id":"that-thai-dao-nhan","name":"Thất thải đạo nhân","cn":"七彩道人","aliases":["Thất thải đạo nhân"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","vaiTro":"Nhân vật bí ẩn, năm xưa lấy đi cây cung Lý Quảng, tự mình nuôi dưỡng thiên đạo","tinhCach":"Bí ẩn; hành tung khó lường","blurb":"Đạo nhân bí ẩn từng lấy đi cây cung Lý Quảng sau khi nó bắn rơi mắt trái Đạo cổ. Được mô tả là người tự mình nuôi dưỡng thiên đạo, mối liên hệ với Thủ Đồ của Chưởng Tôn chưa được xác nhận.","tabs":{"diem":[{"text":"Người lấy đi cây cung Lý Quảng năm xưa, tự mình nuôi dưỡng thiên đạo","chuong":"@c1436"},{"text":"Chủ động phá vỡ Bách Vạn Tu Linh Ấn, bị Chiến lão quỷ xác nhận đây là cơ hội cuối cùng","chuong":"@c1439"}],"kinhLich":[{"importance":"normal","mucCt":"gon","chuong":"@c1436","tieuDe":"Được nhắc: từng lấy cung Lý Quảng","text":"Vương Lâm hồi tưởng: cây cung năm đó đã bị thất thải đạo nhân lấy đi, nay lại ở trong tay thủ đồ Chưởng Tôn, nghi ngờ mối liên hệ giữa hai người.","anchor":"Cây cung này năm đó đã bị thất thải đạo nhân tự mình nuôi dưỡng thiên đạo lấy đi"},{"chuong":"@c1439","importance":"normal","mucCt":"vua","tieuDe":"Bách Vạn Tu Linh Ấn bị phá vỡ","text":"Chiến lão quỷ tiết lộ Thất Thải Đạo Nhân chủ động phá vỡ Bách Vạn Tu Linh Ấn, đây là cơ hội thứ ba và cuối cùng. Không trực tiếp xuất hiện, chỉ qua lời Chiến lão quỷ xác nhận.","anchor":"Thất thải đạo nhân, quả nhiên ngươi vẫn ra tay"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Vương Lâm nghi ngờ mối liên hệ giữa thất thải đạo nhân và Thủ Đồ","ghiChu":""},{"ten":"Chiến Lão Quỷ","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Chiến lão quỷ nhắc tên, nói đây là cơ hội cuối cùng"}],"tuiDo":{}},"nguon":["@c1436","@c1439"]},{"id":"ly-quang","name":"Lý Quảng","cn":"","aliases":[],"gioiTinh":"nam","trangThai":"khong-ro","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1436","tieuDe":"","text":"Được Vương Lâm hồi tưởng về sự oai hùng tuyệt đối khi bắn cung trong vùng đất cổ mộ năm xưa.","anchor":"đã nhìn thấy sự oai hùng tuyệt đối của Lý Quảng"},{"importance":"bridge","mucCt":"gon","chuong":"@c1448","bridge":true,"khoang":"@c1448–@c1448","text":"Được nhắc khi mô tả tư thế bắn tên của người điên giống hệt Lý Quảng mà Vương Lâm từng thấy.","anchor":"Nếu lúc này trong tay hắn có cung tên thì trông sẽ y hệt như Lý Quảng mà Vương Lâm nhìn thấy năm đó"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Dùng cây cung chín đạo phong ấn bắn mũi tên chứa huyết mạch tiên nhân, ghim trúng mắt trái đầu lâu Đạo Cổ Diệp Mịch rồi hóa đá tử vong","chuong":"@c1380"},{"text":"Được Thất Thải Tiên Tôn thu nạp trợ giúp trong trận chém giết Đạo Cổ Diệp Mịch","chuong":"@c1599"},{"text":"Mũi tên năm xưa bắn rơi mắt trái Đạo Cổ bị Vương Lâm thu phục làm bảo vật","chuong":"@c1482"},{"text":"Nhận truyền thừa cây cung từ lão tổ Lý gia, cung này về sau rơi vào tay Vương Lâm","chuong":"@c1870"},{"text":"Hình ảnh giương cung oai hùng được Vương Lâm hồi tưởng nhiều lần, trở thành hình mẫu bất khuất","chuong":"@c1436"}]},"nguon":["@c1436","@c1448"],"vaiTro":"Đạo sĩ áo đen bắn cung — người bắn rơi mắt trái Đạo Cổ Diệp Mịch","tinhCach":"Quyết đoán, dứt khoát trong chiến đấu; thiện xạ phi phàm; oai hùng, bất khuất trước cường địch","blurb":"Lý Quảng là đạo sĩ áo đen nổi danh với tài bắn cung, được Thất Thải Tiên Tôn thu nạp trợ giúp trong cuộc chém giết Đạo Cổ Diệp Mịch tại vùng đất cổ mộ. Ông dùng cây cung lớn mang chín đạo phong ấn bắn mũi tên chứa huyết mạch tiên nhân xuyên qua mọi trở ngại, ghim trúng mắt trái đầu lâu Diệp Mịch rồi hóa đá tử vong. Mũi tên và cây cung năm ấy về sau đều được Vương Lâm thu phục làm bảo vật, còn hình ảnh oai hùng khi giương cung củaông trở thành ký ức không phai trongâm trí Vương Lâm."},{"id":"chien-lao-quy","name":"Chiến lão quỷ","cn":"战老鬼","aliases":["Chiến lão quỷ"],"gioiTinh":"nam","vaiTro":"Sư phụ Chiến Tinh Dã — cường giả Không Kiếp ký sinh Thất Thải","tinhCach":"Ẩn nhẫn thâm trầm, thường quan sát từ xa; bá đạo quyết liệt khi ra tay; tham lam trước pháp bảo và hồn thứ ba; đa nghi cẩn trọng, biết giữ cân bằng thế lực","blurb":"Chiến Lão Quỷ, bí danh Không Kiếp, là cường giả Không Kiếp Sơ Kỳ và sư phụ của Chiến Tinh Dã, từng được nhắc là kẻ khiến Chưởng Tôn kiêng kỵ. Hắn ẩn trong Lôi Tiên Giới, nhiều lần theo dõi Vương Lâm và tứ đại chiến tướng trong cuộc truy tìm hồn thứ ba của Thất Thải Tiên Tôn. Về sau thân phận bị hồn phách Thất Thải Tiên Tôn ký sinh được hé lộ; sau khi tách hồn, hắn khôi phục bá đạo nhưng cuối cùng tử vong trong biến cố giải thoát khỏi Thất Thải.","trangThai":"song","theLuc":[{"ten":"Lý tộc","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Là cường giả cảnh giới Không Kiếp, cao hơn Không Linh và khiến Chưởng Tôn e sợ.","chuong":"@c1134"},{"text":"Từng đi tới giới ngoại và tuyên bố đã đánh bại Thái Cổ Ngũ Tôn.","chuong":"@c1438"},{"text":"Ẩn cư tại Lôi Tiên Giới hoang tàn, tự tiết lộ tu vi Không Kiếp Sơ Kỳ, tương đương Địa Tiên.","chuong":"@c1458"},{"text":"Bất ngờ xuất hiện khi Chưởng Tôn mất cảnh giác, điểm một chỉ khiến Chưởng Tôn bị thương rồi biến mất.","chuong":"@c1493"},{"text":"Được hé lộ từng độ huyền kiếp thất bại, nguyên thần tan nát, từ đó có tiên duyên với hồn thứ hai Thất Thải Tiên Tôn.","chuong":"@c1651"},{"text":"Tách hồn phách Thất Thải Tiên Tôn khỏi thân, khôi phục bá đạo năm xưa trước khi đi tới kết cục tử vong.","chuong":"@c1681"}],"kinhLich":[{"chuong":"@c1438","importance":"normal","mucCt":"ky","tieuDe":"Xuất hiện tuyên bố nhận cung cho Lý tộc","text":"Thanh âm già nua vang lên tuyên bố vẫn chưa chết, nhắc năm xưa từng đi tới giới ngoại đánh bại Thái Cổ Ngũ Tôn đoạt hương hỏa. Thân ảnh hư ảo hiện ra khi ấn ký ánh trăng lao tới, giơ ngón trỏ viết chữ Chiến phá vỡ ánh trăng. Tuyên bố cây cung ngoài Lý tộc ra không ai có thể làm chủ, cất bước đi thẳng tới cung. Chưởng Tôn kinh hãi gọi là Chiến lão quỷ.","anchor":"Tiểu tử nhát gan nhà ngươi mà cũng dám xưng Tôn sao? Cây cung này ngoài Lý tộc ra thì không ai có thể làm chủ"},{"chuong":"@c1439","importance":"normal","mucCt":"ky","tieuDe":"Đoạt cung — tiết lộ Bách Vạn Tu Linh Ấn","text":"Chụp lấy cây cung trôi giữa tinh không, phát hiện dây cung lóe ánh sáng bảy màu rồi đứt ra. Bị dây cung quất trúng, viết bảy chữ Chiến đều bị quật vỡ, phải phun chữ Chiến màu trắng mới chặn được. Ném cây cung vào giới nội rồi nhảy vào Phong Giới Đại Trận. Tiết lộ Thất Thải Đạo Nhân chủ động phá vỡ Bách Vạn Tu Linh Ấn, đây là cơ hội thứ ba và cuối cùng của hắn. Rời đi, để lại lời trêu đùa rằng cung lấy sức sống để sử dụng, ai thích thì lấy.","anchor":"Bách Vạn Tu Linh Ấn. không ngờ ngươi chủ động phá vỡ ấn này, lão phu chính là đang chờ điều này"}],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng Tôn","tag":"doi-thu","quanHe":"Kẻ thù năm xưa","ghiChu":"Từng đánh bại Chưởng Tôn (Thái Cổ Ngũ Tôn), gọi hắn là tiểu tử nhát gan"}],"tuiDo":{}},"nguon":["@c1438","@c1439"]},{"id":"dien-chu-thien-phat-dien","name":"Điện chủ Thiên Phạt Điện","cn":"","aliases":[],"gioiTinh":"nam","trangThai":"tu-vong","theLuc":[{"ten":"Thiên Phạt Điện","trangThai":"gan-bo"}],"vaiTro":"Điện chủ Thiên Phạt Điện, tử trận trong cuồng phong U Minh Thú","tinhCach":"Chưa rõ","blurb":"Điện chủ Thiên Phạt Điện, vừa thoát vòng vây khi ngọc bội Phong Tôn tiêu tan cùng Phong Giới Đại Trận sụp đổ, liền bị cuồng phong màu vàng của U Minh Thú nuốt chết — thân thể, nguyên thần, hương hỏa tan thành mây khói.","tabs":{"diem":[{"text":"Tử vong bi thảm khi vừa thoát vòng vây — bị cuồng phong U Minh Thú tiêu diệt cả thân thể lẫn nguyên thần và hương hỏa","chuong":"@c1439"}],"kinhLich":[{"chuong":"@c1439","importance":"normal","mucCt":"vua","tieuDe":"Tử vong trong cuồng phong U Minh Thú","text":"Vừa thoát khỏi vòng vây do ngọc bội Phong Tôn tiêu tan theo Phong Giới Đại Trận sụp đổ, lập tức bị cuồng phong màu vàng của U Minh Thú nuốt lấy — thân thể, nguyên thần cùng toàn bộ hương hỏa tan thành mây khói.","anchor":"lập tức bị cơn cuồng phong màu vàng này ầm ầm nuốt lấy, không kịp kêu lên một tiếng nào"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1439"]},{"id":"chu-nhu","name":"Chu Như","cn":"朱茹","aliases":[],"gioiTinh":"nu","tabs":{"kinhLich":[{"chuong":"@c1440","importance":"bridge","mucCt":"vua","text":"Nước mắt giàn giụa, kiên quyết đi cùng Tư Đồ Nam rời Vũ Giới tìm Vương Lâm, cùng hắn ngắm tinh hải trong tinh không Côn Hư.","anchor":"Chu Như nước mắt giàn giụa, kiên quyết muốn đi cùng với Tư Đồ Nam"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Nguyên Anh Lý Mộ Uyển đầu thai vào bào thai sơn thôn tại Hạnh Hoa Thôn, chuyển sinh thành Chu Như mang tư chất tuyệt hảo","chuong":"@c0314"},{"text":"Hồn phách được tách khỏi nhục thân khi Lý Mộ Uyển thức tỉnh, nhờ Vương Lâm triệu hồi mà sống sót, sau đó bị xóa ký ức và trở về cuộc đời phàm nhân","chuong":"@c0381"},{"text":"Tu luyện đạt Kết Đan kỳ nhờ khẩu quyết Vương Lâm truyền dạy, bái biệt pho tượng hắn rồi lên Chu Tước Sơn tiếp tục tu hành","chuong":"@c0567"},{"text":"Đột phá Anh Biến nhờ Thiết Nham hy sinh tuổi thọ và sức lực, sau đó rời Chu Tước Tinh","chuong":"@c0846"},{"text":"Được Vương Lâm tìm thấy và thu hồi vận mệnh trong mặt trời thứ chín","chuong":"@c1540"},{"text":"Quyết định chuyển thế đầu thai rời đi, tới bên cạnh Vương Lâm lần cuối","chuong":"@c1694"}]},"nguon":["@c1440"],"vaiTro":"Chuyển sinh phàm nhân của Nguyên Anh Lý Mộ Uyển — nghĩa nữ được Vương Lâm bảo hộ suốt nhiều kiếp","tinhCach":"Quyến luyến sâu sắc, nhiều lần bất chấp tìm kiếm Vương Lâm và không nỡ rời xa; hồn nhiên bộc trực, hay hờn dỗi giận lẫy; dã tính phóng khoáng, gắn bó với hổ Tiểu Bạch như bạn đồng hành; chí tu luyện kiên định, lấy việc tìm lại thúc thúc làm mục đích","blurb":"Chu Như là thân xác phàm nhân do Nguyên Anh Lý Mộ Uyển chuyển sinh tại Hạnh Hoa Thôn, mang tư chất tuyệt hảo bách mạch đều thông, từ nhỏ được Vương Lâm âm thầm bảo hộ rồi nuôi dưỡng trong Tiên Ngọc Bảo Tháp. Sau khi hồn phách được tách khỏi Nguyên Anh Lý Mộ Uyển và ký ức bị xóa, nàng đoàn tụ phụ mẫu rồi tự mình tu luyện đến cảnh Anh Biến, suốt đời lấy việc tìm lại thúc thúc Vương Lâm làm tâm nguyện duy nhất. Trải qua nhiều lần tái ngộ và chia ly, Chu Như cuối cùng được thu hồi vận mệnh trong mặt trời thứ chín, ở bên Vương Lâm như cô con gái trước khi quyết định chuyển thế đầu thai rời đi."},{"id":"thap-tam","name":"Thập Tam","cn":"十三","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1440","importance":"normal","mucCt":"vua","tieuDe":"Sớm nhất rời Vũ Giới tìm chủ nhân","text":"Thập Tam là người sớm nhất rời Vũ Giới, trước cả Tư Đồ Nam. Mang theo pho tượng Vương Lâm, dựa cảm ứng mơ hồ và khí tức trên pho tượng miệt mài tìm kiếm trong tinh không, vẻ kiên nghị, chưa hề mở miệng nói một câu.","anchor":"Người sớm nhất rời khỏi Vũ Giới không phải là Tư Đồ Nam, mà là Thập Tam"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Trời sinh ngộ tính, tu luyện Luyện Hồn Yêu Thuật ba tháng đạt giai đoạn ba, chế thành hồn phiên bảy thước đầu tiên","chuong":"@c0505"},{"text":"Bị phế tu vi thành người tàn phế, không cam lòng, mỗi đêm chịu đau thổ nạp tự phát luyện thể theo pháp Cự Ma Tộc","chuong":"@c0508"},{"text":"Nhận truyền thừa Cự Linh Cửu Tu từ Vương Lâm, kích động quỳ đập đầu thề cả đời tôn Vương Lâm làm Lão tổ","chuong":"@c0530"},{"text":"Ngồi dưới tượng đá Vương Lâm trên đỉnh núi suốt hơn hai nghìn ngày đêm không nhúc nhích, canh giữ động khẩu chờ sư tôn","chuong":"@c1018"},{"text":"Là người sớm nhất rời Vũ Giới, mang theo pho tượng Vương Lâm dựa cảm ứng mơ hồ khổ tìm sư tôn khắp tinh vực","chuong":"@c1440"},{"text":"Quỳ trên hư không bái biệt sư tôn, thề dù ký ức bị phong ấn vẫn không quên ân truyền thụ, tự nguyện bước vào luân hồi chuyển thế","chuong":"@c1697"}]},"nguon":["@c1440"],"vaiTro":"Đại đệ tử của Vương Lâm — thiên tài Luyện Hồn Yêu Thuật kiêm thủ lĩnh bộ lạc Luyện Hồn tại Thiên Vận Tinh","tinhCach":"Trầm ổn kiên nghị, càng trải biến cố càng vững chí; bất khuất không cam lòng, phế tu vi vẫn tự luyện thể mỗi đêm; trung thành tận tụy tuyệt đối, quỳ bái Vương Lâm làm Lão tổ và ngồi canh tượng đá suốt nghìn ngày đêm; cảnh giác điềm tĩnh trong hiểm cảnh","blurb":"Kính Thập Tam là thanh niên trời sinh ngộ tính với Luyện Hồn Yêu Thuật, chỉ ba tháng đã đạt giai đoạn ba và được Vương Lâm thu nhận làm đại đệ tử. Sau khi bị phế tu vi, gã không cam lòng mà mỗi đêm chịu đau thổ nạp luyện thể theo pháp Cự Ma Tộc, dần khôi phục sức mạnh, nhận truyền thừa Cự Linh Cửu Tu rồi quỳ đập đầu tôn Vương Lâm làm Lão tổ, về sau trở thành thủ lĩnh thần thông kinh người của bộ lạc Luyện Hồn, được rèn thân thể bằng máu Cự Ma Tộc và máu vương tộc Cổ Thần đến gần cảnh giới Tiên vệ Ngân Thi. Gã là người sớm nhất rời Vũ Giới, mang theo pho tượng Vương Lâm dựa cảm ứng mơ hồ mà khổ"},{"id":"loi-cat","name":"Lôi Cát","cn":"雷割","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1440","importance":"bridge","mucCt":"vua","text":"Cùng đầu to bỏ Vũ Giới đi tìm chủ nhân Vương Lâm.","anchor":"đầu to và Lôi Cát cũng cùng nhau bỏ đi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Mưu kế câu giờ bại lộ trước Vương Lâm khi chưa quy thuận, bộc lộ bản tính xảo trá thuở ban đầu","chuong":"@c0410"},{"text":"Thoát phong ấn từ quan tài khổng lồ tại tổng bộ Thi Âm Tông, lộ thân là người khổng lồ Cự Ma Tộc","chuong":"@c0844"},{"text":"Chính thức quy phục Vương Lâm, xưng đối phương là chủ nhân và tự nguyện làm vật cưỡi","chuong":"@c0845"},{"text":"Nổi giận xông ra chắn trước nguyên thần Đầu to, thân thể sụp đổ và nguyên thần gần tiêu tan để hộ vệ đồng bạn","chuong":"@c1009"},{"text":"Run rẩy sùng kính trước hư ảnh Cổ Thần sau Thanh quang thuẫn, liên tưởng tới thánh tổ vật của Cự Ma Tộc","chuong":"@c0923"},{"text":"Cùng Đại Đầu rời bỏ Vũ Giới để đi tìm chủ nhân Vương Lâm","chuong":"@c1440"}]},"nguon":["@c1440"],"vaiTro":"Vạn Phu Hậu Cự Ma Tộc — vật cưỡi trung thành quy phục Vương Lâm","tinhCach":"trung thành tận tụy, chủ động xả thân hộ vệ chủ nhân không màng tính mạng; sùng kính trước cường giả và lực lượng vượt bậc; xảo trá mưu mẹo khi chưa quy thuận nhưng triệt để phục tùng sau khi nhận chủ; kiên nghị chịu đựng, dù trọng thương vẫn không lùi bước","blurb":"Lôi Cát là Vạn Phu Hậu của Cự Ma Tộc, từng bị phong ấn trong quan tài khổng lồ tại nơi sâu nhất tổng bộ Thi Âm Tông. Sau khi thoát phong ấn và quy phục Vương Lâm làm chủ nhân, hắn thường xuyên hóa thân khổng lồ hàng trăm trượng để làm vật cưỡi mở đường và hộ pháp cho Vương Lâm xuyên suốt nhiều chiến trường và tinh vực. Dù tu vi không phải cao nhất trong nhóm, Lôi Cát vẫn nhiều lần lấy thân che chắn, chịu trọng thương gần tiêu tan nguyên thần mà không hề lùi bước, và cuối cùng cùng Đại Đầu rời Vũ Giới đi tìm chủ nhân."},{"id":"nu-tu-ao-lam-con-hu","name":"Nữ tử áo lam (chỉ huy Côn Hư)","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Côn Hư Tinh Vực","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tử dung nhan xinh đẹp tuyệt trần, lạnh lùng như băng, được Nam Vân Tử mời đến từ Côn Hư. Chỉ huy một vạn tu sĩ Côn Hư đóng quân bên ngoài cơn lốc sương mù, đồng thời là tổng chỉ huy toàn bộ tu sĩ giới nội đóng quân tại đây.","vaiTro":"Chỉ huy quân Côn Hư và tổng chỉ huy tu sĩ giới nội tại cơn lốc sương mù","tinhCach":"Lạnh lùng; bí ẩn","tabs":{"diem":[{"text":"Dung nhan xinh đẹp tuyệt trần, lạnh lùng như băng, thân phận bí ẩn.","chuong":"@c1440"}],"kinhLich":[{"chuong":"@c1440","importance":"normal","mucCt":"vua","tieuDe":"Chỉ huy quân Côn Hư đóng quân giới nội","text":"Được Nam Vân Tử mời đến từ Côn Hư, chỉ huy một vạn tu sĩ Côn Hư đóng bên ngoài cơn lốc sương mù, đồng thời là tổng chỉ huy toàn bộ tu sĩ giới nội tại đây. Thở dài nói câu bí ẩn hướng về Vương Lâm.","anchor":"Nữ tử mặc áo lam kia chính là vì nguyên nhân đó mà được Nam Vân Tử mời đến từ Côn Hư"}],"tuViMoc":[],"nhanMach":[{"ten":"Nam Vân Tử","tag":"dong-minh","quanHe":"Được Nam Vân Tử mời đến","ghiChu":""},{"ten":"Vương Lâm","tag":"khac","quanHe":"Có mối liên hệ bí ẩn","ghiChu":"Thở dài nói câu ám chỉ Vương Lâm sẽ không biết nàng là ai"}],"tuiDo":{}},"nguon":["@c1440"]},{"id":"van-thu","name":"Văn Thú","cn":"蚊兽","aliases":[],"gioiTinh":"khac","tabs":{"kinhLich":[{"chuong":"@c1440","importance":"bridge","mucCt":"gon","text":"Đàn Văn Thú dung hợp độc hải, không tấn công tu sĩ nào, đi thành đàn gào thét tìm Vương Lâm, tiếng kêu bi ai, tu sĩ nhìn thấy đều dừng lại vái.","anchor":"Văn Thú cũng đi tìm Vương Lâm, số lượng của bọn chúng rất nhiều"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Đột phá từ hạ phẩm linh cấp lên trung phẩm linh cấp, tương đương Nguyên Anh hậu kỳ đại viên mãn.","chuong":"@c0266"},{"text":"Được xác nhận là hung thú đến từ tinh không, sống bằng cắn nuốt vạn vật và hung tính vượt xa yêu thú tu chân.","chuong":"@c0479"},{"text":"Sau trăm năm tế luyện bằng lượng nguyên tinh khổng lồ, lột xác thành công với khí tức ngang Tịnh Niết.","chuong":"@c1153"},{"text":"Tại Phong Tiên Giới, tiến hóa thành Văn Thú Vương mới rồi xác lập vương quyền trong đàn Văn Thú.","chuong":"@c1169"},{"text":"Bất chấp nguy hiểm lột xác nhiều lần, hi sinh thân thể để đưa giọt máu của Vương Lâm vào đài cao và đánh thức chủ nhân.","chuong":"@c1703"},{"text":"Sau khi tới Tiên Cương đại lục, tiếp tục hiện thân làm tọa kỵ, nhiều lần chở Vương Lâm di chuyển và thoát thân.","chuong":"@c1773"}]},"nguon":["@c1440"],"vaiTro":"Linh thú tọa kỵ trung thành của Vương Lâm","tinhCach":"Trung thành hộ chủ; hung mãnh khát máu; nặng tình đồng tộc; kiên quyết tìm chủ","blurb":"Văn Thú, còn được gọi là con muỗi khổng lồ, là hung thú đến từ tinh không và trở thành tọa kỵ, linh thú hộ chủ lâu dài của Vương Lâm. Nó trải qua nhiều lần lột xác, khuất phục các đàn Văn Thú tại Phong Tiên Giới, tiến hóa thành Văn Thú Vương mới và tiếp tục theo Vương Lâm qua hư vô đến Tiên Cương đại lục."},{"id":"nguoi-dien","name":"Liên Đạo Phi","cn":"","aliases":["bổn vương","Nam tử thây khô","Đệ tam vương"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Liên Đạo Phi là tu sĩ mang huyết mạch Tiên Cương, vốn là kẻ ngỗ ngược trên Tiên Cương đại lục từ thời viễn cổ, bị nhốt trong Thất Thải Giới bên trong U Minh Thú không rõ bao nhiêu năm, cô độc đến phát điên. Hắn cứu Vương Lâm bằng máu và tiên lực của mình, truyền Dịch Linh Ấn cùng ba thần thông, rồi quỳ bái Vương Lâm làm sư phụ và hé lộ bí mật Tiên Chi Cửu Tuyệt. Sau khi rời Thất Thải Giới, hắn nhiều lần bị cuốn vào biến cố quanh Vương Lâm, từng lao vào Thất Thải Thương cứu sư phụ, được ca ca cứu chữa trong hoàng cung, về sau hôn mê bị chín sợi xích xuyên thân trong địa cung và hoá thành núi dư","vaiTro":"Tu sĩ tiên tộc viễn cổ mang huyết mạch Tiên Cương — đệ tử của Vương Lâm","tinhCach":"Cô độc đến điên loạn, thường tự xưng bổn vương và nói lảm nhảm; Trọng nghĩa, nhiều lần dùng máu và thân mình cứu Vương Lâm; Tự phụ giữ thể diện nhưng dễ hoảng sợ trước nguy hiểm; Nặng tình với ca ca và ba nương","tabs":{"diem":[{"text":"Lộ diện trong Thất Thải Giới, cho Vương Lâm uống máu mình để cứu mạng, nhiều lần phun máu dùng ấn ký trên tay phải hồi phục thân thể Vương Lâm","chuong":"@c1441"},{"text":"Truyền thụ Dịch Linh Ấn hoàn chỉnh cùng ba thần thông cho Vương Lâm, quỳ dập đầu bái Vương Lâm làm sư phụ và hé lộ bí mật Tiên Chi Cửu Tuyệt","chuong":"@c1450"},{"text":"Chân tướng viễn cổ được Vương Lâm xác nhận: vốn là kẻ ngỗ ngược trên Tiên Cương đại lục, thân phận và lai lịch liên quan tới tiên tộc thời thượng cổ","chuong":"@c1628"},{"text":"Lao vào Thất Thải Thương cứu Vương Lâm, thân phát kim quang nồng đậm, cả hai bị hắc động nuốt vào hư vô","chuong":"@c1493"},{"text":"Được ca ca mặc hoàng bào kéo ra từ vòng xoáy và dùng tiên lực cứu chữa trong hoàng cung khi đang hôn mê","chuong":"@c1713"},{"text":"Hôn mê trong địa cung, toàn thân bị chín sợi xích xuyên qua, về sau hoá thành núi trong không gian xếp chồng dưới hoàng cung Tổ Thành","chuong":"@c1883"}],"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1441","tieuDe":"Lộ diện trong Thất Thải Giới, cho Vương Lâm uống máu","text":"Bị nhốt trong Thất Thải Giới không biết bao nhiêu năm, cô đơn đến phát điên. Phát hiện thi thể Vương Lâm rơi từ trên trời xuống tu chân tinh, sửng sốt bốn năm mới phản ứng, kéo về chỗ mình. Liên tục tấn công thi thể bằng đủ loại thần thông: Dịch Linh Ấn chính tông do Phong Tôn truyền, Phần Giới Cổ Tán, Thất Thải Thuật, bắn mũi tên từ tay không — tất cả nhìn hoành tráng nhưng không có uy lực, chạm thi thể liền tiêu tan. Hàng ngày cắn ngón tay cho máu tươi vào miệng Vương Lâm, tự khoe máu mình đạo thánh cũng quý trọng, thánh nữ Yêu Tông cầu nhiều năm mới được một giọt. Tự xưng Tiểu Ngân Đạo Vương, nhắc tới Cổ Quốc và cung Lý Quảng nhưng không nhớ rõ. Liên tục lảm nhảm nhắc Tiểu Hồng và ca ca.","anchor":"Tiểu Ngân Đạo Vương sao có thể đánh ngươi"},{"mucCt":"ky","text":"Thấy thân thể Vương Lâm không kéo dài ra được liền phẫn nộ, dùng ấn ký quỷ dị trên tay phải vỗ ngực phun ra máu màu vàng nồng đậm tinh thuần tới cực điểm nhiều lần liên tiếp. Cuối cùng cắn đầu lưỡi phun bổn mệnh huyết — trân quý hơn máu thường vô số lần. Mất quá nhiều máu, ngất đi. Tự xưng bổn vương, nhắc tới ca ca nói máu của tộc có thể chữa khỏi mọi vết thương, nhắc tới tiểu yêu nữ tên Phi Phi từng cho hắn ăn, tức giận mắng Tiểu Hồng không tới tìm. Khẳng định máu chỉ có tác dụng khi tự nguyện phun ra, bị rút thì vô dụng.","anchor":"máu của bổn vương nếu không phải tự nguyện phun ra, thì ngay cả bị người khác rút ra cũng không có một chút tác dụng gì","bridge":true,"khoang":"@c1442"},{"mucCt":"ky","text":"Tỉnh dậy sau khi mất nhiều máu, nổi giận vì Vương Lâm chưa hồi phục. Cắn vai Vương Lâm, than tu sĩ Cổ Quốc cứng cỏi. Sai Tiểu Hồng tới Hình gia mang đồ, dọa bảo ca ca tới cướp. Tự giật đứt cánh tay trái trong cơn phẫn nộ (vết thương không máu, cực kỳ sạch), đập cánh tay xuống đất, chửi mắng mấy ngày liền. Khi gắn cánh tay lại, ấn ký hình tròn tràn ngập khí tức sơ khai hiện ra ở miệng vết thương, nhờ đó nhớ ra tam ấn tổ tiên. Bấm quyết khiến tu chân tinh chấn động, rút ấn ký trên mi tâm đặt lên tinh điểm Cổ Thần trên mi tâm Vương Lâm, tuyên bố tam ấn tổ tiên biến thành thân thể bất diệt Tiên Tộc. Bị sức mạnh Cổ Thần từ thân Vương Lâm đánh bắn tung, phun máu. Trước khi ngất nhớ ra ca ca dặn cấm truyền cho ba bộ tộc Cổ Quốc nhưng tự lừa bản thân rồi ngất đi.","anchor":"Sao bổn vương lại quên mất tam ấn của tổ tiên nhỉ","bridge":true,"khoang":"@c1443"},{"mucCt":"vua","text":"Tỉnh lại, nằm từ xa quan sát toàn bộ quá trình biến đổi của Vương Lâm. Nhận ra cảnh tượng kim thiên hắc địa là đệ nhất tướng trong cửu khúc tam tướng, giống khi tiên tổ giáng lâm năm xưa. Thấy Thiên Nghịch xuất hiện, mơ hồ nhớ đó là thứ ca ca đang tìm nhưng lại quên mất.","anchor":"đệ nhất tướng trong cửu khúc tam tướng","bridge":true,"khoang":"@c1444"},{"mucCt":"ky","text":"Tự xưng bổn vương, nói lảm nhảm mấy ngày kể chuyện Tiểu Hồng cho Vương Lâm. Biểu diễn mắt vàng rực uy nghiêm kinh thiên nhưng lập tức xì hơi mất phong thái. Nhận ra mắt Vương Lâm phát kim quang vàng nhạt là mắt vàng của tộc mình. Chứng kiến Vương Lâm dung hợp ma tinh, nhận định đó là tam đại vương tính trong cổ quốc: Cổ Thần bổn tôn, Cổ Ma phân thân. Thắc mắc Vương Lâm rõ ràng là tiên tộc nhưng có bất diệt thể chỉ hắn và ca ca mới có, lại là tu sĩ cổ quốc. Tuyên bố phải điều tra ai to gan cho tu sĩ cổ quốc bất diệt thể tiên tộc.","anchor":"Lấy Cổ Thần làm bổn tôn, Cổ Ma làm phân thân. Đây chính là tam đại vương tính trong cổ quốc","bridge":true,"khoang":"@c1445"},{"mucCt":"ky","text":"Thấy Vương Lâm tỉnh dậy, chấn động tức giận hỏi ai truyền bất diệt thể của tiên tộc cho hắn, nhưng vài giây sau quên sạch, chuyển sang gọi Vương Lâm là tiểu nương tử và tự xưng bổn vương. Bị Vương Lâm dùng cuồng phong cuốn đi mười sáu lần nhưng lại thích thú gào kích thích, chủ động giơ tay chờ bị đá tiếp. Thi gầm thét với hắc viên và thắng, đắc ý khoe giọng tốt nhất, nhắc ca ca ta cũng còn phải sợ. Cuối chương giơ tay phải điểm lên bầu trời, ngưng tụ bàn tay khổng lồ tỏa uy nghiêm mênh mông hóa chưởng ấn giáng xuống — chính là Dịch Linh Ấn rất chính tông.","anchor":"Ai truyền bất diệt thể của tiên tộc cho ngươi? Ta muốn biết tên khốn kiếp nào lại dám làm chuyện này","bridge":true,"khoang":"@c1446"},{"mucCt":"ky","text":"Thi triển Dịch Linh Ấn hoàn chỉnh trước mặt Vương Lâm, phiên bản có vân tay rõ ràng kèm gợn sóng lực chấn động Huyền Vũ tộc bao quanh. Tự hào tuyên bố thần thông trừ ca ca ra không ai sánh bằng, tiết lộ ca ca dặn không được truyền thụ cho ai. Bị Vương Lâm khích tướng bằng vẻ khinh miệt, liên tục thi triển hàng trăm lần suốt bảy canh giờ, kiệt sức nhưng rốt cục tạo được hố sâu ngang bằng. Bị Vương Lâm vu là dùng hai loại thần thông khác nhau, cảm thấy vô cùng oan khuất.","anchor":"Bổn vương rõ ràng chỉ dùng một loại thần thông, tuyệt đối không sai","bridge":true,"khoang":"@c1447"},{"mucCt":"ky","text":"Bị Vương Lâm khích bác, oan ức bật khóc và đọc toàn bộ khẩu quyết Dịch Linh Ấn cho Vương Lâm. Tiết lộ đạo thuật này do “ca ca” đoạt từ tiên tôn rồi truyền cho hắn. Ăn đan dược Vương Lâm cho, khoe khoang biểu diễn thêm ba đạo thuật mạnh mẽ: thuật ô lửa bản gốc Phần Giới Cổ Tán, thuật bắn tên tư thế Lý Quảng, thuật thương bảy màu. Nhắc tới “Tiểu Hồng” cho đan dược cực phẩm năm đó. Nhớ mang máng đã từng bị ai đó dùng chiêu tương tự lừa. Cuối chương thấy hồn ảnh U Minh thú thì hoảng sợ run rẩy, kêu “không ăn được”.","anchor":"Thần thông này gọi là Dịch Linh Ấn. là do ca ca ta đoạt được từ tiên tôn, truyền thụ cho ta","bridge":true,"khoang":"@c1448"},{"importance":"normal","mucCt":"ky","chuong":"@c1449","tieuDe":"Truyền thụ ba thần thông cho Vương Lâm","text":"Bị U Minh thú dọa vỡ mật, tự xưng bổn vương, gọi Tiểu Hồng, Tiểu Ngân cứu giá. Trong hoảng sợ cực độ, chủ động truyền thụ ba loại thần thông cho Vương Lâm: Phần Giới cổ Tán, Toái Thiên Nhất Cung (Lý tộc), thuật bảy màu. Tuyên bố ngoài ba thứ này ra còn giữ thần thông bí mật không thể nói. Sau khi thấy Vương Lâm thu phục U Minh thú, vô cùng kinh ngạc, nhận định Vương Lâm là cao nhân, nhắc lời ca ca rằng trong tinh không cao nhân không ít, tha thiết xin bái Vương Lâm làm sư phụ.","anchor":"Ca ca ta nói rằng bên trong tinh không này cao nhân không ít"},{"chuong":"@c1450","importance":"major","mucCt":"ky","tieuDe":"Bái sư Vương Lâm, hé lộ Tiên Chi Cửu Tuyệt","text":"Quỳ dập đầu bái Vương Lâm làm sư phụ, thề lấy tiên tổ cả đời không phản bội sư môn, vỗ mi tâm phóng lực thề ước dung nhập vào cơ thể Vương Lâm. Buột miệng nhắc đến Tiên Chi Cửu Tuyệt — ca ca chỉ hiểu được Thất Tuyệt — rồi vội ôm miệng nói trong cơ thể có lời thề, nói chi tiết sẽ chịu tiên phạt. Khinh thường toàn bộ thần thông Vương Lâm thi triển nhưng lại mê mẩn Dẫn Lực Thuật. Học Dẫn Lực Thuật gần như tức thì từ ngọc giản, điều khiển từ mấy chục lên trên vạn hòn đá tạo hai đạo quân trận chiến giả, tự đóng vai tiểu nương tử bảy màu. Được Vương Lâm dẫn rời tu chân tinh.","anchor":"Tiên Chi Cửu Tuyệt ngay cả ca ca ta cũng chỉ hiểu ra được có Thất Tuyệt"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Thi thể Vương Lâm rơi vào Thất Thải Giới, tu sĩ điên cho uống máu hàng ngày","ghiChu":"@c1441"},{"ten":"Chưởng Tôn","tag":"khac","quanHe":"Nhắc tới Phong Tôn là người truyền Dịch Linh Ấn chính tông","ghiChu":"@c1441"},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Xin bái làm sư phụ","ghiChu":"Tha thiết cầu xin Vương Lâm nhận làm đồ đệ sau khi chứng kiến hắn thu phục U Minh thú"}],"tuiDo":{"congPhap":[{"ten":"Dịch Linh Ấn","moTa":"Chính tông do Phong Tôn truyền, thuật mạnh nhất Thần Tông, đánh ra còn giống Phong Tôn hơn cả chính Phong Tôn","nguon":"@c1441"},{"ten":"Phần Giới Cổ Tán","moTa":"Biến thành cái ô khổng lồ chống đỡ thiên địa, nhìn hoành tráng nhưng không đủ uy lực","nguon":"@c1441"},{"ten":"Thất Thải Thuật","moTa":"Ánh sáng bảy màu hình thành bánh xe lớn ầm ầm chuyển động","nguon":"@c1441"}]}},"nguon":["@c1441","@c1442","@c1443","@c1444","@c1445","@c1446","@c1447","@c1448","@c1449","@c1450"]},{"id":"nam-tu-trung-nien-ban-tinh","nguon":["@c1417"],"name":"Nam tử trung niên (hạt châu bàn tính)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Cao thủ ẩn nấp dùng ba mươi hai hạt châu bàn tính tấn công sau lưng Vương Lâm, bản thể tới nơi, bị Chu Cẩn phá vỡ pháp bảo và truy kích.","vaiTro":"Kẻ tấn công lén Vương Lâm từ phía sau, liên thủ với Thủy Đạo Tử và Chu Đức.","tinhCach":[{"text":"Ẩn nấp tấn công lén, kinh hãi khi bị phản đòn."}],"tabs":{"diem":[{"text":"Bản thể tới tu chân tinh (không phải phân thân), bị Chu Cẩn đánh trọng thương truy kích.","chuong":"@c1417"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu tấn công","ghiChu":"Tấn công lén sau lưng Vương Lâm bằng hạt châu bàn tính."},{"ten":"Chu Cẩn","tag":"doi-thu","quanHe":"Đối thủ trực tiếp","ghiChu":"Bị Chu Cẩn phá hạt châu và truy kích."}],"tuiDo":{"phapBao":[{"ten":"Ba mươi hai hạt châu bàn tính","moTa":"Ba mươi hai hạt châu xếp thành hàng thẳng tắp, ẩn trong gợn sóng hình tròn tấn công. Bị Chu Cẩn phá vỡ hoàn toàn.","trangThai":"hong","nguon":"@c1417"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}},{"id":"lao-gia-thi-am-tong","name":"Lão già Thi Âm Tông","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thi Âm Tông","trangThai":"gan-bo"},{"ten":"Liên Minh Tinh Vực","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Lão già đến từ Thi Âm Tông thuộc Liên Minh Tinh Vực, cùng Hồng Sam Tử ra tay chống cuồng phong chuông vàng tại Vân Hải.","vaiTro":"Cao thủ Thi Âm Tông, tham gia liên thủ chống cuồng phong","tinhCach":[{"text":"Trầm tĩnh, nhận định tình thế nhanh chóng"}],"tabs":{"diem":[{"text":"Trầm giọng đánh giá Vân Hải không cứu nổi khi cuồng phong bành trướng","chuong":"@c1419"},{"text":"Trầm giọng nhận định Vân Hải không cứu nổi trước cuồng phong chuông vàng","chuong":"@c1419"}],"kinhLich":[{"chuong":"@c1419","importance":"normal","mucCt":"gon","tieuDe":"Hợp lực ngăn cuồng phong chuông vàng tại Vân Hải","text":"Từ phía đối diện Hồng Sam Tử đồng thời xuất hiện, thần sắc ngưng trọng, hai tay bấm quyết ấn về phía trước chống cuồng phong. Trầm giọng nhận định Vân Hải không xong rồi.","anchor":"lão già đến từ Thi Âm Tông trong Liên Minh Tinh Vực cũng đồng thời xuất hiện"}],"tuViMoc":[],"nhanMach":[{"ten":"Hồng Sam Tử","tag":"dong-minh","quanHe":"Đồng minh","ghiChu":"Cùng liên thủ chống cuồng phong"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1419"]},{"id":"nam-tu-trung-nien-hat-chau","name":"Nam tử trung niên (hạt châu bàn tính)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Bước thứ ba","trangThai":"song","blurb":"Cao thủ ẩn nấp dùng ba mươi hai hạt châu bàn tính tấn công lén sau lưng Vương Lâm, bản thể tới tu chân tinh, bị Chu Cẩn phá vỡ pháp bảo và truy kích.","vaiTro":"Kẻ tấn công lén Vương Lâm trong trận chiến tu chân tinh Vân Hải","tinhCach":[{"text":"Ẩn nấp đánh lén, kinh hãi khi bị lộ diện"}],"tabs":{"diem":[{"text":"Dùng ba mươi hai hạt châu bàn tính ẩn trong gợn sóng hình tròn tấn công lén, bản thể tới đây chứ không phải phân thân.","chuong":"@c1417"}],"kinhLich":[{"chuong":"@c1417","importance":"normal","mucCt":"vua","tieuDe":"Tấn công lén Vương Lâm, bị Chu Cẩn phá vỡ truy kích","text":"Dùng ba mươi hai hạt châu bàn tính ẩn trong gợn sóng tấn công sau lưng Vương Lâm. Bị Chu Cẩn thi triển Quần Lang Bái Nguyệt phá vỡ hạt châu, lộ diện bản thể đầy máu kinh hãi, bị truy kích.","anchor":"lộ ra một nam tử trung niên vẻ mặt khiếp sợ, hiện lên vé không thể tin nổi"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Mục tiêu tấn công lén","ghiChu":"Dùng hạt châu bàn tính đánh lén sau lưng Vương Lâm @c1417"},{"ten":"Chu Cẩn","tag":"doi-thu","quanHe":"Bị Chu Cẩn đánh bại truy kích","ghiChu":"Hạt châu bị phá vỡ bởi Quần Lang Bái Nguyệt @c1417"}],"tuiDo":{"phapBao":[{"ten":"Ba mươi hai hạt châu bàn tính","trangThai":"hong","moTa":"Ba mươi hai hạt châu xếp thành hàng thẳng tắp ẩn trong gợn sóng hình tròn, bị Chu Cẩn phá vỡ hoàn toàn.","nguon":"@c1417"}]}},"nguon":["@c1417"]},{"id":"chu-tuoc-doi-dau","name":"Chu Tước đời đầu","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1449","tieuDe":"","text":"Được Vương Lâm nhắc đến khi so sánh khẩu quyết: Chu Tước đời đầu năm xưa chỉ học trộm Phần Giới cổ Tán, không nắm đầy đủ.","anchor":"Chu Tước đời đầu tiên năm đó cũng chỉ là học trộm, mà không nắm được đại thần thông đạo thuật này một cách đầy đủ"}],"diem":[{"text":"Là người hiếm hoi có cách ngăn cản nghiệp hỏa thiêu đốt thân thể, được Lão Chu Tước nhắc lại","chuong":"@c1317"},{"text":"Năm xưa lừa viêm long ra khỏi viêm vực khi còn nhỏ để liên tục lấy máu","chuong":"@c1321"},{"text":"Hư hỏa biến dị của Vương Lâm là loại biến hóa mà ngay cả lão tổ đời đầu cũng chưa từng đạt tới","chuong":"@c1323"},{"text":"Chỉ học trộm được Phần Giới cổ Tán, không nắm trọn vẹn","chuong":"@c1449"},{"text":"Từng nói chỉ có thể đưa vài người rời khỏi động phủ về quê hương Tiên Cương đại lục","chuong":"@c1540"}]},"nguon":["@c1449"],"vaiTro":"Lão tổ đời đầu của Chu Tước tộc — người sáng lập nền tảng nghiên cứu nghiệp hỏa","tinhCach":"mưu lược sâu xa, dám hành sự tàn nhẫn để đạt mục đích; am hiểu sâu về hỏa đạo và nghiệp hỏa","blurb":"Lão tổ khai tộc của Chu Tước tộc, là một trong số hiếm hoi nắm được cách ngăn nghiệp hỏa thiêu đốt thân thể. Năm xưa từng lừa viêm long ra khỏi viêm vực lúc còn nhỏ để liên tục lấy máu, đồng thời chỉ học trộm được Phần Giới cổ Tán chứ không nắm trọn vẹn. Lời truyền lại của người này đặt nghiệp hỏa nhập hồn cao hơn con đường mượn bất diệt hồn hỏa, và hư hỏa biến dị của Vương Lâm là loại biến hóa mà ngay cả lão tổ đời đầu cũng chưa từng đạt tới."}]};
